-- Poems batch 367
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1ffac0d6-cd30-417e-b1e9-361c1d11d9db','建炎丞相成國呂忠穆公退老堂','江常','宋','宋诗','song-poetry','','[]','玉室璿臺奉宴居，醉吟風月在方壺。',64,'全唐诗/poet.song.81000.json','["玉室璿臺奉宴居，醉吟風月在方壺。", "山川大抵因人勝，出處由地與道俱。", "斟酌古今歸奧學，扶持宗社屬嘉謨。", "區區卻笑陶元亮，祇把南山入畫圖。"]'),
('ba52fb07-c27c-4973-85be-b8df754b025a','建炎丞相成國呂忠穆公退老堂詩  其一','錢伯言','宋','宋诗','song-poetry','','[]','今代麒麟第一功，十年勳德與天通。',64,'全唐诗/poet.song.81000.json','["今代麒麟第一功，十年勳德與天通。", "豈知樂聖銜杯地，長在重溟倒景中。", "避寵不妨成遠別，養花無意在珍叢。", "角巾私第何須問，自有公言滿舜聽。"]'),
('73732284-c84c-4317-8fa2-b0ed34b802d5','建炎丞相成國呂忠穆公退老堂詩  其二','錢伯言','宋','宋诗','song-poetry','','[]','？令台獄？羣花，名圃初成將相家。',64,'全唐诗/poet.song.81000.json','["？令台獄？羣花，名圃初成將相家。", "雲母久遮黄閤座，綺疏新照赤城霞。", "調羹梅子生無數，遵渚鴻飛去有涯。", "見說樽前富佳客，亦應思我醉時挝。"]'),
('9a00c07e-0fd4-45e6-8f89-2073e57f9a69','次韻奉和蒙著太尉澹山見示長句','錢伯言','宋','宋诗','song-poetry','','[]','澹巖宛在進江濱，多少篇章刻翠珉。',96,'全唐诗/poet.song.81000.json','["澹巖宛在進江濱，多少篇章刻翠珉。", "聞道鳳凰將九子，恰逢花木正中春。", "杖遊豈爲知名久，歷覽懸知嘯侶頻。", "林外鳥聲應報客，溪頭梅子已生人。", "茅茨信我無三顧，物象因君遂一新。", "試共攜筇采靈草，幽嵐何必與天鄰。"]'),
('db13613c-a39a-4b5c-9e2a-a4148e1fcd1e','澹山巖二首  其一','錢伯言','宋','宋诗','song-poetry','','[]','老眼遍四方，茲焉真鮮儷。',48,'全唐诗/poet.song.81000.json','["老眼遍四方，茲焉真鮮儷。", "室圜懸磬如，天側偃蓋似。", "誰移巨蟒宅，孰受祖龍使。", "祗同澹竹名，佳哉亦少味。"]'),
('f07e600c-0b9c-4d68-b887-1b6f930d05cd','澹山巖二首  其二','錢伯言','宋','宋诗','song-poetry','','[]','造化其偶然，刳山住深谷。',48,'全唐诗/poet.song.81000.json','["造化其偶然，刳山住深谷。", "迹壓瀟湘頭，迥披九疑足。", "千齡隔仙凡，跬步變寒燠。", "石田儻可種，願受自耕祿。"]'),
('e5bb781b-48a9-42eb-afe1-a1a2d6c7d831','戲書送澹山入院  其一','錢伯言','宋','宋诗','song-poetry','','[]','雲本無心出岫，水豈有意趨東。',28,'全唐诗/poet.song.81000.json','["雲本無心出岫，水豈有意趨東。", "勢或使之然者，何妨巾拂談空。"]'),
('a678a216-026d-4857-b98f-c2e2a37b7ec5','戲書送澹山入院  其二','錢伯言','宋','宋诗','song-poetry','','[]','子好逢場作戲，我方置散投閑。',28,'全唐诗/poet.song.81000.json','["子好逢場作戲，我方置散投閑。", "世味久如嚼蠟，合向茲山往還。"]'),
('ed217212-e0b9-48df-a183-61757829d145','句','錢伯言','宋','宋诗','song-poetry','','[]','華戎交氣俗，淮汴倒清渾。',12,'全唐诗/poet.song.81000.json','["華戎交氣俗，淮汴倒清渾。"]'),
('3dd4fb35-862e-4928-847a-1dca48667163','寄羅廷揚','張觷','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','曾聞避世門金馬，何事逃名寨石牛。',32,'全唐诗/poet.song.81000.json','["曾聞避世門金馬，何事逃名寨石牛。", "四海重湖今鼎沸，可能同上岳陽樓。"]'),
('5636fd00-2f39-471f-995a-56d81fd6e4bf','賦跛鼈先生趙萬宗二首  其一','傅崧卿','宋','宋诗','song-poetry','','[]','生長兵間接太平，封巒親見告功成。',32,'全唐诗/poet.song.81000.json','["生長兵間接太平，封巒親見告功成。", "茂陵遺稿猶施用，跛鼈如何獨未行。"]'),
('b1be3d58-c4af-4bbd-9b3d-3a6c02c74eec','賦跛鼈先生趙萬宗二首  其二','傅崧卿','宋','宋诗','song-poetry','','[]','鶴書東召竟牢辭，一去辭鯨世莫追。',32,'全唐诗/poet.song.81000.json','["鶴書東召竟牢辭，一去辭鯨世莫追。", "會有丹青遺像在，誰將配食季真祠。"]'),
('0f6a8ed6-33a8-4c5e-afa1-28fec4b67895','以冰餉同舍','傅崧卿','宋','宋诗','song-poetry','','[]','蓬萊道山，羣仙所遊。',40,'全唐诗/poet.song.81000.json','["蓬萊道山，羣仙所遊。", "清異人境，不風自涼。", "火雲騰空，莫之能炎。", "餉以冰雪，是謂附益。"]'),
('d7bb9a91-c966-4403-8b1c-ad5c609c36ff','句','傅崧卿','宋','宋诗','song-poetry','','[]','色带墨痕迷舊沼，響隨鐘韻下層樓。',16,'全唐诗/poet.song.81000.json','["色带墨痕迷舊沼，響隨鐘韻下層樓。"]'),
('d1f4d81f-4934-438a-8804-5e35dce46ea5','喜神贊','慕容氏','宋','宋诗','song-poetry','','[]','丹青得意以爲真，一筆掃成身外身。',32,'全唐诗/poet.song.81000.json','["丹青得意以爲真，一筆掃成身外身。", "不二法中無這箇，到頭那箇是真形。"]'),
('fe14e54c-f396-43ad-97e2-2166d8ac4e6f','叔厚內翰寵示喜雪詩謹次高韻','胡交修','宋','宋诗','song-poetry','','[]','吾君憂歲爲民祈，天報精衷喜莫違。',64,'全唐诗/poet.song.81000.json','["吾君憂歲爲民祈，天報精衷喜莫違。", "盈尺定占京輦應，餘花猶到汝邦飛。", "潤流土脈霑濡洽，巧著寒梢點綴微。", "春色欲隨晴色動，勸耕農野漸芳菲。"]'),
('6c1411f8-ac5b-4bfb-9fe5-5714f0f0d3ea','德升尚書置酒邀叔厚內翰與余同會叔厚席間賦詩道舊復寵示德升妙句俾余同和謹次韻奉呈','胡交修','宋','宋诗','song-poetry','','[]','履聲曾接中臺武，鑾禁陪刊翠琰名。',64,'全唐诗/poet.song.81000.json','["履聲曾接中臺武，鑾禁陪刊翠琰名。", "二老風流同燕席，一罇談笑會江城。", "歲寒松柏青無改，酒畔篇章語可驚。", "辱敘金蘭分贈我，勤拳尤識故人情。"]'),
('0ff146a3-720f-45b3-9b68-5bf6107111e1','再和前韻奉呈','胡交修','宋','宋诗','song-poetry','','[]','綸掖瑣闈曾並直，賢關芸閣早聞名。',64,'全唐诗/poet.song.81000.json','["綸掖瑣闈曾並直，賢關芸閣早聞名。", "追陪每憶同清禁，邂逅開懷在赤城。", "良會惟知文字飲，高歌應有鬼神驚。", "相逢一笑真何樂，寄此樽前莫逆情。"]'),
('f2b1f228-ec72-42a0-90fd-ed9d5228600b','雜興十首  其一','程俱','宋','宋诗','song-poetry','','[]','一日復一日，百年如此耳。',48,'全唐诗/poet.song.81000.json','["一日復一日，百年如此耳。", "那將千百計，來日何窮已。", "逝者不可追，來者安可知。", "正恐聞道晚，勿言功用遲。"]'),
('f947f35c-169e-4711-8109-7f5d807487e2','雜興十首  其二','程俱','宋','宋诗','song-poetry','','[]','誤點成駮牛，妙技有餘賞。',48,'全唐诗/poet.song.81000.json','["誤點成駮牛，妙技有餘賞。", "作意畫蛇足，至今猶撫掌。", "君看人間事，類此或往往。", "浩歎可奈何，悠然起遐想。"]'),
('52070ed7-f58f-4d45-9ac2-a7effe99cc13','雜興十首  其三','程俱','宋','宋诗','song-poetry','','[]','中夜忽自省，昔我今是非。',48,'全唐诗/poet.song.81000.json','["中夜忽自省，昔我今是非。", "音聲故如昨，齒長鬚滿頤。", "有人夢中言，子念無乃癡。", "今猶昔人耳，昔人安在兹。"]'),
('ebfc8e27-e1eb-42a3-b1fb-ecef06ce6233','雜興十首  其四','程俱','宋','宋诗','song-poetry','','[]','濯濯簷下溜，刁刁樹間鳴。',48,'全唐诗/poet.song.81000.json','["濯濯簷下溜，刁刁樹間鳴。", "蟲號百鳥閙，小大各有聲。", "聲多不留礙，響振元無形。", "何殊百千炬，光影各自明。"]'),
('922873b4-23fc-4504-8e33-a9dc3fd702c4','雜興十首  其五','程俱','宋','宋诗','song-poetry','','[]','胡葵向晨照，日引一尺長。',48,'全唐诗/poet.song.81000.json','["胡葵向晨照，日引一尺長。", "松栽四五年，擢幹未出墻。", "漙漙露方晞，借此顔色芳。", "各留一寸心，試待九月霜。"]'),
('cd6e49df-fde2-4fad-9278-f045fda1fc14','雜興十首  其六','程俱','宋','宋诗','song-poetry','','[]','春鳩一何拙，社燕一何巧。',48,'全唐诗/poet.song.81000.json','["春鳩一何拙，社燕一何巧。", "天陰逐其婦，飲啄聊自了。", "銜泥亦綢繆，託此華廈好。", "物生固有分，巧拙均一飽。"]'),
('0507dc02-9f96-4ac0-9ad0-dc131254d7b7','雜興十首  其七','程俱','宋','宋诗','song-poetry','','[]','穇穇新藁秸，補此茅屋漏。',48,'全唐诗/poet.song.81000.json','["穇穇新藁秸，補此茅屋漏。", "問云力田人，歲事苦耘耨。", "終年手足胝，得此以自覆。", "香秔一過眼，糠覈餘滿竇。"]'),
('9a477240-58ec-45a2-b4bc-8c332f35abab','雜興十首  其八','程俱','宋','宋诗','song-poetry','','[]','昔年過吳江，戀戀不能去。',48,'全唐诗/poet.song.81000.json','["昔年過吳江，戀戀不能去。", "臨江塵思盡，廓若掃翳霧。", "兹爲三年留，已厭波濤怒。", "乃知常人情，趣新方捨故。"]'),
('d9c16bc2-124c-4ac3-9afc-094436716baf','雜興十首  其九','程俱','宋','宋诗','song-poetry','','[]','軋軋田邊車，卷卷不得休。',48,'全唐诗/poet.song.81000.json','["軋軋田邊車，卷卷不得休。", "出之一寸痕，益以幾尺流。", "扶提暴中野，強作田家謳。", "車聲真哭聲，天遠將誰尤。"]'),
('b4ddffd0-9105-4099-9055-9a02ec426503','雜興十首  其一○','程俱','宋','宋诗','song-poetry','','[]','少小思振奇，頗恨身不長。',48,'全唐诗/poet.song.81000.json','["少小思振奇，頗恨身不長。", "身長益多累，信與憂俱生。", "回思二紀間，浪使儵忽爭。", "誰能補黥劓，反我孩與嬰。"]'),
('e3c0e07c-f7d4-40ab-afb0-e1d9c798097c','秋思','程俱','宋','宋诗','song-poetry','','[]','涼飈動秋思，中夜一長歎。',192,'全唐诗/poet.song.82000.json','["涼飈動秋思，中夜一長歎。", "月回西南隅，澹若霜華亂。", "清甘吸露井，起坐待晨盥。", "毋爲事安眠，急景不可玩。", "午陰日以薄，墜葉黄且枯。", "遶舍足榆柳，鳴條眼中疏。", "芸芸悴方榮，髪白不再青。", "所以姑射子，騎龍出蒼冥。", "殘炎如老健，雖壯寧復久。", "新涼若涓流，已快執熱手。", "蕭然發朝暮，羽扇一芻狗。", "移奪定誰尤，論功亦何有。", "饑蟬得清風，向夕聲更急。", "林間鳴絡緯，長伴幽蛩泣。", "青燈對青編，秋氣已復然。", "誰謂月有恨，正應人可憐。"]'),
('b302a40a-b929-4316-9984-61705c44da2c','吳縣游靈巖','程俱','宋','宋诗','song-poetry','','[]','春物已如許，放舟出横塘。',288,'全唐诗/poet.song.82000.json','["春物已如許，放舟出横塘。", "扶橈漾淥漲，迨此白日長。", "草木有佳色，欣欣弄浮陽。", "幽禽靜相呼，乘和自翻翔。", "春風不着人，浩浩吹我裳。", "終年思煩促，於此興未央。", "捨舟得平地，陟彼萬仞崗。", "明霞堕山西，夜氣鬰已蒼。", "豈無從我遊，夾道鬚髯張。", "風來得好語，落落隨低昂。", "幽堂掃禪榻，静對燈燭光。", "身輕浴新出，境寂慮欲忘。", "虛窗忽含曉，睡起日照梁。", "羣山發春姿，秀碧澹以芳。", "晨光晞薄露，草樹滋幽香。", "徜徉尋昔遊，步屧循長廊。", "振衣一長嘯，寸目了八荒。", "上嗟百世基，竟坐一笑亡。", "當時館娃地，今作選佛場。", "乃知諸夢境，遁化豈有常。", "飄然詠歸歟，此適頃未嘗。", "重來會有興，肯使墮渺茫。", "旁人挽余言，借問身閑忙。", "吾方有公事，子去無相妨。"]'),
('be5932b3-88c2-497c-8203-d29b83c3389a','古風送錢定國顯道  其一','程俱','宋','宋诗','song-poetry','','[]','登崖無坦蹊，下瀨無平波。',60,'全唐诗/poet.song.82000.json','["登崖無坦蹊，下瀨無平波。", "尋常即千里，奈此巇阻何。", "朝躋青陽硤，暮入萬牛渦。", "見之令人老，况乃身所過。", "賴有萬頃陂，洗我心煩痾。"]'),
('b265fd24-a28e-4621-b10b-6ed7300a8aba','古風送錢定國顯道  其二','程俱','宋','宋诗','song-poetry','','[]','中林有幽華，乃擅一國香。',72,'全唐诗/poet.song.82000.json','["中林有幽華，乃擅一國香。", "終年不自見，道路草木長。", "應知當門病，要謝移根傷。", "終恐荷鋤人，遡風襲流芳。", "紉之瓊瑤佩，致彼君子堂。", "永捐盈腰艾，扈服不可忘。"]'),
('5d1e4fb5-b427-4935-8db4-1a25d77136a1','送傅國華墨卿赴保塞簿','程俱','宋','宋诗','song-poetry','','[]','閉門坐咄咄，出門長太息。',216,'全唐诗/poet.song.82000.json','["閉門坐咄咄，出門長太息。", "問之何爲爾，歲月亦可惜。", "褰衣臨大河，跬步燕粵隔。", "回車撫長劍，玉食慘無色。", "男兒重性命，慷慨輕遠適。", "非關饑所驅，豈爲五鼎食。", "國華浙東來，觸熱向河北。", "行行四千里，易若持被直。", "怪無懷土念，語軟心似石。", "要令飽辛勤，不使鴆安逸。", "顧余一畸士，束髪守編策。", "夜闌相對語，耿耿氣横臆。", "保州幾窮塞，百里望疆埸。", "蕭蕭易水寒，壯士不復得。", "君家義陽侯，尺八建雄績。", "時平廓信度，胡頸安足赤。", "深藏百僚底，聊作青衫客。", "吾徒會時須，要子繼休奕。"]'),
('faa4a0a6-fbb6-4edc-b5d5-4107065433a6','過方子通惟深','程俱','宋','宋诗','song-poetry','','[]','白日苦易晚，我懷多隱憂。',192,'全唐诗/poet.song.82000.json','["白日苦易晚，我懷多隱憂。", "憂思劇春浸，浩漫不可收。", "出門欲有適，舉步且復休。", "塵中等膠擾，念此將焉投。", "駕言城東北，閻閭即巖丘。", "是中有幽人，厲志凌霜秋。", "寸田荆棘盡，不假斤斧脩。", "門無雜車馬，一飯乃見留。", "虛堂芝朮香，下有百尺虬。", "蒼陰匝平地，老幹森下樛。", "堂中羅酒漿，耿耿燈燭幽。", "四天黮無光，萬籟肅以揫。", "炯然坐相向，更僕語益遒。", "我身動乖迕，夢寐喬松遊。", "常恐在泥滓，永爲天所囚。", "會當從之子，濯足萬里流。"]'),
('6303d2c4-842d-494d-8c02-f95285930c1b','夜聞壁間蛩鳴有感二首  其一','程俱','宋','宋诗','song-poetry','','[]','露草亦已冷，寒蛩獨無依。',60,'全唐诗/poet.song.82000.json','["露草亦已冷，寒蛩獨無依。", "入我壁間鳴，出處定有時。", "誰言秋氣高，感此動物微。", "我欲以意續，一歎三嗟咨。", "耿耿夜將旦，殘星月邊稀。"]'),
('92e70857-5d4b-4550-b508-d80bd8d5eae7','夜聞壁間蛩鳴有感二首  其二','程俱','宋','宋诗','song-poetry','','[]','寒日苦易短，燕鴻暮何之。',60,'全唐诗/poet.song.82000.json','["寒日苦易短，燕鴻暮何之。", "念爾捨沙漠，爲此萬里飛。", "銜蘆不厭高，繫書端寄誰。", "寒聲夜相呼，客子涕已垂。", "聲斷腸亦斷，歸期各何時。"]'),
('3347686d-efe8-4028-94c1-d468ec309cfc','夜半聞横管','程俱','宋','宋诗','song-poetry','','[]','秋風夜攪浮雲起，幽夢歸來度寒水。',64,'全唐诗/poet.song.82000.json','["秋風夜攪浮雲起，幽夢歸來度寒水。", "一聲横玉静穿雲，響振疏林葉空委。", "曲終時引斷腸聲，中有千秋萬古情。", "金谷草生無限思，樓邊斜月爲誰明。"]'),
('f05e0513-bce8-4d07-bbfe-129a8496a3e7','讀神仙傳六首  其一','程俱','宋','宋诗','song-poetry','','[]','騎龍上天入太清，繼世而往在我盈。',66,'全唐诗/poet.song.82000.json','["騎龍上天入太清，繼世而往在我盈。", "握鈴而呼大司命，主非使者走折脛。", "乃知神仙非智巧，積功累行如邠鎬。", "專懷邪辟祈長年，誰言淮南雞犬飛上天。"]'),
('84e71ba1-b0ae-494f-b1a9-2acc81a3b66c','讀神仙傳六首  其二','程俱','宋','宋诗','song-poetry','','[]','安期生，赤玉舄，遺之東海濱。',68,'全唐诗/poet.song.82000.json','["安期生，赤玉舄，遺之東海濱。", "千年求我蓬萊下，祖龍豈是千年人。", "安期一量舄，葱嶺一隻履，茫茫九州在泥滓。", "至人去之如脫屣，吁嗟祖龍蕭翁寧悟此。"]'),
('b0deb7dc-9c45-43fc-85f5-24c3b46dc8f8','讀神仙傳六首  其三','程俱','宋','宋诗','song-poetry','','[]','鯉魚腹中有隱符，白魚腹中有素書。',48,'全唐诗/poet.song.82000.json','["鯉魚腹中有隱符，白魚腹中有素書。", "鞭靈走石纔一戲，騎麟上天亦徒耳。", "誰能解衣涿水中，使人呼指赤鯶公。"]'),
('f8c979a0-8c7c-4454-963e-3c81672e4d47','讀神仙傳六首  其四','程俱','宋','宋诗','song-poetry','','[]','莫作龍眉山頭客，三百年不得作直。',66,'全唐诗/poet.song.82000.json','["莫作龍眉山頭客，三百年不得作直。", "故應未辦作李公，投身百斛旨酒中。", "鼓琴先生有怒色，有愛終當爲物役。", "江都王勿預人事，倮蟲膏血使誰從汝索。"]'),
('1f0f02eb-c176-4097-8faa-d0ea66e5b710','讀神仙傳六首  其五','程俱','宋','宋诗','song-poetry','','[]','崑崙下有三頃田，赤烏玉兔蹲兩邊。',68,'全唐诗/poet.song.82000.json','["崑崙下有三頃田，赤烏玉兔蹲兩邊。", "下有烏靈木，灌以華池泉。", "耕之不用一寸鐵，使公家富不可說。", "如坻如京會有盡，萬物皆吾槖中物，摶泥作金何屑屑。"]'),
('51d1b1db-31a9-4b23-8c41-de77e42b1b71','讀神仙傳六首  其六','程俱','宋','宋诗','song-poetry','','[]','胥門着蔡經，市門着梅福。',68,'全唐诗/poet.song.82000.json','["胥門着蔡經，市門着梅福。", "我爲松江吏，與汝相望亦相逐。", "高冠長劍衛士從，有口底事使蠟封。", "此身况不爲陳尉，就公蠟封三尺喙，不能擲米作珠爲狡獪。"]'),
('faa5af92-6a05-4466-aa7e-fe39a0480e6b','古釣臺歌送阮閱休美成沿檄浙東','程俱','宋','宋诗','song-poetry','','[]','餓夫一往西山空，攫金胠篋清晝同。',360,'全唐诗/poet.song.82000.json','["餓夫一往西山空，攫金胠篋清晝同。", "東方作矣事何若，玉柙未解裙襦中。", "排肩炙手日卓午，暮夜掉臂日送西飛鴻。", "謂言冰壺不受汙，正似馬耳經東風。", "我思一人，去我千載，乃在浙水之東富春瀨。", "山嶔嶇兮矗雲漢，溪流喧豗白石亂。", "瀨聲盡處萬尋碧，蟠蜒蜿兮守斯人之故宅。", "旁人指山名釣臺，下視九土氛黄埃。", "投竿百犗何足道，直拂三珠挂瑤草。", "彼一人兮皎獨立，清風爲神冰爲骨，佩瓊蕤兮結明月。", "紉蘅蘭以薦枕兮，服龍淵之無缺。", "羊裘蒙茸溪水旁，大勝被衮升明堂。", "劉秀發兵誅不道氣，厭昆陽纔一掃。", "登床撫腹坐太息，始信赤符非至寶。", "君房素癡定不癡，致位鼎足何其危。", "阿諛順旨腰領絕，安知直言身見殺。", "我昔客新定，挂帆七里灘。", "整冠拜祠下，巖巖千仞層臺巔。", "神遊八海極，彷彿聆其語。", "但覺萬古松風寒，滔滔舉世無不可。", "正自喪我非毋我，嚴灘水清山翠微。", "貪廉懦立歸來兮，奎蹄絮縫不可以久棲。"]'),
('3dd7890d-3dd2-4b95-addf-9ec3c6ac8f71','即事戲作四首  其一','程俱','宋','宋诗','song-poetry','','[]','老烏作巢一何拙，柳條垂絲今秃缺。',64,'全唐诗/poet.song.82000.json','["老烏作巢一何拙，柳條垂絲今秃缺。", "銜枝復墮苦饒舌，編條作巢枝錯節。", "老烏柳好汝勿傷，藏烏待得春葉長。", "安巢令汝着哺母，密葉更能庇風雨。"]'),
('bfcd72e2-5180-40d7-98fe-458b8fe7b439','即事戲作四首  其二','程俱','宋','宋诗','song-poetry','','[]','黄雀黄雀飛相逐，相呼門前啄遺粟。',32,'全唐诗/poet.song.82000.json','["黄雀黄雀飛相逐，相呼門前啄遺粟。", "啄粟飽即休，有人挾箒掃泥待作粥。"]'),
('d0f4f067-a992-453f-af88-11ced45443aa','即事戲作四首  其三','程俱','宋','宋诗','song-poetry','','[]','鶴唳固有似，云何啄泥取蚯蚓。',48,'全唐诗/poet.song.82000.json','["鶴唳固有似，云何啄泥取蚯蚓。", "蚯蚓食泉曾不惡，鰌鱓蜿蜒尤不忍。", "何如忍饑向芝田，腥涎溷爾不得飛上天。"]'),
('2a06f974-13e5-46f0-8d56-c8f4c8ab0a53','即事戲作四首  其四','程俱','宋','宋诗','song-poetry','','[]','烏啼未必惡，麾去恨不早。',68,'全唐诗/poet.song.82000.json','["烏啼未必惡，麾去恨不早。", "鵲噪兩耳聾，主人亦言好。", "安知一喙鳴，喜戚自顛倒。", "朝來羣鵲噪不已，童稚無知助吾喜。", "羣鵲自與烏爭巢，慎勿喜歡真誤爾。"]'),
('9d4c2a30-926b-47ea-bd55-b037e2eb4dca','謝人惠硯','程俱','宋','宋诗','song-poetry','','[]','帝鴻墨海世不見，近愛端溪青紫硯。',128,'全唐诗/poet.song.82000.json','["帝鴻墨海世不見，近愛端溪青紫硯。", "溪流見底寒且清，光凝淺紺淵之精。", "斧柯千古遺仙局，雲暗半山含紫玉。", "割雲鑱玉巧如神，龍尾銅臺可奴僕。", "君來自南數千里，不載珠璣似薏苡。", "芊芊溪草裹石硯，文字之祥直送喜。", "明窗大几墨花春，爐山吐蘭千穗雲。", "虛中含默静相對，那復草玄驚世人。"]'),
('b44a7003-53eb-4af0-8aa1-e3fef4d36c6f','穹窿葬事回邑有感','程俱','宋','宋诗','song-poetry','','[]','生别萬里餘，會面終有期。',144,'全唐诗/poet.song.82000.json','["生别萬里餘，會面終有期。", "死别不轉眸，一朝千古非。", "白日光在天，玄陰閟泉扉。", "盈盈閨中秀，土化成枯骴。", "冠笄共甘苦，謂見素髪垂。", "那知死生變，不待桑蔭移。", "室有病時菌，篋有嫁時衣。", "了了眼中事，閑粧静容儀。", "垂楊手曾折，爲我當春稀。", "迅流無迴波，落英無還枝。", "空房閴無迹，新墳草離離。", "傷心北門道，同來不同歸。"]'),
('0ea0a19c-dd75-46d0-8c59-aa3223307b12','遊華藏此君亭','程俱','宋','宋诗','song-poetry','','[]','山空木葉脫，霜露日已寒。',168,'全唐诗/poet.song.82000.json','["山空木葉脫，霜露日已寒。", "蕭蕭歲寒子，勁氣不可干。", "下庇秋草根，上棲衆鳥安。", "煙梢掠雲漢，過者仰首觀。", "云何九衢罅，有此五畝寛。", "况當祇洹舍，永謝翦伐歎。", "高人名此君，千載莫敢刊。", "豈同渭川封，肯汙秦氏官。", "鵷鶵未來食，螟螣或見殘。", "終然保常操，特立良獨難。", "我疑卞忠貞，鐵石瑣肺肝。", "遺骸寄此地，藏碧留餘丹。", "精誠入毛髪，化此千琅玕。", "見之發三歎，臨風肅衣冠。"]'),
('55d40650-b1c2-4102-9327-a458c9d75acd','獨遊保寧鳳凰臺','程俱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','饑鴞嚇腐鼠，鳴鳥久不聞。',216,'全唐诗/poet.song.82000.json','["饑鴞嚇腐鼠，鳴鳥久不聞。", "一登鳳凰臺，目送蒼梧雲。", "山川麗晚日，氲氲發餘薰。", "覽此萬里輝，振我衣上塵。", "前瞻翠回環，極望天無垠。", "低昂玄盤踞，佳氣或未湮。", "山坳指樓觀，青骨今尚神。", "馳煙謝逋客，三徑久已榛。", "長松眇如薺，下有高世人。", "斯人不可作，此道日以新。", "回睇白鷺洲，長江瀉沄沄。", "遙岑出澹碧，不辨楚與秦。", "我行適淮西，出處難重陳。", "豈無覉旅歎，乃有山水因。", "兹遊頗幽獨，作伴影與身。", "寧辭足力盡，聊使眉頭伸。", "憑虛默自計，逝將祈孔賓。", "寄聲華陽老，異日期相親。"]'),
('027e1964-2e9e-4b8c-8ada-396cae109dde','過劉姓園居','程俱','宋','宋诗','song-poetry','','[]','負郭三頃稻，並田五畝園。',192,'全唐诗/poet.song.82000.json','["負郭三頃稻，並田五畝園。", "人生如此足，安用華其軒。", "親戚居南陌，交遊在東村。", "有酒輒共醉，傾輸見情言。", "三徑雜桃李，九畦蒔蘭蓀。", "黄柑百頭奴，碧梧萬支孫。", "山供景無盡，石映溪不渾。", "桑麻中饋任，布刈鄰翁論。", "下以活妻孥，上以奉清温。", "時從赤松子，亦訪吳市門。", "嗟我抱此志，十年若朝昏。", "家山眇天末，松菊豈復存。", "兹園臨官道，坐笑車馬奔。", "前山復場圃，疏築隨坳墩。", "我來適春穠，亂眼紅青紛。", "怳然動鄉思，夢寄東飛雲。"]'),
('6b6508c0-d018-45c3-ad05-09a69c980b15','宿海會寺','程俱','宋','宋诗','song-poetry','','[]','萬杉堆青没山骨，雲埋七峰時出没。',144,'全唐诗/poet.song.82000.json','["萬杉堆青没山骨，雲埋七峰時出没。", "飛泉拂石瀉哀湍，下有萬古蛟龍窟。", "藏頭睡熟呼不起，地坼三年蝗蝻出。", "千山脉理漬清甘，一罅涓涓流石液。", "同遊况與惠詢輩，納屐振衣何勃窣。", "大門當前新築道，跨水曲欄欹突兀。", "舂鳴轣轆趁朝炊，水畎懸流機械發。", "搘筇對此自三歎，抱甕老人長搰搰。", "却坐幽堂忽浩歌，回首已失西山日。"]'),
('cc982d3f-e21a-47f2-bfdc-d17f20727f31','山谷寺','程俱','宋','宋诗','song-poetry','','[]','竺法暨華土，出傳骨與書。',252,'全唐诗/poet.song.82000.json','["竺法暨華土，出傳骨與書。", "金仙屹不動，坐使四海趨。", "山川第一勝，盡爲佛者居。", "葱葱灊之谷，蛟鸞互盤紆。", "一爲飛錫先，方士回雲車。", "顧盼榛楚地，翬簷湧層虚。", "英靈護泉脈，飲此白足徒。", "當年蓋國衆，莫挽碧眼胡。", "傳衣到三葉，此地滋焦枯。", "異氣生傑閣，宸奎動天樞。", "神龍盡傾向，寶此明月珠。", "三聖陟帝所，雲章久寧渝。", "餘霑及婆塞，歲復六七夫。", "堂中老沙門，古態幾皇胥。", "定知黄龍窟，不着點額魚。", "門開兩山峽，萃然七浮圖。", "沙步對石麓，溪流清且徐。", "危甍隱深樾，間見碧與朱。", "朝來雨脚斷，雲氣尚卷舒。", "懸知磴道滑，一水不復逾。", "州家有造詣，上馬及未晡。"]'),
('7e4273db-b5ad-4a79-a88c-57a2d128cdb7','石牛洞','程俱','宋','宋诗','song-poetry','','[]','陽城山頭遽如許，金華山中呼不去。',112,'全唐诗/poet.song.82000.json','["陽城山頭遽如許，金華山中呼不去。", "癡牛赤脚墮天河，共向空山飽煙霧。", "阿瞞安知眇道士，丹井至今存故處。", "琤淙萬古穿石斷，峽束奔流閙山塢。", "嵬峨上鬰千仞勢，洞下坡陀無塊土。", "文公古句驚舊觀，拂拭蒼莓增媚嫵。", "亦欲磨崖放楚狂，掃迹政恐山神怒。"]'),
('d8503445-a564-41a1-87f6-f061756142b7','望九華','程俱','宋','宋诗','song-poetry','','[]','卷簾坐對江南山，掠眼送青來亹亹。',128,'全唐诗/poet.song.82000.json','["卷簾坐對江南山，掠眼送青來亹亹。", "雲泉肺腸久厭飫，挂頰悠然聊復爾。", "奇峰遠澹忽四五，爽秀駸駸逼窗几。", "平生九華盛名下，一見定知真是矣。", "非關目力覩天奥，正覺羣山如聚米。", "好人好人有高韻，不獨江州孟公子。", "直緣佳處無仕逕，落莫道邊同苦李。", "大是忘年耐久交，藜杖青鞋結終始。"]'),
('a7e23f70-c5e2-47d7-a237-2082f0900fe9','谿行歎','程俱','宋','宋诗','song-poetry','','[]','潾潾石間流，落落灘下石。',144,'全唐诗/poet.song.82000.json','["潾潾石間流，落落灘下石。", "相因成悍嶮，日夜更拒激。", "化爲百雷車，轉入千丈碧。", "推舟上磊砢，盡日不尋尺。", "我行三伏中，正自澀如棘。", "于時久不雨，陽炎劇炊炙。", "谿流僅如綫，但見沙渚赤。", "逶迤呼蛇港，百步涉重磧。", "迢迢神亭瀨，奡盪無遺力。", "此身誠不貲，此日良足惜。", "胡爲棄分陰，盡室寄囏阨。", "長謡飛仙章，慷慨三歎息。"]'),
('e90fc86d-960c-433c-bf3f-e807f740291a','山中對酒','程俱','宋','宋诗','song-poetry','','[]','秋容澹青山，爽秀雨皆足。',108,'全唐诗/poet.song.82000.json','["秋容澹青山，爽秀雨皆足。", "清溪照千仞，空翠疑可掬。", "何年顧兔窟，桂子墮山腹。", "老香散深林，屑玉綴黄粟。", "朝來客衣動，一葉下空谷。", "客心如棼絲，日月共煩促。", "胸中尚磊塊，陶寫賴新淥。", "要當酒千鍾，澆我愁萬斛。", "顧有獨醒人，脩然倚枯木。"]'),
('f710208d-064e-4fe1-8343-2e60653735b5','二月二日富陽城東  其一','程俱','宋','宋诗','song-poetry','','[]','閉門三日坐聽雨，不知春光已如許。',64,'全唐诗/poet.song.82000.json','["閉門三日坐聽雨，不知春光已如許。", "桃李弄晴成艷笑，穠李怯風猶半吐。", "當年赤白桃李花，恨無佳人絕代歌。", "無事對花豈易得，有酒不飲將如何。"]'),
('713ff0aa-5727-4789-963b-c5cd0def6458','二月二日富陽城東  其二','程俱','宋','宋诗','song-poetry','','[]','一春何許最佳處，柳色初匀思殺人。',64,'全唐诗/poet.song.82000.json','["一春何許最佳處，柳色初匀思殺人。", "風揉雨練不可觸，明綠映空顔色新。", "舊雨來時花未齊，今雨一過花團枝。", "明朝試踏城西路，已復可憐枝上稀。"]'),
('5c77cebc-9756-4706-99d1-d3c63da4a521','桐廬道中書事','程俱','宋','宋诗','song-poetry','','[]','一星熠熠初尚微，俄頃滿天如灼龜。',64,'全唐诗/poet.song.82000.json','["一星熠熠初尚微，俄頃滿天如灼龜。", "溪流黯黮四山黑，怒芒當空唯太白。", "舉頭仰書天漫漫，飛星縱横絕河漢。", "新月未高不可見，終夜起坐發三歎。"]'),
('639a3f98-d251-4bbc-a071-657a8be40a83','題張大丞明園亭','程俱','宋','宋诗','song-poetry','','[]','京華真陸海，聲利之所闤。',228,'全唐诗/poet.song.82000.json','["京華真陸海，聲利之所闤。", "向來山林士，往往去不還。", "濡足未肯已，没身何足歎。", "張侯翰林客，金龜著朝班。", "生平用一指，談笑起廢殘。", "紛紛多盧子，名譽莫敢攀。", "五十未云老，幡然歸故山。", "歸來謝奔走，治此五畝園。", "養樹如養生，斤斧不浪干。", "醫花如醫疾，察標見其源。", "上有十圍木，蓊然午陰寛。", "下有百步荷，紅鮮映清瀾。", "爽氣日多佳，西山挂簷端。", "安能九衢內，髀肉磨韉鞍。", "我今坐奇窮，進退坎井間。", "違己恨紆轡，長饑思抱關。", "當時彭澤令，四壁唯瓢簞。", "折腰未爲辱，徑去曾無難。", "而我亦何者，栖栖猶強顔。"]'),
('87e45f47-1f8a-475e-9be3-9057e9ae4e68','送崔閑歸廬山四首  其一','程俱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','白露下脩竹，當窗作秋聲。',84,'全唐诗/poet.song.82000.json','["白露下脩竹，當窗作秋聲。", "冷然拂商絃，客子中夜驚。", "振衣一長嘯，下瀨如飛星。", "昔者去草堂，新松蔭軒榮。", "别來今十年，霜華着青青。", "想見溜雨姿，森蒼舞蛟鯨。", "歸與當及健，羈栖亦何營。"]'),
('275a6fb9-4531-44ec-8ea5-be802d08b164','送崔閑歸廬山四首  其二','程俱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','瑯琊山中水，韻入三尺桐。',84,'全唐诗/poet.song.82000.json','["瑯琊山中水，韻入三尺桐。", "琅然醉翁操，發自玉澗翁。", "流泉不成音，寫寄十二宫。", "醉翁不可見，妙語聊形容。", "嘗聞三峽泉，上與天漢通。", "請君記餘響，相彼玉佩風。", "此聲倘可繼，那復有此公。"]'),
('8d03a89e-e887-44ee-a709-aa0bb24b0a29','送崔閑歸廬山四首  其三','程俱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','論世得師友，陶公乃其人。',108,'全唐诗/poet.song.82000.json','["論世得師友，陶公乃其人。", "清遊入夢寐，廬山真夙因。", "邇來二十年，浪染衣上塵。", "陶公已去久，歘如空中雲。", "廬山如高士，可望不可親。", "坐想虎溪路，聞鐘動微顰。", "永懷爐峰頂，飛煙發朝曛。", "羨子歸故隱，兹焉畢其身。", "吾意久規往，當從君問津。"]'),
('2883e54e-3584-4ce8-a810-aa486b5658cf','送崔閑歸廬山四首  其四','程俱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','吾友胡少汲，結廬皖公城。',96,'全唐诗/poet.song.82000.json','["吾友胡少汲，結廬皖公城。", "灊山有小隱，背負紫翠屏。", "前臨一溪水，可以濯我纓。", "欲分青山半，留我谷口耕。", "信美非吾鄉，翩然遂宵征。", "聞君草堂處，亦復占地靈。", "虛簷倚蒼崖，下有玉澗鳴。", "樂哉不可到，因君懷友生。"]'),
('85764e2d-d0c2-4431-b7e1-0eecd4272e66','黄魯直有食甘念慈母衣綻懷孟光之句用爲韻作五作以寄旅懷  其一','程俱','宋','宋诗','song-poetry','','[]','據梧不必席，裹趼不必舄。',48,'全唐诗/poet.song.82000.json','["據梧不必席，裹趼不必舄。", "饑來太倉陳，飽勝列鼎食。", "願言伏嵁巖，保此稼穡甘。", "正使能已百，寧當籠暮三。"]'),
('06175729-7c16-46de-a12a-f41221b63302','黄魯直有食甘念慈母衣綻懷孟光之句用爲韻作五作以寄旅懷  其二','程俱','宋','宋诗','song-poetry','','[]','凋林如白鬢，色變不可染。',48,'全唐诗/poet.song.82000.json','["凋林如白鬢，色變不可染。", "招提據木末，清凜絕浮念。", "俯窺羣啄雞，仰見烏哺兒。", "歛手不敢嚇，無爲傷彼慈。"]'),
('69ab67a9-06eb-4c39-9592-ba02935dd0ad','黄魯直有食甘念慈母衣綻懷孟光之句用爲韻作五作以寄旅懷  其三','程俱','宋','宋诗','song-poetry','','[]','吳山視諸山，聳秀若諸母。',72,'全唐诗/poet.song.82000.json','["吳山視諸山，聳秀若諸母。", "上有一段雲，使我屢回首。", "瀫水向浙水，涼飊生遠漪。", "中有一雙鯉，爲傳我所思。", "高堂有華髪，游子行當歸。", "歸歟不可緩，霜露沾人衣。"]'),
('efc0643d-7602-48c6-91a1-9e63273291c0','黄魯直有食甘念慈母衣綻懷孟光之句用爲韻作五作以寄旅懷  其四','程俱','宋','宋诗','song-poetry','','[]','棼絲不可經，百結不可綻。',48,'全唐诗/poet.song.82000.json','["棼絲不可經，百結不可綻。", "吾今成放浪，豈復事編簡。", "羈游無好懷，坐看西日頹。", "壯心正不已，亦復何爲哉。"]'),
('0eca3705-6623-4130-b216-3e125d379fcb','黄魯直有食甘念慈母衣綻懷孟光之句用爲韻作五作以寄旅懷  其五','程俱','宋','宋诗','song-poetry','','[]','伯鸞未山棲，俯首愧賢孟。',84,'全唐诗/poet.song.82000.json','["伯鸞未山棲，俯首愧賢孟。", "一朝相告語，矯首謝三聘。", "謝公卧東山，故有經綸興。", "夫人勸之仕，擁鼻作傖詠。", "終然爲時須，起攬晉國柄。", "古人重行藏，二士聿有光。", "吾志屬有在，姑安此糟糠。"]'),
('f06729be-efe6-4794-881f-34e5b8d950ef','有美一人  其一','程俱','宋','宋诗','song-poetry','','[]','有美一人在昭君，藕絲爲衣蘭作裙。',64,'全唐诗/poet.song.82000.json','["有美一人在昭君，藕絲爲衣蘭作裙。", "君初顧言淑且真，直欲載以黄金輪。", "人心變化如浮雲，明粧覺暗笑作顰。", "何當還之承華茵，令君宴寢凝清芬。"]'),
('4830046e-4668-40cc-9f9c-072fb752987e','有美一人  其二','程俱','宋','宋诗','song-poetry','','[]','有美一人在煙汀，朱顔朝滌玉壺冰。',56,'全唐诗/poet.song.82000.json','["有美一人在煙汀，朱顔朝滌玉壺冰。", "素手暮理朱絲繩。", "語言窈窕丹鳳鳴，坐持紈扇睇秋螢。", "何當還之翡翠屏，爲君把鏡整衿纓。"]'),
('d6cf0cf5-a2b0-48fc-9a1d-a75adacd258b','有美一人  其三','程俱','宋','宋诗','song-poetry','','[]','有美一人在南浦，月明採珠光照渚。',48,'全唐诗/poet.song.82000.json','["有美一人在南浦，月明採珠光照渚。", "瑤衣被體金索縷，獨抱幽寒沬煙雨。", "何當置之白玉宇，爲君歌陽春激楚。"]'),
('58715933-293b-49cf-8155-869ecf7f377a','辨師鼓琴','程俱','宋','宋诗','song-poetry','','[]','上人芒屨麻爲衣，常脩如幻三摩提。',131,'全唐诗/poet.song.82000.json','["上人芒屨麻爲衣，常脩如幻三摩提。", "但依三業作供養，坐見八德金沙池。", "是中寶網間行樹，微妙音出難思惟。", "師從定觀起奮迅，寫之三尺桐與絲。", "枯桐{号攵}然若空谷，人倚繩床支槁木。", "枯桐枯木静相向，中有世間無盡曲。", "曲中有曲非宫商，及門但覺聲琅琅。", "罷琴一笑各揮手，庭樹微風清夜涼。"]'),
('03e96191-616d-4245-9078-0070d738e814','山中秋夜','程俱','宋','宋诗','song-poetry','','[]','夜氣挾秋至，颸然出戶庭。',108,'全唐诗/poet.song.82000.json','["夜氣挾秋至，颸然出戶庭。", "空山答清漏，客夢忽以醒。", "林梢月未墮，流光委疏櫺。", "冷露濕山桂，寒蕤動幽馨。", "整衣坐蒲團，破屋呈稀星。", "我身本無涯，寒暑飽所經。", "以彼泡電境，勞此草木形。", "吾猶昔人耳，不與寒暑并。", "蘧然返初枕，人境已兩冥。"]'),
('eadc5574-821e-407f-b135-22c8e47f484a','賦長興錢圃翁詩','程俱','宋','宋诗','song-poetry','','[]','學書要不成，學圃苦不早。',96,'全唐诗/poet.song.82000.json','["學書要不成，學圃苦不早。", "向來執戟郎，何似於陵老。", "我無拏雲意，所念在一飽。", "閉門種蕪菁，抱甕澤枯槁。", "荒畦財一席，嚙嚼到春草。", "頗聞長興翁，八十顔色好。", "城西有寛閑，終歲常却掃。", "安得五畝園，如翁一生了。"]'),
('820e9424-a6bb-4da6-8593-2ce6810cb1e9','秀州沈珪漆煙最善持葉翰林詩來求余詩爲作一首','程俱','宋','宋诗','song-poetry','','[]','白頭柱史寥陽居，浮提龍檢封金壺。',144,'全唐诗/poet.song.82000.json','["白頭柱史寥陽居，浮提龍檢封金壺。", "千金寶液出方外，灑作三元雲篆書。", "至今道德五千字，一一破闇如明珠。", "安知此老天地祖，聊遣二化爲詼娛。", "華亭老工入吳市，戲以淳漆滋松腴。", "壁中科斗何足道，勒崇正欲遵河圖。", "故令墨客從毛穎，玉堂伴直鄰清都。", "如椽之筆吐光燄，賡歌紀瑞無時無。", "却分圭璧到蓬戶，寂漠著書憐腐儒。"]'),
('8ba86df6-a4f3-48ba-accd-b6ab7e721b7a','吳下去冬不寒春不雨人以爲病城中火災相仍自十二月至今凡八九發雍熙佛寺災勢尤甚閭里訛言相驚往往徙貨泉載家具日爲避火計二月乙巳郡守以承天佛寺慧感神像供府第爲佛事禳禱是日雨明日雪丁未又大雪農事有初火怪庶或熄人心稍安作詩記其事','程俱','宋','宋诗','song-poetry','','[]','飛蟲滿空冬不冰，迎春草木皆夭榮。',208,'全唐诗/poet.song.82000.json','["飛蟲滿空冬不冰，迎春草木皆夭榮。", "轆轤續綆楹桷燥，緋衣老人白晝行。", "城中一日二三發，徼巡司虣徒縱横。", "化城海藏湧地出，耀眼金碧明青冥。", "中宵澒洞半天赤，一彈指頃隨煙升。", "重雲仙人具悲智，脫屣珍麗依無生。", "千年吳地赴緣感，疾甚景響從形聲。", "入廛應供始敷坐，一雨便覺歊塵清。", "黎明密雪灑四澤，灝氣交徹何晶熒。", "勾芒蒙潤亦助喜，眩轉鼓舞隨飛英。", "畢方褫魄走荒外，雖有光怪何由呈。", "衡茅倦客正高卧，浩歌黄竹饑腸鳴。", "妻孥號寒不敢恨，且慰南畝滋春耕。"]'),
('53871f7b-dbbc-4590-a4b8-429b3366dbd2','和葉翰林阻雨楓橋','程俱','宋','宋诗','song-poetry','','[]','白雨下車軸，江湖與天鄰。',120,'全唐诗/poet.song.82000.json','["白雨下車軸，江湖與天鄰。", "渾流已横潰，川陸無行人。", "蕩蕩淮楚舟，篙檣動蕭晨。", "淹留寒山寺，河灣俯清淪。", "虛堂夢春草，落紙佳句新。", "長嘯寄遐想，深談破無因。", "泊無軒裳累，但覺山林親。", "遲遲去魯意，欲駕還逡巡。", "陰霖固無限，所念商農迍。", "乃知君子懷，絕出世俗塵。"]'),
('3dd3d006-71f1-42fe-8616-5e6656f61bee','天寧潛老以山中春莫三詩投鴻慶尚書末章見及次韻答之  其一','程俱','宋','宋诗','song-poetry','','[]','大空無故新，春物自來去。',48,'全唐诗/poet.song.82000.json','["大空無故新，春物自來去。", "風幡有時轉，霜鐸深夜語。", "芸芸無定在，榮悴更彼此。", "誰於百草頭，了不挂絲縷。"]'),
('47c58eb6-91ba-4dda-b3b7-7ccb864caabd','天寧潛老以山中春莫三詩投鴻慶尚書末章見及次韻答之  其二','程俱','宋','宋诗','song-poetry','','[]','當年白尚書，居士衆稱首。',48,'全唐诗/poet.song.82000.json','["當年白尚書，居士衆稱首。", "魔軍坐調伏，消散如拉朽。", "何如丹陽侯，法鼓開聽牖。", "方當與天遊，豈復爲物囿。"]'),
('2d534099-818a-44af-8fe3-453ca27d16b8','天寧潛老以山中春莫三詩投鴻慶尚書末章見及次韻答之  其三','程俱','宋','宋诗','song-poetry','','[]','踉蹌鶴阿師，遮眼寄經籍。',48,'全唐诗/poet.song.82000.json','["踉蹌鶴阿師，遮眼寄經籍。", "苦吟思島可，達觀泯儒墨。", "高軒時一過，解带有餘適。", "頹然後車人，大瓠號五石。"]'),
('346f17fa-94c0-4c6d-933c-5bdbeca86e75','泊義興長橋','程俱','宋','宋诗','song-poetry','','[]','俠骨久已朽，南山長於菟。',84,'全唐诗/poet.song.82000.json','["俠骨久已朽，南山長於菟。", "當時老蛟窟，遺種今有無。", "我來適秋成，場圃收刈初。", "年豐似足樂，薄酒儻可酤。", "田家復何事，父老仍愁吁。", "滔滔五濁海，所向誰當娛。", "長年得強健，且食清溪魚。"]'),
('b8cb5a8c-0aaf-43f8-a5ff-d9ce8107334c','遊善權寺','程俱','宋','宋诗','song-poetry','','[]','放舟荆溪上，溪水清且徐。',132,'全唐诗/poet.song.82000.json','["放舟荆溪上，溪水清且徐。", "雲中離黑山，慘淡初有無。", "捨舟並松麓，下直浮屠居。", "朅來東軒上，爽氣已有餘。", "飛來定何年，無乃與此俱。", "奔流潄庭下，比竹梁寒渠。", "山深絕凡境，物物清以臞。", "蕭森倚巖秀，夭矯懸崖枯。", "幽禽發寒唳，響振高林疏。", "我行亦良苦，却步計已迂。", "解衣卧清晝，慰我千里劬。"]'),
('bd3741c8-6dd3-4179-8ccc-51b0a8c2750f','善權洞','程俱','宋','宋诗','song-poetry','','[]','嘗聞包山境，中有林屋天。',180,'全唐诗/poet.song.82000.json','["嘗聞包山境，中有林屋天。", "旁通號地脉，嶽瀆潛鈎連。", "兹山豈其類，澒洞皆中穿。", "二巖岌山足，琤淙激奔泉。", "牛羊走大石，吐受無窮年。", "金堂下石液，雪積如烹煎。", "從來米鹽稱，浪播俚俗傳。", "一洞啟山腹，穹窿亦聯綿。", "誰題九斗字，大篆仍深鐫。", "中藏丈五石，屹若龍騰淵。", "回頭問主人，我輩定不凡。", "云何逐官牒，常得我所耽。", "向來共幽討，九鏁藏芝巖。", "而我自林屋，翩然遊皖灊。", "洪崖儻可俯，不在南山南。"]'),
('2998b4fc-0c1b-4110-af7c-ed9279d42771','白馬洞','程俱','宋','宋诗','song-poetry','','[]','披榛不知疲，詰屈巖下路。',108,'全唐诗/poet.song.82000.json','["披榛不知疲，詰屈巖下路。", "俄然見深窾，偊步入巖戶。", "一泓窈而澄，百步清以騖。", "人言紫髯仙，白馬從此度。", "磷磷盡赤石，丹竈遺滓汙。", "收藏已兒啼，効速勝麻護。", "因知世盲聾，荒怪雜疑誤。", "虛空如許大，長嘯可平步。", "胡爲萬山底，躑躅向煙霧。"]'),
('5fb710f2-d515-4099-8404-b0b8c3e36365','神魚泓是日與諸公流杯水中如西丘故事','程俱','宋','宋诗','song-poetry','','[]','柳州固奇士，戲好亦幽絕。',132,'全唐诗/poet.song.82000.json','["柳州固奇士，戲好亦幽絕。", "遠懷西丘飲，千古清興發。", "徜徉恨無所，盤俎對羈紲。", "聊爲五里行，邂逅一壺挈。", "神魚伏山根，渟湛初一穴。", "侵侵決寒溜，沙石助清越。", "披莎得盤石，離坐若天設。", "實觴競乘流，眩轉亦飄瞥。", "爭持或三釂，遇坎時一蹶。", "歡來朱碧亂，笑罷巾帽脫。", "相望西丘游，詎易議優劣。"]'),
('3c81e2b0-0b5f-4fee-9d36-4572cef3fc8b','九斗壇','程俱','宋','宋诗','song-poetry','','[]','萬族同一垢，齊州集微塵。',120,'全唐诗/poet.song.82000.json','["萬族同一垢，齊州集微塵。", "高靈不來下，厭此濁惡薰。", "從來築壇處，往往清無鄰。", "腥羶遠人迹，庶或來仙真。", "兹壇峙幽絕，尚有古制存。", "龜圖布八隅，彷彿數兌坤。", "黄冠道中寒，寓址今祇園。", "遊人躡其上，未覺大象尊。", "空令恨聃史，不使羣聾奔。", "蓋公雖未見，豈乏欒與垣。"]'),
('92971a7a-8a67-4db2-810b-fa5e7041c8f7','張公洞','程俱','宋','宋诗','song-poetry','','[]','昔年京江夜，飛夢投雲山。',288,'全唐诗/poet.song.82000.json','["昔年京江夜，飛夢投雲山。", "仍追謫仙老，嘯咏層崖巔。", "左盼俯無地，蒼巒生紫煙。", "當時賦幽賞，妙境竟莫宣。", "今我來自東，扶橈漾荆川。", "飽聞張公洞，怪絕駭所傳。", "聊從二三子，一結青山緣。", "北靈敞奇觀，下矚壺中天。", "怳然驚昨夢，了了墮我前。", "仄徑繚危棧，重扃護靈淵。", "奇礓互圾倚，側洞時鈎穿。", "初疑天台聚，納此一室間。", "夸娥運神化，不隘亦不顛。", "又疑清都客，翩然下雲軿。", "幢旄儼行立，導從森蟬聯。", "丹梯香霧濕，玉室珠瓔懸。", "撐虛一柱屹，戴重三能騫。", "鉛竈久已冷，青騾那可鞭。", "香壇望八景，東晨開五便。", "坡陀忽度險，宛轉漫無邊。", "或深如列廈，或迮纔容肩。", "高躋乍捫頂，偊步欲墊泉。", "不知行遠近，一步目九遷。", "噫嘻此天設，端在太古先。"]'),
('9179fd85-66dc-4c4c-a9e6-e04fd8f7c53f','借居毗陵東門四首  其一','程俱','宋','宋诗','song-poetry','','[]','客去不能寐，翛然清夜闌。',72,'全唐诗/poet.song.82000.json','["客去不能寐，翛然清夜闌。", "樓居俯長川，仰視天宇寛。", "長川濯雲漢，錯落星宿寒。", "青燈故可親，且還對塵編。", "其人骨已朽，千載與我言。", "掩卷三太息，虛簷清露漙。"]'),
('44c8eee6-179f-4579-8d61-4abf5b5bb186','借居毗陵東門四首  其二','程俱','宋','宋诗','song-poetry','','[]','急景不可挽，吾生豈無涯。',72,'全唐诗/poet.song.82000.json','["急景不可挽，吾生豈無涯。", "吳中十年舊，鬚鬢亦已華。", "嗟我壯且老，方知失林鴉。", "欲歸巷無廬，欲駕塗無車。", "而子亦羈滯，心事如蓬麻。", "人生無巧拙，命耳將如何。"]'),
('f6dd9100-ac78-4bcf-a004-24076ec2f1c8','借居毗陵東門四首  其三','程俱','宋','宋诗','song-poetry','','[]','猗猗隔河樹，羃羃緣堦草。',72,'全唐诗/poet.song.82000.json','["猗猗隔河樹，羃羃緣堦草。", "時當長養候，顔色豈不好。", "萌芒忽柯葉，茂大旋枯槁。", "滔滔不自知，但見壯而老。", "人生亦草木，萬化迭侵擾。", "朱顔日夜變，素抱豈自保。"]'),
('75368abd-0fc0-4580-96a8-afc8e0eec70e','借居毗陵東門四首  其四','程俱','宋','宋诗','song-poetry','','[]','借居臨官道，堂陰俯長河。',72,'全唐诗/poet.song.82000.json','["借居臨官道，堂陰俯長河。", "前車接來軫，從棹紛相摩。", "我獨居其間，超然嘯而歌。", "頗從故人語，安用高軒過。", "旁有五畝園，不知主誰何。", "時能曳屐往，豈異吾山阿。"]'),
('59b8d48f-58cf-40b1-9d7d-1f7155469fa9','和柳子厚讀書','程俱','宋','宋诗','song-poetry','','[]','事賤反多暇，居卑適無虞。',168,'全唐诗/poet.song.82000.json','["事賤反多暇，居卑適無虞。", "人間不爭地，聊此謝畏途。", "豈無營營子，熟視付一吁。", "廛中亦何有，坐聽日月逾。", "展卷閱千古，置書忘萬殊。", "不妨權子母，亦復商有無。", "平生僅識字，乃與憂患俱。", "持此遊學海，層臺漸積蘇。", "年來但遮眼，頗覺心恬愉。", "囊錢足自飽，肯怖騶朱儒。", "起卧一榻間，兀如橛株拘。", "涼風北窗下，不減愚溪愚。", "誰能三萬卷，懸頭苦劬劬。", "小極正當寐，睡魔不須驅。"]'),
('c050dd14-cc80-441b-b349-977c55ec7320','虞君明謩和劉氏園居詩再用前韻作因以敘出處之意','程俱','宋','宋诗','song-poetry','','[]','靖節直有道，高懷俯黄園。',192,'全唐诗/poet.song.82000.json','["靖節直有道，高懷俯黄園。", "翹足北窗下，超然詣羲軒。", "早悟俗中惡，歸老三家村。", "清詩有遺味，誰知本無言。", "回觀一世間，不辨艾與蓀。", "青黄飾斷木，冠裳裹王孫。", "當時甚寒餓，聲利終莫渾。", "公今二千石，此事安足論。", "入當陪雋賢，峨冠宣與温。", "出當仗漢節，登車金馬門。", "豈爲尚平子，但畢兒女昏。", "我今乃窮士，壯圖無一存。", "摧頹風埃下，坐見歲月奔。", "歸歟乃其分，卜勝如浮墩。", "他年有餘食，會見脫世紛。", "過我五湖上，一區同子雲。"]'),
('4a93cfc5-4bb3-4927-abd4-68b3a47d63e4','陪君明華燕集復用前韻','程俱','宋','宋诗','song-poetry','','[]','華藏萬竿玉，何殊辟疆園。',192,'全唐诗/poet.song.82000.json','["華藏萬竿玉，何殊辟疆園。", "城中最佳處，時復過高軒。", "危亭望北郭，依依遠人村。", "露葉有佳色，桃蹊亦無言。", "纍纍古藤陰，附石如菖蓀。", "下有小衡霍，巑岏列兒孫。", "方池是魚樂，水作千里渾。", "座滿北海客，文追謫仙論。", "襟期樗散鄭，目繫忘言温。", "斯須接棋戰，堅壁如轅門。", "不有覆舟慮，寧爲注金昏。", "越醫死更起，齊霸亡爲存。", "日入萬籟息，羈禽趣林奔。", "林間屹層臺，此豈蕭公墩。", "徜徉步松月，香露時披紛。", "胡床興不淺，點綴無微雲。"]'),
('e74fcdc3-0826-4719-83be-f9914c46c62b','初秋偶題','程俱','宋','宋诗','song-poetry','','[]','涼風入高梧，冷翠滴幽露。',72,'全唐诗/poet.song.82000.json','["涼風入高梧，冷翠滴幽露。", "新娥欲西流，綽約一回顧。", "中宵汲冰華，爽氣拂庭戶。", "蕭然視天宇，目送流螢度。", "微雲澹河漢，雲漢亦容與。", "宜搜静中境，安得此佳句。"]'),
('46a480a9-7fab-41f5-8d59-df979b1bbd61','和傅冲益冬夜獨酌用柳子厚飲酒詩韻','程俱','宋','宋诗','song-poetry','','[]','忽忽歲晼晚，幽懷寄芳樽。',96,'全唐诗/poet.song.82000.json','["忽忽歲晼晚，幽懷寄芳樽。", "及兹寒夜永，寫我憂思煩。", "放杯獨長謡，翕如負晴暄。", "那知曲身直，但覺冰腸温。", "遙思石林亭，玉雪今正繁。", "安能松窗下，撚鬚哦五言。", "須君尋昔遊，攀梅擷蘭蓀。", "勝事難重得，悠然空默存。"]'),
('17374e5c-6b88-44b6-a810-e190bc2b37f2','秋日市區作','程俱','宋','宋诗','song-poetry','','[]','火壯亦已老，朝昏發微涼。',144,'全唐诗/poet.song.82000.json','["火壯亦已老，朝昏發微涼。", "高梧逼秋枕，曉夢不得長。", "區中了無營，起卧在一牀。", "時時忽忘我，徑至無何鄉。", "是身亦何爲，萬化詎未央。", "朅來蘭陵市，三見草木黄。", "頗欲索其身，窮年就庚桑。", "臨淵故有羨，說食誰能嘗。", "尚有平生懷，嶔崎類癡狂。", "佳時坐自失，恐復墮渺茫。", "有生浪營營，有志終遑遑。", "胡爲自前却，坐待兩鬢霜。"]'),
('831ef686-b1ae-45fe-8f0a-89fbdb614a5e','客舍寫懷呈王八丈侍郎五首  其一','程俱','宋','宋诗','song-poetry','','[]','君門如雲漢，可望不可攀。',72,'全唐诗/poet.song.82000.json','["君門如雲漢，可望不可攀。", "地上挾冰子，肉身無羽翰。", "豈無國士知，勢有不得言。", "空懷激揚意，歸坐自長歎。", "此意重千金，寧論官九遷。", "所愧誤賞音，賞音從古難。"]'),
('7356fbf4-e4e0-446a-9318-590d70fce9e6','客舍寫懷呈王八丈侍郎五首  其二','程俱','宋','宋诗','song-poetry','','[]','長安窮居客，一日一歲長。',84,'全唐诗/poet.song.82000.json','["長安窮居客，一日一歲長。", "况乃夏方半，迢迢良未央。", "頳虬駕瓊車，萬里飛炎光。", "冰崖不可見，仰視峰雲翔。", "蝸蟠兩壁間，跂想深夜涼。", "一暍非死所，念之熱中腸。", "其誰卧清晝，雲樹羅千章。"]'),
('24d54ce1-8e1d-435c-b740-287665f36141','客舍寫懷呈王八丈侍郎五首  其三','程俱','宋','宋诗','song-poetry','','[]','束髪營五斗，飄然落江湖。',72,'全唐诗/poet.song.82000.json','["束髪營五斗，飄然落江湖。", "當時尚癡絕，秣驥初問途。", "去國十五年，俯仰同朝晡。", "心隨澤中雉，官作竿上魚。", "及兹才一遷，名實初未殊。", "且當百里地，磨研城旦書。"]'),
('13827a33-e2a9-4f26-8a9c-5e2262496429','客舍寫懷呈王八丈侍郎五首  其四','程俱','宋','宋诗','song-poetry','','[]','一室不可掃，陰晴兩非宜。',60,'全唐诗/poet.song.82000.json','["一室不可掃，陰晴兩非宜。", "朝蠅汙簡編，暮蚊入裳衣。", "爾來三日雨，門有一尺泥。", "所喜庭戶間，新涼洗餘曦。", "貧賤無造請，閉關良不癡。"]'),
('ee67ee82-ddb6-4f23-a548-aaf711d31372','客舍寫懷呈王八丈侍郎五首  其五','程俱','宋','宋诗','song-poetry','','[]','白雲浮東南，下有姑胥臺。',72,'全唐诗/poet.song.82000.json','["白雲浮東南，下有姑胥臺。", "去家桃始花，歘見温風來。", "久無萬金書，一使羈懷開。", "倚門有華髪，扶床有提孩。", "雖無凍餒憂，百慮不可排。", "何當放雙槳，黄流入清淮。"]'),
('416e0667-d759-4fbb-a9b2-e1843db03e01','秋將穫水行田中不復留因窽塍通溝引水過堂下小兒以芒葦作車其上晝夜决决不休戲書','程俱','宋','宋诗','song-poetry','','[]','水行山原溉平疇，時當斷壺穫且收。',208,'全唐诗/poet.song.82000.json','["水行山原溉平疇，時當斷壺穫且收。", "功成則退逝不留，去彼畎遂來清溝。", "測之深咫淺可杯，循除㶁㶁環一丘。", "堆沙累石隘厥流，勢激灧澦吞黄牛。", "誰持機緘設中洲，折芒斷葦駕兩輈。", "置之不汨亦不浮，六輻眩轉無時休。", "推行作止莫可諏，孰居無事供其求。", "迫而後動真無尤，眩轉自彼非吾謀。", "屈伸臂頃一萬周，我無欣厭何名憂。", "孰能觀身與此侔，衆假合集成堅柔。", "沈輕燥濕交相仇，逝川洄洑更春秋。", "滔滔南北東西游，死生壯老休王囚。", "形骸流運我則不，物境萬變何其幽。"]'),
('ad48f06b-4a92-49b1-96ac-0a456d07ca00','同江彦文緯江仲嘉褒度菱湖嶺遊三衢諸山道靈真出入巖谷勝絕可駭雜然有卜築之意然此地寥閴人所不爭小隱不難致顧吾曹出處何如耳二公皆脩真養氣精進不衰予晚聞此道又爲憂病頓挫志倦體疲每思益友儻得静舍安餘年資二子以待老豈不樂哉作詩敘游且志本末巖谷之勝實自仲嘉發之予嘗聞而賦詩所謂武陵迷漢魏妙喜斷山川者也','程俱','宋','宋诗','song-poetry','','[]','我昔未省事，倀倀如病狂。',288,'全唐诗/poet.song.82000.json','["我昔未省事，倀倀如病狂。", "仰規結繩初，下歷漢魏唐。", "謂此紙中語，卷舒在行藏。", "功名戾契取，有志要必償。", "趼足方不暇，何由放洪荒。", "行年冠而字，世故頗已嘗。", "試窺竺乾書，出入應帝王。", "丘軻有妙藴，合處如宫商。", "形骸乃塵沫，笑唾却老方。", "蹭蹬過二紀，身如浮海航。", "風濤浩無際，寄命蛟鼉鄉。", "外爲萬緒嬰，內以百慮戕。", "摧頹不一偶，病骨無由強。", "初心益乖迕，始覺計未良。", "擬追赤松遊，補我黥劓創。", "惟時子真子，青衫尉南昌。", "亦有虬鬚翁，種桃擷春芳。", "不求飛霞珮，肯受紫錦囊。", "至言無旁午，照用寂以忘。", "爾來又十年，前却方徬徨。", "何殊一日暴，正坐多歧亡。", "虬鬚彼幽人，物化不可量。", "子真日千里，似欲窮扶桑。", "安知阡陌間，共此暇日長。"]'),
('fdc4ba9a-d076-4725-b7c6-9406b7dbc593','戲呈虞君明察院謩  其一','程俱','宋','宋诗','song-poetry','','[]','三仕三已心如空，一壑一丘吾固窮。',64,'全唐诗/poet.song.82000.json','["三仕三已心如空，一壑一丘吾固窮。", "門施雀羅正可樂，車如雞栖良不惡。", "胸中九華初欲成，綵衣玉斧雙鬟青。", "世間何樂復過此，不失清都左右卿。"]'),
('992db384-4bd9-4e37-890d-89ef3f497ee3','戲呈虞君明察院謩  其二','程俱','宋','宋诗','song-poetry','','[]','長安陸海知洪爐，五金出入無精粗。',80,'全唐诗/poet.song.82000.json','["長安陸海知洪爐，五金出入無精粗。", "平生椎鈍堅重質，一往融液隨流珠。", "請觀五石大瓠種，正以濩落浮江湖。", "環中何者爲榮辱，千鍾何如三釡粟。", "坦途緩步東方明，大勝跨虎臨深谷。"]'),
('da4b8adf-dca3-48f1-bcb7-4f8f72c99bbe','君明見和再作  其一','程俱','宋','宋诗','song-poetry','','[]','十年接淅家屢空，門無八關延五窮。',67,'全唐诗/poet.song.82000.json','["十年接淅家屢空，門無八關延五窮。", "誰言浩浩有餘樂，世故撩人工作惡。", "君不見韓非白首終無成，至今說難書汗青。", "要之賦命默有制，巧拙安知司馬卿。"]'),
('b02506b2-cfe2-4b9a-a4a5-6c4bbf8ccb19','君明見和再作  其二','程俱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','羨公腹有金丹爐，凡泥六一何其粗。',80,'全唐诗/poet.song.82000.json','["羨公腹有金丹爐，凡泥六一何其粗。", "棗梨扶疏荆棘盡，夜半北海收明珠。", "爾來問舍浙江曲，正以畫笥觀西湖。", "我生抗髒今耐辱，貧病欲貸監河粟。", "他年公伴赤松遊，遺我刀圭固玄谷。"]'),
('313c9d1b-50b9-4032-95e3-5ba54e60e4c2','出北關再以前韻作寄  其一','程俱','宋','宋诗','song-poetry','','[]','從公十日羈愁空，超然似欲忘途窮。',64,'全唐诗/poet.song.82000.json','["從公十日羈愁空，超然似欲忘途窮。", "神遊八極共天樂，浮白不應嫌客惡。", "中年偃蹇百無成，唯有見賢雙眼青。", "狂歌時有眇道士，擬賦臞仙非長卿。"]'),
('483b24c8-efb7-455d-b3e2-729cb2eab057','出北關再以前韻作寄  其二','程俱','宋','宋诗','song-poetry','','[]','平生清夢遊香爐，雲巖犖确衢山粗。',80,'全唐诗/poet.song.82000.json','["平生清夢遊香爐，雲巖犖确衢山粗。", "不應近捨武林秀，僧寶况多滄海珠。", "勝遊屢約不成往，白雨連日翻平湖。", "公如二疏方不辱，我亦三吳甘脫粟。", "會當乘雪叩公門，正恐鳴騶還入谷。"]'),
('86b214d8-3520-4d37-90c2-d742cf85a289','雨霽行西湖二首  其一','程俱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晨輝麗春山，雨過松竹香。',72,'全唐诗/poet.song.82000.json','["晨輝麗春山，雨過松竹香。", "連峰翠欲滴，動搖雲水光。", "長堤如卧虹，草暗路已荒。", "菰蒲破綠浄，老葑日以張。", "念昔總角遊，祗今二毛蒼。", "物境既非昨，我身安得常。"]'),
('dd1e5757-7ebe-44df-8685-1914e85ac6ae','雨霽行西湖二首  其二','程俱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','半生走三吳，問舍如捕風。',108,'全唐诗/poet.song.82000.json','["半生走三吳，問舍如捕風。", "敢辭百尺樓，高卧愧元龍。", "向來江道人，卜宅湖山中。", "安知三十年，忽如化人宫。", "蒼雲翳修竹，飛閣凌春空。", "主人兩鬢霜，驅車大河東。", "豈念五畝園，方作萬里封。", "而我志幽獨，長年羨冥鴻。", "翻無容足地，茅茨翦蒿蓬。"]'),
('680618dd-f39b-4135-8fe7-c5cb14996dca','哭阿申二首  其一','程俱','宋','宋诗','song-poetry','','[]','我生百不諧，進退得坎井。',96,'全唐诗/poet.song.82000.json','["我生百不諧，進退得坎井。", "二毛初抱子，亦足慰衰冷。", "珠庭照日角，眉目秀而炯。", "人言驥墮地，意作千里騁。", "居然萬金産，每見百憂醒。", "嗟哉時夜計，便欲老箕潁。", "安知隨泡露，變滅失俄頃。", "悲來淚成河，俯仰弔孤影。"]'),
('0bbb56a6-2c4a-4608-9c35-2626294d4eed','哭阿申二首  其二','程俱','宋','宋诗','song-poetry','','[]','遺劍日以遠，刻舟那可求。',96,'全唐诗/poet.song.82000.json','["遺劍日以遠，刻舟那可求。", "滄溟一漚發，散滅何當收。", "而我舐犢悲，中懷不能休。", "推排更嵬磊，棘刺生衿喉。", "夜夢多見之，犀玉照兩眸。", "沉憂信傷人，曉覺雙鬢秋。", "深慚東門達，恐效西河尤。", "所念盛德後，一身如綴旒。"]'),
('2a789ea2-06e2-4201-bf03-910a6aa3d5c9','秋夜寫懷呈常所往來諸公兼寄吳興江仲嘉八首  其一','程俱','宋','宋诗','song-poetry','','[]','秋聲不關人，倦客偏入耳。',48,'全唐诗/poet.song.82000.json','["秋聲不關人，倦客偏入耳。", "蕭蕭舞黄葉，策策振疏葦。", "明知壯則老，搖落固其理。", "如何石心人，慨歎中夜起。"]'),
('c9430601-7b20-4cff-9123-0dbf7830be52','秋夜寫懷呈常所往來諸公兼寄吳興江仲嘉八首  其二','程俱','宋','宋诗','song-poetry','','[]','蓬藋没三徑，藤虆上瓜廬。',60,'全唐诗/poet.song.82000.json','["蓬藋没三徑，藤虆上瓜廬。", "時聞步屧聲，款關問何如。", "定坐無雜語，文章較精粗。", "馬融辭東觀，抗髒與世疏。", "顧此窮巷士，華顛空著書。"]'),
('51762d40-1f06-43d4-956d-0029e3f77b31','秋夜寫懷呈常所往來諸公兼寄吳興江仲嘉八首  其三','程俱','宋','宋诗','song-poetry','','[]','外監嗟已遠，吾猶識其孫。',60,'全唐诗/poet.song.82000.json','["外監嗟已遠，吾猶識其孫。", "森然見孤韻，辨作懸河翻。", "低頭向螢窗，有類鶴在樊。", "讐書五千卷，字字窮根源。", "頗攜未見書，過我樵無煙。"]'),
('5c8a71a7-7aa0-4ab6-bcaa-263f7888abae','秋夜寫懷呈常所往來諸公兼寄吳興江仲嘉八首  其四','程俱','宋','宋诗','song-poetry','','[]','向來霜秋句，俯仰歲一終。',84,'全唐诗/poet.song.82000.json','["向來霜秋句，俯仰歲一終。", "人間有寒暑，方外無窮通。", "青青千丈松，不改冰雪容。", "坐閱蒲與柳，飄蕭隨雨風。", "寒松老益高，蒲柳老益衰。", "流萍况無蒂，復與飛蓬期。", "却掃計不早，出門欲何之。"]'),
('d007707f-21af-4307-9fc0-83570d8fe0db','秋夜寫懷呈常所往來諸公兼寄吳興江仲嘉八首  其五','程俱','宋','宋诗','song-poetry','','[]','剝啄驚牛枕，軒昂見長身。',72,'全唐诗/poet.song.82000.json','["剝啄驚牛枕，軒昂見長身。", "蒼髯如脩竹，定非俯仰人。", "德公卧襄陽，不踏官府塵。", "此老頗似之，酒酣見天真。", "結廬甚幽獨，已辦老圃鄰。", "披榛時一來，數面久益親。"]'),
('8d3ce919-c596-4200-9bfc-c46beae6d83c','秋夜寫懷呈常所往來諸公兼寄吳興江仲嘉八首  其六','程俱','宋','宋诗','song-poetry','','[]','二士出吳下，諸生有楊王。',84,'全唐诗/poet.song.82000.json','["二士出吳下，諸生有楊王。", "相從寂寞濱，無乃計未良。", "縱横三千字，坐可致玉堂。", "詞章乃穅秕，不直粟一囊。", "我愧非子雲，文書昧偏旁。", "窮居似韓子，草樹亦荒涼。", "時能出佳句，慰我秋夜長。"]'),
('6a3a8d42-f866-4232-b818-1c2ab542a572','秋夜寫懷呈常所往來諸公兼寄吳興江仲嘉八首  其七','程俱','宋','宋诗','song-poetry','','[]','物色一如此，凄風薄人衣。',48,'全唐诗/poet.song.82000.json','["物色一如此，凄風薄人衣。", "遙憐卞山客，增歎雉朝飛。", "固知難爲懷，舉餐念齊眉。", "忽使梨棗間，纒綿生繭絲。"]'),
('b6336c96-4327-4d25-9c07-3d059856e2b8','秋夜寫懷呈常所往來諸公兼寄吳興江仲嘉八首  其八','程俱','宋','宋诗','song-poetry','','[]','清霜掃蕃廡，豈爲一草木。',72,'全唐诗/poet.song.82000.json','["清霜掃蕃廡，豈爲一草木。", "方春萬物遂，苑籞及冰谷。", "乾坤本平施，憎愛豈有屬。", "不應懷偏慳，獨遇吾黨酷。", "奇窮坐迂疏，此事計已熟。", "如何半世間，生理常刺促。"]'),
('90a767bb-e372-4dae-8733-a9c417d99702','與江仲嘉褒趙叔問子晝潘杲卿杲分題賦詩以顔魯公裴晉公賀監陳希夷畫像爲題以我思古人爲韻余得裴晉公我字韻一首','程俱','宋','宋诗','song-poetry','','[]','晉公護河東，身退勢亦左。',108,'全唐诗/poet.song.82000.json','["晉公護河東，身退勢亦左。", "憂心極饑渇，讜議抗嵬瑣。", "居朝重九鼎，下賊飛一笴。", "淮西彈丸地，孺子甚么麽。", "發兵本無難，萬口無一可。", "平淮取淄青，如掇掌中果。", "折衝乃餘事，世論豈知我。", "天方厭唐德，莫捄蕭牆禍。", "空餘丘禱詩，千古幽淚墮。"]'),
('d04ab8fc-7139-4f32-abd8-18565cda86ba','夜坐','程俱','宋','宋诗','song-poetry','','[]','饑烏夜啼棲復起，仡粟飛光透窗紙。',128,'全唐诗/poet.song.82000.json','["饑烏夜啼棲復起，仡粟飛光透窗紙。", "捲簾萬瓦白生煙，桂影扶疏浄如洗。", "回腸正隨清漏轉，葉下空庭亂如霰。", "青燈耿耿夜何其，雲篆吐蘭初一線。", "歲云暮矣萬竅號，霜天旅雁求其曹。", "月行虚空幾萬里，羣犬吠光聲正豪。", "蒲團瞑目空危坐，逝者如斯白駒過。", "悠悠昨夢不可攀，此身此心何日閑。"]'),
('5cfeedec-68c3-4c43-93e7-d066e6b5c8ea','春日寫懷','程俱','宋','宋诗','song-poetry','','[]','春風遍芳華，一國盡狂醉。',84,'全唐诗/poet.song.82000.json','["春風遍芳華，一國盡狂醉。", "窮閻獨不知，但見長蒿薺。", "秋飈起蘋末，一華初未墜。", "幽懷獨先覺，意象已凄厲。", "故知春與秋，初不爲我計。", "危弦自應悲，寒木終易脆。", "要之夢中夢，憂樂同一寐。"]'),
('a06d7d1c-ae99-43a0-bdf6-99f8ad3589ef','豁然閣','程俱','宋','宋诗','song-poetry','','[]','雲霞墮西山，飛帆拂天鏡。',60,'全唐诗/poet.song.82000.json','["雲霞墮西山，飛帆拂天鏡。", "誰開一窗明，納此千頃静。", "寒蟬發澹白，一雨破孤迥。", "時邀竹林交，或盡剡溪興。", "扁舟還北城，隱隱聞鐘磬。"]'),
('09ae7e34-7ade-464a-a8da-5e31ea95bfdb','二十八舍歌示錢定國顯道','程俱','宋','宋诗','song-poetry','','[]','山川不捨騂與角，亢鼻孤豚殊不惡。',224,'全唐诗/poet.song.82000.json','["山川不捨騂與角，亢鼻孤豚殊不惡。", "委身投筆事氐羌，何異天球薦房闥。", "人心如面各不同，蛇頭蝎尾吾安容。", "脂韋肯效箕箒態，拔劍撞斗真才雄。", "少年食牛有餘氣，大笑文章幾女工。", "立談寧與子虛比，危冠欲入明光宫。", "功成築室依故丘，作書重壁垂千秋。", "宸奎一扎呼不起，閉門老死如黔婁。", "爾來養生如養胃，未羨昴精刀筆吏。", "疲神畢慮子所訶，鳳觜鸞膠誰汝試。", "昔賢忘心身亦空，身如丘井心如風。", "君言作解皆魔鬼，蒲柳松筠同盡耳。", "三星在霤能幾許，張拳且擊關南鼓。", "遊龍作御雲生翼，軫地蓋天從莫逆。"]'),
('42296e67-c338-4b59-954a-85fefa38fc2a','數詩述懷','程俱','宋','宋诗','song-poetry','','[]','一生共悠悠，今者曷不樂。',120,'全唐诗/poet.song.82000.json','["一生共悠悠，今者曷不樂。", "二十起東山，誤爲微官縛。", "三年瞬眸耳，郵傳那久託。", "四壁自蕭然，青編束高閣。", "五更霜鐘動，起視星錯落。", "六律聿其周，忽忽更歲籥。", "七哀哦幽韻，感念驚獨鶴。", "八極豈不廣，衰懷了無託。", "九原歎多賢，死者那可作。", "十里望煙村，天隨去寥廓。"]'),
('50096f86-452a-46da-b081-7a9c499f7e0a','讀陶靖節詩','程俱','宋','宋诗','song-poetry','','[]','吾觀靖節詩，三歎有遺音。',96,'全唐诗/poet.song.82000.json','["吾觀靖節詩，三歎有遺音。", "卧看起詠之，愔愔澹多心。", "欲學靖節詩，慎勿學其語。", "心源如古井，衡氣光發宇。", "言無出言意，妙語自天與。", "譬如清泠淵，月湛不可取。", "嶔崎阨驚湍，乃若震雷鼓。", "斯言可深味，往往棄如土。"]'),
('949bd1ca-bc11-47d8-8afb-b4c2b3f03e18','八音歌贈别趙子雍𪛌之二首  其一','程俱','宋','宋诗','song-poetry','','[]','金鑛具奇質，百鍊出其剛。',96,'全唐诗/poet.song.82000.json','["金鑛具奇質，百鍊出其剛。", "石中含結綠，追彼蒲穀章。", "絲也談有餘，於道乃易方。", "竹林醉黄壚，誕放非古狂。", "匏瓜固非倫，順俗豈所望。", "出門謝惡友，要若拒獠羌。", "革枉表斯正，渟滓水乃清。", "木貴就繩矩，願言贈子行。"]'),
('2f7533dd-2aca-4ff0-8104-33b4e5a9c3f8','八音歌贈别趙子雍𪛌之二首  其二','程俱','宋','宋诗','song-poetry','','[]','金張珥漢貂，况乃出天派。',96,'全唐诗/poet.song.82000.json','["金張珥漢貂，况乃出天派。", "石渠重儒冠，武弁聊復戴。", "絲麻宜自任，粗使有管蒯。", "竹簡書汗青，高吟當人籟。", "匏雖貴中虛，植固須本大。", "土耕戒莽鹵，道耕惡疵累。", "革带勿佩韋，贈子絃作佩。", "木強雖過中，寧師伯夷隘。"]'),
('0b33e9c0-bd0e-4168-a994-1c7d1e48d0eb','寫懷','程俱','宋','宋诗','song-poetry','','[]','宇宙一火宅，我身寓其間。',108,'全唐诗/poet.song.82000.json','["宇宙一火宅，我身寓其間。", "靈臺真逆旅，憂喜更往還。", "其來不可却，倐去不可攀。", "冥然閉六鑿，暫使逆旅閑。", "中虛本無住，夜半移舟山。", "身隨事物化，鬢與寒暑斑。", "奈此業累深，始知定力慳。", "况兹塵沫聚，豈比金石頑。", "顧影忽自笑，吾心定何顔。"]'),
('678444b7-a9a2-4de1-ae58-0e4aa5673936','和楊秀才友夔三首  其一','程俱','宋','宋诗','song-poetry','','[]','天地有肅殺，好生本無傷。',96,'全唐诗/poet.song.82000.json','["天地有肅殺，好生本無傷。", "陽施待秋成，相濟如宫商。", "芸芸共欣榮，衆葉薿薿光。", "回頭失故林，蕭條弄微陽。", "獨有歲寒姿，掀髯尚低昂。", "流膏亦歸根，晬如養中黄。", "大哉一氣中，人心自炎凉。", "安知晞春露，不異腓草霜。"]'),
('5460cdb7-909e-4bf1-bda1-0099a4d1163a','和楊秀才友夔三首  其二','程俱','宋','宋诗','song-poetry','','[]','誰謂方寸地，并包無故新。',96,'全唐诗/poet.song.82000.json','["誰謂方寸地，并包無故新。", "長宵不能寐，萬緒愁攻人。", "展轉計後有，攀緣及前身。", "苦恨隙駒疾，回嗟穢塗辛。", "披衣問何居，夢覺兩不真。", "白鳥固已空，青燈聊可親。", "念此紙上迹，皆爲窖中塵。", "投卷嘿忘我，栖雞已鳴辰。"]'),
('f280619a-4093-4ae7-b46c-7d64dbd16592','和楊秀才友夔三首  其三','程俱','宋','宋诗','song-poetry','','[]','三吳足秔稌，狼戾及宋梁。',96,'全唐诗/poet.song.82000.json','["三吳足秔稌，狼戾及宋梁。", "故爲胥門隱，未辦耕南陽。", "豈無如雲稼，竭澤歸富強。", "收成一過眼，胼胝念黔蒼。", "綿綿太平區，阡陌盡八荒。", "願從鼓腹游，自放逍遙埸。", "貴賤均飽煖，藜羮等膏粱。", "那令力田夫，一飯不可望。"]'),
('92222ac4-902e-4b7f-817c-8df3635521cd','同餘杭尉江仲嘉褒道人陳祖德良孫遊洞霄宫','程俱','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','太湖隱吏迂且頑，手扳柱頰看西山。',384,'全唐诗/poet.song.82000.json','["太湖隱吏迂且頑，手扳柱頰看西山。", "筆床茶竈向何許，往來洞庭林屋間。", "舊聞西門徹懸霤，故整煙艇尋苕川。", "却驚天柱矗雲表，勢與太華爭擎天。", "幅巾跨馬及曉鼓，逸思自覺奔春泉。", "其誰從者二妙士，金庭老客南昌仙。", "齊驅共語失長道，但見平阪連桑田。", "籃輿後繼獨不語，鼻息栩栩山聳肩。", "崗回澗曲若無路，萬疊老翠漫秋煙。", "三山對起鎻詰屈，僅容蹄轍通人寰。", "羊腸移險在平地，九疑山色荒聯綿。", "穿松酌水尋二洞，低隱巖腹高山巔。", "山巔石室如列廈，接肘可置千賓筵。", "最憐西洞隔凡處，凝乳絡壁留空圓。", "我將拂袖去不返，戲擊雷鼓揮神鞭。", "三華寶衣立可致，九赤班符何足傳。", "只將尻與駕神馬，豈顧家火燒凡鉛。", "又疑靈物之所宅，卵孕變化蟠蜿蜒。", "金龍玉簡投不滿，恐復下與東溟連。", "我嗟何地非聖處，火聚正坐青雲軿。", "目前閶闔晝自啟，電頃已超天地先。", "正緣一念重山嶽，障硋何啻重城堅。", "就令信脚到仙宇，凡骨至死包腥羶。", "膠膠世網浪自纒，會當去之如蛻蟬。"]'),
('4af090e9-9180-4c58-bef4-ae97b481b607','灌竹','程俱','宋','宋诗','song-poetry','','[]','戶樞不容蠧，展轉夕與朝。',168,'全唐诗/poet.song.82000.json','["戶樞不容蠧，展轉夕與朝。", "死水不赴壑，淺於杯所膠。", "人生戒甚逸，起我少自勞。", "呼僮續長綆，落落鳴桔橰。", "攜瓢傍脩竹，灌灑繞百遭。", "念此十二君，離羣自江臯。", "移栽一年餘，已長數尺梢。", "齋前雨霜叢，歲久根已交。", "交根纒籜龍，卷葉不復搖。", "聊蘇夏日畏，未謝春雨膏。", "蕭蕭便生涼，霍若雲霧消。", "却坐井邊石，清泉濯雙骹。", "官閑但數數，聽以老圃嘲。", "豈敢運甓比，漫欲滋枯焦。"]'),
('f4c2232e-f68a-4d2f-bb5c-f58b309156b3','送江仲嘉褒東還家山方將從赤松子遊爲作仙遊之詩以相步虛云','程俱','宋','宋诗','song-poetry','','[]','空山月出栖鳥驚，濺濺暗溜山間鳴。',144,'全唐诗/poet.song.82000.json','["空山月出栖鳥驚，濺濺暗溜山間鳴。", "桂陰羃歷夜香冷，有人步虛聞紫青。", "翩然騎麟下青冥，君非遠遊定方平。", "雲軿冉冉風袂舉，左右玉立花娉婷。", "手摩我頂一笑粲，别來彈指三千齡。", "至言不煩去畦町，齒下端有真長生。", "忽然縱身浮太廷，却笑煉砂飛八瓊。", "採芝方壺濯南溟，秦姬吹簫緱氏笙。", "茫茫齊州九窖塵，人間可哀胡不聞。"]'),
('ed7058e4-4c82-4ec7-a25b-8dc7583dce33','到官兩旬四走山野作詩以自勞云','程俱','宋','宋诗','song-poetry','','[]','上山偃伸如望天，下山傴仆如深泉。',240,'全唐诗/poet.song.82000.json','["上山偃伸如望天，下山傴仆如深泉。", "胡爲持此不貲寶，來試萬丈懸崖巔。", "前人見踵後見頂，反足鳥道相攀牽。", "欻然置我章貢上，水激石罅奔雷填。", "荒塍曲澗無遠近，渺渺不見墟中煙。", "土岡鑿路狹如隧，蘇壁藤薜蛟蛇纒。", "寒風颼飀失白日，上有萬木蒼陰玄。", "航溪之深掲其淺，碎石齧足聲號川。", "茗山發我一長喟，彼有吳市人中仙。", "飛瓊練玉存故處，祗有井竈無霜鉛。", "我今正坐五斗米，悔不辟粒從期佺。", "向來吳松厭羈旅，三歲半逐鴟夷船。", "故教筦庫着疏嬾，坐守兀兀聊窮年。", "安知求逸得奔走，豈異避挺蒙戈鋋。", "咄嗟萬事無必計，努力唯有歸園田。"]'),
('2246e864-22e7-499b-bbcd-d73dcfac2992','吳正仲提舉至游堂','程俱','宋','宋诗','song-poetry','','[]','妙喜寄鍼穎，大空浮海漚。',144,'全唐诗/poet.song.82000.json','["妙喜寄鍼穎，大空浮海漚。", "翛然一環堵，安住有至游。", "內觀如寒龜，無縛浪自囚。", "外遊如渇鹿，逐焰無時休。", "安知至游處，不止亦不流。", "廣文來東南，持節十四州。", "江海見函丈，雲林入衣裘。", "平生山水國，不滿一轉眸。", "高堂坐隱几，笑遣車下牛。", "虛簷白日静，顧眄九極周。", "是中有至樂，可以忘春秋。", "却來觀世夢，聊復憂人憂。"]'),
('9751cb92-59c0-47ff-aa25-00d0d42691ce','和林德祖惠山詩一首','程俱','宋','宋诗','song-poetry','','[]','好山如幽士，勝絕不可攀。',120,'全唐诗/poet.song.82000.json','["好山如幽士，勝絕不可攀。", "往者天姥夢，長謡愁謫仙。", "兹山出平野，秀特無株連。", "招提倚雲錦，森然見林巒。", "幽尋無十里，正處閑忙間。", "入門心目静，世累若可捐。", "靈泉出土脉，汨汨無流難。", "茶神瀹浮乳，方士沉餘丹。", "我生猿鶴姿，頗有山水緣。", "何時共清賞，杖屨窮崖巔。"]'),
('6334e3e0-95c7-44fa-af4c-3f33dc33a690','用德祖韻送毛彦時二首  其一','程俱','宋','宋诗','song-poetry','','[]','往者玉樓客，棲遲感秋蓬。',144,'全唐诗/poet.song.82000.json','["往者玉樓客，棲遲感秋蓬。", "龍鍾江海士，屑屑悲窮冬。", "今我亦羈旅，號寒思祝融。", "故鄉邈千里，胡馬長嘶風。", "平生飲最少，亦復賢聖中。", "其誰共談笑，無乃志所同。", "泮宫備文質，楩楠飾雕櫳。", "毛子亦好古，摛辭麗春工。", "飄然適我願，一舸來自東。", "明時獵英奇，備問羅臯龍。", "逢辰若公等，附鳳雲從龍。", "遙知賦伐木，相望有梁鴻。"]'),
('5fe74655-41a2-480b-a302-81c5ccdeaeeb','用德祖韻送毛彦時二首  其二','程俱','宋','宋诗','song-poetry','','[]','斷港冰未泮，海風起蓬蓬。',144,'全唐诗/poet.song.82000.json','["斷港冰未泮，海風起蓬蓬。", "君行亦良苦，浮家秋復冬。", "故人一相遇，醉覺心形融。", "道舊有深樂，班荆餘古風。", "何當度楊子，起視東井中。", "未應迫期會，促步佐一同。", "况當萬燈燃，流光煖疏櫳。", "胡爲即言别，繫書憑鳥工。", "空令千里月，團團出天東。", "解舟動棲禽，破曉啼匆匆。", "酒闌城西道，已失銜燭龍。", "振衣一回首，瞥去如驚鴻。"]'),
('0022d040-3b39-4f40-98cc-48a2b65cd969','爲宜興鄭主簿賦寓軒一首','程俱','宋','宋诗','song-poetry','','[]','物生太空中，巨細同一寓。',120,'全唐诗/poet.song.82000.json','["物生太空中，巨細同一寓。", "機緘固有待，舟壑本無住。", "二儀立毫塵，萬化失朝暮。", "要之儻來寄，正自墮形數。", "滔滔人間世，俯仰若泡露。", "浮遊皆適然，蚊睫漫來去。", "着身方丈室，聊作槁梧據。", "了觀諸幻境，內外絕欣惡。", "須知五藴山，今我聊託附。", "回頭主人翁，妙住了無處。"]'),
('493cd558-cd4f-4917-abdf-db68cbbebb55','君明出留題吳江詩次韻','程俱','宋','宋诗','song-poetry','','[]','包山水脉通西垠，森然林屋開東晨。',160,'全唐诗/poet.song.82000.json','["包山水脉通西垠，森然林屋開東晨。", "飛仙下視三萬頃，豈異滴水陶家輪。", "時時餘浸被吳楚，赤子𫙺𫙺哀漂淪。", "松江一支東入海，海道今者皆揚塵。", "遂令洪波洄不吐，禹跡莫辨僞與真。", "滔滔利往橋下水，省照黄綬孤吟身。", "月輪行空萬籟息，尚記此境清無倫。", "當時苦恨無好句，空負歲月臨江津。", "得公新詩妙入理，羊酪敢方千里蒓。", "公言慎勿作境會，取捨過咎由來均。"]'),
('0e4eb8cb-6385-4729-ad0e-d1fe940ec1a7','題滕司戶虛舟庵和韻','程俱','宋','宋诗','song-poetry','','[]','萬族同一海，至人乘桴浮。',132,'全唐诗/poet.song.82000.json','["萬族同一海，至人乘桴浮。", "狂風鼓溟壑，安問蜃與鰌。", "擾擾墮濁水，蚩蚩守藏舟。", "其誰善游者，動寂兩不侔。", "紛綸萬境前，了了轉處幽。", "愛君虛舟句，勿逐虛舟求。", "徜徉曹掾中，聊作虛舟留。", "長維五藴山，亦泳愛水流。", "飄搖度夷險，不喜亦不憂。", "我乃蹇淺人，褊心屢招尤。", "君心果空曠，永矣從君遊。"]'),
('d2c8e6c7-e04a-4ef5-8130-e9963ac20c45','同江趙潘集以鐘監博山爐黟硯石屏爲題予得鐘監分韻得金字鐘監蓋響板也形製如鐘背作雲雷紋面可監我曹創爲之銘曰癸巳作鐘監子子孫孫永保用張有篆甚奇古','程俱','宋','宋诗','song-poetry','','[]','帝軒工鳬和九金，童丁炎鑠成婦壬。',112,'全唐诗/poet.song.82000.json','["帝軒工鳬和九金，童丁炎鑠成婦壬。", "戲驅豐隆發凝陰，雷轟列缺光下臨。", "飛精入範天機深，四規閼明追蠡瘖。", "厥聲鏗宏中黄林，隱如霜降豐山岑。", "豈唯正衣冠佩簪，對之炯炯生肅心。", "應而不藏無古今，監之無窮叩逾音。", "至人之心我所欽，盤盂不須銘且箴。"]'),
('4d552d2d-4177-42e9-99ba-dfdca43747b0','再分題得易分韻得醉字一首','程俱','宋','宋诗','song-poetry','','[]','吾觀空劫初，妙藴固無示。',120,'全唐诗/poet.song.82000.json','["吾觀空劫初，妙藴固無示。", "誰令南北海，七竅鑿元氣。", "靈龜出洪河，六畫乃其寄。", "庖犧覷天巧，創物發奇秘。", "太虛本無邊，小大隨汝視。", "窮之得幾深，見者自仁智。", "或從鍊丹砂，或用資卜筮。", "終然有神護，回祿翻引避。", "絕編固冰釋，覆瓿正心醉。", "却懷投閣生，寂寞發長喟。"]'),
('4f513633-224d-4ec2-b91a-a1c26dd147f5','雨霽同仲嘉小酌久之雲開月出光照席上頗發清興戲作此詩','程俱','宋','宋诗','song-poetry','','[]','初月脫氛翳，微雲遞疏光。',96,'全唐诗/poet.song.82000.json','["初月脫氛翳，微雲遞疏光。", "徘徊照庭戶，皎皎涵清觴。", "牢愁不可排，磊塊如高岡。", "煩君着酒澆，身世得暫忘。", "舉觴漱明月，似覺幽桂香。", "擬吹三江水，浣此九轉腸。", "中宵起四顧，河漢生微凉。", "飄然想風馭，夢寄無何鄉。"]'),
('b3f98c52-4299-4e71-807b-f1aed26361b1','過吳興城北超覧堂','程俱','宋','宋诗','song-poetry','','[]','佛子固多幻，開軒納羣山。',120,'全唐诗/poet.song.82000.json','["佛子固多幻，開軒納羣山。", "平疇展摩衲，回塘縈玉環。", "新荷麗朝日，一一發清妍。", "引簟北窗下，雲嵐揖高寒。", "超然醉司馬，寄傲羲皇前。", "座有眇道士，長謡九華丹。", "張翁老篆癖，勢逼之罘鐫。", "濡毫記姓名，夭矯龍騰淵。", "日没羣動息，城陰静娟娟。", "長林有歸翼，吾駕亦言還。"]'),
('f3ebeffe-7ceb-457a-ae64-70de7cbb4070','奉陪知府內翰至卞山有詩五首 玉德泉','程俱','宋','宋诗','song-poetry','','[]','卞維吳興鎮，傑出衆山外。',168,'全唐诗/poet.song.82000.json','["卞維吳興鎮，傑出衆山外。", "晴朝自生輝，韞玉見奇態。", "新阡表南陽，獨據山水會。", "青松三萬本，已復出蓬艾。", "靈泉發道左，天遣資灌溉。", "初無一綫溜，泛濫欲浮芥。", "披榛佇方空，餘浸忽可澮。", "清踰金沙泓，甘此中泠派。", "朝涵卞峰雲，暮作霅溪瀨。", "豈惟供百須，旱歲亦多賴。", "殷勤五大夫，隨喜奉微蓋。", "嘗聞瑜瑾姿，德與君子配。", "兹泉爲人出，固是神所介。", "當令玉德名，相與流千載。"]'),
('4c54e369-259a-47f7-ad73-3fd8421d7f33','奉陪知府內翰至卞山有詩五首 庵居','程俱','宋','宋诗','song-poetry','','[]','幽亭名思洛，寒潭俯澄虛。',132,'全唐诗/poet.song.82000.json','["幽亭名思洛，寒潭俯澄虛。", "回頭三百年，勝地成荒墟。", "公今草堂址，無乃昔所居。", "環之碧玉峰，带以清冷渠。", "流泉響琴筑，松竹皆簫竽。", "妙哉無盡藏，一一爲我娛。", "東岡作蘭若，鍾梵鄰樵漁。", "亦有桑柘村，旁開蔬果區。", "何煩引三徑，故自與世疏。", "主人去霄漢，夜直承明廬。", "斯遊入清夢，儻寄空中書。"]'),
('a425ead5-3f97-4483-9d46-52558f2270de','奉陪知府內翰至卞山有詩五首 朱氏山居','程俱','宋','宋诗','song-poetry','','[]','嶔崎寶山麓，亂石如鬭獸。',156,'全唐诗/poet.song.82000.json','["嶔崎寶山麓，亂石如鬭獸。", "雲根盡中空，噓吸弄昏晝。", "兹山頗似之，無乃共靈構。", "如何在人境，有此泉石囿。", "深巖隱薈翳，竹樹兩森秀。", "坡陀接煙磴，足力恣所究。", "恍然天地開，遠目千嶂驟。", "中營五畝宅，何必封石窌。", "桑麻無外求，茶果供日富。", "夭條列僮奴，花草更黼繡。", "生生所應有，取足謝奔走。", "嗟余四方志，老大無一就。", "對此寸心驚，無因託圭竇。"]'),
('fd2959be-8126-4502-94a3-bcb0991c592c','奉陪知府內翰至卞山有詩五首 西庵','程俱','宋','宋诗','song-poetry','','[]','是公固麟鳳，入獸不亂羣。',204,'全唐诗/poet.song.82000.json','["是公固麟鳳，入獸不亂羣。", "吳儂欲爭席，但見一幅巾。", "籃輿從逋客，上下寂寞濱。", "却行共談笑，愧此禮意親。", "行行得西庵，杉竹含清薰。", "解衣静盤礴，虛窗蕙煙紛。", "濡毫散珠璣，咳唾不自珍。", "曳屣轉山足，長林蔽浮雲。", "旁連衆迤邐，上有高嶙峋。", "穹窿見深洞，劃如敞重闉。", "往者玉京子，翔空駕飈輪。", "于今蛻骨在，堅重踰蒼珉。", "頗欲窮其源，燃犀問蛇神。", "鉤穿忽無間，信有仙凡分。", "却尋招提路，松風亦隨人。", "潺潺石橋水，洗盡荆吳塵。", "胡床興不淺，已覺千山曛。"]'),
('d6a7b234-2fcc-4c8f-a0a8-e95c44300502','奉陪知府內翰至卞山有詩五首 夜歸','程俱','宋','宋诗','song-poetry','','[]','日入三籟息，羣山鬰蒼蒼。',72,'全唐诗/poet.song.82000.json','["日入三籟息，羣山鬰蒼蒼。", "巾裾濕煙霧，宛轉度澗岡。", "涓涓暗泉鳴，冉冉松筠香。", "林梢吐纖月，露葉瑣碎光。", "歸來叩禪扉，幽燈對繩牀。", "相羊有餘適，笑詠白雪章。"]'),
('acaf5644-1db4-43ae-aaeb-ba5529a5754b','同遊道場何山二首 道場山','程俱','宋','宋诗','song-poetry','','[]','何年窣堵波，獨立妙峰頂。',120,'全唐诗/poet.song.82000.json','["何年窣堵波，獨立妙峰頂。", "憧憧五湖舟，黑月仰光影。", "千章列雲構，靈液走甘冷。", "隆樓絕清空，横側見峰嶺。", "下窺三州聚，塵末集毫潁。", "振衣薄雲漢，萬劫彈指頃。", "遼遼天宇大，出没笑蛙井。", "堂中老比邱，奮迅頗精猛。", "擬分數椽地，飽飯卧清境。", "何必少陵翁，聞鍾始深省。"]'),
('bfae74e6-31e3-4734-b4b4-8a6cce83dcac','同遊道場何山二首 何山','程俱','宋','宋诗','song-poetry','','[]','謝公滄海士，眷眷在林壑。',156,'全唐诗/poet.song.82000.json','["謝公滄海士，眷眷在林壑。", "飛輿下層巒，及此日未落。", "翩然何山麓，古澗謝疏鑿。", "方橋跨清泠，鬰密交翠幄。", "通幽更窮深，木末見楹桷。", "琅璫鳴老屋，拉攞相倚薄。", "莊嚴布金地，藤蔓土花剝。", "當年軒裳客，小隱事鉛削。", "能令此山名，谷口振京洛。", "如何給園居，勝士久不作。", "豈惟雪山輕，顧恐泉水濁。", "周行一泛覽，懷古歎冥漠。", "安知千載人，不作來遊鶴。"]'),
('d999900e-c803-49e2-a876-0d2eb2690bc7','同遊勝林亭次韻','程俱','宋','宋诗','song-poetry','','[]','會意不在遠，巢枝良有餘。',96,'全唐诗/poet.song.82000.json','["會意不在遠，巢枝良有餘。", "居然勝林境，魚鳥皆欣娛。", "危城俯回谿，歸航數風蒲。", "幽蹊接遐觀，褰裳欲凌虛。", "却顧容膝地，清陰繞扶疏。", "念此晨日長，言旋更踟躕。", "翰林留新句，體骨超黄初。", "深藏恐飛去，照夜空江湖。"]'),
('0ffe3278-4677-4d0d-bbbf-91474ecc66d1','同葉翰林遊虎丘分韻得丘字','程俱','宋','宋诗','song-poetry','','[]','四顧渺平野，孤撐見林丘。',120,'全唐诗/poet.song.82000.json','["四顧渺平野，孤撐見林丘。", "常疑湧地出，儻復海所浮。", "上有千人臺，靈蹤想前脩。", "無情肯深義，頑石亦點頭。", "下有百尺淵，神光干斗牛。", "陰崖不見日，草木皆先秋。", "兩晉多達士，東亭抑其流。", "結廬遠車馬，寄此山之幽。", "一朝施白足，棄去如毛輶。", "矧伊桑下宿，肯作賈胡留。"]'),
('f1f94acb-01fe-449e-a218-efc7de0224f3','同葉內翰遊南峰竊觀壬辰舊題詩謹次嚴韻','程俱','宋','宋诗','song-poetry','','[]','道林彌天辯，妙譽傾斗南。',240,'全唐诗/poet.song.82000.json','["道林彌天辯，妙譽傾斗南。", "山陰有餘賞，禹穴或已探。", "晚歲折筇杖，兹焉寄伽藍。", "呼鷹閱神駿，對客手自談。", "却顧夸奪子，心兵戰方酣。", "當時蹇驢輩，蹴踏豈所堪。", "斯人不可見，荒徑昔已諳。", "青鞋踏松月，幽燈照禪龕。", "爾來十五年，身世猶朝三。", "羈游了無蒂，飛蓬轉毗嵐。", "愧此石窟人，堅持證那含。", "如公世所挽，明堂要樟柟。", "徘徊弭玉節，聊酌需泉甘。", "老乃澗底松，霜枝鬰毿毿。", "尚有蠧書癖，囊中密如蠶。", "中年錮泉石，此外無餘耽。", "從公恣幽討，形疲意猶貪。", "安得五畝園，旁營二空庵。", "心游萬物表，曠若巨海涵。", "恨無買山具，撫境思髯參。"]'),
('3e1c3cda-59a6-4173-8b36-8a4c81534f63','葉翰林有徐熙桃竹方尺許索詩輙賦一首','程俱','宋','宋诗','song-poetry','','[]','寒禽抱幽叢，意得窺綠浄。',48,'全唐诗/poet.song.82000.json','["寒禽抱幽叢，意得窺綠浄。", "夭華媚霜筠，慘澹若春暝。", "胡僧手幻藥，納此方池境。", "重重玄涉入，妙悟付毛穎。"]'),
('b28ec86e-05fa-47d0-865d-17e1ec33be7b','仲嘉錄示新齋聯句用韻書懷奉寄一首','程俱','宋','宋诗','song-poetry','','[]','我歌無庸歸，禮意固有屬。',168,'全唐诗/poet.song.82000.json','["我歌無庸歸，禮意固有屬。", "渠儂方不顧，欲問何拘曲。", "乃知交際難，不若逃空谷。", "憂端浩無窮，日飲思枕麴。", "文求世人笑，字異山鬼哭。", "龍鸞閱斯冰，劍弩對鷂鵠。", "鴈門既呼卿，司武或見梏。", "閉關固自如，青簡得三復。", "誰後足趦趄，墮彼手翻覆。", "汨泥無紆轡，絕迹慕前躅。", "故人有新詩，遠寄資賸馥。", "鳴嚶倡復和，流徵斷還續。", "華如三女粲，學陋一夔足。", "吟餘寫幽懷，蹇思慚刻燭。"]'),
('f4251e03-9981-4c6b-8c2b-31e584e5d970','夜寒大風洶洶不能寐用前韻作一首','程俱','宋','宋诗','song-poetry','','[]','朔風如長兵，犀兕貫七屬。',168,'全唐诗/poet.song.82000.json','["朔風如長兵，犀兕貫七屬。", "寥寥挾霜露，浩浩入空曲。", "羈禽無安巢，凍獸吼冰谷。", "枯摧卵壓山，石走塵飛麴。", "終朝恣飄鼓，衆竅如歌哭。", "客懷正無聊，默念歎鴻鵠。", "窮愁巧相尋，夜氣恐將梏。", "羲娥不我待，始姤今已復。", "黄昏歌苦寒，達旦幾翻覆。", "悲蛩尚啾喧，餓鼠時躑躅。", "青編置牀頭，芸竹有餘馥。", "枯腸浪自苦，無食安能續。", "平生僅識字，無地寄雙足。", "呼僮屏書眠，傳記真舉燭。"]'),
('575cd630-bd17-49bb-a346-1068af516da9','遷居城北蝸廬','程俱','宋','宋诗','song-poetry','','[]','有舍僅容膝，有門不容車。',120,'全唐诗/poet.song.82000.json','["有舍僅容膝，有門不容車。", "寰中孰非寄，是豈真吾廬。", "不作大耳兒，閉關種園蔬。", "茅薝接環堵，無地可灌鋤。", "不作下榻翁，一室謝掃除。", "平生四海志，投老河魚枯。", "願從素心人，不減南村居。", "蕭然冰炭外，傲晲萬物初。", "坐視蠻觸戰，兼忘糟粕書。", "聊呼赤松子，伴我龜腸虛。"]'),
('1886ed7e-0a8d-4a21-8689-408f10d16c52','蔡州葉翰林寄示近詩次韻八首 浚治西池','程俱','宋','宋诗','song-poetry','','[]','世間潢潦生蝌斗，聞說西池歲時久。',160,'全唐诗/poet.song.82000.json','["世間潢潦生蝌斗，聞說西池歲時久。", "不應朝滿夕已除，秋至先衰等蒲柳。", "知公旁觀久技癢，聊試他年膏苗手。", "泥塗不忍海波臣，畚鍤故煩牛馬走。", "嘗聞汝水行地底，出沒川原無不有。", "濺濺忽作寫盤珠，盎盎俄承注牀酒。", "清涵荇藻更姿媚，明燭鬚眉見妍醜。", "巢蓮永無龜曳尾，雨花定有魚頒首。", "使君佳政盡如此，說尹遙知不容口。", "何由步屧逐春風，作社慇慇就田叟。"]'),
('91ecdbcb-f911-40b2-82b1-3c4b6b35b222','蔡州葉翰林寄示近詩次韻八首 諸葛莱','程俱','宋','宋诗','song-poetry','','[]','三雄未辨誰朱紫，祇有群狙聊作使。',160,'全唐诗/poet.song.82000.json','["三雄未辨誰朱紫，祇有群狙聊作使。", "卧龍偃蹇正躬耕，一飽但知藜藿美。", "平生習氣故難盡，品藻蕪菁傳錦里。", "投醪飲河真有味，置薤留根何足比。", "要知茹草可終身，肯作染羮搖食指。", "公今嘯諾坐堂上，方丈盈前寧少此。", "戲持微草調諸傖，筆勢滔滔下南紀。", "云亭漫吏食不足，幾欲送窮煩鬰壘。", "拔毛蒸瓠當家鶩，潄石枕流徒厲齒。", "因公始識武侯鯖，蓋地何當似芣苢。"]'),
('8fe76c40-fa12-4c03-a4b0-b60042f72349','蔡州葉翰林寄示近詩次韻八首 九日雨中對菊忽忽塊坐用雨中對花韻三首 其一','程俱','宋','宋诗','song-poetry','','[]','胸中有天游，一室未爲迫。',72,'全唐诗/poet.song.82000.json','["胸中有天游，一室未爲迫。", "永懷東籬翁，那復有此客。", "重陰敗佳辰，長雨不爲澤。", "堆豗對黄華，菜色被臧獲。", "黄華亦蕭條，伴我霜鬢白。", "猶能相呴嚅，嫩葉供小摘。"]'),
('8d97a60b-691a-4514-8a3f-025b378011d9','蔡州葉翰林寄示近詩次韻八首 九日雨中對菊忽忽塊坐用雨中對花韻三首 其二','程俱','宋','宋诗','song-poetry','','[]','去年蛾眉山，痛飲真得計。',72,'全唐诗/poet.song.82000.json','["去年蛾眉山，痛飲真得計。", "新蟾繼秋陽，明潔謝點綴。", "今年坐蝸廬，簷溜落空砌。", "花開信多雨，會少苦分袂。", "茫茫大塊間，游子况無蒂。", "百年能幾何，行復驚改歲。"]'),
('87b25c58-1e50-4ab3-90f1-8067a24e0ba9','蔡州葉翰林寄示近詩次韻八首 九日雨中對菊忽忽塊坐用雨中對花韻三首 其三','程俱','宋','宋诗','song-poetry','','[]','危心如危絃，未斷先凜凜。',72,'全唐诗/poet.song.82000.json','["危心如危絃，未斷先凜凜。", "風庭忽知秋，中夜不安枕。", "力行無遠塗，積縷成重錦。", "男兒未蓋棺，雅志安得寢。", "榮衰非所念，身世固已審。", "亦復羡久生，聊爲老籛飲。"]'),
('a6ed02ad-8623-42a9-a3e3-f17d9eef4b98','蔡州葉翰林寄示近詩次韻八首 卞山信至三首 其一','程俱','宋','宋诗','song-poetry','','[]','公昔奉阡隴，二毛不勝簪。',96,'全唐诗/poet.song.82000.json','["公昔奉阡隴，二毛不勝簪。", "扶杖事耘植，咿唔雜呻吟。", "耿耿霜露感，遑遑蓼莪心。", "浮雲爲愁容，鳥獸亦哀音。", "徘徊動行路，下比元與任。", "宿草今已長，新松鬰森森。", "尚有五芝秀，熒熒爛如金。", "爲公賦南陔，凱風吹我襟。"]'),
('4728f1df-acc2-4b93-9e99-ac197ffefce1','蔡州葉翰林寄示近詩次韻八首 卞山信至三首 其二','程俱','宋','宋诗','song-poetry','','[]','行雲本無心，虚舟但乘流。',96,'全唐诗/poet.song.82000.json','["行雲本無心，虚舟但乘流。", "主人非逋客，不使芳杜羞。", "鳴騶入山谷，黽勉赴所求。", "明知廊廟具，豈爲猿鶴留。", "朝來尺素書，聯翩自巖丘。", "平安喜筠柏，寧論橘千頭。", "豈無木石居，吾非若人儔。", "既與世同樂，那容不同憂。"]'),
('037372c4-23db-4539-a2fa-ac76b147cdff','蔡州葉翰林寄示近詩次韻八首 卞山信至三首 其三','程俱','宋','宋诗','song-poetry','','[]','往客霅溪上，舒娥幾虧盈。',96,'全唐诗/poet.song.82000.json','["往客霅溪上，舒娥幾虧盈。", "深窮卞山境，勝概不可名。", "柴車逐公游，登臯復臨清。", "夜投阿蘭若，松窗待朝明。", "濟勝劇許掾，評詩陋鍾嶸。", "靈滋初可抔，龍籜忽已萌。", "斯遊今幾時，坐想飛泉鳴。", "尚應几杖間，隱隱金石聲。"]'),
('825cfbbb-e9db-4d85-9ebf-75d5ba56c21a','題葉翰林閱駿圖','程俱','宋','宋诗','song-poetry','','[]','葉公龍友天下才，當年麒麟天上來。',320,'全唐诗/poet.song.82000.json','["葉公龍友天下才，當年麒麟天上來。", "儒童抱送太一况，下游閶闔觀瓊臺。", "高標故自賞神駿，肯使餘恨遺蒿萊。", "帝閑食粟幾千駟，盛氣勃鬰馳天街。", "穩銜金勒立仗下，俯視冀北皆駑駘。", "驪黄不來八龍遠，尚有寫照埋氛埃。", "短屏高障久零落，意象崪嵂求其儕。", "收羅絕足共一處，引素便覺風沙開。", "偉哉十馬盡殊相，神物變化須風雷。", "騰驤振迅各有態，豈顧短脰空徘徊。", "持韁頓轡者誰子，無復墮淚鳴聲哀。", "刷燕秣越安足道，會逐銜燭西山頹。", "其中一驥屹不動，尾垂青絲蹄卓錐。", "安知萬里志未已，但見寂寞如寒灰。", "龍眠老筆不再得，幻化百億紛驪騧。", "鄭生晚出擅圖貌，盛名欲與曹韓偕。", "肉身飛入九天去，清都樓觀金崔嵬。", "玉花照夜不論價，想見火齊珊瑚堆。", "只今此畫已難致，肯戲秃筆霑殘煤。", "千金市骨意不淺，對此慷慨傷虺尵。"]'),
('1243aadc-7dc7-42b5-a836-04b2d99a1836','元夕塊坐因用葉翰林去年見寄元夕詩韻寫懷  其一','程俱','宋','宋诗','song-poetry','','[]','兒童逐遨戲，先春禱春晴。',120,'全唐诗/poet.song.82000.json','["兒童逐遨戲，先春禱春晴。", "心如飄風快，目若冰壺明。", "寧爲惜日計，所願佳節并。", "老來見紛麗，如乾闥婆城。", "流光不可挽，譬彼空中聲。", "那知節物佳，翛然謝將迎。", "幽燈對簡編，歷歷記所更。", "斯須閉關卧，鼻息驚雷鳴。", "寤念北山北，田家已催耕。", "胡爲異鄉久，空寒猿鶴盟。"]'),
('bc5f6ece-4f87-4ee8-b466-489ae70b02af','元夕塊坐因用葉翰林去年見寄元夕詩韻寫懷  其二','程俱','宋','宋诗','song-poetry','','[]','短日良易暗，凝陰有時晴。',120,'全唐诗/poet.song.82000.json','["短日良易暗，凝陰有時晴。", "何人勸之照，燭燎皆爭明。", "今年春苦寒，寒威劇幽并。", "連綿積三白，雲埋闔廬城。", "深泥浹新雨，行路無人聲。", "藜燈不來下，箕卜豈復迎。", "朝來日照梁，天氣忽已更。", "稍聞橋市間，簫鼓遠近鳴。", "吳人尚游樂，急如赴春耕。", "唯有窮巷士，守窮如守盟。"]'),
('8d6c7d5d-29d8-4b70-a9eb-25c4402e71ca','西安謁陸蒙者老大夫觀著述之富戲用蒙老新體作  其一','程俱','宋','宋诗','song-poetry','','[]','丈人意何長，縱目文史足。',72,'全唐诗/poet.song.82000.json','["丈人意何長，縱目文史足。", "琅然五行落，洞視不再讀。", "作書兼遠奘，衆妙探玄竺。", "時時歌四始，笑捧五經腹。", "高堂發新稾，重複羅籖軸。", "觀之類窺管，諷味得膏馥。"]'),
('444cb568-6f12-434b-b1d4-99d1d1dcb06d','西安謁陸蒙者老大夫觀著述之富戲用蒙老新體作  其二','程俱','宋','宋诗','song-poetry','','[]','白頭書生黑頭翁，長安時花幽澗松。',144,'全唐诗/poet.song.82000.json','["白頭書生黑頭翁，長安時花幽澗松。", "遠飛近啄雖異志，天命厚薄無雌雄。", "鈎深采博燥喉吻，守此一畝蓬蒿宫。", "杜門不出交二仲，木陰澗曲遙相通。", "紫囊貝葉資藝苑，款關一見踰三冬。", "亭亭漫吏多所歷，乾死書螢心似漆。", "王門賓閣不留行，赭顔趼足搜泉石。", "茅簷正欲結雲根，竹葉榴花薦餘瀝。", "當從元亮賦言歸，木茹麻衣永投筆。"]'),
('8c10ef87-5456-416c-a706-3831f8716d4b','昨夕風月頓清獨坐中庭夜分不寐翛然四顧寂無人聲如在塵外作詩一首以寫一時之適','程俱','宋','宋诗','song-poetry','','[]','鄰家雙井桐，下有羃翠庭。',96,'全唐诗/poet.song.82000.json','["鄰家雙井桐，下有羃翠庭。", "晚來微風過，已復含秋聲。", "歸舍對環堵，筠窗亦泠泠。", "月輪正行空，洗光自東溟。", "常星爲失色，肯與纖雲并。", "廓如凈琉璃，中有玉鑑明。", "太虚本無滓，心目固自清。", "浩然天壤間，洞視萬古情。"]'),
('e5685e89-e54a-4fdb-8de2-bacad8359e19','數日春物甚麗坐閱歲華偶成古句','程俱','宋','宋诗','song-poetry','','[]','東皇駕蒼龍，超忽了八區。',188,'全唐诗/poet.song.82000.json','["東皇駕蒼龍，超忽了八區。", "清明風從冰輪際，轉入厚地潛嘘嚅。", "周行無間寂無迹，但見動植咸照蘇。", "赩如醇醪入花骨，凍塊一一成豐腴。", "花光照空日色醉，天宇蕩滉青蓮敷。", "爛霞漲淥萬堆雪，剪刻不用施鉛朱。", "銅丸晝漏五十刻，銜燭緩轡經天衢。", "游人正與春物競，汲汲磨蟻同馳驅。", "固知一氣共舒慘，機關默動非人須。", "孰居無事主張是，繡黼萬象歸無餘。", "青黄赤白豈有意，應見略似摩尼珠。", "區中代謝未有極，故自有物無榮枯。"]'),
('f54f64ce-20de-4f26-b37f-c64cee224da9','陳君學正草堂成提點大夫梅十五丈有詩且蒙借示見邀同作謹次原韻因以敘懷','程俱','宋','宋诗','song-poetry','','[]','行藏固殊塗，臭味非一族。',288,'全唐诗/poet.song.82000.json','["行藏固殊塗，臭味非一族。", "或峨冠攫金，或被褐懷玉。", "持身凜冰淵，或洞洞屬屬。", "和光略畦町，或落落碌碌。", "或來儀帝庭，或去隱王屋。", "堆豗肉生髀，馳騖趼重足。", "或委餘膏粱，或不厭杞菊。", "或翬飛千柱，采錯煖金綠。", "或蝸盤四壁，分光待鄰燭。", "要之皆幻寄，眇矣太倉粟。", "明冥默乘除，塞馬更禍福。", "陳公作茅齋，足以媚幽獨。", "苟全真易成，知足定不辱。", "有門晝常關，何必在巖谷。", "向來萬金堂，奔走九州牧。", "一朝巢自焚，始悔突不曲。", "何如東郭舍，椽柱隨把束。", "翛然已忘世，肯嘆碩人軸。", "我今客吳門，饑卧謝僕僕。", "年來寄蓬茨，慕此高讓俗。", "室中了無藏，鼠竊屢驅逐。", "衰懷百念冷，對境無可欲。", "窮通如四序，損益正三復。", "衡門可棲遲，薄酒等醽醁。"]'),
('b89eba5f-2c72-4ac0-8dd2-5ffcc012a3f7','十月五日集季野家歸作','程俱','宋','宋诗','song-poetry','','[]','賢愚孰無營，急景信可惜。',216,'全唐诗/poet.song.82000.json','["賢愚孰無營，急景信可惜。", "如何闔廬城，乃有此閑客。", "懷安豈初志，運甓有餘力。", "相從無何鄉，邂逅一日適。", "虚窗得朝陽，寒凜作春色。", "琴書羅棐几，一一凈如拭。", "畫沙見奇蹤，落屑非近識。", "似追永和還，未覺正始隔。", "崢嶸衡霍囿，莽蒼雲夢澤。", "時華玄低卬，幽鳥共深寂。", "誰驅此變幻，戲納方丈域。", "慚公傾春釀，澆我憂思積。", "豈無車公語，顧匪伯仁匹。", "長檠蠟華摧，起視霜月白。", "酣歌美清夜，擁髻侍通德。", "參差吐幽妍，鑿落灧芳碧。", "觥籌不留行，爲問此何夕。", "言歸謝主人，五斗安可極。"]'),
('38cbff41-0f00-4538-8aee-cc8a94806da6','戲示江協律漢','程俱','宋','宋诗','song-poetry','','[]','酸寒北山尉，憔悴孔州守。',72,'全唐诗/poet.song.82000.json','["酸寒北山尉，憔悴孔州守。", "枯魚同處陸，濡沬賴詩酒。", "當時年尚壯，意氣亦何有。", "祇今雙鬢華，十載一回首。", "仕初君似遇，遊倦吾已醜。", "邂逅記昔遊，空嗟漢南柳。"]'),
('c63d0ceb-023a-4d8c-843a-2c91a40b837a','再和一篇以答固窮之句','程俱','宋','宋诗','song-poetry','','[]','車行有險夷，初不入天守。',72,'全唐诗/poet.song.82000.json','["車行有險夷，初不入天守。", "乘顛了無擇，正自全於酒。", "我身天地間，毫末寄九有。", "正當带笭箵，章甫誤加首。", "久知田園樂，不信村野醜。", "平生笑何人，戚戚柳州柳。"]'),
('2a33551d-9523-4e72-a6f5-564d22e95414','江再和戲答四篇  其一','程俱','宋','宋诗','song-poetry','','[]','當年季將軍，晚節河東守。',72,'全唐诗/poet.song.82000.json','["當年季將軍，晚節河東守。", "誰令一人譽，揮去坐使酒。", "長卿起遐陬，落筆賦烏有。", "要之乃雕篆，意不在黔首。", "窮通付造物，世俗浪妍醜。", "何必送五窮，呼奴結車柳。"]'),
('ec998f39-48ab-4fac-a93f-5b87867c4226','江再和戲答四篇  其二','程俱','宋','宋诗','song-poetry','','[]','長言屹秦城，古例開墨守。',72,'全唐诗/poet.song.82000.json','["長言屹秦城，古例開墨守。", "三年不窺園，一吻莫飲酒。", "斯人浪自苦，初不繫無有。", "何如從子微，亦復問賢首。", "此身未能了，何暇念億醜。", "超然方丈間，觀化肘生柳。"]'),
('0f37567f-76f4-4a35-80de-302ef556dec5','江再和戲答四篇  其三','程俱','宋','宋诗','song-poetry','','[]','君家翠巖翁，三一久已守。',72,'全唐诗/poet.song.82000.json','["君家翠巖翁，三一久已守。", "與沈愛欲泥，寧飲聲聞酒。", "當知華藏海，正在十二有。", "他年涅槃門，燕路須北首。", "胖然一心定，六賊如獲醜。", "感彼志冰霜，吾衰等蒲柳。"]'),
('37beda7f-9e8f-427a-acab-0f4bbbc91aa0','江再和戲答四篇  其四','程俱','宋','宋诗','song-poetry','','[]','太平一春臺，好在四夷守。',72,'全唐诗/poet.song.82000.json','["太平一春臺，好在四夷守。", "持盈何足道，飽德醉以酒。", "君爲樂歌詞，嘉瑞無不有。", "不知府中士，誰子號稱首。", "如君真嫵媚，孰謂施嬙醜。", "故應洗餘累，令君繼温柳。"]'),
('9edfd9ce-1520-451d-8bf0-f74cb7084076','季野見和次韻二首  其一','程俱','宋','宋诗','song-poetry','','[]','談遷太史令，趙衛淛西守。',60,'全唐诗/poet.song.82000.json','["談遷太史令，趙衛淛西守。", "妙齡中青錢，大筆笑玄酒。", "一麾分隼旟，七載去螭首。", "行看賈生還，固異顔駟醜。", "何許從宸游，金鞍繫宫柳。"]'),
('95e0045b-cec2-4ad4-9003-fa4ef544cf7b','季野見和次韻二首  其二','程俱','宋','宋诗','song-poetry','','[]','此身非匏瓜，圭竇可長守。',72,'全唐诗/poet.song.82000.json','["此身非匏瓜，圭竇可長守。", "初爲絃歌計，肯飲中山酒。", "深虞委司敗，政術空無有。", "故將老衡茅，敢復嘆華首。", "公詩金錯刀，刻畫無鹽醜。", "應憐五窮韓，定作三黜柳。"]'),
('77788cb7-0e66-4a4c-9a0f-390aee4e4e4a','次韻葉內翰游西余山用袁奉議韻','程俱','宋','宋诗','song-poetry','','[]','平子愧明略，長卿真倦遊。',240,'全唐诗/poet.song.82000.json','["平子愧明略，長卿真倦遊。", "笭箵儻可佩，瑤玉豈復舟。", "舊聞西余老，猖狂白蘋洲。", "毫端寶刹見，塵起大地收。", "奮迅師子王，蚓蛙視蛟虯。", "向來大滌翁，晚節萬戶侯。", "襄陽一轉語，富貴真雲浮。", "此道久已微，碔砆混琳球。", "念昔過苕霅，尋谿亦經丘。", "同遊今安在，十載一瞬眸。", "幾欲挂長劍，刻舟笑延州。", "焉知甕中人，寂默無春秋。", "香爐着古廟，一念萬劫休。", "安得五畝園，良苗接平疇。", "脫身饑寒外，結友高勝流。", "二邊無餘習，六賊可盡劉。", "誰能使危膓，一日一萬周。", "須公謝三旌，故事追羊求。", "青鞋一幅巾，往來山之幽。", "且復載明月，深潭戲垂鈎。"]'),
('8241222e-b83b-402b-8d44-9a665ac45105','次韻江司兵寄示所和趙司錄相從飲解嘲之句','程俱','宋','宋诗','song-poetry','','[]','卜居林塘靜，禽魚樂融融。',240,'全唐诗/poet.song.82000.json','["卜居林塘靜，禽魚樂融融。", "陽和一披拂，照爛黼繡工。", "柔條罥繁枝，幽香來晚風。", "誰謂武陵遠，臨清千樹紅。", "俯仰村郭間，從容聖賢中。", "暮見月圓缺，餘光入疏櫳。", "朝乘日車作，坐守四壁空。", "遙想趙與江，屈身薄書叢。", "正類鸛雀碧，未爲覆盆烘。", "祿隱寄簪笏，神遊在方蓬。", "時時望西山，把酒一笑同。", "茗碗傾石鼎，山蔬出筠籠。", "不妨問中聖，何暇賦惱公。", "趙子五車腹，春秋富終童。", "居然出其類，儼如黄髪翁。", "江子事超曠，町畦漫無封。", "但見磊砢姿，温溫若春濃。", "人生迭相笑，傖父嘲吳儂。", "鴟夷與井缾，憂樂殊初終。", "且當從所好，迂轡若爲容。"]'),
('ab8282ed-28a9-488a-899a-8e691a167003','空相僧舍書事','程俱','宋','宋诗','song-poetry','','[]','午景入疏竹，堂陰筠粉香。',132,'全唐诗/poet.song.82000.json','["午景入疏竹，堂陰筠粉香。", "疏簾撲空翠，無風自微凉。", "棋聲破禪寂，日轉幡影長。", "霏煙觸垂瓜，泛乳搜枯膓。", "投局起尋勝，徘徊雨花堂。", "巢蓮見靈龜，信有千歲祥。", "徐觀乃跛鼈，圉圉循菰蒋。", "笑罷得歎息，是非可兼忘。", "却坐對談麈，冰松想千章。", "斯須二三子，矯若驚鴻翔。", "府中有料理，不作功曹狂。"]'),
('795627e2-bdcd-4d8c-bb51-a5fdbf01bfcd','戲贈江仲嘉司兵','程俱','宋','宋诗','song-poetry','','[]','君不見謝公栖遲樂東土，起作司馬征西府。',214,'全唐诗/poet.song.82000.json','["君不見謝公栖遲樂東土，起作司馬征西府。", "莫年談笑有穰孫，鶴唳風聲走強虜。", "又不見子猷剡川高興闌，肯隨鶴書落人間。", "不知騎曹底官職，朝來拄頰看西山。", "平生清真翠巖老，泉石膏肓偶同調。", "歲寒落落見孤松，不忍低眉寧枯槁。", "年來無米繼朝炊，聞說吳興富魚稻。", "不妨來作古司兵，士卒投醪止鳬藻。", "美哉洋洋霅溪水，秋塘百里荷花繞。", "當年釣徒放浪處，醉目悠然送歸鳥。", "斯人不死世不識，往往凌波弄瑤草。", "君方參同佐龍虎，我欲治荒種梨棗。", "會當月夜見龐眉，一笑超然凌八表。"]'),
('77eba2a7-da54-449f-ac68-0e7f3f94950b','次韻和江司兵浙江觀潮','程俱','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','寥天月魄更旁哉，歸墟兩潮時去來。',288,'全唐诗/poet.song.82000.json','["寥天月魄更旁哉，歸墟兩潮時去來。", "乃知大塊與人等，欠噫風動聲爲雷。", "支川千億具毛竅，四溟翕張玄牝開。", "人間百刻乃一息，斷岸飄鼓如輕埃。", "二山横控江海際，挾以幽闕雙嵬嵬。", "偉哉吞吐王百谷，視彼淺狹真臺陪。", "倒流千里駭凡目，正自違性同棬杯。", "相傳昔者楚亡將，事成國霸遭雄猜。", "英靈不没尚爲爾，姓字往往欺啼孩。", "錦鄉功成老元帥，酒酣拔劍歌莫哀。", "戲令強弩飛勁箭，大堤屹立藏風桅。", "吳兒荒怪不足錄，適與支諾資談咍。", "豈知六合有常理，水中出火能焚槐。", "當年謝公正遊樂，遺形物表如王駘。", "微吟獨嘯向海道，幾見銀雪西山回。", "讀君新句寫奇觀，便似放目吳王臺。", "何當共此散煩鬰，大瓠五石充瓶罍。", "更因長風破巨浪，與君掛席尋蓬萊。"]'),
('ab4117ad-05d5-4d0b-9150-30c1007e57c7','送趙子晝奉議歸睢陽用熊倅韻','程俱','宋','宋诗','song-poetry','','[]','紛華眩人劇朱碧，子獨好書如好色。',144,'全唐诗/poet.song.82000.json','["紛華眩人劇朱碧，子獨好書如好色。", "王孫被服甚寒生，射策君門先破的。", "榮州書窟三萬卷，錦嚢付此龐眉客。", "南遊句吳北大魏，亦復徒勞問刀筆。", "不唯唇齒腐經史，正自雲山鏁胸臆。", "老來息交思簡事，爲子忘劬廢晨昔。", "春風滿帆送歸舸，回首清游如昨日。", "知君名駿定千里，不待朝庭訪幽側。", "有書時寄雁南飛，顧我漁樵正爭席。"]'),
('af046bed-b21f-4caf-b598-db34f3ff0da2','同趙奉議離吳興江仲嘉與其兄仲舉送百餘里醉中戲作此句一首','程俱','宋','宋诗','song-poetry','','[]','大江飲酒如澆灰，小江縱酒顛如雷。',128,'全唐诗/poet.song.82000.json','["大江飲酒如澆灰，小江縱酒顛如雷。", "扁舟相送不道遠，百二十里雲帆開。", "云亭老人窮不死，故園茅屋荒蒼苔。", "闔廬城中一畝地，已辨甕牖鋤蒿萊。", "吳興上佐吾黨士，十年縱賞西王臺。", "眉間黄色袨綵服，柁樓長嘯春風回。", "要須酩酊酬此别，不離萬頃添金杯。", "明朝相望即湖海，縱有美酒何爲哉。"]'),
('58c1a952-0bf8-4809-ae54-111538bfe0b3','蝸廬有隙地三兩席稍種樹竹已有可觀戲作七篇 菊','程俱','宋','宋诗','song-poetry','','[]','吾聞酈侯國，産菊千丈潭。',72,'全唐诗/poet.song.82000.json','["吾聞酈侯國，産菊千丈潭。", "采華食其葉，垂根漬芳甘。", "遂令酈川氓，難老如彭聃。", "庭前有古井，秋霖發清涵。", "慇懃東籬綠，覆此白玉奩。", "時能嚼新蘂，汲月散餘酣。"]'),
('e8458614-58a8-482c-a9f0-6a0ffed98a9e','蝸廬有隙地三兩席稍種樹竹已有可觀戲作七篇 竹','程俱','宋','宋诗','song-poetry','','[]','種玉未渠久，疏篁長兒孫。',72,'全唐诗/poet.song.82000.json','["種玉未渠久，疏篁長兒孫。", "勝會不在多，何須辟疆園。", "我觀榛蕪地，塵思紆且煩。", "蕭森對此君，清涼徹心源。", "草木初無情，妄作凈穢觀。", "乃知識種子，正是生死根。"]'),
('812b733a-83d2-4cb0-8a26-26ffa350602f','蝸廬有隙地三兩席稍種樹竹已有可觀戲作七篇 鳯仙','程俱','宋','宋诗','song-poetry','','[]','微華若么鳯，倒挂茂蔚中。',48,'全唐诗/poet.song.82000.json','["微華若么鳯，倒挂茂蔚中。", "鳴鳥不可見，幽懷寄芳叢。", "初移幾寸苞，稍展兩翅紅。", "能使寂寞濱，餘妍映蒿蓬。"]'),
('7cdd086f-226c-40e6-bee7-a642132eea4f','蝸廬有隙地三兩席稍種樹竹已有可觀戲作七篇 鷄冠','程俱','宋','宋诗','song-poetry','','[]','峨冠百草頭，意象出其類。',48,'全唐诗/poet.song.82000.json','["峨冠百草頭，意象出其類。", "望之似木鷄，正自五官廢。", "寧須斷其尾，無乃假予臂。", "可復近幽窗，談玄有深詣。"]'),
('ca964a57-2ebc-4197-b8c1-9c9e8cce5576','蝸廬有隙地三兩席稍種樹竹已有可觀戲作七篇 紅莧','程俱','宋','宋诗','song-poetry','','[]','嘉生苦不榮，凡草忽猥大。',60,'全唐诗/poet.song.82000.json','["嘉生苦不榮，凡草忽猥大。", "君看庭中莧，易長劇稂稗。", "初無封植意，不見蟲鳥害。", "穰穰筠菊間，紅紫不可殺。", "微功尚足收，染我盤中菜。"]'),
('dc6f4da6-61ff-4d52-9501-dc3bb571eeeb','蝸廬有隙地三兩席稍種樹竹已有可觀戲作七篇 芭焦','程俱','宋','宋诗','song-poetry','','[]','芭蕉中無堅，譬彼泡夢幻。',48,'全唐诗/poet.song.82000.json','["芭蕉中無堅，譬彼泡夢幻。", "了然觀我身，生死知一貫。", "學書端未暇，覆鹿真自亂。", "一雨過空庭，秋聲入深宴。"]'),
('644b87e1-d860-487b-8835-cc8d35de45f3','蝸廬有隙地三兩席稍種樹竹已有可觀戲作七篇 水青','程俱','宋','宋诗','song-poetry','','[]','水青雖楚楚，不復中棟梁。',48,'全唐诗/poet.song.82000.json','["水青雖楚楚，不復中棟梁。", "黄封入雕檻，亦足被寵光。", "朝離糞壤區，暮上君子堂。", "胡爲伴幽獨，墮此一畝荒。"]'),
('a570e87c-f52e-483a-a56b-e21e5d33b87f','黄嘉父朝請公彦示詩以不數面爲言且索近著次韻謝答一首','程俱','宋','宋诗','song-poetry','','[]','黄公游不成，白髮奉朝請。',144,'全唐诗/poet.song.82000.json','["黄公游不成，白髮奉朝請。", "東歸樂閑燕，有味如雋永。", "雙鳬倦朝飛，獨鶴方夜警。", "知余亦衰窮，繫馬無復騁。", "貽詩重瓊玖，未展意先領。", "勞生厭塵霧，對此得暫屏。", "終當遣長鬚，亦復釣縮頸。", "相過舉清觴，野水吹萬頃。", "君當傾錦囊，我亦倩毛穎。", "時尋招提勝，蓮社比宗炳。", "如何迫寒餓，去棹聊一整。", "興盡即言歸，江湖足佳景。"]'),
('96391236-2e80-4ae0-aa1b-4da5d0b3c6c7','和楊彝甫靜妙軒','程俱','宋','宋诗','song-poetry','','[]','君家執戟郎，寂寞墜天祿。',96,'全唐诗/poet.song.82000.json','["君家執戟郎，寂寞墜天祿。", "蕭然劉董外，那用相窘束。", "居無甔石儲，但有書滿屋。", "君今老衡茅，出處異蘭菊。", "靜中獨觀妙，四達開惠目。", "中園鬰黄華，庭下森翠竹。", "饑來索盤餐，小極須睡足。", "時當叩君門，爲問梅子熟。"]'),
('46c1526a-494d-4075-8a0a-49525b693370','過毛達可友給事覽壁間舊詩次韻二首  其一','程俱','宋','宋诗','song-poetry','','[]','堂前清颸發，樹外赤日西。',132,'全唐诗/poet.song.82000.json','["堂前清颸發，樹外赤日西。", "坐令天壤間，氣候忽不齊。", "解带席嘉蔭，長哦壁間題。", "故應有神護，塵土不得迷。", "前年款公門，鷤䳏亦已啼。", "今年復羈旅，庭莎欲鳴鷄。", "西游有底急，觸熱忘卑棲。", "似爲饑所驅，不計轍與蹄。", "綈袍意彌厚，盤餐洗羮藜。", "磊塊久不澆，醇醪代朝虀。", "襄陽之新句，夜直難相攜。"]'),
('1d617ba2-0f05-4dc1-92bb-59cbe8c08b4f','過毛達可友給事覽壁間舊詩次韻二首  其二','程俱','宋','宋诗','song-poetry','','[]','黄華非不佳，寒澹每見少。',84,'全唐诗/poet.song.82000.json','["黄華非不佳，寒澹每見少。", "蕭蕭亦無言，懷抱不自曉。", "深嫌小桃夭，欲伴霜松矯。", "窺叢慰寂寞，時有南飛鳥。", "主人真賞奇，灌植勤便了。", "徘徊傍東籬，高興在塵表。", "坐有白頭生，臨風百憂繞。"]'),
('c4de5b25-f3cd-4840-9421-2c0767a876ee','北固懷古','程俱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','阿瞞長驅壓吳壘，飲馬長江投馬箠。',96,'全唐诗/poet.song.82000.json','["阿瞞長驅壓吳壘，飲馬長江投馬箠。", "英雄祗數大耳兒，彷彿芒碣赤龍子。", "幄中况有南陽客，布衣躬耕無甔石。", "當時鼎足計未成，聊此一奇空赤壁。", "人隨流水去不還，卧羊頑石留空山。", "如今留石亦煨燼，山與長江相向閑。"]'),
('61ef4acc-5036-47ae-a352-2ceffb9908ef','焦山','程俱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','龍伯不解事，投竿牽大鼇。',158,'全唐诗/poet.song.82000.json','["龍伯不解事，投竿牽大鼇。", "逆流直上三萬里，怒捲渤澥秋風潮。", "適當長江入海處，屭贔擲此雙岧嶤。", "一山正臨聲利窟，來檣去櫓紛𦪈艚。", "一山獨與世疏闊，突據幽險盤雲濤。", "飛仙播蕩去不返，止有一翁身姓焦。", "至今金玉作山骨，草木堅勁無夭條。", "爾來寂寞幾千歲，稍見遊子來山椒。", "吁嗟一與人境接，世故擾擾如牛毛。", "安得夸娥還着鼇背上，因之置我三山高。"]'),
('f6b76eed-c735-4d25-95a3-5746a8ab3e93','和葉翰林湖上夜歸古句','程俱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','琅玕一紙傳青桐，西湖默存清夢中。',160,'全唐诗/poet.song.82000.json','["琅玕一紙傳青桐，西湖默存清夢中。", "遙知湖上發新倡，凡馬一洗煙雲空。", "翰林文章舊驚世，聊試三輔分符銅。", "玉槃無聲轉清夜，水天交貫冰朣朧。", "况聞許下足名士，歗詠鼓舞馮夷宫。", "擔簦獨欠此狂客，憔悴企踵臨西風。", "朝來珠璧入懷袖，坐想星宿羅心胸。", "自憐華髪烏帽底，俯仰正慚張長公。", "何當從公萬物表，妙契不待將無同。", "展書三復更太息，但見缺月穿疏櫳。"]'),
('d8df9c31-1220-4736-8267-ea3629cacc6b','秋華無幾尚有紫薇相對里巷間','程俱','宋','宋诗','song-poetry','','[]','晚花如寒女，不識時世粧。',96,'全唐诗/poet.song.82000.json','["晚花如寒女，不識時世粧。", "幽然草間秀，紅紫相低卬。", "榮木事已休，重陰閟深蒼。", "尚有紫薇花，亭亭表秋芳。", "扶疏綴繁柔，無復粉艷光。", "空庭一飄委，已覺巾裾凉。", "手中蒲葵箑，雖復未可忘。", "仰視白日永，凄其感冰霜。"]'),
('c2c8f6d0-704e-460f-a82c-1c443f781bbc','傅冲益寄淮口阻風及清淮道中詩二首又次漣水一首用其韻和寄  其一','程俱','宋','宋诗','song-poetry','','[]','羣玉聚名雋，作書如九丘。',120,'全唐诗/poet.song.82000.json','["羣玉聚名雋，作書如九丘。", "回觀白虎儒，謭淺安可侔。", "傅子故疏爽，十年嗟滯留。", "嶔崎百憂後，晚爲造物收。", "平生未見書，頗足資吟謳。", "縱未服豸角，且當佐螭頭。", "安知免官去，觸熱送濁流。", "清朝正須才，洗垢方鎮浮。", "豈使三語掾，垂綸逐羣鷗。", "譬如飄風頃，終濟萬里舟。"]'),
('89cbcb7c-9160-45de-afdd-85ee5671fc52','傅冲益寄淮口阻風及清淮道中詩二首又次漣水一首用其韻和寄  其二','程俱','宋','宋诗','song-poetry','','[]','青山照長淮，氣象一方冠。',180,'全唐诗/poet.song.82000.json','["青山照長淮，氣象一方冠。", "清光堪溶溶，洛尾殺湍悍。", "斯遊今一紀，回首若朝旦。", "塵容故如昨，凡骨終不換。", "但於憔悴餘，生死知一貫。", "歸田食不足，乘障力難捍。", "折腰委吏間，亦豈愧儒緩。", "自君彈冠西，吾事足悲惋。", "坐看秋空雲，已復澹河漢。", "鮮歡杯杓乾，絕學編策斷。", "西山雖爽氣，烏幘安敢岸。", "思君笑言樂，目送歸翼亂。", "朝來得新詩，一一錦繡爛。", "塵膺久結約，邂逅百憂泮。", "何當索此身，久矣次山漫。"]'),
('e3d85dc1-bf3a-4eed-a86a-2e6a5eb571b4','傅冲益寄淮口阻風及清淮道中詩二首又次漣水一首用其韻和寄  其三','程俱','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','故人尺素來天際，頗憶當年任守壘。',192,'全唐诗/poet.song.82000.json','["故人尺素來天際，頗憶當年任守壘。", "平明一笑百事空，不作細書書紙尾。", "寄書五湖夸海岱，入眼滄溟無百里。", "軍城崪屼枕青山，地脈遙從岱宗起。", "題詩要爲寫高閣，播颺意欲先糠粃。", "晚登南宫頭已白，却駕朱轓臨泗水。", "丹燒未辨令威鶴，神遊先跨琴高鯉。", "可憐蕭散竹林士，埋玉青山骨空委。", "人生一世偶相值，轉首羲皇不停晷。", "西山妙蹟欲仙去，爽氣朝來盡如洗。", "遙知弔古一長喟，引送澆愁付浮蟻。", "有詩淮上可微吟，會有流魚出傾耳。"]'),
('d0f09c0f-d47e-4422-bcf6-c9b9c0066688','周萃秀才惠詩次韻酬之一首','程俱','宋','宋诗','song-poetry','','[]','病驥伏長坂，悲鳴想戎軒。',168,'全唐诗/poet.song.82000.json','["病驥伏長坂，悲鳴想戎軒。", "游魚落枯肆，墮淚臨河墳。", "人生道脩阻，趼足窮崑崙。", "沈淵探驪頷，一跌萬鬼鄰。", "我老不解事，區區算沙塵。", "讀書亦良苦，內視餒且貧。", "爲文富詼笑，初不救否屯。", "爾來自箴切，習氣不復存。", "方將補黥劓，寂兀謝世紛。", "朝露視窮達，春冰釋癡嗔。", "君胡創推激，發我惰與昏。", "如君東吳秀，俊拔昔所聞。", "名駒始就秣，意氣已不羣。", "抗髒市門客，豈堪同日論。"]'),
('ca2a3a1e-72c3-4324-98de-093053ed6c6f','秋雨三首  其一','程俱','宋','宋诗','song-poetry','','[]','細字忽難讀，松窗失朝暉。',96,'全唐诗/poet.song.82000.json','["細字忽難讀，松窗失朝暉。", "開簾視天宇，屯雲凝如黳。", "霏微乍噴灑，翕忽看淋漓。", "斯須建百川，中庭即方池。", "秋雷亦動地，勢洶萬鼓鼙。", "虚簷忽無聲，蒼狗變白衣。", "飄搖露穹碧，涼飈洗蒸炊。", "雨師真解事，作止適所宜。"]'),
('4a54a644-004e-453b-b25f-feeee2e20a33','秋雨三首  其二','程俱','宋','宋诗','song-poetry','','[]','十日麗辰次，如環了無端。',120,'全唐诗/poet.song.82000.json','["十日麗辰次，如環了無端。", "人言秋甲子，畏濕不畏乾。", "向來譙門道，旁立三尺壇。", "故勤壁間緣，一起泥中蟠。", "青衣躍且躁，有如沐猴冠。", "先聲忽灑道，直此辰與干。", "邇來未旬浹，三見急雨寒。", "黄流抺河草，連檣度平瀾。", "良苗有佳色，未覺千畝寛。", "時暘亦須早，無使江湖翻。"]'),
('49d458a7-4257-4423-995a-57ecd341a256','秋雨三首  其三','程俱','宋','宋诗','song-poetry','','[]','華首三不遇，求田亦良圖。',120,'全唐诗/poet.song.82000.json','["華首三不遇，求田亦良圖。", "莫嗔湖海士，豪氣故不除。", "扶犂本吾事，二頃終勝無。", "繞舍生蒿蓬，閉門種英蕪。", "從渠百尺樓，笑此蝸牛廬。", "吳中久卜鄰，會從故人居。", "荆溪一廛地，儻與求羊俱。", "屠門過大嚼，一雨喜有餘。", "正恐二三子，聯翩躡雲衢。", "空令千里駕，悵望黄公壚。"]'),
('adf8d01e-b461-4359-ae40-cf59fcb16afd','過紅梅閣一首','程俱','宋','宋诗','song-poetry','','[]','春風如醇酒，着物物不知。',132,'全唐诗/poet.song.82000.json','["春風如醇酒，着物物不知。", "能使死瓦色，化爲明艷姿。", "寒枯出繁秀，巧與節物期。", "江梅故幽獨，綽約不自持。", "居然北枝後，迨此白日遲。", "春風日浩蕩，醉色回冰肌。", "清妍有餘態，衆芳謝凡卑。", "憑虚一回睇，俯仰歲月馳。", "所恨培雪根，向來歲寒枝。", "差池弄芳晚，坐令顔色移。", "顔色故嫵媚，幽香無故時。"]'),
('85f103c7-dcb8-4802-be5f-b93e26844b68','周憲之用余送趙子雍詩韻作屬德祖及余同作二首  其一','程俱','宋','宋诗','song-poetry','','[]','嗟我涉世路，有如陸推舟。',108,'全唐诗/poet.song.82000.json','["嗟我涉世路，有如陸推舟。", "尋常不可冀，况乃萬里流。", "安能逐驪騄，超忽十二州。", "雖然晚聞道，淺矒如孫休。", "往者謝五斗，種瓜從故侯。", "家山三畝宅，白首遂首丘。", "一爲饑所驅，復作漫浪遊。", "曲意泯圭角，終然足人尤。", "焉知大隱地，亦復懷百憂。"]'),
('ab3d9068-298a-4659-b668-19d23d664d73','周憲之用余送趙子雍詩韻作屬德祖及余同作二首  其二','程俱','宋','宋诗','song-poetry','','[]','大雲吳中士，妙學兼般舟。',108,'全唐诗/poet.song.82000.json','["大雲吳中士，妙學兼般舟。", "筆下走三峽，胸中包九流。", "考古自墳典，探玄極方州。", "別來十五年，邂逅一笑休。", "作書不求聞，取重惟桓侯。", "尚北宮獨冷，塵埃忘跖丘。", "爾者稍薦賢，蒲輪遂西遊。", "會當君相間，作詩繼何尤。", "遙知市門子，人不堪其憂。"]'),
('ff39eea0-1ec5-4a16-87fc-f66d44af0f58','劉朝散長源淮夫劉先生彝之子孝弟有賢行年六十一且致仕侍其親義興爲賦詩一首','程俱','宋','宋诗','song-poetry','','[]','劉侯六十衣綵衣，上堂娛戲如嬰兒。',256,'全唐诗/poet.song.82000.json','["劉侯六十衣綵衣，上堂娛戲如嬰兒。", "慈顔華髪顧之笑，坐令寒日生春暉。", "折腰歛板三十載，晚登名籍黄金閨。", "緋衫裹束不料暖，况坐筦庫窮刀錐。", "古心古貎乃天與，雖欲嫵媚將安施。", "一朝拂袖不回顧，擇鄰問舍荆溪湄。", "人言家徒四壁立，如君四壁初無之。", "我知劉侯有至樂，視世五鼎同糠糜。", "分陰不博雙白璧，啜菽自作羔豚肥。", "有兒教飭知禮節，不以口耳傳書詩。", "應門侍坐走前後，翼翼想見名家規。", "天恩優老命之仕，俾繼祿食安其私。", "古人未必兼有此，篤行知足如君稀。", "聖皇側席思厚俗，詔取八行登前龜。", "向來蒲輪走四海，有賢如此誰當知。", "冥鴻一舉不可挽，道路仰首空嗟咨。"]'),
('e2945dab-771f-4f79-a920-814116ec5b08','題蒋永仲蜀道圖','程俱','宋','宋诗','song-poetry','','[]','梓州别駕真雛鳯，賞古探奇坐饑凍。',272,'全唐诗/poet.song.82000.json','["梓州别駕真雛鳯，賞古探奇坐饑凍。", "要窺瓊苑蔚藍天，直上潼江歷秦宋。", "每逢佳處靜盤礴，流出胸中九雲夢。", "乾坤坱圠本無迹，我獨毫端發神用。", "戲驅萬變寄陶寫，軒豁端倪巧摶控。", "蒼筠擢秀飽冰雪，古幹撐空中梁棟。", "奇礓那得在山谷，回首何年委堅重。", "輪囷偃蓋屈金鐵，夭矯驚虬起巖洞。", "舂江莽蒼迷東西，漢南老柳參差垂。", "煙中遠近見本末，明星已沒城烏啼。", "平生險怪三峽水，古木巃嵸陰風吹。", "石間雷雹殷九地，出入噴薄無窮時。", "我身趼足半天下，偃蹇故是山林姿。", "南行灊霍北嵩洛，應接不暇空狂癡。", "作詩寫意如捕景，况有三絕窮天機。", "清晨對此怳自失，眼中太白横峨嵋。", "請君十襲秘緹革，恐復仙去歸無期。"]'),
('d6a5da51-9cbe-4c9b-9550-4e12e898e131','寄開化李令光四首  其一','程俱','宋','宋诗','song-poetry','','[]','我行阡陌間，苗麥已復青。',84,'全唐诗/poet.song.82000.json','["我行阡陌間，苗麥已復青。", "茅茨間新槀，鷄犬有和聲。", "不見吏索錢，田家得其生。", "鷄犬亦肥字，不遭無事烹。", "於斯可觀政，豈在赫赫名。", "父老亦相語，驩然就春耕。", "官租及時了，卒歲樂無營。"]'),
('ab3cb793-476b-46fe-802f-3ab239330de6','寄開化李令光四首  其二','程俱','宋','宋诗','song-poetry','','[]','李侯諸生秀，峨冠論玄虚。',72,'全唐诗/poet.song.82000.json','["李侯諸生秀，峨冠論玄虚。", "安知俗吏事，小試已可書。", "厪心究人瘼，要使安田廬。", "慨然有奇趣，耿耿非世儒。", "乃知百里間，亦足寄所攄。", "誰當索幽隱，置彼九達衢。"]'),
('8c437bfd-c3d7-4133-87ce-a70c1ba9fe51','寄開化李令光四首  其三','程俱','宋','宋诗','song-poetry','','[]','山間古梅林，有鴞集其端。',96,'全唐诗/poet.song.82000.json','["山間古梅林，有鴞集其端。", "不飛亦不鳴，彈射莫敢干。", "下窺羣雀雛，啄顙刳其肝。", "欣然舐兩爪，意得良自安。", "飛來多凡鳥，助此凶且殘。", "安知萬山曲，亦復鳴棲鸞。", "相咻固不可，見嚇技亦殫。", "衆鳥既有恃，相斯在歲寒。"]'),
('7108250b-d4e0-47a4-9476-070ecb8ead7a','寄開化李令光四首  其四','程俱','宋','宋诗','song-poetry','','[]','平生四方人，墮地隨蓬桑。',96,'全唐诗/poet.song.82000.json','["平生四方人，墮地隨蓬桑。", "故鄉二頃田，稊米寄太倉。", "從渠雀鼠耗，敢計松菊荒。", "未能思計然，錐刀折氂芒。", "十年乃一歸，歸席不煖牀。", "吾廬正如寄，縣府固相忘。", "偶聞賢長官，邂逅尉所望。", "吾寧媚之子，故是衆所臧。"]'),
('5b84bf34-32af-4ff0-843b-8f7d3d8f7c1b','同叔問諸人以橘栗柿蔗爲題以東南之美爲韻余得橘美字韻一首','程俱','宋','宋诗','song-poetry','','[]','三閭老沈湘，嘉頌誰爲美。',108,'全唐诗/poet.song.82000.json','["三閭老沈湘，嘉頌誰爲美。", "白華發幽馨，春色薦甘醴。", "金衣光出懷，縹實酸裂齒。", "豈無三百苞，未見十二子。", "緬懷商山翁，善幻亦徒耳。", "壺中何足道，千刹一毫比。", "我今老而窮，饘粥思乞米。", "恨無千頭奴，杼柚供萬指。", "慇懃祝移根，勿作江北枳。"]'),
('8ac34d59-2d85-4809-8b61-41dbdef94382','仲嘉分題得詩分韻得經字是日仲嘉以事先歸代作一首','程俱','宋','宋诗','song-poetry','','[]','六義岀秦火，至今如日星。',84,'全唐诗/poet.song.82000.json','["六義岀秦火，至今如日星。", "人言三百篇，聖手昔所經。", "我疑東家丘，削迹不自懲。", "羈臣與孽子，中有怨刺情。", "胡爲不删去，被彼絃歌聲。", "遂令甫白輩，不識至道精。", "昔爲人所重，今爲時所輕。"]'),
('22d4d174-095f-4d85-96fc-7d18b2d4dad1','建除一首酬林德祖虙','程俱','宋','宋诗','song-poetry','','[]','建旟撫方面，簪筆登雲衢。',144,'全唐诗/poet.song.82000.json','["建旟撫方面，簪筆登雲衢。", "除書無虚日，念子何躊躇。", "滿堂羅經史，問字無停車。", "平明戶外屨，接迹叩所需。", "定坐爲詳說，從周述唐虞。", "執經退食罷，貝梵頗卷舒。", "破魔無堅壘，解髻皆明珠。", "危絃寡知音，寂寞空居諸。", "成詩遠相寄，尺鯉來東吳。", "收之巾十襲，永好不可渝。", "開緘歎奇决，已作東歸圖。", "閉蕃着空舍，誰辨公車書。"]'),
('0f4f431f-814c-4a0f-8d1f-dbaedf209db9','仲嘉被檄來吳按吏用非所長既足嘆息而或者妄相窺議益足笑云戲作十二辰歌一首','程俱','宋','宋诗','song-poetry','','[]','驅驥搏鼠難爲功，不如置之牛皂中。',96,'全唐诗/poet.song.82000.json','["驅驥搏鼠難爲功，不如置之牛皂中。", "平生暴虎笑馮婦，豈向兔脚分雌雄。", "龍山從事盛德士，達觀已悟蛇憐風。", "馬曹五斗直如寄，羊仲三徑終當同。", "羣猴憎猿坐殊趣，甕中醯鷄無遠度。", "從渠狗曲誚王生，欲辨龍猪復誰語。"]'),
('0bd45aa6-496a-4101-b468-f402d52a4414','聞仲嘉叔問繼以職事行縣道遊茶山及諸勝境作寄一首','程俱','宋','宋诗','song-poetry','','[]','春風入山骨，毛甲亦已舒。',288,'全唐诗/poet.song.82000.json','["春風入山骨，毛甲亦已舒。", "晨熹被春山，草木清而姝。", "况乃顧渚源，雲關護靈區。", "陰崖氣亦暖，瑞草先春敷。", "金沙出清泉，甘冽滋芳腴。", "依依楊柳村，渺渺桑苧居。", "前瞻大小寒，窈窕窮崎嶇。", "飛流吐明月，轉壑千雷車。", "參天亡陳檜，霜黛鬰不枯。", "當時臨春地，變滅成榛蕪。", "安知歲寒質，千載獨不渝。", "大中乾元字，入木蛟鸞俱。", "薰風想佳句，奇蹤典刑餘。", "獨往三住翁，至今有遺墟。", "真游豈易遇，庶或聞沉榆。", "飽聞東吳勝，欲往世累拘。", "二子獨幽討，仙舟繼籃輿。", "林間伯勞飛，茶篚春事初。", "尚有北枝秀，明空雪千株。", "幽香發清夜，肝膽生冰壺。", "王事既料理，清游亦忘劬。", "遙知山水間，快若縱壑魚。", "今我方祿隱，居然卧蝸廬。", "畫墁固無役，反如著轅駒。"]'),
('67156488-301c-40a6-a358-5c037eed41eb','園居荒蕪春至草生日尋野蔬以供匕筯今日枯枿間得蒸菌四五亦取食之自笑窮甚戲作此詩一首','程俱','宋','宋诗','song-poetry','','[]','平生囁嚅口，出語無媚悅。',288,'全唐诗/poet.song.82000.json','["平生囁嚅口，出語無媚悅。", "定非肉食姿，賦分在藜蕨。", "僑居得空園，窮陋亦清絕。", "分陰豈不惜，飽睡送日月。", "蕪菁不須種，衆草今已茁。", "朝來一雨過，青細皆可掇。", "東籬有更生，杞狗僅堪捋。", "乃知天隨生，豈羡五鼎列。", "堂萱不吾負，芽甲破春雪。", "縻身薦瓢簞，解我憂思結。", "薺花雖未繁，着地爛於纈。", "驚雷發蒸菌，自可當夏鼈。", "馬蘭亦芳脆，人莧固凡劣。", "晴朝當炙背，俯僂事挑抉。", "家人各盈襜，汲井手自挈。", "滿炊太倉陳，侑以冬菹冽。", "盤中長闌干，置饋每虚撤。", "恨無籜龍苞，此味那得闕。", "長謠青青槐，饞液想庭樾。", "妻孥覆相誚，男子志勳烈。", "君非老浮圖，菜本可長齧。", "况兹閑草木，豈爲刀匕設。", "乃翁笑摩腹，萬事付一吷。", "此中有真趣，勿爲兒輩說。"]'),
('0dcd9335-1c58-486a-b398-2af6816f5b66','同趙叔問江仲嘉遊法華之勝爲曲水會有客先焉還飲舟中分韻賦詩得山字一首','程俱','宋','宋诗','song-poetry','','[]','乖龍忽起華陽天，東來御雨鳴空山。',160,'全唐诗/poet.song.82000.json','["乖龍忽起華陽天，東來御雨鳴空山。", "豐隆轟空光照地，怒髯抉石翻雲煙。", "蜿蜒遺跡尚如昨，勢若九曲來河源。", "紛紛火齊散林莽，至今璀璨青霞端。", "我來夏木正森寂，萬籜篵篵抽琅玕。", "冰渠逗玉轉清淺，爽氣五月生秋寒。", "安知引勝獨無處，雙鳬徑度飛帆前。", "強尋幽逕俯東澗，一笑却棹稽山船。", "如聞神物家近岫，雪色千丈明山川。", "誰能遺我太平酒，戲追玉斧希林巔。"]'),
('ae041200-8398-49b8-b864-f7e5a30060bb','同江仲嘉納凉飛英寺','程俱','宋','宋诗','song-poetry','','[]','浮圖湧平地，翳彼燒空雲。',240,'全唐诗/poet.song.82000.json','["浮圖湧平地，翳彼燒空雲。", "虚堂引脩廊，白晝來清薰。", "翛然據胡床，振我衣上塵。", "芙渠出金沙，氣作芝蘭芬。", "冉冉度池閣，依依著裾巾。", "道人拂朱絃，攫醳清且純。", "回觀笙篁耳，寡和非陽春。", "步屧中幽討，禪房逕疏筠。", "幽窗不見日，無異昔所聞。", "蒼然小山桂，偃蹇冰雪根。", "紛紛壁間題，蛇蚓雜鳯麟。", "媸妍等一戲，日月無停輪。", "我老厭羈旅，三年困歊氛。", "年年走長道，東越西遊秦。", "白汗信揮雨，孤蓬坐如焚。", "今年下苕霅，過此金蘭人。", "何山豈不好，積翠相依因。", "炎威不相貸，可望不可親。", "須君蠟雙屐，重來約秋旻。", "兹遊亦蕭爽，聊足慰吾懃。"]'),
('158fe708-4d63-4168-ac4d-a8dbb54cf792','九月七日夜夢王元規詰旦其弟元矩適相訪感而作詩一首','程俱','宋','宋诗','song-poetry','','[]','故人入幽夢，彷彿平生懷。',96,'全唐诗/poet.song.82000.json','["故人入幽夢，彷彿平生懷。", "心知九泉隔，意象慘不開。", "哦詩不成章，惝怳誰能裁。", "曰此蕭爽士，寧當沒黄埃。", "清晨客在門，乃自烏衣來。", "典刑見難弟，共歎一息乖。", "幽明不可詰，此夢何爲哉。", "回觀南園道，微徑已蒿萊。"]'),
('3b4040b4-75fd-45c2-8dd7-d922d6c96c53','南窗夜集叔問戲取樟木腦然雪爲燈因與仲嘉叔問聯句一首','程俱','宋','宋诗','song-poetry','','[]','性空本無方，水火不留礙。',156,'全唐诗/poet.song.82000.json','["性空本無方，水火不留礙。", "陽生至陰中，此理固有在。", "初疑水焚槐，忽若鏡加艾。", "又如大海中，神龍出光怪。", "冰姿映烈焰，勢恐不兩大。", "原燎正焮騰，湯沃忽崩敗。", "涓涓煖泉湧，熠熠寒光碎。", "偉哉六合間，恢詭不勝載。", "陰風結飛雨，來自九天外。", "蒼樟出芳液，根節依大塊。", "初非氣相求，又豈天所配。", "如何冰炭仇，乃作坎離會。", "因知造化機，幻手端可貸。"]'),
('b7d78879-5b98-4d54-af16-0fad14f8baa6','九日塊坐無聊越州使君季野舍人見過敝廬會方回承議亦至因遊章公山林登覽甚適越州置酒暮夜乃歸作詩一首','程俱','宋','宋诗','song-poetry','','[]','獨坐正搔首，華軒款柴荆。',240,'全唐诗/poet.song.82000.json','["獨坐正搔首，華軒款柴荆。", "念兹節物佳，及此久雨晴。", "駕言共幽討，一放遠目明。", "森蒼蛾眉山，上有百尺亭。", "遙岑出西南，杳藹川原平。", "城中十萬家，煙雲隱飛甍。", "凉秋得遐觀，始覺天地清。", "朱欄據木末，開筵敞南榮。", "持觴屢相屬，泛彼東籬英。", "不知日云暮，初月忽已升。", "秋娥亦徘徊，流光代華燈。", "風流龍山集，坐見千古情。", "慷慨相顧言，曜靈急飛騰。", "人生無根蒂，聚散不可憑。", "懸知明年會，相望若初星。", "公如洪都宴，傑閣依青冥。", "儻有英妙客，摛文煥丹青。", "我如斜山翁，浪愛九日名。", "幽憂不能寫，濁酒或自傾。", "會與鑑湖老，兹山聊復登。"]'),
('6726af84-51bc-4b2d-9993-a1ad8b407223','夜宿丞舍即事呈蒋大匠存誠蘇少監元老  其一','程俱','宋','宋诗','song-poetry','','[]','羣動夜方息，啾啾草間鳴。',60,'全唐诗/poet.song.82000.json','["羣動夜方息，啾啾草間鳴。", "殘炎未云謝，遽作凉秋聲。", "秋風來幾時，朝暮氣已清。", "虛窗置方榻，境寂身暫輕。", "卧念平生懷，展轉不得寧。"]'),
('afcbc9dd-a582-4523-9f1e-fb0cfbe434f5','夜宿丞舍即事呈蒋大匠存誠蘇少監元老  其二','程俱','宋','宋诗','song-poetry','','[]','王生一言善，從容水衡丞。',72,'全唐诗/poet.song.82000.json','["王生一言善，從容水衡丞。", "無功樂佳釀，能令濁流清。", "顧我老且奇，微官代躬耕。", "正當急跨馬，問訊桷與楹。", "觀公成風手，一引朱絲繩。", "簡書可少置，頗哀此無能。"]'),
('4517acc5-6d31-4db1-98c5-8e8f9b88fff6','和同舍胡元茂松年夜直書懷  其一','程俱','宋','宋诗','song-poetry','','[]','南枝掛明月，羈羽無安眠。',72,'全唐诗/poet.song.82000.json','["南枝掛明月，羈羽無安眠。", "天寒倚脩竹，窈窕誰當看。", "平生飽幽獨，古井不復瀾。", "一來英俊中，夢寐猶林泉。", "夜直石渠閣，周廬别閑寛。", "恨無青藜杖，照此清夜寒。"]'),
('4cd0360b-e10c-40a2-8eaa-f3fc2618721f','和同舍胡元茂松年夜直書懷  其二','程俱','宋','宋诗','song-poetry','','[]','腐儒足嘲病，志願餐與眠。',72,'全唐诗/poet.song.82000.json','["腐儒足嘲病，志願餐與眠。", "潭潭右文地，不作侏儒看。", "翬飛接觚稜，碧瓦如澄瀾。", "儻使論白虎，寧當賦甘泉。", "人間未見書，縱目宇宙寛。", "顧語芝蘭友，勿嫌松桂寒。"]'),
('0816fcea-92db-43b8-8f1e-dfb28d464f89','趙叔問過别留夜話偶閱鮑溶詩有感用韻作','程俱','宋','宋诗','song-poetry','','[]','磨蟻不停足，故交益無多。',96,'全唐诗/poet.song.82000.json','["磨蟻不停足，故交益無多。", "向來苕谿夢，但有高軒過。", "昂昂芝田態，長饑玉山禾。", "顧我老且窮，吹毛從鳥窠。", "何當寂寞濱，紉蘭共捫蘿。", "非無煙霞志，奈此饑凍何。", "言離更躊躇，參横照斜河。", "爲公睇金臺，慷慨徒悲歌。"]'),
('c72010f2-0990-4bf6-9d88-92d59e2f4b57','方時敏見和再作屬時敏','程俱','宋','宋诗','song-poetry','','[]','世上窘邊幅，如公患才多。',96,'全唐诗/poet.song.82000.json','["世上窘邊幅，如公患才多。", "欲方曹劉駕，似恐不啻過。", "居然東吳瑞，豈但異畝禾。", "試令南宫直，文采照錦窠。", "華髪乃未遇，高花繞青蘿。", "千載鳶肩生，低頭客常何。", "一朝風雲上，顧豈求監河。", "勉旃安固窮，聊復曳屣歌。"]'),
('457615da-40ff-41ab-89f3-cdc2f57ee8a1','得小圃城南用淵明歸田園居韻六首  其一','程俱','宋','宋诗','song-poetry','','[]','城南美林壑，城上皆青山。',108,'全唐诗/poet.song.82000.json','["城南美林壑，城上皆青山。", "山光照庭戶，於此可盡年。", "穰穰千古區，化作魚蒲淵。", "秋蕖渺無際，紅鮮間田田。", "邂逅得小隱，連山在其前。", "流泉带其左，松篁接風煙。", "它年營把茅，不待雪滿顛。", "寧圖五鼎食，坐失十載閑。", "願比小人腹，一餐期果然。"]'),
('4fdad024-b7f7-4b6d-9f25-c2415321b74e','得小圃城南用淵明歸田園居韻六首  其二','程俱','宋','宋诗','song-poetry','','[]','說難死韓非，法蔽嘆商鞅。',72,'全唐诗/poet.song.82000.json','["說難死韓非，法蔽嘆商鞅。", "當時軒冕計，肯作刀鋸想。", "辰來陰影集，事過流電往。", "胡爲意無窮，機械日爭長。", "俗中多局促，正覺斯道廣。", "斯道不可迷，荒塗闢榛莽。"]'),
('37bdde73-b5f9-449e-9911-ebdd27fc16b9','得小圃城南用淵明歸田園居韻六首  其三','程俱','宋','宋诗','song-poetry','','[]','年大百無味，區中故人稀。',48,'全唐诗/poet.song.82000.json','["年大百無味，區中故人稀。", "京江一都會，卜築行當歸。", "儻回故人車，雲關訪荷衣。", "時來吐情話，未覺世相違。"]'),
('f28e07c0-f6b7-4b97-905d-f2277cd49938','得小圃城南用淵明歸田園居韻六首  其四','程俱','宋','宋诗','song-poetry','','[]','餘生甚窮獨，四海誰與娛。',96,'全唐诗/poet.song.82000.json','["餘生甚窮獨，四海誰與娛。", "故鄉道脩阻，宛在太末墟。", "向來親仁意，正擬城南居。", "烏衣丈人行，玉樹珊瑚株。", "所冀鄰里間，徜徉從所如。", "如何漳濱卧，使我恨有餘。", "會當悟杯蛇，靈府靜以虚。", "且復陪杖屨，敢言通有無。"]'),
('c2a89269-947f-4bf8-8592-7cf36b90b66e','得小圃城南用淵明歸田園居韻六首  其五','程俱','宋','宋诗','song-poetry','','[]','緬懷斜川人，勝日追鄰曲。',48,'全唐诗/poet.song.82000.json','["緬懷斜川人，勝日追鄰曲。", "超然睇層丘，鷄黍聊自足。", "却觀夸奪子，勝負一棋局。", "空懷千歲憂，晝短思秉燭。"]'),
('440113f8-0f1d-4136-b786-f3516c7f9daa','得小圃城南用淵明歸田園居韻六首  其六','程俱','宋','宋诗','song-poetry','','[]','長安冠蓋區，九軌三廣陌。',84,'全唐诗/poet.song.82000.json','["長安冠蓋區，九軌三廣陌。", "不知烏帽底，誰獨適吾適。", "定無羊求子，相與數晨夕。", "莫言三徑微，永杜聲利隙。", "流風有仍孫，心不受形役。", "朱門見蓬戶，華榜標世績。", "二仲倘可睎，忘年賴謙益。"]'),
('1343519a-08e1-4883-8c52-9010e41d0bd5','偶書二首  其一','程俱','宋','宋诗','song-poetry','','[]','我身如甘柘，既壓無復味。',60,'全唐诗/poet.song.82000.json','["我身如甘柘，既壓無復味。", "一爲老所壓，乃與枯柘類。", "岀家既後時，止觀若昏睡。", "唯於讀誦中，味出甘柘外。", "不作算沙人，依語不依義。"]'),
('a4b70eb8-7578-4405-9776-531d172ba9bf','偶書二首  其二','程俱','宋','宋诗','song-poetry','','[]','壯膏日已减，老炷安得久。',60,'全唐诗/poet.song.82000.json','["壯膏日已减，老炷安得久。", "亦如臨河樹，岸墊根復朽。", "久生安足羡，捄死常饑走。", "誰言黄老師，語異竺乾叟。", "生死未嘗關，知爲不亡壽。"]'),
('638b7594-b71d-4dba-ba86-44e6f92b0255','感春三首用退之韻  其一','程俱','宋','宋诗','song-poetry','','[]','春物感兵氣，微陽有無間。',60,'全唐诗/poet.song.82000.json','["春物感兵氣，微陽有無間。", "遙天覆長路，仰視青漫漫。", "歸來如新燕，巢土初未乾。", "投迹浪自喜，乘和亦翩翩。", "安得出八極，舉身青霞端。"]'),
('6e092575-0d45-46b8-b3ff-6d1256a448d7','感春三首用退之韻  其二','程俱','宋','宋诗','song-poetry','','[]','今晨風日佳，積潦亦已退。',72,'全唐诗/poet.song.82000.json','["今晨風日佳，積潦亦已退。", "安能如寒龜，自縶形骸內。", "春風入桃臉，巧笑已無賴。", "誰云五畝園，浩蕩了無外。", "流年不可攀，短髪久已白。", "星星亦種種，那復三萬尺。"]'),
('210cbdb3-88ad-4915-bdd0-1c707eaf8cae','感春三首用退之韻  其三','程俱','宋','宋诗','song-poetry','','[]','春光浩無邊，淡沲周八極。',60,'全唐诗/poet.song.82000.json','["春光浩無邊，淡沲周八極。", "向來遊樂地，鼙鼓森矛戟。", "賤貧非所嘆，稅駕無安席。", "常虞風濤際，咫尺燕越隔。", "却笑同谷翁，哀歌諒何益。"]'),
('1c5ebfa4-8fe3-48b9-8130-042ce56af2a2','和柳子厚詩十七首 覺哀','程俱','宋','宋诗','song-poetry','','[]','老境一如此，羲娥日交侵。',132,'全唐诗/poet.song.82000.json','["老境一如此，羲娥日交侵。", "霜毛三千丈，安問尺與尋。", "陳力會知止，嘉言佩周任。", "歸來北山北，邂逅得素心。", "朝見東日昇，暮見西日沉。", "流運有終古，朱顔豈常今。", "譬之如澠酒，豈耐無停斟。", "萬化未有極，誰能惜分陰。", "捕影良自苦，沈哀寄微吟。", "安知菩提樹，正在生死林。", "長風振遙壑，三籟有餘音。"]'),
('c30ac6a0-73df-43d7-ae74-0130efc2f917','和柳子厚詩十七首 同趙叔問涉澗伐荒蘙得大石壁立喬木蒼然上蔽雲日因平築尋丈地時憩其下','程俱','宋','宋诗','song-poetry','','[]','披榛亦捫蘿，度此幽澗曲。',48,'全唐诗/poet.song.82000.json','["披榛亦捫蘿，度此幽澗曲。", "寒藤繞蒼壁，杉桂雜篁竹。", "雲泉固膏肓，大勝谿壑欲。", "彼哉機士懷，冰炭甚寒燠。"]'),
('29ea3c11-d9d1-48a7-9ab1-c07073568959','和柳子厚詩十七首 曉起','程俱','宋','宋诗','song-poetry','','[]','勞生垢濁中，長夜不知曉。',36,'全唐诗/poet.song.82000.json','["勞生垢濁中，長夜不知曉。", "幽人自超然，下視正膠擾。", "中冠及鷄晨，夢覺常了了。"]'),
('0ee85bac-7f3b-47ac-9e88-ce78759c4287','和柳子厚詩十七首 趙叔問被召赴行在','程俱','宋','宋诗','song-poetry','','[]','登車大梁下，掃迹金川湄。',96,'全唐诗/poet.song.82000.json','["登車大梁下，掃迹金川湄。", "佳人倚脩竹，鉛華爲誰施。", "滔滔大塊間，一一窮途悲。", "今晨尺一書，趣駕當及時。", "磐石久不固，慇懃濟時危。", "豺狼尚縱横，蔓草恐復滋。", "當宁正嘗膽，諸公力猷爲。", "老子意不淺，長哦江漢詩。"]'),
('4ac9b88e-3a0c-4d5b-951f-4556bc9a42b7','和柳子厚詩十七首 示從父弟偉','程俱','宋','宋诗','song-poetry','','[]','汝年近知非，我老過艾服。',84,'全唐诗/poet.song.82000.json','["汝年近知非，我老過艾服。", "向來萬金書，一紙百過讀。", "安知復一處，林壑時追逐。", "茅茨稍經營，秔稌今已熟。", "壺觴悅情語，步屧三徑竹。", "安能捨冰墟，蟣虱弔湯沐。", "相期戢良規，不辱在知足。"]'),
('7060ddf9-3abd-4236-a694-e3d154dc584d','和柳子厚詩十七首 早凉過西塢','程俱','宋','宋诗','song-poetry','','[]','尋壑轉松嶺，雨餘秋氣清。',48,'全唐诗/poet.song.82000.json','["尋壑轉松嶺，雨餘秋氣清。", "時時捨籃輿，散策亦意行。", "石磴縈巃嵸，幽泉高下鳴。", "蒲團蔭嘉樹，兀坐已忘情。"]'),
('21fe4f54-5075-4003-b021-4f9f5c5af60e','和柳子厚詩十七首 卜築西塢','程俱','宋','宋诗','song-poetry','','[]','出處初漫浪，淹留失佳時。',96,'全唐诗/poet.song.82000.json','["出處初漫浪，淹留失佳時。", "時英盡珠璞，寧復見誰差。", "一去四十年，伏櫪久已疲。", "幸此歲將暮，穿雲弄清漪。", "窈窕煙塢中，蒼陰晝森垂。", "兹焉寄茅屋，横仄任所宜。", "谷口蘙杉竹，柴門畏人知。", "誰言一邱壑，儻與汗漫期。"]'),
('5d60f3ea-3676-4ddf-b248-e7d82a999c43','和柳子厚詩十七首 寫懷因簡趙叔問','程俱','宋','宋诗','song-poetry','','[]','胡塵暗中原，世路日以艱。',168,'全唐诗/poet.song.82000.json','["胡塵暗中原，世路日以艱。", "脱身九死中，自笑老且頑。", "才志本不競，拂衣謝塵寰。", "相從莫逆人，雲蘿共躋攀。", "固知千里駒，未免山復山。", "我已卜西谷，背崖結三間。", "豈無風篁嶺，亦有明月灣。", "平生真遠遊，舊觀忽以還。", "兒童釣遨處，陳迹猶班班。", "叠嶂藹空翠，暗泉響餘潺。", "采芝嵁巗下，長謠想商顔。", "逋客不復駕，居然掩雲關。", "從來悟泡影，豈但忘觸蠻。", "所幸戎馬際，餘生得長閑。"]'),
('bf42544f-4128-46a3-986c-ff78755ab3a2','和柳子厚詩十七首 終日塊坐無與晤言戲作','程俱','宋','宋诗','song-poetry','','[]','大音無成虧，寂然無瑕謫。',48,'全唐诗/poet.song.82000.json','["大音無成虧，寂然無瑕謫。", "莫嗟無往還，正自主忘客。", "談玄口挂壁，對鏡心似石。", "相向兩無言，秋山倚空碧。"]'),
('fa6cbaec-7284-4e5a-b4ed-9abc68262f8a','和柳子厚詩十七首 示了空長老','程俱','宋','宋诗','song-poetry','','[]','老空嗜酒肉，早歲事禪寂。',72,'全唐诗/poet.song.82000.json','["老空嗜酒肉，早歲事禪寂。", "歸來山中舍，杖屨不停跡。", "高門走縣薄，兩版扃四壁。", "醉來見閑卧，度此風雨夕。", "遙遙慧日峰，法涌分一滴。", "應笑北山人，藜羮比香積。"]'),
('6a7fa8e7-063e-42c0-ad76-3c0c4d813cc2','和柳子厚詩十七首 寄茭湖江仲長袤','程俱','宋','宋诗','song-poetry','','[]','急澗無止水，秋蘭無故叢。',96,'全唐诗/poet.song.82000.json','["急澗無止水，秋蘭無故叢。", "别來今幾年，坐閱毗嵐風。", "交親半鬼籙，生者仍衰窮。", "及兹過君家，樽酒一笑同。", "知我厭鼙鼓，煩君韻絲桐。", "相攜步林壑，暫覺萬慮空。", "樗社寄莊叟，醉鄉着無功。", "醒來百憂集，尚寐期無聦。"]'),
('8a0c19bb-be42-4b48-8064-5825f99b5bc6','和柳子厚詩十七首 天久不雨高田皆坼鄉人祈禱閱月乃雨遠近告足有足喜者','程俱','宋','宋诗','song-poetry','','[]','長夏久不雨，良田失欣榮。',108,'全唐诗/poet.song.82000.json','["長夏久不雨，良田失欣榮。", "塵生畎澮間，小大空營營。", "麻粟半乾死，所憂負春耕。", "嗷嗷走香火，靈湫汲寒清。", "梵唄喧里社，油雲被嘉生。", "俄然下甘澤，驩聲接柴荆。", "年年鎬京宴，及此萬寶成。", "偷生得一飽，感慨難爲情。", "顧念龍在野，悲歌淚縱横。"]'),
('61098e43-742a-4894-a8c9-fcb64374eb46','和柳子厚詩十七首 寄江彦文緯','程俱','宋','宋诗','song-poetry','','[]','往追雙玉人，芒屨踏巖谷。',48,'全唐诗/poet.song.82000.json','["往追雙玉人，芒屨踏巖谷。", "阿咸今獨往，宰上森拱木。", "公來定何時，舊唱猶能續。", "尋壑復穿雲，仙山看飛鹿。"]'),
('64621de0-b307-43ab-b0f8-d9e39c0feb1a','和柳子厚詩十七首 十二月二十三日大雪中種物','程俱','宋','宋诗','song-poetry','','[]','密雲彌四極，紛紛亂空華。',96,'全唐诗/poet.song.82000.json','["密雲彌四極，紛紛亂空華。", "斯須失千嶂，僵木忽以芽。", "眼中萬株春，璀璨通巖涯。", "迨此凡艷熄，坤輿凈無瑕。", "蒼根移遠梅，不惮澗谷遐。", "含冰伴幽獨，思慮無由邪。", "寶樹發銀界，無脩證三耶。", "皎皎天宇外，何勞凌絳霞。"]'),
('362bbf42-2d83-421c-af2b-09beb6194c93','和柳子厚詩十七首 野人致紫竹栽手植方丈後','程俱','宋','宋诗','song-poetry','','[]','名山昔遠遊，老罷無復覩。',108,'全唐诗/poet.song.82000.json','["名山昔遠遊，老罷無復覩。", "永懷避世士，往往寄農圃。", "移家白雲根，及此未春雨。", "桃梅足新栽，把玩喜欲舞。", "可無紫琅玕，葉作翠鳯羽。", "寵光松菊徑，蕭散煙霞聚。", "雌雄比嶰谷，顔色蓋南浦。", "龍鞭雖未行，玉茁亦已吐。", "咄嗟勿留情，萬物乃吾府。"]'),
('6205a2c0-f2e8-44fb-b4c9-3ca0eff68387','和柳子厚詩十七首 得白菌引酒徑醉','程俱','宋','宋诗','song-poetry','','[]','春霖接歲寒，鮭菜已久索。',48,'全唐诗/poet.song.82000.json','["春霖接歲寒，鮭菜已久索。", "誰持玉輪菌，侑我金鑿落。", "安知老瓦盆，平昔滋味薄。", "得此徑陶然，朱顔忽如昨。"]'),
('c7dae0e6-1bb6-4f6a-9342-a86dbfe03378','和柳子厚詩十七首 辛亥正月六日夜雷已發聲大雨達旦山中流泉高下噴薄殆不啻九十九不減仇池也','程俱','宋','宋诗','song-poetry','','[]','故歲聿其除，微陽已潛回。',108,'全唐诗/poet.song.82000.json','["故歲聿其除，微陽已潛回。", "始兹魚上冰，殷地驚春雷。", "急雨暗清夜，飛流散巖隈。", "遲明起四顧，玅境神所開。", "未信小有洞，蒼崖隔凡埃。", "琤淙十九泉，潄玉松風哀。", "褰裳喜欲狂，幽興不可裁。", "妙喜真斷取，呼猿定飛來。", "相與俯清駃，傳杯聊遡洄。"]'),
('52f89074-0b37-48a3-8cb9-798a89c48637','戲書古句題山居','程俱','宋','宋诗','song-poetry','','[]','青山秀色若可餐，卷書饑坐看南山。',64,'全唐诗/poet.song.82000.json','["青山秀色若可餐，卷書饑坐看南山。", "樂哉洋洋巖下水，可以樂饑仍洗耳。", "石田墝埆不敢荒，時耕带月歸带霜。", "田中不了麴蘖事，蝉腹且追張子房。"]'),
('ab0cbd78-3bf9-4fa8-86fa-1c40024bafce','五月二日同叔問過彌陀閣觀山中飛瀑','程俱','宋','宋诗','song-poetry','','[]','飛泉落青冥，掩冉振森木。',120,'全唐诗/poet.song.82000.json','["飛泉落青冥，掩冉振森木。", "驚雷殷厚地，噴薄轉空谷。", "崩湍爭喧豗，潄此千丈玉。", "洶如秦軍破，勢比不周觸。", "初疑三峽移，無乃九井蹙。", "雲中阿蘭若，峻嶺鏁重麓。", "悽寒絕人境，共此媚幽獨。", "長饑不難忍，洗耳謝羈束。", "君方應時須，我已甘脫粟。", "正恐山不深，從今友麋鹿。"]'),
('adcaed10-f04b-4a03-a9eb-d2358f810d85','戲題錢守宋漢傑泉巖古刹','程俱','宋','宋诗','song-poetry','','[]','廣文斗酒邀同襟，胸中嵩衡鬰千尋。',144,'全唐诗/poet.song.82000.json','["廣文斗酒邀同襟，胸中嵩衡鬰千尋。", "醉來盤礴吐幽怪，慘澹崖谷森相臨。", "向來三絕信珠璧，肯用抵鵲荆山岑。", "詩中有畫畫中句，兩峰高並藍田陰。", "祇應摩詰可方駕，老向海角嗟英沉。", "何人左手作右字，題此古刹藏煙林。", "不知眼力尚能爾，疊嶂巃嵸窮幽深。", "使君家世舊湖海，戲假尺素資謳吟。", "更登日觀望八極，中有山水無窮音。"]'),
('2f1dba18-d234-449f-9bb2-1d5f8bdee75f','某前日謁見國史侍讀尚書獲款燕談蒙出示周楊子書報許藏山中得巖壑之勝過冷泉亭者歎想不已俾某賦詩退成七言古句一首上呈','程俱','宋','宋诗','song-poetry','','[]','素王之宫行秘府，斷取瀛州納環堵。',320,'全唐诗/poet.song.82000.json','["素王之宫行秘府，斷取瀛州納環堵。", "諸儒何必四庫書，正自胸中有千古。", "野人上車纔不落，索米無庸面如鼓。", "歸來仰屋坐太息，咄咄書空欲誰語。", "石林居士今龍坂，憂國形臞心獨苦。", "向來豈止見夷吾，叩閣何由避寒暑。", "伯仁三日應可爾，頓解新亭對悽楚。", "坐中人傳雙尺素，思洛橋南霅溪渚。", "山回壤接二百里，許藏幽奇天所與。", "人間那得此巖壑，坐想周郎喜而舞。", "蒼崖壁立欲千仞，蔽日青林自風雨。", "信知靈境不待匠，古澗穿巖巧吞吐。", "慇懃留此萬里流，更覺山川生媚嫵。", "了觀澄湛本非住，却覓喧豗無處所。", "手誅陰木結茅屋，掀抉高深期盡取。", "四山擢翠若無地，三石撐空裊相柱。", "書詞豈夸驚我甚，下視呼猨觸天姥。", "卞峰勝絕固自足，莫爲東山思解組。", "龍驤雲起要侯王，鶴唳風聲走夷虜。", "會令藿食保安眠，北固山南事幽圃。"]'),
('5bf004b9-1183-4eb7-a1fc-a7e3096fa3f5','山居 勝林堂','程俱','宋','宋诗','song-poetry','','[]','超然出稠林，無二無分别。',24,'全唐诗/poet.song.82000.json','["超然出稠林，無二無分别。", "若問勝林堂，清風滿庭樾。"]'),
('ee4820cb-b84a-4d07-8f9d-3c7ef1a86153','山居 妙高堂','程俱','宋','宋诗','song-poetry','','[]','君知妙高堂，何異妙峰境。',24,'全唐诗/poet.song.82000.json','["君知妙高堂，何異妙峰境。", "向來妙高人，宛在妙峰頂。"]'),
('f6f3e87e-94cb-4850-b8cb-1842550aa81e','山居 常寂光庵','程俱','宋','宋诗','song-poetry','','[]','云何常寂光，徧在一切處。',24,'全唐诗/poet.song.82000.json','["云何常寂光，徧在一切處。", "元本住庵人，無來亦無去。"]'),
('8600cd80-8380-411e-bf20-8a10ad955ce2','山居 無垢池','程俱','宋','宋诗','song-poetry','','[]','滃然集清冷，無厭亦無受。',24,'全唐诗/poet.song.82000.json','["滃然集清冷，無厭亦無受。", "故此巖下池，予名曰無垢。"]'),
('57fb5ab1-b571-42df-833c-09f4f359e42b','山居 普潤池','程俱','宋','宋诗','song-poetry','','[]','疊翠繞幽谷，清池鍾百泉。',24,'全唐诗/poet.song.82000.json','["疊翠繞幽谷，清池鍾百泉。", "安知一壑雲，利澤浸無邊。"]'),
('f3c94166-81b2-4595-901c-fe2b62213be6','山居 妙湛池','程俱','宋','宋诗','song-poetry','','[]','妙華出淤泥，定水湛然滿。',24,'全唐诗/poet.song.82000.json','["妙華出淤泥，定水湛然滿。", "上有清凉峰，森蒼映清淺。"]'),
('00b322c2-ccdb-4d3a-b32f-52849f2df63d','山居 寂照堂','程俱','宋','宋诗','song-poetry','','[]','古鏡懸大虚，摩尼珠五色。',24,'全唐诗/poet.song.82000.json','["古鏡懸大虚，摩尼珠五色。", "紛然百草頭，寂照照常寂。"]'),
('8c122f4d-1fb0-4fc7-8626-996cc76065af','山居 定林','程俱','宋','宋诗','song-poetry','','[]','定林在何許，窈窕鍾山麓。',24,'全唐诗/poet.song.82000.json','["定林在何許，窈窕鍾山麓。", "得非夸娥民，遺我障巖谷。"]'),
('c6b0f6cf-3e72-4da6-abec-ad97f6673c19','山居 盤谷','程俱','宋','宋诗','song-poetry','','[]','重重翠聯錦，一掩一回處。',24,'全唐诗/poet.song.82000.json','["重重翠聯錦，一掩一回處。", "三徑踏煙霞，披榛自來去。"]'),
('697050e1-4001-485a-bbf4-bc18bcf23f70','山居 谷口堂','程俱','宋','宋诗','song-poetry','','[]','子真巖石耕，名稱動都邑。',24,'全唐诗/poet.song.82000.json','["子真巖石耕，名稱動都邑。", "不比北山翁，銷聲寄禪寂。"]'),
('9566c5a7-6d00-4b35-a019-0401721e4490','山居 雲巢','程俱','宋','宋诗','song-poetry','','[]','朝見雲飛簷，暮見雲生礎。',24,'全唐诗/poet.song.82000.json','["朝見雲飛簷，暮見雲生礎。", "客至覓雲巢，雲深在何許。"]'),
('02447a52-6dd2-4270-8827-05ef34929f28','山居 競秀泉','程俱','宋','宋诗','song-poetry','','[]','千山秀回環，靈液走巖竇。',24,'全唐诗/poet.song.82000.json','["千山秀回環，靈液走巖竇。", "清甘佇方空，可嚥不可潄。"]'),
('215f1d2d-11d5-4ba3-94ca-4af99088978f','山居 繡谷亭','程俱','宋','宋诗','song-poetry','','[]','西山屬黄岡，相錯宛如繡。',24,'全唐诗/poet.song.82000.json','["西山屬黄岡，相錯宛如繡。", "倚杖立幽亭，歸鴻沒煙岫。"]'),
('bf58d3f0-8c37-468e-a796-600e63a9d397','山居 韜雲磴','程俱','宋','宋诗','song-poetry','','[]','陰陰韜雲徑，步步雲生足。',24,'全唐诗/poet.song.82000.json','["陰陰韜雲徑，步步雲生足。", "巾裾撲空翠，逶迤向山麓。"]'),
('12c8a788-de2e-4c36-a930-8f46c1e78a0a','山居 清音澗','程俱','宋','宋诗','song-poetry','','[]','潺湲清音澗，便是偃溪水。',24,'全唐诗/poet.song.82000.json','["潺湲清音澗，便是偃溪水。", "長笑箕穎人，區區洗吾耳。"]'),
('ba21f3f0-c9c8-4855-a035-3c7123d1c8a2','山居 虚緣靜','程俱','宋','宋诗','song-poetry','','[]','萬緣正繁興，當處即解脫。',24,'全唐诗/poet.song.82000.json','["萬緣正繁興，當處即解脫。", "當知本來空，不受汝摩撮。"]'),
('bce96c04-3ca5-475c-b141-3c2f75034256','山居 崇蘭塢','程俱','宋','宋诗','song-poetry','','[]','猗蘭轉光風，幽芳被山谷。',24,'全唐诗/poet.song.82000.json','["猗蘭轉光風，幽芳被山谷。", "悵望斷金人，同心不同躅。"]'),
('a04443a5-5146-4a2b-a428-7a8584a49d21','山居 梅谷','程俱','宋','宋诗','song-poetry','','[]','穠華敢爭先，獨立傲冰雪。',24,'全唐诗/poet.song.82000.json','["穠華敢爭先，獨立傲冰雪。", "故當首羣芳，香色兩奇絕。"]'),
('916bf0fd-6bbc-4455-b3f2-4a154a03cc11','山居 三休臺','程俱','宋','宋诗','song-poetry','','[]','三徑屬桃煙，遙遙想寧極。',24,'全唐诗/poet.song.82000.json','["三徑屬桃煙，遙遙想寧極。", "終當珮飛霞，頡頏向空碧。"]'),
('65fb9d29-ab6f-41e5-b567-42b8fb218ce1','山居 達觀堂','程俱','宋','宋诗','song-poetry','','[]','蒼陰羃杉松，延緣幽出谷。',24,'全唐诗/poet.song.82000.json','["蒼陰羃杉松，延緣幽出谷。", "豁然天地開，八極啟遠目。"]'),
('5dec8984-a2bb-412a-b3aa-07bb5b8ea8ee','山居 通幽徑','程俱','宋','宋诗','song-poetry','','[]','躋攀通幽徑，鬰密森松竹。',24,'全唐诗/poet.song.82000.json','["躋攀通幽徑，鬰密森松竹。", "雲雪正埋山，深林閟寒綠。"]'),
('a5e6f673-977f-417c-ad0f-38ac6850ffcd','山居 漆林','程俱','宋','宋诗','song-poetry','','[]','敬侯那易學，正自追農圃。',24,'全唐诗/poet.song.82000.json','["敬侯那易學，正自追農圃。", "平生老瓦盆，安用雕髹許。"]'),
('129b82ba-97c9-4d48-8143-3be019b4726d','山居 竹嶺','程俱','宋','宋诗','song-poetry','','[]','嘉名追輞川，未辨茱萸沜。',24,'全唐诗/poet.song.82000.json','["嘉名追輞川，未辨茱萸沜。", "勿使斤斧侵，煙梢拂雲漢。"]'),
('fdd53db3-dd35-424d-b4fe-39edf38a9d5d','山居 慧照峰','程俱','宋','宋诗','song-poetry','','[]','晹光出扶桑，照耀四天下。',24,'全唐诗/poet.song.82000.json','["晹光出扶桑，照耀四天下。", "慧日破無明，蒙光失長夜。"]'),
('ef44bc3e-300b-4c06-8675-37be69c1b6df','山居 清凉峰','程俱','宋','宋诗','song-poetry','','[]','峞峨古澗西，萬木集歸鳥。',24,'全唐诗/poet.song.82000.json','["峞峨古澗西，萬木集歸鳥。", "炎炎日流金，爲君除熱惱。"]'),
('ce5cf4f9-4971-4faa-ae3e-28996f456b54','山居 德雲庵','程俱','宋','宋诗','song-poetry','','[]','德雲老比丘，經行衆山頂。',24,'全唐诗/poet.song.82000.json','["德雲老比丘，經行衆山頂。", "普光明法門，觸自無二境。"]'),
('2c1d0fbd-1ca8-4592-94f5-b683574626f9','山居 法乳泉','程俱','宋','宋诗','song-poetry','','[]','山腰發靈滋，甘美勝牛乳。',24,'全唐诗/poet.song.82000.json','["山腰發靈滋，甘美勝牛乳。", "應持供茶神，慎勿汙烹煮。"]'),
('e291c85e-373b-40eb-b33a-39a4e747db15','山居 菊泉','程俱','宋','宋诗','song-poetry','','[]','一泓貯清泉，百本蓊佳菊。',24,'全唐诗/poet.song.82000.json','["一泓貯清泉，百本蓊佳菊。", "長年汲芳甘，霜鬢倘重綠。"]'),
('533e810e-5457-47ec-a83d-5dd9aefd81fd','山居 羃翠軒','程俱','宋','宋诗','song-poetry','','[]','開軒面杉竹，冷翠搖清空。',24,'全唐诗/poet.song.82000.json','["開軒面杉竹，冷翠搖清空。", "披衣水邊石，長夏來薰風。"]'),
('e6633cae-8ae6-4447-8c98-72f64eb37dac','歙溪硯','程俱','宋','宋诗','song-poetry','','[]','硯鳯池，石龍尾，金其聲，玉其理，文字之祥助公喜。',120,'全唐诗/poet.song.82000.json','["硯鳯池，石龍尾，金其聲，玉其理，文字之祥助公喜。", "助公喜，爲公壽，籋雲衢兮龍爲友。", "儀簫韶兮鳴鳯咮，金玉相兮椒蘭臭。", "老復丁兮昃還晝，壽而臧兮世無有。", "生彌長兮視彌久，見太平兮休戰鬬。", "泳學海兮恢文囿，俯松喬兮齒倉籀。", "翰林客卿管城偶，揮毫振藻常無咎。"]'),
('cd1c294a-86a4-4edf-88df-d28e50d5e704','春日與汪彦章藻趙叔問相約遊樟林閣樟林閣蓋郡豪冢舍背城郊墟無與比者因詠靖節感彼柏下人安得不爲歡之句偶書五言呈同遊二公','程俱','宋','宋诗','song-poetry','','[]','人生歸有盡，大齊不踰百。',156,'全唐诗/poet.song.82000.json','["人生歸有盡，大齊不踰百。", "君看花間冢，背郭高歷歷。", "向來夸奪志，汗漫何窮極。", "一朝隨露電，變滅無餘迹。", "所以靖節翁，壺觴樂晨夕。", "寧爲鬰澗松，不作移根栢。", "豈惟一窮通，固自忘夷跖。", "吾生亦崎嶇，末路苦荆棘。", "投閑得蕭散，身病頭更白。", "豈無素心人，相與弄泉石。", "及晨爲兹遊，聊用適吾適。", "溪山景無盡，秀色光照席。", "安能仰屋歎，抱恨長戚戚。"]'),
('9632935c-9638-4797-a06f-76aa48f39ae9','晨起梳頭髪白且稀有感','程俱','宋','宋诗','song-poetry','','[]','余髪已種種，我懷亦依依。',288,'全唐诗/poet.song.82000.json','["余髪已種種，我懷亦依依。", "風林無安巢，寒日無餘輝。", "束髪隨官牒，前言服良規。", "豈惟會計當，自詭牛羊肥。", "妄獻北闕書，野芹安足希。", "一挂邪士籍，徒嗟寸誠微。", "惓惓畎畝志，正作禍患機。", "羈危不如人，行行向知非。", "世變不可料，胡塵暗王畿。", "真人起白水，帝命式九圍。", "誤沐宣室召，白頭侍經幃。", "誰言螢爝光，敢近白日暉。", "誰言草木萌，敢試雷霆威。", "野馬立仗下，軒昂妄鳴嘶。", "棄之老牛皂，無復瞻龍墀。", "天公了無私，與奪適所宜。", "時方急功名，選愞安所施。", "士方貴才辨，安用鈍訥爲。", "常人與善士，何異於愚癡。", "譬之救焚溺，珮玉行逶迤。", "棄捐乃其理，刺天看羣飛。", "幸非高明室，百鬼浪見闚。", "自從伏嵁巖，風淫得偏扉。", "有足不得行，有手不得持。"]'),
('abfa359d-1267-4558-921c-6f9f95cbb5ae','叔問縱步郊野得竹栽二小叢攜以見分','程俱','宋','宋诗','song-poetry','','[]','叢筠無尺長，氣與西山爽。',48,'全唐诗/poet.song.82000.json','["叢筠無尺長，氣與西山爽。", "聊持內方丈，便作淇渭想。", "會當冰雪餘，傑立千林上。", "自非歲寒人，誰與共幽賞。"]'),
('9090c08a-51f3-4234-844e-d48603321e7b','觀白公蘭若寓居詩如寫余懷但不能晨游夜息如彼自由耳輙用韻作','程俱','宋','宋诗','song-poetry','','[]','生非廊廟姿，雅志在林野。',72,'全唐诗/poet.song.82000.json','["生非廊廟姿，雅志在林野。", "擬作奢摩他，疾至薩芸若。", "身心溈山牛，得失塞翁馬。", "城南寄僧坊，一室謝掃灑。", "當時醉吟翁，高謝香山下。", "安知衰病夫，亦有如翁者。"]'),
('25729aa2-3b0c-4651-a2a9-8c68e23e207f','比者彦文少卿一再枉過且有卜鄰之約投老山林深慰孤陋兹者誤蒙召旨固已具述多病不才乞侍祠宫觀矣辱貺佳篇佩戢厚意謹次韻奉酬','程俱','宋','宋诗','song-poetry','','[]','衰遲澹無營，百念已灰冷。',180,'全唐诗/poet.song.82000.json','["衰遲澹無營，百念已灰冷。", "時吟蘂珠句，聊復寄二景。", "平生坐五窮，相逐如形影。", "華顛行路難，雅志不一逞。", "逝言北山北，耕釣得重整。", "結廬甚幽深，不覺在人境。", "江公飽叢林，高視妙峰頂。", "時迂百里駕，清坐舉春茗。", "相期老嵁巖，守望依同井。", "久知無朋酒，出沒均酩酊。", "向來醒而狂，投老狂方醒。", "如何紫泥書，名姓蒙記省。", "控辭苦陳情，抱病當自屏。", "肯令曉猿驚，滓辱及崖嶺。", "新詩比移文，三復得深領。"]'),
('5b93ea5d-ad8c-4dac-abfd-1bfb8a183878','和蒋尚書園第新亭二首  其一','程俱','宋','宋诗','song-poetry','','[]','千尋屹冰臺，一室穿甕牖。',48,'全唐诗/poet.song.82000.json','["千尋屹冰臺，一室穿甕牖。", "傷生定難遵，極侈固無取。", "兹亭挹空翠，勢出巨靈手。", "縱目雲夢區，時來賦烏有。"]'),
('d2b4fa56-d692-433a-ba0f-090a9e3ad90b','和蒋尚書園第新亭二首  其二','程俱','宋','宋诗','song-poetry','','[]','羣山對西丘，突兀幾千歲。',48,'全唐诗/poet.song.82000.json','["羣山對西丘，突兀幾千歲。", "超然宇宙間，安用乘雲氣。", "松筠非小草，出處皆遠志。", "他年姚尚書，指畫要十事。"]'),
('55780110-d8c7-4f7d-870c-f4a1cdd73357','以夜宿匠舍詩示晁以道說之乃以古句爲謝次韻酬之一首','程俱','宋','宋诗','song-poetry','','[]','平生拙自理，不辦一畝宫。',120,'全唐诗/poet.song.82000.json','["平生拙自理，不辦一畝宫。", "聊從斵輪扁，敢慕執戟雄。", "慚非五鳯手，正着雙鳬中。", "何言散騎省，難下青藜翁。", "相望一牛吼，有客方固窮。", "牀頭河洛書，瑩光吐長虹。", "時時發佳句，執若萬折東。", "我詩出龜賜，寒螿抱霜叢。", "誰當寫秋思，妙器無號鐘。", "相從無何境，曳履哦清風。"]'),
('3ae6d685-7da8-49dc-9c04-1628c9066a37','借葉內翰畫令小江模寫','程俱','宋','宋诗','song-poetry','','[]','十年同舍今華顛，印山滿眼囊無錢。',208,'全唐诗/poet.song.82000.json','["十年同舍今華顛，印山滿眼囊無錢。", "每看圖畫輙心醉，自笑說食流饑涎。", "世間范李真幻士，斷取妙喜移山川。", "朝來問疾方丈室，但怪衡霍羅窗軒。", "飄風急雨暗四澤，轉看錦翠開雲煙。", "崔嵬磊塊凍相倚，恍然雪塞藍田關。", "是中大有結茅地，指點三徑依林泉。", "世人無乃笑癡絕，心境二妄交相纒。", "安知三萬師子座，同此幻力無中邊。", "衢山小江新悟幻，落筆欲追祈與虔。", "願從公借此妙景，已具東絹和丹鉊。", "照中寫照供幻觀，聊自慰藉銷窮年。", "千巖萬壑納環堵，更令一拂松風絃。"]'),
('759bbe42-6d88-4f8e-9116-236dcff17ab6','自仲嘉云亡未始見夢舟行夜入吳興境有夢如平生感而賦詩四首  其一','程俱','宋','宋诗','song-poetry','','[]','江子隘斯世，翛然向方蓬。',84,'全唐诗/poet.song.82000.json','["江子隘斯世，翛然向方蓬。", "一朝成千古，寤寐不復通。", "夜入霅溪境，胡然見幽夢。", "高標何所似，俯仰風中松。", "笑談如平生，炯炯雙方瞳。", "去年經行地，陳迹亦已空。", "故應玄真老，相與游無窮。"]'),
('31df066f-a5ef-4bb7-a0af-7515a2eb6a65','自仲嘉云亡未始見夢舟行夜入吳興境有夢如平生感而賦詩四首  其二','程俱','宋','宋诗','song-poetry','','[]','諸人久不死，而使武子先。',84,'全唐诗/poet.song.82000.json','["諸人久不死，而使武子先。", "斯言太癡絕，愛惡無乃偏。", "君看雅正情，播在三百篇。", "秦人哀三良，百身寧可捐。", "相鼠有深刺，嗟哉胡不遄。", "此豈惑者歟，加膝墜諸淵。", "乃知孫楚狂，未必非公言。"]'),
('5cc38426-ac95-4e2b-8897-f4510d5af308','自仲嘉云亡未始見夢舟行夜入吳興境有夢如平生感而賦詩四首  其三','程俱','宋','宋诗','song-poetry','','[]','世以勢論士，君誠不如人。',84,'全唐诗/poet.song.82000.json','["世以勢論士，君誠不如人。", "揚揚乘軒者，志滿氣甚振。", "外見七尺軀，中有萬斛塵。", "鑿枘固難入，鶚鸞豈相倫。", "炙手苟可熱，行路爲雷陳。", "高棲冷如鐡，骨肉不得親。", "誰能獨無死，榮辱久乃真。"]'),
('5e4f3c1a-e4b5-4697-b76b-181451ebf84e','自仲嘉云亡未始見夢舟行夜入吳興境有夢如平生感而賦詩四首  其四','程俱','宋','宋诗','song-poetry','','[]','皇天非無知，伯道固有後。',84,'全唐诗/poet.song.82000.json','["皇天非無知，伯道固有後。", "百年能復幾，僅比一昏晝。", "久知彭籛夭，不及殤子壽。", "向來簞瓢生，廟食至今侑。", "東陵雖飽死，千載有餘臭。", "梟藩得刳腸，苕折謾遺鷇。", "試當問玄夫，此理或可究。"]'),
('69847953-c32a-4094-b948-b245a2f2dcbd','初到書局以萬七千錢得一老馬盲右目戲作古句自嘲一首','程俱','宋','宋诗','song-poetry','','[]','蹄間三尋汗流赭，九逵雷雹爭飛灑。',160,'全唐诗/poet.song.82000.json','["蹄間三尋汗流赭，九逵雷雹爭飛灑。", "我窮那得騁追風，正擬虺尵行果下。", "平生畏途飽經歷，夜半臨深無馭者。", "故應造物巧相戲，却比盲人騎瞎馬。", "李南知音當促步，廣漢騰嘲不相假。", "執鞭良稱塞翁兒，並轡聊從杜陵夏。", "龐然病顙豈其類，老矣問途那可舍。", "徑煩一夫事刷秣，似桂新芻不盈把。", "向來伯厚亦安在，結駟雞棲同土苴。", "他年東去把撩風，縱爾逍遙汴東野。"]'),
('0ab22d15-b215-49f6-97cb-3945b3a23ffd','神霄宫知宫陳應常邀鄉人集道堂余不果往毛彦時有詩諸公皆和見率同作次韻一首','程俱','宋','宋诗','song-poetry','','[]','南枝月明烏鵲飛，北風驚沙燕馬嘶。',256,'全唐诗/poet.song.82000.json','["南枝月明烏鵲飛，北風驚沙燕馬嘶。", "倦遊乃有故鄉念，強學處士聽朝雞。", "馬蹄得得烏帽底，與日競走東還西。", "安知神府在人境，曉霧十里飛香猊。", "咄嗟似與化人遇，宫殿盤欝窮煙霏。", "瑛房蘂箧浩無極，當關九虎何由闚。", "仙郎邀客自清旦，閴若岫戶臨江湄。", "向來同是爛柯客，石梁跨野長虹垂。", "登晨未辨七盟蓋，祈年欲採三華芝。", "授書忽作蘂珠吏，雲篆豈特傳盟威。", "故人一笑共清景，常談曲謹皆芟夷。", "而余煮餅北窗卧，正坐世網纒綿之。", "棗瓜麟脯不同舉，但見綵筆方交馳。", "蕭然俯仰在環堵，窮巷偪仄仍喧卑。", "高堂修竹寄遐想，况烹雪乳調清絲。", "徑須暇日一尋勝，眼中塵袂空成帷。"]'),
('ccc66a8b-500d-48fb-8936-a7d1d09c2919','以蒋永仲畫雙松爲故人壽','程俱','宋','宋诗','song-poetry','','[]','青松千歲姿，擢質萬仞岡。',144,'全唐诗/poet.song.82000.json','["青松千歲姿，擢質萬仞岡。", "霜根初茁秀，氣已凌千章。", "去天尺五地，雨露先衆芳。", "晨光爲膏沐，鬛鬛傾扶桑。", "故應神物護，茂葉成深蒼。", "爾來向三紀，已作拏雲驤。", "豈惟蔽牛馬，固已中棟梁。", "上有參天枝，下有延年肪。", "蒼蔭被草木，皆爲芝木香。", "衆鳥不敢巢，或來孤鳳凰。", "會當回萬牛，一柱來明堂。", "却顧冰澗底，歲寒永相望。"]'),
('f72aef55-c52f-4586-84d8-00e3c6e8ab9b','詩送趙承之祕監鼎臣安撫鄧州三首  其一','程俱','宋','宋诗','song-poetry','','[]','平生竹隱翁，胸次着千古。',96,'全唐诗/poet.song.82000.json','["平生竹隱翁，胸次着千古。", "揮毫劇翻瀾，碑版照秦楚。", "十年屈僚佐，留使望天府。", "今年道山顛，士論乃深許。", "歌詞薦清廟，盛典更藻斧。", "忽持南陽節，聲動漢江浦。", "清班寄麟臺，雄職暫符虎。", "遙知佳政傳，召杜安足數。"]'),
('d1808785-8a51-4dce-9d7e-0785f4abaf08','詩送趙承之祕監鼎臣安撫鄧州三首  其二','程俱','宋','宋诗','song-poetry','','[]','往者南陽耕，相望鹿門翁。',84,'全唐诗/poet.song.82000.json','["往者南陽耕，相望鹿門翁。", "時來拜牀下，鷄黍相與同。", "安知田舍中，離鳳友伏龍。", "我疑兩州間，地美物亦豐。", "故應釣遊處，清泉蔭高松。", "人英何代無，儻有前賢風。", "弓旌恐難致，羔雁或可通。"]'),
('6687ab5e-ddd7-459a-8a4d-16d14c911175','詩送趙承之祕監鼎臣安撫鄧州三首  其三','程俱','宋','宋诗','song-poetry','','[]','潭潭內史府，侃侃東西錄。',84,'全唐诗/poet.song.82000.json','["潭潭內史府，侃侃東西錄。", "當年得一士，衆視驚刮目。", "何殊致洪造，初不羡博育。", "林侯忽東歸，懷寶媚幽獨。", "趙侯小騰騫，文采冠羣玉。", "要之進退間，了不異蘭菊。", "因公懷若人，皎皎歎空谷。"]'),
('d8f692e7-32f4-475e-bbc4-07f947daa32b','和酬梅悅之大夫澤送行古句','程俱','宋','宋诗','song-poetry','','[]','讀書何如事耕種，唇腐頭童得饑凍。',160,'全唐诗/poet.song.82000.json','["讀書何如事耕種，唇腐頭童得饑凍。", "半生塌翼堕江湖，仰視羣飛困嘲弄。", "閉門誦說不知悔，時以聖賢資折中。", "饑來驅我向京華，爲米折腰随所用。", "一官此固初不惡，浪以討論辭冗從。", "梅公據鞍殊矍鑠，滿腹精神比錢鳳。", "新詩借我快筆端，省向江南賦雲夢。", "向來高門邇衡陋，杖履時來窺牖甕。", "今公三徑爲誰開，顧我五窮那易送。", "會當投檄復言歸，時訪祇園談不共。"]'),
('fb3d9059-bd7f-4769-b9e8-b8fc2c8b4c3f','和同會舍千葉緋桃','程俱','宋','宋诗','song-poetry','','[]','飛花動江光，風力兩相怯。',144,'全唐诗/poet.song.82000.json','["飛花動江光，風力兩相怯。", "扁舟老參謀，覓句時拄頬。", "連昌出墻枝，晞日香江挹。", "深宫夾修篁，歲久森翠葉。", "至今丹青妙，華宇張九疊。", "誰移此繁英，密蔭如栽接。", "因依肖蜾臝，變幻胥蝴蝶。", "忽如剪緋㠾，又似翻錦箧。", "殷唇注猩血，細蘂輕蚊睫。", "爭春雖云晚，鬭麗固當捷。", "冰實儻可分，仙梯不難躡。", "賡詩憎怪煩，我意終未惬。"]'),
('cd00c3c2-e25d-4a62-8de4-e861706039c4','同舍以筆墨更相遺有詩見邀同作','程俱','宋','宋诗','song-poetry','','[]','将軍白首玄池陰，手持毛錐如綠沉。',208,'全唐诗/poet.song.82000.json','["将軍白首玄池陰，手持毛錐如綠沉。", "千人獨掃杜陵老，百犗欲連東海任。", "中山豪族一當百，即墨堅壘高臨深。", "孫郎精騎固無匹，長卿偏師那可侵。", "久知良工須利器，豈但善賈緣多金。", "故追老兔盡三窟，已倒霜松踰十尋。", "於莵猶存鳳閣卧，黄庭不博鵝池臨。", "清觀越石已成冢，始信管城真盡心。", "客卿摩頂利天下，修竹欲汗南山林。", "儒生意廣亦自苦，但有遺迹藏來今。", "兩公筆陣略相抗，往往鉞並張旗參。", "鋪揚功伐借二物，寸木可使齊高岑。", "嗟余絕學久焚棄，嘿守三一朝飛森。"]'),
('de437dd9-ae99-4533-8c64-d27b060f2a0b','松鶴圖','程俱','宋','宋诗','song-poetry','','[]','崑崙五城十二樓，洪河空注經神州。',308,'全唐诗/poet.song.82000.json','["崑崙五城十二樓，洪河空注經神州。", "西連仙掌五萬里，一柱上直清都浮。", "琳琅琪碧乃凡草，青華絳實森纍樛。", "南辰真人厭嫵媚，下勅保命更冥搜。", "元精結感浹地軸，奮此倚天蒼鬛虬。", "燭龍晞露吐珠琲，青女歛轡回春秋。", "上有飛晨焕景之卿雲，下有金精石髄之清流。", "盤根疏節孤且直，扶疏羣木罕與儔。", "風濤吹落九天上，倒景雨沛參雲油。", "睟然和氣發柯葉，俯芘芝朮齊薰蕕。", "當年箕潁眇䨥闕，戶牖森翠蒼陰稠。", "挺生初不待封殖，天遣異質榮仙洲。", "居然神蔡産千歲，不但明堂來萬牛。", "台符兩兩直其上，芳膏美蔭被九丘。", "紫清騏驥下擇木，展翮還自青田幽。", "瓊芝瑤草供俛啄，蓬閬曾記添仙籌。", "會有玉沙丹露飲，清風飄颯玄霜裘。", "巢雲友鳳乃其所，昂昂肯爲鷄羣謀。", "神霄之境接華蓋，永作帝瑞同天遊。"]'),
('9e8d3525-0af4-4d34-8055-1d6e2e97130e','晁無斁将之錄示近詩有和其兄以道說之詩次韻以致區區兼簡以道  其一','程俱','宋','宋诗','song-poetry','','[]','往登妙高臺，千嶂如聚墨。',156,'全唐诗/poet.song.82000.json','["往登妙高臺，千嶂如聚墨。", "煌煌化人宫，屹立斷鼇足。", "題輿亦不惡，嘯詠此浮玉。", "粃糠空在前，不謂公肯辱。", "竟乖南州望，聊作信都福。", "吹竽定誰真，抱璞安忍哭。", "高情禦外物，不計處與出。", "端如屋間籕，障以千步築。", "我窮居城南，甕牖藩援禿。", "華裾每來過，暖語加帛粟。", "洋洋塤箎音，珍重同結綠。", "吟毫久不濡，辱贈不敢獨。", "所慚春螽股，持抗不周觸。"]'),
('f1303d9d-3f3c-4ccf-b246-65d67fe09317','晁無斁将之錄示近詩有和其兄以道說之詩次韻以致區區兼簡以道  其二','程俱','宋','宋诗','song-poetry','','[]','談詩如談禪，練性如練墨。',156,'全唐诗/poet.song.82000.json','["談詩如談禪，練性如練墨。", "壮心悟龜毛，少作豈蛇足。", "平生甚元龍，未信今伯玉。", "十年得投閑，高卧謝寵辱。", "定知貧勝富，固自平爲福。", "著書着名山，會使山鬼哭。", "結廬近三休，爲米時一出。", "猶嫌佛場選，肯問燕臺築。", "俗人難與言，鏡髢遺盲禿。", "前年客長安，正覓三釡粟。", "塵中一傾蓋，爽氣岷峨綠。", "别來更崎嶔，寡陋嗟我獨。", "塵埃箧中書，有手不暇觸。"]'),
('cb077645-ebe6-4890-8754-668d0b75a577','復次韵酬葉翰林見寄','程俱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','渭川十頃青，上谷千竈墨。',156,'全唐诗/poet.song.82000.json','["渭川十頃青，上谷千竈墨。", "縣河供拂石，濡筆應未足。", "公初入承明，神采映冰玉。", "孤芳信難羣，廉士故可辱。", "虚懷得逢蒙，泛愛近藉福。", "終然翟公題，正堕楊朱哭。", "于今十年後，猶作一麾出。", "何當還宣温，不用求釣築。", "遙知西湖柳，蔽芾誰敢禿。", "應餘金石文，會使天雨粟。", "留連借三輔，夏木今再綠。", "斯文詠公歸，悵望非我獨。", "羈懷老無堪，覽卷百憂觸。"]'),
('704af216-632a-4655-b9de-9ccd606b4f0a','次韵寄謝公表韓公朝請','程俱','宋','宋诗','song-poetry','','[]','世人如鰂魚，自蔽飜吐墨。',156,'全唐诗/poet.song.82000.json','["世人如鰂魚，自蔽飜吐墨。", "猩熊亦何罪，不衛唇與足。", "要當如木雁，安問定石玉。", "向來休休翁，老去稱耐辱。", "迹高名自汙，卒享清凈福。", "肯爲接輿生，叩木妄歌哭。", "韓公早聞道，垢濁久已出。", "終成九層臺，不棄一簣築。", "長安列戟第，桐影将缺秃。", "寧辭治中輿，且食祠宫粟。", "胸中荆棘盡，華髪當更綠。", "抗塵我何庸，勇退公所獨。", "何如善刀藏，聊放虚舟觸。"]'),
('45d2a129-6c3d-4c52-a0db-605a768975a4','次韵寄謝存之曾公學士','程俱','宋','宋诗','song-poetry','','[]','往居闔廬城，有客面如墨。',156,'全唐诗/poet.song.82000.json','["往居闔廬城，有客面如墨。", "論文口瀾翻，嗜學苦不足。", "時稱曾校書，秀句示珠玉。", "今晨塵眼開，來贈忽先辱。", "風騷窮乃工，投閑詎非福。", "言音關感動，妙比韓娥哭。", "此道久荒蕪，名家亦時出。", "五言古長城，屹若萬夫築。", "何如丹鳳樓，樸斵千嶂禿。", "雖然皆戲劇，渺甚一毛粟。", "付之兩忘情，蘭蕙等茨綠。", "聞公會西游，顧我陋而獨。", "掃齋待清談，奮麈或相觸。"]'),
('abcf05c1-6aa8-4e9b-b83b-5d563876821c','和葉翰林送李從事','程俱','宋','宋诗','song-poetry','','[]','賞音真兩難，邂逅多契闊。',120,'全唐诗/poet.song.82000.json','["賞音真兩難，邂逅多契闊。", "一朝間容刀，三歲歌采葛。", "古人抱修能，初不露錐末。", "誠令處囊中，談笑堪式遏。", "豈無識玉人，顧恐鑠金奪。", "遂令緇衣好，歛迹裁自脫。", "畫蛇杯已疏，志鵠弓遽撥。", "徒嗟湖海上，髪白齒牙豁。", "懷公劇梅林，念至失焦渇。", "臨風賦新謡，憂思不可掇。"]'),
('77974ea2-787d-4899-a9ed-e4e8b4287b4f','次韻和潁昌葉翰林 同許學士亢宗幹譽汎舟潩水 其一','程俱','宋','宋诗','song-poetry','','[]','高雲下甘澤，膚寸即有餘。',96,'全唐诗/poet.song.82000.json','["高雲下甘澤，膚寸即有餘。", "瀛波納牛迹，亦復鱣鯨居。", "翰林補天手，妙語追三閭。", "聊從潁川借，似厭承明廬。", "坐令嘯諾地，不異畏壘墟。", "斯人樂佳政，欣若飽稻魚。", "恢恢雲夢胸，中有幾石渠。", "時來潩水旁，傲睨萬物初。"]'),
('d32e9e86-e0cf-4d66-a58b-508c214f8d24','次韻和潁昌葉翰林 同許學士亢宗幹譽汎舟潩水 其二','程俱','宋','宋诗','song-poetry','','[]','嗟我一寸筳，登公五言城。',96,'全唐诗/poet.song.82000.json','["嗟我一寸筳，登公五言城。", "時窺錦囊句，似發黄鐘聲。", "閉門得長哦，有酒或細傾。", "誰云千里隔，回薄萬古情。", "駕言從公游，上馬短策横。", "塵纓縛我急，有足安得行。", "何當來上都，既見心始平。", "爲公賦三秋，寤歎空營營。"]'),
('ca3d03e7-fe9b-4c3a-a078-1020bfe28677','次韻和潁昌葉翰林 同許學士亢宗幹譽汎舟潩水 其三','程俱','宋','宋诗','song-poetry','','[]','往者巾柴車，追遊卞山村。',96,'全唐诗/poet.song.82000.json','["往者巾柴車，追遊卞山村。", "今焉鎮三輔，鼓吹喧譙門。", "遙知手種松，浸有蒼苔痕。", "許下今樂郊，勝事亦復繁。", "但令足兵食，飽暖同君恩。", "長安舉頭見，煌煌太微垣。", "江湖與魏闕，一一寄默存。", "正恐受釐室，虚懷待微言。"]'),
('5eca27ec-76a5-490d-aa80-ceb335961a43','次韻和潁昌葉翰林 同許學士亢宗幹譽汎舟潩水 其四','程俱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','許侯蓋静者，無乃祖遠遊。',96,'全唐诗/poet.song.82000.json','["許侯蓋静者，無乃祖遠遊。", "着身朝市間，深若無所求。", "命駕眇千里，西湖正凉秋。", "是中有真趣，軒裳何悠悠。", "潩水清且姝，仙舟度深幽。", "徐行問疾苦，懷新想平疇。", "坐念方外樂，饞涎麴車流。", "持觴會相屬，我唱公當酬。"]'),
('27a72161-b17a-4508-a141-ebfd937977d7','次韻和潁昌葉翰林 目病廢讀書','程俱','宋','宋诗','song-poetry','','[]','空華信無根，遺迹故非足。',120,'全唐诗/poet.song.82000.json','["空華信無根，遺迹故非足。", "如公三萬卷，碨磊貯心曲。", "中虚自昭曠，不必巖電目。", "納芥本無難，膠弦端可續。", "亡書共推張，斷簡當問束。", "笑談針左盲，指顧命騷僕。", "豈知窮巷士，眼暗髪将秃。", "短檠黮無光，默坐守幽獨。", "正當黜聰明，豈復分句讀。", "便便了無庸，但有孝先腹。"]'),
('543bfff2-adfd-4407-9d48-02c491002602','生第三兒','程俱','宋','宋诗','song-poetry','','[]','生兒如班伯，絕業出金華。',144,'全唐诗/poet.song.82000.json','["生兒如班伯，絕業出金華。", "惱人如添丁，索抱聲啞啞。", "人生各有分，豪末不可加。", "丹山無凡鷇，寒根無早芽。", "如公翔千仞，衆鳥不敢譁。", "将雛一來儀，美瑞世所夸。", "嗟我困冰谷，霜枝鬰盤拏。", "華顛有二女，爾爾聊自佳。", "今年熊羆夢，亦復來貧家。", "平生坐著書，每笑括與奢。", "籃輿一幅巾，緩步可當車。", "儻學長史掾，修真凌景霞。"]'),
('a603ee14-acee-4be5-9190-1159f02db5ec','生第三兒 同許幹譽步月飲杏花下','程俱','宋','宋诗','song-poetry','','[]','公不見錦衣白璧誰家郎，春風得意尋春忙。',150,'全唐诗/poet.song.82000.json','["公不見錦衣白璧誰家郎，春風得意尋春忙。", "紅雲步障三十里，一色繁艷無餘香。", "又不見玉川穠李正清絕，夜攜仙客通寥陽。", "連天剪刻萬枝雪，縞裙練帨看明粧。", "古來勝賞不易得，况乃花下延舒光。", "豪端頓挫役萬物，如彼棗葉持鍼芒。", "昔人曲水詠觴處，茂林修竹空宫牆。", "騁懷弔古賴何物，麴生風味安可忘。", "自憐春色不到眼，歸卧北窗書滿床。"]'),
('93f62013-436b-44bd-a9f9-3b50975a2621','故人張達明徴餉舒朮将以古句次韵酬之','程俱','宋','宋诗','song-poetry','','[]','憶官古龍舒，妙境開禹甸。',276,'全唐诗/poet.song.82000.json','["憶官古龍舒，妙境開禹甸。", "潄流探九井，曳屐窮四面。", "借居龍溪上，窗戶列巖巘。", "客懷劇棼絲，撩亂不可剪。", "時時出登臨，款段勝屈産。", "如持古神搥，破此牢愁鍵。", "地靈多草木，灌蔓森秀軟。", "嘗聞左宫仙，蘂笈發珍瑑。", "摛辭敘山精，豐綺信無㥏。", "幾尋青冥劚，時作芙蓉搴。", "雲琅未云剖，月醴忽以泫。", "回觀豨苓輩，市積空𡾰嵼。", "至今阿連功，焜燿華陽典。", "寧當柙而藏，正恐知者鮮。", "豈同西一方，但取一笑莞。", "力驅三彭仇，况比黄金腆。", "芳腴散靈柔，坐使百疴遣。", "故人山中來，雅素過何點。", "應知藜莧腹，豈復禁茗碗。", "輕翔不可獨，分送勤折簡。", "新詩出強韻，趣步不容挽。", "微吟復小啜，氣味清而婉。", "何須養生論，藥石問中散。"]'),
('cd6bd899-31b7-4e38-846d-2519fb4d9c37','雪中與禮部同舍過葆真宫','程俱','宋','宋诗','song-poetry','','[]','朝來青霞城，洶涌爛銀闕。',180,'全唐诗/poet.song.82000.json','["朝來青霞城，洶涌爛銀闕。", "悠然眄天宇，晶瑩欲冰徹。", "虚空無表裏，白照混日月。", "九區絕纖塵，爽氣爭栗冽。", "初疑騫林境，琢玉墮飛屑。", "人間出靈苗，頃刻皆秀發。", "不知皇季氏，羽衛森幢節。", "剛風振長空，襟珮劇飄瞥。", "真仙足按地，險穢盡平潔。", "坐令三千界，一洗聲利熱。", "偉哉此遐觀，曳屐到濛越。", "池臺静相照，澒洞失坳垤。", "仰窺乾坤大，未信東南缺。", "要須風露腹，始稱此清絕。", "安得垂天鵬，一跨眇空闊。"]'),
('0b413eea-d122-4f7e-a728-3553cfec8247','虎圖','程俱','宋','宋诗','song-poetry','','[]','山深草長鬰崷崒，俯仰蕭森蔽雲日。',160,'全唐诗/poet.song.82000.json','["山深草長鬰崷崒，俯仰蕭森蔽雲日。", "於菟一嘯谷風生，舉頭爲城鬚爲戟。", "藜蒿不采中梁柱，雉兔麞猿亦蕃息。", "它山豈無三萬仞，跛䍧直上無難色。", "朝游芻牧行葦盡，暮投斤斧千林赤。", "乃知鳥獸有折衝，不獨鷙翰空纍百。", "何人寫此出林態，巖電耽耽氣深寂。", "書堂高挂走螭魅，不怒而威如有德。", "流傳影象一如此，大勝留皮配圭璧。", "古來真虎不易逄，僕姑誤沒南山石。"]'),
('ff29825c-284a-4fe7-ad9a-643dce9b2d40','春日與會要同舍會飲西園','程俱','宋','宋诗','song-poetry','','[]','今我忽不樂，駕言及陽春。',156,'全唐诗/poet.song.82000.json','["今我忽不樂，駕言及陽春。", "西郊桃始華，未動車馬塵。", "名園開綠野，氣象淑且新。", "相從同舍郎，珠璧驚市人。", "垂鞭度長楊，和風拂衣巾。", "時花靚無言，草木含晴薫。", "迢迢西荘鏡，似與江南鄰。", "漾舟入天境，不辨水與雲。", "誰移呼猿澗，亂石瑣怪珍。", "奔雷轉三峡，可潄不可渾。", "止水照我心，流泉醒我神。", "終年九衢客，一洗聲利氛。", "歸來卧蝸舍，夢堕吴松濱。"]'),
('170e9d8f-b799-4a3d-abd2-a80ae5a29c0d','和滕子濟考古圖','程俱','宋','宋诗','song-poetry','','[]','我生百無味，忘懷欲捐書。',240,'全唐诗/poet.song.82000.json','["我生百無味，忘懷欲捐書。", "翛然謝糟粕，傲睨萬物初。", "平生蠧魚間，習氣未盡袪。", "朝來覧千古，似歷仙公壺。", "權輿自四目，雨粟號靈魖。", "天球周序陳，科斗魯壁餘。", "切玉有至理，范金足良模。", "彭亨屹漢鼎，璀璨羅商瑚。", "初疑鳥遺跡，忽若龜負圖。", "典刑尚可見，聊用舉一隅。", "翻思楊子雲，語默與道俱。", "豈無載酒人，相對時軒渠。", "奇字决魚魯，微言折甄舒。", "譬彼學耕稼，當從老長沮。", "滕侯飽今古，禀秀連青徐。", "三年考聚訟，坐判墨與儒。", "入眼爛珩玦，搜奇到黄虞。", "端令宇宙中，俯仰縱所如。", "我欲發其秘，聯詩慚貫珠。", "何殊穰田祝，豚蹄操酒盂。"]'),
('0d5e92a3-6d38-4d42-9f0f-0683b88a4265','和蔡待制放蟬一首','程俱','宋','宋诗','song-poetry','','[]','放歌北亭漁，千古有生氣。',144,'全唐诗/poet.song.82000.json','["放歌北亭漁，千古有生氣。", "當時及物心，豈在坳堂內。", "如公有遠度，寄此枝上嘒。", "定知膚寸雲，四海不難至。", "應憐風露腹，不受塵土蔽。", "寧嫌壤中丸，聊復一引臂。", "初如飛鳥揚，下逐游鱗戲。", "終然跐清波，振翼出荷芰。", "斯須曳餘響，决起望陰邃。", "臨風贈良規，毋以利昏智。", "禽魚逐甘香，鼎俎芼薑桂。", "請觀垂天鵬，纖繳安可冀。"]'),
('e5b1cff7-ead3-48a4-943b-6c29f7371f27','龍尾硯同毛彦時随聯句','程俱','宋','宋诗','song-poetry','','[]','歙水清以駃，歙山文且堅。',240,'全唐诗/poet.song.82000.json','["歙水清以駃，歙山文且堅。", "誰持玉斧琢，製此月様圓。", "想當結繩後，要使鳥跡傳。", "雕鎪見骨格，豈與瓦礫全。", "陂陀百氏圃，泓澄九經淵。", "墨海不復見，柯巖那可肩。", "星稀涵緯象，眉綠生春妍。", "規模異鎔鐡，濡寫殊懷鉛。", "正當秋兔穎，發此霜松煙。", "一從毛褚遊，幾作蟲魚箋。", "徴辭想妃子，揾首懷張顛。", "寧同李生瘞，聊續胡公鐫。", "常疑老蚌殻，浸潤成膏妍。", "堅踰鵝池鑄，質射銅臺埏。", "紛紛况多僞，渇雀同梔鞭。", "琳坳隱多水，十手寄所宣。", "池光瀲墨色，雲氣開毫聯。", "翔鸞及垂露，逸勢徒飛騫。", "誰云過珪璧，或用磨戈鋋。", "吾今欲焚棄，負耒歸園田。"]'),
('fd5f1a98-3eb3-4b34-bf84-23a4fb4497c3','泛舟鑑湖同趙來叔子泰趙叔問聯句','程俱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春風卷三江，雨雹暗秦望。',288,'全唐诗/poet.song.82000.json','["春風卷三江，雨雹暗秦望。", "今晨風日佳，遠目聊一放。", "人情暫愉悅，天宇亦清曠。", "逝将一葉舟，遠破萬里浪。", "澄波撥寒醅，疊巘展新障。", "飄搖過餘芳，容與矚孤漾。", "停雲冒山巔，新綠浮天上。", "枯楊吐輕黄，倚岸抹晴漲。", "遠水沒輕鷗，覉禽變圓吭。", "鑑湖清可啜，蕺菜柔堪餉。", "時當祓禊友，路指蘭亭嚮。", "豈無謫仙盃，聊舉剡溪榜。", "吟牋灑餘研，茶竈發新煬。", "徜徉寫幽憂，蕭爽絕纖坱。", "年華自繁穠，世故足悽愴。", "弔古意雖遐，感時心自亮。", "雄濤折東南，舊牒分霸王。", "梅梁寄遺靈，禹跡疑可訪。", "星分九土毛，带挽百川洚。", "胼胝識神姦，玉帛來崛強。", "規模至今存，形勢亦云壮。", "膽嘗信焦思，金範徒審象。", "當年浣紗人，絳縷起窮巷。", "姑胥失層臺，榛棘遶青嶂。"]'),
('3e6cb97a-9d48-4713-ae9b-79466e324ebd','會要官集西池同舍翁挺作詩次其韻','程俱','宋','宋诗','song-poetry','','[]','瓊構涌空碧，魚龍濯晴波。',120,'全唐诗/poet.song.82000.json','["瓊構涌空碧，魚龍濯晴波。", "游人與春競，奈此西日何。", "緬懷散花洲，青笠委綠蓑。", "當年漁樵侣，問我何時過。", "依然五湖境，亂眼煙雲多。", "恍疑三壺夢，欲繼七字哦。", "恨無石心兒，慨慷叩舷歌。", "時英滿四座，自許皆隋和。", "翁子獨不語，詩源瀉懸河。", "不作杜陵老，眼寒驚綺羅。"]'),
('e68e1a47-18eb-49ef-90e0-c22d7880527a','道山堂後小桃著花頗有幽態','程俱','宋','宋诗','song-poetry','','[]','春陽入花骨，疏葉皆昌豐。',144,'全唐诗/poet.song.82000.json','["春陽入花骨，疏葉皆昌豐。", "蓬山足松檜，不作倚市容。", "小桃三四花，擢秀冰雪中。", "頩顔澹無言，綽有林下風。", "無人對清賞，似笑華髪翁。", "老來懶尋芳，掛杖無青銅。", "不知春色深，但怪風日融。", "頗聞西郊路，欲作朝霞烘。", "何須逐流水，有馬如游龍。", "騎驢哦新句，醒醉同一空。", "當年玄都觀，葵麥棲殘紅。", "却顧此幽絕，蕭然對繁穠。"]'),
('df07ee5d-3fee-4de5-87d0-34302ef2c80d','分題得舡子和尚一首','程俱','宋','宋诗','song-poetry','','[]','洪波鼓溟壑，浩浩包神姦。',96,'全唐诗/poet.song.82000.json','["洪波鼓溟壑，浩浩包神姦。", "安知五濁海，平地即九淵。", "此老獨安住，蕭然五湖天。", "勿言一葉舟，中有宇宙寛。", "我昔初吏隱，掌中視包山。", "垂絲月明夜，獨立無往還。", "當年夹山人，付此八尺竿。", "安知翻瀾口，終日本無言。"]'),
('ddd0b889-3790-4e1f-b0db-30688e7812bf','避寇村舍戲踏杷顛仆','程俱','宋','宋诗','song-poetry','','[]','試踏百齒杷，怳如乘風航。',60,'全唐诗/poet.song.82000.json','["試踏百齒杷，怳如乘風航。", "𠿕覷不自持，尋丈得仆僵。", "牛驚更疾足，天全偶無傷。", "代斵既創手，學製安可嘗。", "田翁一笑粲，何日千斯倉。"]'),
('0b1de8a0-7512-440f-a2ca-ba30f191708c','漸寒補治籬壁防盗戲書','程俱','宋','宋诗','song-poetry','','[]','元龍湖海士，豪氣老不除。',108,'全唐诗/poet.song.82000.json','["元龍湖海士，豪氣老不除。", "龐公解脫人，法界一蘧廬。", "寶藏且不顧，家資何足儲。", "一朝四壁空，聊與妻孥居。", "今我貧病老，視身猶贅餘。", "室中亦何有，但有數箧書。", "饑寒士之常，肯歎食無魚。", "一官有微祿，二頃亦可鉏。", "騰騰苟任運，水到自成渠。"]'),
('81a40f8d-d012-40df-8afc-da88ccd32838','叔問觀韋蘇州詩至蕭條竹林院風雨叢蘭折幽鳥林上啼青苔人迹絕燕居日已久夏木紛成結几閣積羣書時來北窗閱以爲適與景會寫以寄予因用韻書懷云','程俱','宋','宋诗','song-poetry','','[]','憂時鬢成絲，念遠心欲折。',48,'全唐诗/poet.song.82000.json','["憂時鬢成絲，念遠心欲折。", "年芳豈不好，花下輙愁絕。", "衰顔有時丹，病指不能結。", "來往但鄰翁，奇書每同閱。"]'),
('7823da1a-0276-41c3-8d43-99dd57520cc0','傷前輩諸賢無存者復用前韻','程俱','宋','宋诗','song-poetry','','[]','峞峨玉山頹，磊砢霜松折。',48,'全唐诗/poet.song.82000.json','["峞峨玉山頹，磊砢霜松折。", "羣同冀北空，絃爲鍾期絕。", "鞭從晏嬰執，襪慕王生結。", "往躅那可追，我躬方不閱。"]'),
('72d397fe-a941-4552-af03-8bf1c065475f','自寛吟戲効白樂天體','程俱','宋','宋诗','song-poetry','','[]','武陵讁九年，下惠仕三已。',288,'全唐诗/poet.song.82000.json','["武陵讁九年，下惠仕三已。", "或窘如拘囚，或了無愠喜。", "吾生憂患餘，年忽及耆指。", "偏痱未全安，抱病更五禩。", "進爲心已灰，棄置甘如薺。", "坐狂合投閑，佚老宜知止。", "向令身安健，不過如是耳。", "每思古窮人，我幸亦多矣。", "照鄰嬰惡疾，羈卧空山裏。", "纒綿竟不堪，抱恨赴潁水。", "文昌兩目盲，無復見天地。", "簡編既長辭，游覽永無冀。", "吾今雖抱病，蹇曳非頓委。", "時時扶杖行，積步可數里。", "校之卧床席，欲坐不能起。", "雖扶不能行，懸絕安可比。", "時從親故談，亦不廢書史。", "右臂故依然，運筆亦持已。", "籃輿時出遊，初不廢牢體。", "况無他證候，色脉若無異。", "詳觀動息間，儻有安全理。", "侍祠了無庸，竊祿愧索米。", "借居浮屠宫，非村亦非市。", "廷堂甚爽塏，高屋敞窗几。"]'),
('adeb4b5e-4eb9-4369-b01c-b0e44c5c0a8e','次韻和叔問古風送曾吉甫提刑','程俱','宋','宋诗','song-poetry','','[]','夢覺紙窗白，幽禽語匆匆。',240,'全唐诗/poet.song.82000.json','["夢覺紙窗白，幽禽語匆匆。", "傳呼動林野，楚歌已三終。", "故人忽在眼，四牡來城東。", "閉門雀可羅，繞舍森蒿蓬。", "如何不我遺，臭味固所同。", "昔别全盛日，華戎文軌通。", "豈意喪亂後，晤言復相從。", "知君飽新得，敬慎過南容。", "肅然氣深稳，隱如匣藏鋒。", "向來夸奪境，變滅毗嵐風。", "訪舊半鬼錄，榮衰等虚空。", "顧我老且病，齒搖頭欲童。", "念子方潁脫，如錐出囊中。", "會如金僕姑，犀兕貫七重。", "光華得膚使，周咨廣堯聰。", "黠虜将革面，天方誘其衷。", "皇明並日月，塵霧不得蒙。", "遄歸侍幃幄，海嶽增深崇。", "儻因東飛翼，一訪白髪翁。", "時哉不可失，决去如驚鴻。"]'),
('abbe4239-cb29-456f-8c3e-8d422e3ce935','贈别吴忱宣德','程俱','宋','宋诗','song-poetry','','[]','吳公河南守，薦士得賈生。',288,'全唐诗/poet.song.82000.json','["吳公河南守，薦士得賈生。", "偉兹天下士，何止千人英。", "吳公失名字，功業曖不明。", "要非萬頃波，莫著横海鯨。", "當時好賢意，豈愧勃與嬰。", "蔽賢如面牆，自使兩目盲。", "好賢如力穡，穰穰嘉穀成。", "至今餘慶在，望著河南城。", "如君豈其裔，樂善莫與京。", "高門二千石，世德故可評。", "平生周旋士，往往凌青冥。", "作吏今十年，讀書不求名。", "向來光山政，何異古所稱。", "嗟哉士營己，寧使我負人。", "聊須借汝頭，一用朱吾輪。", "今君乃能爾，所棄如毛塵。", "故知古賢世，尚見風俗淳。", "猗予一畸士，落落良可憎。", "折腰務求合，俗眼竟不青。", "憧憧九衢內，邂逅蓋一傾。", "何從乃知我，頓有交歡情。", "相随若形影，出語見肺膺。", "長安速化地，頑鈍終無營。", "中宵起歸思，襆被東南征。"]'),
('9e75f613-cf05-4774-a0bc-9d88d6e37ca5','焦秀才出舊作送李世弼佐古詩李侯舊見知今亡矣覽之愴然爲和一首','程俱','宋','宋诗','song-poetry','','[]','李侯使東南，談士不容口。',96,'全唐诗/poet.song.82000.json','["李侯使東南，談士不容口。", "傾倉飽元元，倒屣先九九。", "虚懷無故新，盡下商可否。", "摛文真鸑鷟，考異自科斗。", "臨人武城宰，薦士河南守。", "當從古人求，敢用時輩偶。", "如何二毛初，蒿里澆絮酒。", "悲歌不成章，千古一揮手。"]'),
('debc5c0e-9b63-4335-aa5f-475b2387372e','酬焦秀才一首','程俱','宋','宋诗','song-poetry','','[]','焦生老儒冠，耳目接前輩。',96,'全唐诗/poet.song.82000.json','["焦生老儒冠，耳目接前輩。", "詞源如春水，浩浩漲清渭。", "長篇極舂容，島可青瑣碎。", "人生各有趣，相笑等醒醉。", "胡爲嗜文章，不作速化計。", "明珠枉投贈，懷袖欲三歲。", "今晨雪寒門，剝啄驚熟睡。", "軒昂開劇談，良足慰幽悴。"]'),
('c13eb3eb-93c6-408b-9d18-6f166fecbba0','送林德祖致仕東歸','程俱','宋','宋诗','song-poetry','','[]','浩浩聲利間，静躁同一區。',192,'全唐诗/poet.song.82000.json','["浩浩聲利間，静躁同一區。", "排肩日中市，有類逐獸趨。", "中朝尺寸地，衆睇咸睢盱。", "安知大雲客，出與飛雲俱。", "翛然棄之去，初不計卷舒。", "紛紛軒裳士，瞠目口爲呿。", "茫然更歎息，不間賢與愚。", "乃知楊少尹，未足繼兩疏。", "當時老而傳，不失仕且居。", "非同會稽史，苦誓困簡書。", "不比狂季真，索身憂病餘。", "耆年了無事，方當騁亨衢。", "投簪逸湖海，沛若縱壑魚。", "雖無揮金事，日者誰公如。", "清風激多士，故是明時須。", "恨無采詩氏，儻有東歸圖。"]'),
('5f0d592c-c3bf-4e1d-ad7f-e540e1b0822c','送太府宋少卿京赴邠州守一首','程俱','宋','宋诗','song-poetry','','[]','使君西南雋，掞藻陽臺春。',144,'全唐诗/poet.song.82000.json','["使君西南雋，掞藻陽臺春。", "聲稱動華省，故是青雲人。", "時於鵷鷺行，軒昂見長身。", "向來清官曹，往往席上珍。", "聊憑五經笥，一校九府緡。", "寧論尹卿筆，有志不自伸。", "探懷出銀黄，笑指漆水濱。", "房公嘯諾地，廐吏持朱輪。", "懸知涇渭間，廣畝連高囷。", "洪河潤九里，坐息西羌塵。", "長言繼豳風，耕稼可重陳。", "會當采謡俗，夜誦供華勛。"]'),
('6a672147-f9fa-4e2f-bf48-423062951305','周太博攜詩見投作詩酬之','程俱','宋','宋诗','song-poetry','','[]','在事常鬰鬰，抛官意揚揚。',108,'全唐诗/poet.song.82000.json','["在事常鬰鬰，抛官意揚揚。", "安能屈五斗，秉耒庸何傷。", "往者永康令，柴桑遠相望。", "烹魚得頳尾，縮手生背芒。", "投簪息吾駕，刺口時談王。", "坐見明月溪，柔柯擢長楊。", "願以三寸舌，横流制湯湯。", "櫑具驚曼倩，長裾識鄒陽。", "憑軾下賊壘，頹雲如壞墻。"]'),
('45be069c-50ba-44e6-b43c-e0f2df6ca604','初秋  其一','程俱','宋','宋诗','song-poetry','','[]','金天却炎威，二氣始交戰。',48,'全唐诗/poet.song.82000.json','["金天却炎威，二氣始交戰。", "雲奇未摧峰，江浄欲呈練。", "曉風清蟬腹，宿霧凝荷面。", "凉氣忽侵衣，庭花亂如霰。"]'),
('402c5b95-ad35-40a8-8935-58878dc5227b','初秋  其二','程俱','宋','宋诗','song-poetry','','[]','新凉發巾裾，欣此清夜永。',60,'全唐诗/poet.song.82000.json','["新凉發巾裾，欣此清夜永。", "寒蟲如泣恨，啾唧不可省。", "急節度霜砧，疏陰閟桐井。", "林搖澹月碎，葉颭幽露炯。", "坐久睇空簷，流螢點秋影。"]'),
('3e387e5d-72ef-4712-85dc-4c1f5409d09c','秀峰游戲效李長吉體','程俱','宋','宋诗','song-poetry','','["\u592a\u6e56"]','玉龍衝碧縈山脊，蜿蜿踏龍上穹碧。',144,'全唐诗/poet.song.82000.json','["玉龍衝碧縈山脊，蜿蜿踏龍上穹碧。", "神奇鬼巧鑱高青，露壓春煙染山色。", "舉頭便足千里遊，太湖萬頃涵天白。", "剪霞噀霧濕青紅，錦楣花礎明清空。", "松聲拂枕破幽夢，冰輪逗滑寒朣朧。", "殿角聯珠掛星斗，透冷飛光射疏牖。", "古香飄桂夜陰陰，雲樓報晚生銅吼。", "摧頹覊客青山人，悠悠九土飛紅塵。", "眼前歷歷千古意，琴臺不見吴宫春。"]'),
('e0aef47c-83a7-4fc0-a5ed-65fe1015b3d8','過顔幾故居有感','程俱','宋','宋诗','song-poetry','','[]','幽蘭忌當門，野馬難駕車。',240,'全唐诗/poet.song.82000.json','["幽蘭忌當門，野馬難駕車。", "顔生跅㢮士，一跌不可扶。", "少年豪於文，自擬靈蛇珠。", "生涯寄罇酒，醉目随飛鳬。", "興來不停筆，似覺膽力麄。", "開胸吐奇秀，濆湧春雲疏。", "嶔崎四五十，不挂薦士書。", "漫滅禰衡刺，佯狂阮生途。", "拂衣苕溪上，茅簷客東吴。", "懸鶉冬不完，脫粟午未餔。", "醉中有天地，别是仙翁壺。", "惜哉不覊才，白首甘窮閭。", "平時同袍客，半在青雲衢。", "音塵邈山河，豈顧荘魚枯。", "覊棲風塵下，日月雙馳駒。", "誰知聚沫身，倐去不可呼。", "死惟一函土，生獨四壁居。", "寄骸無尺地，傳業無遺孤。", "詩人多命薄，此語或不誣。", "吳天千古月，空照酒家壚。"]'),
('c8174d6a-f267-408b-b336-c6c9d7e0c2f8','登凌歊臺','程俱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','凌歊正在塵歊外，四起雲山翠欲浮。',96,'全唐诗/poet.song.82000.json','["凌歊正在塵歊外，四起雲山翠欲浮。", "丹檻昔時空勝事，錦袍何處想靈遊。", "鼇分一島來平野，鯨吸長江带兩州。", "手决飛雲天作幕，坐侵寒露月垂鈎。", "向來時有千巖夢，對此渾消萬古愁。", "醉目歸鴻天際沒，地高空闊更宜秋。"]'),
('43e734a0-983c-4714-b143-7354fc1613ae','同趙子雍過朱元益耜樂圃','程俱','宋','宋诗','song-poetry','','[]','秋風脫葉盡，弱質例可憎。',168,'全唐诗/poet.song.82000.json','["秋風脫葉盡，弱質例可憎。", "樂圃森老木，深蒼欝奔騰。", "中有白眉子，貎古心亦澄。", "歲寒儷松筠，豈直朱絲繩。", "籃輿一尋訪，相攜得良明。", "促膝對軟語，沉憂釋春冰。", "叢編出奇蹤，璀璨獻與凝。", "琱戈及篆鼎，往往見未曾。", "慚君傾佳釀，幽亭暮方登。", "但怪一林白，孤蟾自東升。", "斯須接詩戰，掉鞅苦不勝。", "羡子醉經史，吾方着弓矰。", "白眼安取轉，尊拳恐相仍。", "見子意已足，何須酒如澠。"]'),
('49118cde-ae3c-4293-a714-6269ddc1d96b','送朱伯原博士赴太學','程俱','宋','宋诗','song-poetry','','[]','朱公将赴成均時，炎炎六月雲峰奇。',144,'全唐诗/poet.song.82000.json','["朱公将赴成均時，炎炎六月雲峰奇。", "閶門鼓聲催畫鷁，陂塘菡萏方華滋。", "朝雲回首暮雲合，汗青嵬磊扃巖扉。", "先生顧此重惜去，片帆未肯乘風飛。", "賤子乃前致以詞，誠知去魯心遲遲。", "丈夫出處會有時，從來猿鶴焉能知。", "醇儒况復生盛世，終老巖穴将何爲。", "公其去矣莫迴首，君王仄席思賢久。", "公懷慷慨善哉言，挽舟便出楓橋口。"]'),
('06e7bd94-5cc8-4dc8-8f90-60ec69e66a30','送朱伯修延年入京秋試','程俱','宋','宋诗','song-poetry','','[]','朱生西遊不負書，胸中自有一千卷。',112,'全唐诗/poet.song.82000.json','["朱生西遊不負書，胸中自有一千卷。", "囊中亦不貯黄金，肯學癡兒事遊宴。", "會稽要待買臣歸，洛中須使張華見。", "扁舟去日春正深，嬌紅嫩白粉成林。", "沙頭酒盡一麾手，黄鸝亦作離羣首。", "明年射策先髦傑，晝繡還鄉春事歇。", "剰沽美酒膾鱸魚，同醉垂虹亭上月。"]'),
('5a87a837-b89e-4ed2-96ef-c8e530313b70','雪中口占二首  其一','程俱','宋','宋诗','song-poetry','','[]','萬木號風雪未乾，畫簷冰筯水精寒。',32,'全唐诗/poet.song.82000.json','["萬木號風雪未乾，畫簷冰筯水精寒。", "日高丈五猶慵起，夢到江湖理釣竿。"]'),
('51278df4-9245-41d4-86dd-33a5cc5930b3','雪中口占二首  其二','程俱','宋','宋诗','song-poetry','','[]','一夜滿城三尺雪，寒林枯木盡生春。',32,'全唐诗/poet.song.82000.json','["一夜滿城三尺雪，寒林枯木盡生春。", "盆池水窄成冰鑑，庭竹枝低掃玉塵。"]'),
('be5c02ad-48b1-4b06-ac0a-2125daedd830','和虞長洲遊虎丘','程俱','宋','宋诗','song-poetry','','[]','尋壑復經丘，人看李郭舟。',48,'全唐诗/poet.song.82000.json','["尋壑復經丘，人看李郭舟。", "藤花多背日，桐葉最知秋。", "虎去藜藿盡，龍歸蛙黽愁。", "振衣臨石壁，未羨習池遊。"]'),
('19f78a00-0456-41fb-b5d8-09b5cd8d9a2b','移竹','程俱','宋','宋诗','song-poetry','','[]','寓目無清致，興懷要此君。',96,'全唐诗/poet.song.82000.json','["寓目無清致，興懷要此君。", "影移千畝月，枝散五湖雲。", "鳯實和筠得，龍苞带籜分。", "傷根同柏大，剪葉異芝焚。", "拔篠衣霑粉，連鞭蘚破紋。", "虚心寧擇地，直節任離羣。", "但欲通三徑，何須比萬軍。", "凛然真玉立，蔓草即堪耘。"]'),
('bce6d370-5fed-4093-b9f4-839f0415c814','和友人陳傅道師仲司錄遣興之作','程俱','宋','宋诗','song-poetry','','[]','急景去不返，官遊心易闌。',48,'全唐诗/poet.song.82000.json','["急景去不返，官遊心易闌。", "死生交道絕，冷暖世情看。", "適俗須多可，随緣亦大難。", "一年還欲盡，三界直無安。"]'),
('7983fc80-d5ea-48d0-9d64-4a059d6d2078','沙塞松江','程俱','宋','宋诗','song-poetry','','[]','三江既入今安有，萬化無端去莫留。',64,'全唐诗/poet.song.82000.json','["三江既入今安有，萬化無端去莫留。", "蟹蚌失波枯斥岸，蛟龍移窟見沙洲。", "水窮范蠡扁舟返，海變麻姑兩鬢秋。", "通塞正應天數在，荷蓑持鍤直堪愁。"]'),
('8c9c795b-0307-4ed3-acfd-09966c3ea8cb','曉起','程俱','宋','宋诗','song-poetry','','[]','霜林一望極空寒，曉鼓催人覺夢殘。',64,'全唐诗/poet.song.82000.json','["霜林一望極空寒，曉鼓催人覺夢殘。", "黄霧带晴江渺渺，勁風翻影露漙漙。", "香飄引篆新添火，髪密勝簪慢整冠。", "藏拙懶便惟少事，興來閑借遠山看。"]'),
('9d629198-3211-47c0-ac4c-2907d496f598','餘杭法喜院荆文公書堂文公康定中讀書於此','程俱','宋','宋诗','song-poetry','','[]','鍾山太傅起從龍，鼓動風雷指顧中。',64,'全唐诗/poet.song.82000.json','["鍾山太傅起從龍，鼓動風雷指顧中。", "未見圖形求傅野，豈知徒步客新豐。", "青鞋曾訪餐芝老，白首惟餘擣藥童。", "藏壁故應留斷簡，至今山鬼慟悲風。"]'),
('26bb202a-af71-4652-9967-913c7d944cae','送蒋主簿入都赴試一首','程俱','宋','宋诗','song-poetry','','[]','東南貢吏紫髯郎，一馬駸駸客路長。',64,'全唐诗/poet.song.82000.json','["東南貢吏紫髯郎，一馬駸駸客路長。", "袖裏山林洗塵霧，腹中文字了縑箱。", "流年過我長如許，樂事知君詎未央。", "行恐饑來驅我去，也遮西日上河梁。"]'),
('6b92b8bb-75a6-4cdb-a6f1-3d65bc240981','罷吏客郡城已數月滯留忽已歲暮浩然興歎作一首','程俱','宋','宋诗','song-poetry','','[]','一行作吏向吴城，五見陬隅上薄冰。',64,'全唐诗/poet.song.82000.json','["一行作吏向吴城，五見陬隅上薄冰。", "魏覬三章堪自約，殷源百尺敢言登。", "揶揄祇送人爲郡，噎媢初非我負丞。", "鞅掌棲遲俱害性，不知鬚鬢欲侵凌。"]'),
('eefc8792-d090-46e5-a962-9ea9cc2bb5cc','寒夜遣懷一首','程俱','宋','宋诗','song-poetry','','[]','強醉重雲欲散鹽，三更飛霰忽驚簾。',64,'全唐诗/poet.song.82000.json','["強醉重雲欲散鹽，三更飛霰忽驚簾。", "大呼何與癡人事，此意多應俗士嫌。", "出戶仰看天漫漫，持盃愁作夜厭厭。", "消除心事都無處，下盡中軍三百籖。"]'),
('a46e85de-119a-458c-a031-c04cd10215bb','高郵旅泊書懷寄淮東提舉蔡成甫觀兼呈鄭使君弇三首  其一','程俱','宋','宋诗','song-poetry','','[]','久客頗自厭，長歌胡不歸。',48,'全唐诗/poet.song.82000.json','["久客頗自厭，長歌胡不歸。", "束書方有適，捧檄定焉依。", "塵裏音容改，山中信息稀。", "十年長漫浪，深覺負荷衣。"]'),
('fb6c63c7-03e5-479c-bfab-1be78b52673c','高郵旅泊書懷寄淮東提舉蔡成甫觀兼呈鄭使君弇三首  其二','程俱','宋','宋诗','song-poetry','','[]','命矣周南滯，時哉冀北空。',48,'全唐诗/poet.song.82000.json','["命矣周南滯，時哉冀北空。", "居無刮目視，動有轉喉窮。", "泛宅如蠻蜑，淫書伴蠧蟲。", "飄蓬故人念，賴有繡衣公。"]'),
('0a980e40-00df-417f-88e2-ed0d0c0df16e','高郵旅泊書懷寄淮東提舉蔡成甫觀兼呈鄭使君弇三首  其三','程俱','宋','宋诗','song-poetry','','[]','長夏熱欲死，迎秋氣已清。',48,'全唐诗/poet.song.82000.json','["長夏熱欲死，迎秋氣已清。", "蚊蠅任來往，螟螣尚縱横。", "行止厭人問，棲遲真自驚。", "使君高義在，解榻見深情。"]'),
('abc63dbd-15d4-4ba8-a819-1d2df3b032e3','喜雨呈鄭高郵','程俱','宋','宋诗','song-poetry','','[]','赤地無遺蘖，懸知一歲空。',72,'全唐诗/poet.song.82000.json','["赤地無遺蘖，懸知一歲空。", "乖龍忽解事，死虎亦爭功。", "土燥財霑塊，人安未轉蓬。", "翻思瀉東海，何計請天公。", "田畝膏腴闊，河流脉絡通。", "邦人依豈弟，指日望登豐。"]'),
('c30933e0-9bef-4246-a6e8-4a39d46f3eac','人日書懷兼呈吴中二三友','程俱','宋','宋诗','song-poetry','','[]','東西南北走紅塵，又見江淮草木薫。',64,'全唐诗/poet.song.82000.json','["東西南北走紅塵，又見江淮草木薫。", "小謝篇章成畫餅，卧龍功略付浮雲。", "棲遲枳棘今如許，嘯傲冰霜賴此君。", "俛俯折腰成底事，故交千里漫離羣。"]'),
('69c9cbda-a77a-4664-abf9-c1a8ba235310','許主簿見和過有推借再作奉呈','程俱','宋','宋诗','song-poetry','','[]','身謀自昔須三窟，世味端能敗一薫。',64,'全唐诗/poet.song.82000.json','["身謀自昔須三窟，世味端能敗一薫。", "醉裏閑愁濃似酒，春來歸思亂於雲。", "松栽咫尺傳盧老，棗實方将訪許君。", "却喜雲孫共來往，扁舟時入白鷗群。"]'),
('1fc7aed9-5786-4842-b8ad-f24f9dcacda1','用前韻作招許主簿','程俱','宋','宋诗','song-poetry','','[]','風騷無復見黄初，尚想應劉載後車。',64,'全唐诗/poet.song.82000.json','["風騷無復見黄初，尚想應劉載後車。", "病骨不知緣底事，愁眉時得爲君舒。", "動人春色來随鷰，入眼溪流静見魚。", "祇有此中多好句，可來茅閣試憑虚。"]'),
('5d84c79b-8d60-4e1e-854d-14d03503bf03','謹追和諸父留題雲門聲闍黎經閣詩一首','程俱','宋','宋诗','song-poetry','','[]','傑閣護真文，金仙妙大雲。',48,'全唐诗/poet.song.82000.json','["傑閣護真文，金仙妙大雲。", "風林終日說，露柱一時聞。", "谷暖春先到，山高日易曛。", "經行復宴坐，華雨任繽紛。"]'),
('19632486-06da-4d7d-8d10-1be01626f379','適軒','程俱','宋','宋诗','song-poetry','','[]','厭苦常從樂未央，不如要足兩俱忘。',64,'全唐诗/poet.song.82000.json','["厭苦常從樂未央，不如要足兩俱忘。", "當饑糲食遺三鼎，便體綈袍勝五章。", "夜雪扁舟千嶂凈，午風高枕一窗凉。", "飄然自適非人適，肯受轅駒六尺韁。"]'),
('46b186d8-d052-4acb-ab7e-55a1dc327ef1','謝江仲舉惠酒','程俱','宋','宋诗','song-poetry','','[]','山城無物可忘憂，但有平原病督郵。',64,'全唐诗/poet.song.82000.json','["山城無物可忘憂，但有平原病督郵。", "知我囊中無白水，煩君若下出青州。", "芳甘未謝三羊醖，傲兀能消萬古愁。", "會待東郊春意動，鳴鞭乘興草堂遊。"]'),
('fe5b0155-60d4-465f-8c87-12c5406e4c9c','次韵張祠部見示','程俱','宋','宋诗','song-poetry','','[]','大滌先生不諱貧，鬢髯雖白臉長春。',64,'全唐诗/poet.song.82000.json','["大滌先生不諱貧，鬢髯雖白臉長春。", "三江魚美東曹後，二柳泉甘慧曉鄰。", "懷組歸來無長物，挂冠誰復並清塵。", "自憐出處俱違性，旋結衡茅寄此身。"]'),
('35f297a4-7125-45e8-b0bf-c70bf6858017','章僕射山林','程俱','宋','宋诗','song-poetry','','[]','王子池臺迹已荒，年來華構壓高岡。',64,'全唐诗/poet.song.82000.json','["王子池臺迹已荒，年來華構壓高岡。", "長林不礙千山月，老榦猶含九夏霜。", "便覺平泉冠東洛，還依淥水記南塘。", "蝸廬却喜通幽徑，岸幘時來一嘯長。"]'),
('e4646090-1cdf-4606-a602-d6ba07296308','次韻張祠部敏叔游滄浪蘇子美故園','程俱','宋','宋诗','song-poetry','','[]','醉倒春風載酒人，蒼髯猶想見長身。',64,'全唐诗/poet.song.82000.json','["醉倒春風載酒人，蒼髯猶想見長身。", "試尋遺址名空在，却歎張羅事已陳。", "稍置曲欄穿徑竹，别開高閣俯汀蘋。", "拏舟更欲陪清賞，要看毫端藻繪春。"]'),
('0514a781-2708-4563-aae0-d683707fced3','次韵鄭大夫半隱亭','程俱','宋','宋诗','song-poetry','','[]','脫屣歸來稅兩轓，信知塵世有蕭閑。',64,'全唐诗/poet.song.82000.json','["脫屣歸來稅兩轓，信知塵世有蕭閑。", "幽亭似近郎君谷，捷徑知非少室山。", "歲月優游真得計，風塵憔悴獨何顔。", "園林日涉仍多趣，坐看雲飛鳥倦還。"]'),
('19fd9d6d-6c5e-40d6-9a3f-289bc175496a','哦詩夜坐缾罍久空無以自勞寄吴興趙司錄江兵曹','程俱','宋','宋诗','song-poetry','','[]','詩成不直一杯水，年大常懷千歲憂。',64,'全唐诗/poet.song.82000.json','["詩成不直一杯水，年大常懷千歲憂。", "何須中令能強記，正要将軍爲破愁。", "故人久負丘壑志，公子欲尋梁宋游。", "相逢儻有蒲萄淥，肯向西凉博一州。"]'),
('e8a443e7-8ed3-47c9-8b0f-fd4625db058b','九日寫懷','程俱','宋','宋诗','song-poetry','','[]','節物驚心兩鬢華，東籬空繞未開花。',64,'全唐诗/poet.song.82000.json','["節物驚心兩鬢華，東籬空繞未開花。", "百年将半仕三已，五畝就荒天一涯。", "豈有白衣來剝啄，亦從烏帽自欹斜。", "真成獨坐空搔首，門柳蕭蕭噪暮鴉。"]'),
('0b47e7dd-64f1-4163-8f84-f4a4aa9409bb','次韵葉翰林見寄  其一','程俱','宋','宋诗','song-poetry','','[]','雅望清班亦醉翁，暫令槐閣曳鈴空。',64,'全唐诗/poet.song.82000.json','["雅望清班亦醉翁，暫令槐閣曳鈴空。", "更評他日歸賢守，畫諾何人稱治中。", "便合追鋒來就日，已知投刃有成風。", "貽書千里兼金意，俎豆常憐斷尾雄。"]'),
('b1f600c1-54dd-447d-826c-640dc3f3bfca','次韵葉翰林見寄  其二','程俱','宋','宋诗','song-poetry','','[]','相望千古一涪翁，還向江湖四壁空。',64,'全唐诗/poet.song.82000.json','["相望千古一涪翁，還向江湖四壁空。", "病目自甘桃李後，野麋難着鳯麟中。", "未成下澤還鄉里，且寄窮閻蔽雨風。", "舉世知音常契闊，空悲沉抑爲誰雄。"]'),
('297dca2e-c907-4a93-8f28-268f9d5f7646','傅國華從使遼東已事還朝拙詩送别  其一','程俱','宋','宋诗','song-poetry','','[]','夫君胸次有天游，笑指滄溟寄一漚。',64,'全唐诗/poet.song.82000.json','["夫君胸次有天游，笑指滄溟寄一漚。", "正使叩舷歌小海，不妨安席詠洪流。", "翩翩聊試千金學，刺刺應慚萬里侯。", "歸袖飄然望華闕，獨留珠玉照遐幽。"]'),
('0a57dd5d-cae4-4afa-9200-b60c594ee076','傅國華從使遼東已事還朝拙詩送别  其二','程俱','宋','宋诗','song-poetry','','[]','向來南北歎流年，十載相逢走道邊。',64,'全唐诗/poet.song.82000.json','["向來南北歎流年，十載相逢走道邊。", "作佛頓慚靈運後，着鞭猶恐祖生先。", "彈冠豈欲夸三組，負耒還思受一廛。", "默計此身端未了，别懷撩亂故依然。"]'),
('f04b96e1-25bf-4f09-a99e-3dbe21c9f41a','窮居苦雨','程俱','宋','宋诗','song-poetry','','[]','慢膚便腹轉疏慵，睡足茅簷目過鴻。',64,'全唐诗/poet.song.82000.json','["慢膚便腹轉疏慵，睡足茅簷目過鴻。", "墨客縱令三尺喙，木奴何似十年功。", "門前羅雀非吾病，竈底生蛙不世窮。", "舊雨未乾新雨漲，可憐愁絕力田翁。"]'),
('8519b351-28d4-448f-9971-4cc5bb47ef59','謝張敏叔餉陸子泉','程俱','宋','宋诗','song-poetry','','[]','接輿叩木狂歌處，猶有清泉出翠微。',64,'全唐诗/poet.song.82000.json','["接輿叩木狂歌處，猶有清泉出翠微。", "不學癡人供水遞，肯分餘潤及柴扉。", "七甌已辦煎茶厄，三咽能忘啜菽饑。", "身寄吴門聲利窟，更思冰洞濯塵衣。"]'),
('612f5b6d-f2ab-4dfb-b16e-c8d5df0af01b','張敏叔得請謝事欽俯高躅因成口號','程俱','宋','宋诗','song-poetry','','[]','富貴紛紛有底難，乘時如探槖中丸。',64,'全唐诗/poet.song.82000.json','["富貴紛紛有底難，乘時如探槖中丸。", "高人不啻曇華見，晚節誰爲趙璧完。", "且喜芝蘭俱秀發，不嫌松桂愈清寒。", "他年仄席思耆舊，矍鑠猶能一據鞍。"]'),
('46d1cbfc-19e4-4f91-85f5-8b71f4608966','晚雨菊','程俱','宋','宋诗','song-poetry','','[]','異質寧當雜衆芳，故留寒潁度微霜。',64,'全唐诗/poet.song.82000.json','["異質寧當雜衆芳，故留寒潁度微霜。", "三鍰何必分靈樹，九畹那能擅國香。", "不惜繁英供夕餌，肯持佳色媚朝陽。", "徑須移奉華堂燕，路草多應愧久妨。"]'),
('033f6a9a-e00d-4101-a095-7cc5c9cb6956','葉內相赴淮西','程俱','宋','宋诗','song-poetry','','[]','向來英妙壓鼇頭，去國三年白鬢秋。',64,'全唐诗/poet.song.82000.json','["向來英妙壓鼇頭，去國三年白鬢秋。", "蕭傅豈煩更吏治，賈生元自贊皇猷。", "高文已得江山助，遠業寧爲管晏留。", "聞說雲亭已除地，正須椽筆紀鴻休。"]'),
('14b126ab-fc5f-4823-ba86-5bfd6975b728','江仲嘉仕吴興雅重道場山長老惠顔仲嘉之柩以八月十五日至山下顔以是日告寂','程俱','宋','宋诗','song-poetry','','[]','道人非復世間情，居士空留身後名。',64,'全唐诗/poet.song.82000.json','["道人非復世間情，居士空留身後名。", "共擬凌雲成一笑，不妨乘月話三生。", "桐鄉定有蟬衣在，葱嶺遙知虎錫鳴。", "耿耿幽懷無處寫，眼中泉石記經行。"]'),
('3e049abb-1b96-44ea-b207-7f75ed0c5486','觀王君玉侍郎集有酒明詩次韻','程俱','宋','宋诗','song-poetry','','[]','簿領青州掾，風姿麴秀才。',48,'全唐诗/poet.song.82000.json','["簿領青州掾，風姿麴秀才。", "長煩拍浮手，持贈合歡杯。", "屢舞回風急，傳籌白羽催。", "深慚偃師氏，端爲破愁來。"]'),
('c28bed8d-82ba-4252-97f2-d378d3e4265c','九日陪章湖州致平援登道埸山泛舟溪上','程俱','宋','宋诗','song-poetry','','[]','九日登臨得翠微，拂天松竹引丹梯。',64,'全唐诗/poet.song.82000.json','["九日登臨得翠微，拂天松竹引丹梯。", "神遊八表層霄近，目盡千山落日低。", "人散飛雲留畫棟，舟回初月照清溪。", "故知王謝風流在，吹帽何人醉似泥。"]'),
('c3d9de74-4fc3-447f-b548-0c5447457441','次韵趙叔問對雪共酌有懷江仲嘉之作','程俱','宋','宋诗','song-poetry','','[]','怳然身寄一山川，玉宇銀墻墮我前。',64,'全唐诗/poet.song.82000.json','["怳然身寄一山川，玉宇銀墻墮我前。", "欲便乘風向寥廓，恨無新句落雲烟。", "延枚座右頻虚席，訪戴人遐歎獨賢。", "遙想支頤對秦望，朝來清思浩無邊。"]'),
('ad93d5ec-b78b-436b-8d3f-3da98cdfebf5','癸巳歲除夜誦孟浩然歸終南舊隱詩有感戲效沈休文八詠體作 北闕休上書','程俱','宋','宋诗','song-poetry','','[]','說將且不暇，于時真自疏。',48,'全唐诗/poet.song.82000.json','["說將且不暇，于時真自疏。", "深慚叔孫子，未辦茂陵書。", "正自饑欲死，敢言忠有餘。", "平生畎畝志，本不羡嚴除。"]'),
('14a1d335-3d54-4bfe-a6ff-6f90b2c3c612','癸巳歲除夜誦孟浩然歸終南舊隱詩有感戲效沈休文八詠體作 南山歸敝廬','程俱','宋','宋诗','song-poetry','','[]','故廬今茂草，新構羡茅茨。',48,'全唐诗/poet.song.82000.json','["故廬今茂草，新構羡茅茨。", "久慕泉石約，空令猿鶴悲。", "一廛端可共，三徑復誰期。", "會結忘年友，歸雲茹紫芝。"]'),
('36912427-5f06-4092-9f18-85b8af6cfe55','癸巳歲除夜誦孟浩然歸終南舊隱詩有感戲效沈休文八詠體作 不才明主棄','程俱','宋','宋诗','song-poetry','','[]','沃壤有多稼，良工無廢材。',48,'全唐诗/poet.song.82000.json','["沃壤有多稼，良工無廢材。", "固知時不棄，正坐老無媒。", "病驥終難駕，寒花不易開。", "古來天下士，取次沒蒿萊。"]'),
('afb4ac4f-6198-4710-8962-e27321e7a5f4','癸巳歲除夜誦孟浩然歸終南舊隱詩有感戲效沈休文八詠體作 多病故人疏','程俱','宋','宋诗','song-poetry','','[]','雁足慵難寄，雞棲出厭頻。',48,'全唐诗/poet.song.82000.json','["雁足慵難寄，雞棲出厭頻。", "路長時有夢，人遠遽如新。", "膠漆唯窮士，雲泥隔要津。", "囂囂亦何病，懶放任天真。"]'),
('3ec4f6d4-7451-405d-a580-91e4428ee5e0','癸巳歲除夜誦孟浩然歸終南舊隱詩有感戲效沈休文八詠體作 白髪催年老','程俱','宋','宋诗','song-poetry','','[]','轉眼過三紀，搔頭見二毛。',48,'全唐诗/poet.song.82000.json','["轉眼過三紀，搔頭見二毛。", "先秋同柳弱，早白誤山高。", "種種從渠落，青青竟莫逃。", "形骸姑置此，痛飲讀離騷。"]'),
('3c2a61e2-da7f-4a55-af02-c5a3fbb4d633','癸巳歲除夜誦孟浩然歸終南舊隱詩有感戲效沈休文八詠體作 青陽逼歲除','程俱','宋','宋诗','song-poetry','','[]','憔悴身仍健，峥嶸歲又窮。',48,'全唐诗/poet.song.82000.json','["憔悴身仍健，峥嶸歲又窮。", "天寒春未應，臘盡雪初融。", "萬化豈有極，一生常轉蓬。", "誰知元不動，日月自西東。"]'),
('bdecd706-5071-4ab9-bcae-8cfbd245da9e','癸巳歲除夜誦孟浩然歸終南舊隱詩有感戲效沈休文八詠體作 永懷愁不寐','程俱','宋','宋诗','song-poetry','','[]','腷膞南枝鵲，鏗宏半夜鐘。',48,'全唐诗/poet.song.82000.json','["腷膞南枝鵲，鏗宏半夜鐘。", "寥寥數寒漏，唧唧類吟蛩。", "馬革思強仕，牛衣慕老農。", "此身何處是，展轉聽朝舂。"]'),
('e988a650-fc74-4a23-ada7-f92ed600c96f','癸巳歲除夜誦孟浩然歸終南舊隱詩有感戲效沈休文八詠體作 松月夜窗虚','程俱','宋','宋诗','song-poetry','','[]','透隙風號屋，翻簷雪灑窗。',48,'全唐诗/poet.song.82000.json','["透隙風號屋，翻簷雪灑窗。", "遙知迷九澤，似欲卷三江。", "引睡翻書帙，澆愁泥酒缸。", "無因踏松月，癡坐對青釭。"]'),
('21769d4d-43c8-4351-bdbb-53e8b715b1d7','避寇村舍','程俱','宋','宋诗','song-poetry','','[]','再脫兵戈裏，全家走路塵。',48,'全唐诗/poet.song.82000.json','["再脫兵戈裏，全家走路塵。", "百年同是客，萬事不如人。", "幻境終歸盡，生涯正要貧。", "故人知在否，魂斷楚江濱。"]'),
('22b0ff32-e2a5-4983-a3e6-ba4682e22a21','哭王元規','程俱','宋','宋诗','song-poetry','','[]','華顛傾蓋便忘年，信有烏衣不乏賢。',64,'全唐诗/poet.song.82000.json','["華顛傾蓋便忘年，信有烏衣不乏賢。", "膝上中郎名譽早，湖南司馬歲時遷。", "去天尺五非無地，擊水三千竟莫前。", "唇齒五車真底用，人琴冥漠付重泉。"]'),
('09420c89-715d-418d-8e49-3cc645fba467','和答何蒙聖删定','程俱','宋','宋诗','song-poetry','','[]','胸中林壑寄商顔，門外紅塵了不關。',64,'全唐诗/poet.song.82000.json','["胸中林壑寄商顔，門外紅塵了不關。", "年去人猶昔人耳，身游才與不才間。", "與君同覺夢中夢，顧我長嗟山復山。", "何日方舟歸里社，韋編應許試窺班。"]'),
('7f293c35-bb7b-4c91-8a59-a93e458cf284','江仲嘉書稱去常山靈真洞半里許得林壑殊勝余記昔過謝源道中亂峰峭壁間竹樹薈蘙今仲嘉所稱得非此耶因寄百二十字','程俱','宋','宋诗','song-poetry','','[]','聞說靈真路，旁開小洞天。',144,'全唐诗/poet.song.82000.json','["聞說靈真路，旁開小洞天。", "蒼巒閟清境，陸地接飛仙。", "壁立驚猿掛，松枯老蔓纒。", "攢空永亭石，潄壑定林泉。", "烟磴盤三徑，玄窗属五便。", "武陵迷漢魏，妙憙斷山川。", "騰絕端如此，經營有老焉。", "烹魚幾折屐，命駕擬加鞭。", "易秃三千丈，寧辭四萬錢。", "把茅應早計，拱木歎流年。", "鴻鵠須塵外，鵷鸞自日邊。", "人生各有在，雅志共超然。"]'),
('e69bc271-18bc-4cbf-bf42-6a128056724b','鄒侍郎挽詞二首  其一','程俱','宋','宋诗','song-poetry','','[]','蠻貊人無間，鄉閭行益尊。',48,'全唐诗/poet.song.82000.json','["蠻貊人無間，鄉閭行益尊。", "芝蘭有餘化，桃李竟無言。", "遠日來千兩，他年歎九原。", "死生如可作，安用百身存。"]'),
('5fe539c8-2725-49c6-acf0-c14b71db6bc9','鄒侍郎挽詞二首  其二','程俱','宋','宋诗','song-poetry','','[]','夷跖雖殊趣，彭殤共一歸。',48,'全唐诗/poet.song.82000.json','["夷跖雖殊趣，彭殤共一歸。", "投荒萬里再，乘化百年非。", "細行皆無憾，常言亦造微。", "祇應存信史，千古有沾衣。"]'),
('22db6707-e65e-410f-b0e7-a1070452758d','與蒋子有道丁田相從吴下之適感而賦詩','程俱','宋','宋诗','song-poetry','','[]','三徑旁臨招隱溪，子真池館叩林扉。',64,'全唐诗/poet.song.82000.json','["三徑旁臨招隱溪，子真池館叩林扉。", "拏舟雪夜多乘興，步屧春風每醉歸。", "居舍相望一牛吼，官途常作二鳬飛。", "試尋邀月持杯地，共覺勞生四十非。"]'),
('437660c7-3d67-4dcd-af55-7b32660a864e','暴書會和陳正字磷觀御製書二首  其一','程俱','宋','宋诗','song-poetry','','[]','龍檢金壺記子年，寥陽宫殿玉虚前。',64,'全唐诗/poet.song.82000.json','["龍檢金壺記子年，寥陽宫殿玉虚前。", "三元初識皇文袐，八法爭看御墨鮮。", "叢簡舊藏丹蘂箧，羣仙疑近白蛙泉。", "隆樓縹緲侵雲漢，神物撝呵衛九天。"]'),
('a38c4823-0b45-47ea-ac0b-d7b4cafad06b','暴書會和陳正字磷觀御製書二首  其二','程俱','宋','宋诗','song-poetry','','[]','七聖雲章秘紫清，睿謨神藻發長生。',64,'全唐诗/poet.song.82000.json','["七聖雲章秘紫清，睿謨神藻發長生。", "六爻妙盡超龍瑞，千里真修敘廣成。", "但覺焕文驚俗眼，何勞掘筆避書名。", "法宫涵演方無盡，玉海濡毫卷四瀛。"]'),
('ad61d4cc-939d-45ad-b265-7b23aa0075db','送傅舍人國華使高麗二首  其一','程俱','宋','宋诗','song-poetry','','[]','長嘯溟波又一遊，眼中壺嶠接滄洲。',64,'全唐诗/poet.song.82000.json','["長嘯溟波又一遊，眼中壺嶠接滄洲。", "紫薇垣近三台象，銀漢槎浮八月秋。", "七制還須補天筆，二帆聊展濟川舟。", "從容歸奏承清問，膏澤東南四十州。"]'),
('2f5907fe-5421-491c-be12-3a8adf3d892b','送傅舍人國華使高麗二首  其二','程俱','宋','宋诗','song-poetry','','[]','翩翩淥水泛紅蓮，一紀重來擁使旜。',64,'全唐诗/poet.song.82000.json','["翩翩淥水泛紅蓮，一紀重來擁使旜。", "雲外兩星明漢莭，海東千里戴堯天。", "舊聞箕子多遺俗，會使匃奴失左肩。", "五十年來蒙惠渥，故應微風莫深鐫。"]'),
('2969ede6-59b9-45aa-bcfa-257b24bc2b00','送朱職方希亮出使利州路二首  其一','程俱','宋','宋诗','song-poetry','','[]','許下多名士，朱公盛德人。',48,'全唐诗/poet.song.82000.json','["許下多名士，朱公盛德人。", "懷文深自匿，謀道不求伸。", "雅望臺中妙，宣恩劍外春。", "聊憑巴漢水，一洗九街塵。"]'),
('b265aec1-ffdd-48aa-9780-fcf562d4dfa6','送朱職方希亮出使利州路二首  其二','程俱','宋','宋诗','song-poetry','','[]','星使出文昌，仍分古華陽。',48,'全唐诗/poet.song.82000.json','["星使出文昌，仍分古華陽。", "過家真晝繡，擁節異懷章。", "泛應超餘刃，深心即道埸。", "前旒須獻納，早晚侍明光。"]'),
('112e9050-0742-4976-b68f-a47578a5a2ec','和江仲嘉見寄  其一','程俱','宋','宋诗','song-poetry','','[]','蓽門蓬舍不知春，車似雞栖甑有塵。',64,'全唐诗/poet.song.82000.json','["蓽門蓬舍不知春，車似雞栖甑有塵。", "千里傳情望雙鯉，一杯和影祇三人。", "交親離合同巢燕，身世覉危獨繭綸。", "四體不勤心擾擾，擬将玄旨問吴筠。"]'),
('fc32be0f-a9ed-4131-b9c6-3edc01703fbf','和江仲嘉見寄  其二','程俱','宋','宋诗','song-poetry','','[]','寒谷應殊尺五天，鹽車無復望騰騫。',64,'全唐诗/poet.song.82000.json','["寒谷應殊尺五天，鹽車無復望騰騫。", "至人未免填溝壑，大隱不如居市廛。", "長笑呼鷹思上蔡，獨令留石在平泉。", "茅茨欲作終焉計，未有滄浪四萬錢。"]'),
('c29a6ee4-dbcd-43e3-a72c-1ac4c8fbad9f','何蒙聖挽詞二首  其一','程俱','宋','宋诗','song-poetry','','[]','倦遊初返北山農，一面忘年得此翁。',64,'全唐诗/poet.song.82000.json','["倦遊初返北山農，一面忘年得此翁。", "易學知公無復過，詩窮如我敢言工。", "安知接跡金蘭直，便作回頭夢幻空。", "本自無生今豈滅，不因吾道有西東。"]'),
('bfccd510-483e-4196-853a-f5e76eb2e1fa','何蒙聖挽詞二首  其二','程俱','宋','宋诗','song-poetry','','[]','五籍紛綸井大春，一言超詣阮參軍。',64,'全唐诗/poet.song.82000.json','["五籍紛綸井大春，一言超詣阮參軍。", "王門設醴重經席，藏室讎書老蠧芸。", "問字毫釐分鳥跡，論文領略到皇墳。", "他年宿草傷心地，千里衢山隔暮雲。"]'),
('2b7debae-ce69-4594-b052-391415b04f57','酬潁昌葉內翰見招','程俱','宋','宋诗','song-poetry','','[]','觸石西遊泝濁波，京華旅食謝經過。',64,'全唐诗/poet.song.82000.json','["觸石西遊泝濁波，京華旅食謝經過。", "年侵鏡裏今如此，歌缺壺邊可奈何。", "賓閣遙知懸玉麈，直廬應許到金坡。", "須公一節趨環召，猶及昆明百步荷。"]'),
('e7ef3e0e-0b0f-47d9-a7a4-2ba0d88c62fc','旅舍寫懷','程俱','宋','宋诗','song-poetry','','[]','半世江湖寄此身，冰墟何意及陽春。',64,'全唐诗/poet.song.82000.json','["半世江湖寄此身，冰墟何意及陽春。", "離騷痛飲非名士，款段還鄉亦善人。", "病木作花真強活，長魚沉陸恐摧鱗。", "清時英俊如麻葦，敢歎長年甑有塵。"]'),
('cdcf9098-4d03-4e71-9433-f65eda7336c0','酬葉翰林喜某除官東觀  其一','程俱','宋','宋诗','song-poetry','','[]','冰谷難通杜曲天，淺聞那識絳人年。',64,'全唐诗/poet.song.82000.json','["冰谷難通杜曲天，淺聞那識絳人年。", "揮斤始免從輪扁，操牘寧堪佐史遷。", "正恐商樊譏浪仕，可令齊魯歎無傳。", "笭箵挂壁空回首，林有孫枝竹長鞭。"]'),
('bc968c2f-b41c-4599-8736-ea4e4e1a5f4d','酬葉翰林喜某除官東觀  其二','程俱','宋','宋诗','song-poetry','','[]','列宿羅胸妙補天，巨鼇峰頂號耆年。',64,'全唐诗/poet.song.82000.json','["列宿羅胸妙補天，巨鼇峰頂號耆年。", "致君舊擬唐虞上，去國徒驚歲月遷。", "夢筆絲綸建瓴下，憇棠膏澤置郵傳。", "平生傾倒燕臺意，可使英豪慕執鞭。"]'),
('085d0373-85b1-4ecb-ac34-5107d6cf928c','送葉善卷致仕歸吴','程俱','宋','宋诗','song-poetry','','[]','衛尉新除蓋次公，便抛簪紱向江東。',64,'全唐诗/poet.song.82000.json','["衛尉新除蓋次公，便抛簪紱向江東。", "秋鱸正與蓴絲美，夜鶴休驚蕙帳空。", "滿腹詩書元未試，會心林壑與誰同。", "自憐華髪無歸處，慚愧冥冥物外鴻。"]'),
('c1e1d17d-85f5-47b7-9358-e44779e0ede6','和同舍雪晴即事','程俱','宋','宋诗','song-poetry','','[]','雪消晴沼漲微波，一局文楸比爛柯。',64,'全唐诗/poet.song.82000.json','["雪消晴沼漲微波，一局文楸比爛柯。", "塵外清霄三島近，日邊春色五雲多。", "不妨窈窕耽書癖，時遣旗搶戰睡魔。", "洶湧詩情何所似，九軍雷動伐靈鼉。"]'),
('71f5ea1d-e381-4b27-a823-d5159ab5f8de','和同舍上元迎駕起居','程俱','宋','宋诗','song-poetry','','[]','瓊構浮空錦作山，五門遙比望金鑾。',64,'全唐诗/poet.song.82000.json','["瓊構浮空錦作山，五門遙比望金鑾。", "燭龍飛度崑丘曉，玉斧修成寶鑑寒。", "便覺冰荷回暖律，怳疑雲翼傅靈丸。", "都人喜色瞻鸞蓋，更擬交光雪未殘。"]'),
('7335d7f3-6f90-48b2-bdd3-4e093b82ee54','和同舍夏日四詩  其一','程俱','宋','宋诗','song-poetry','','[]','寒暑不到處，翛然天地中。',48,'全唐诗/poet.song.82000.json','["寒暑不到處，翛然天地中。", "夏冰聊善幻，性水自真空。", "松壑凝寒露，荷燈障遠風。", "峨峨欲千仞，扇暍意無窮。"]'),
('5ceed983-0f3e-4d93-8180-96e2b3f6e9ab','和同舍夏日四詩  其二','程俱','宋','宋诗','song-poetry','','[]','曉來風破睡，天外失參横。',48,'全唐诗/poet.song.82000.json','["曉來風破睡，天外失參横。", "雨作刻漏下，人思江海傾。", "林塘回秀色，廛市亦歡聲。", "漏屋吾無憾，聊蘇秉耒氓。"]'),
('b71728d1-b4a3-4386-acaf-e106d58bba9d','和同舍夏日四詩  其三','程俱','宋','宋诗','song-poetry','','[]','夜氣接平旦，微凉生太虚。',48,'全唐诗/poet.song.82000.json','["夜氣接平旦，微凉生太虚。", "庭槐秋影動，簷月曉光餘。", "執熱寧無間，探湯固有初。", "斯須銜燭轉，汗漬羽陵書。"]'),
('abf256ee-accf-4302-a92a-8fb630e3aae8','和同舍夏日四詩  其四','程俱','宋','宋诗','song-poetry','','[]','赤日不可度，紅塵能許深。',48,'全唐诗/poet.song.82000.json','["赤日不可度，紅塵能許深。", "糞除知有意，垢净亦惟心。", "葉落石門曉，花殘桃徑吟。", "安知煩溽地，擁篲却流金。"]'),
('28934b94-f638-4987-b5f8-946d69e8ef94','車駕幸袐書省口號  其一','程俱','宋','宋诗','song-poetry','','[]','端門清蹕隱修廊，麟省新開接建章。',64,'全唐诗/poet.song.82000.json','["端門清蹕隱修廊，麟省新開接建章。", "六玉虬飛黄道穩，五芝華聳頳袍光。", "風生凡腋天顔近，春入仙洲晝漏長。", "拭目訓詞成飽德，共瞻雲日仰陶唐。"]'),
('d6478463-03d7-4bf4-92b2-3a5de99d8317','車駕幸袐書省口號  其二','程俱','宋','宋诗','song-poetry','','[]','清塵膏雨浹人寰，金殿晴開瑞霧間。',64,'全唐诗/poet.song.82000.json','["清塵膏雨浹人寰，金殿晴開瑞霧間。", "帝座騰輝臨璧府，飈輪紆景按蓬山。", "龍鸞初識昭回迹，麑鹿驚随侍從班。", "再拜逡巡戴君賜，却迎天仗款賢關。"]'),
('a73d87a6-4cfe-4393-b42f-45df6090a9e5','和田龍圖升之登秋宴口号  其一','程俱','宋','宋诗','song-poetry','','[]','赭黄高拱玉霄間，金殿祥驎九色斑。',64,'全唐诗/poet.song.82000.json','["赭黄高拱玉霄間，金殿祥驎九色斑。", "湛露恩濃開鎬宴，大風歌奏仰龍顔。", "自驚垂老抛農畝，浪逐羣仙款帝關。", "銀甕白環方紀瑞，汗青修竹盡南山。"]'),
('29dc0e22-bfb0-457e-bdc0-2330b1dd57c4','和田龍圖升之登秋宴口号  其二','程俱','宋','宋诗','song-poetry','','[]','矍鑠仍堪将帥間，壮猷聊與虎臣班。',64,'全唐诗/poet.song.82000.json','["矍鑠仍堪将帥間，壮猷聊與虎臣班。", "公車獻賦城南杜，郎省興嗟北地顔。", "合殿千官瞻黼扆，中天雙闕敞瓊關。", "彤庭拜舞嵩三呼，延閣干雲真道山。"]'),
('d0b60a89-9f84-4450-af48-2f51f466f792','林德祖有詩寄光祿蒋卿夢錫堦及送朱博士駿發終篇皆見及次韻寄懷  其一','程俱','宋','宋诗','song-poetry','','[]','閉門那復賦三都，傳世何妨強著書。',64,'全唐诗/poet.song.82000.json','["閉門那復賦三都，傳世何妨強著書。", "東海遺榮行路歎，南山歸隱故人疏。", "尚平婚嫁無餘累，摩詰身心即凈居。", "六十挂冠雖早計，絕勝銜索泣枯魚。"]'),
('2bd4cc99-87f8-493d-91ad-e97a51b31e32','林德祖有詩寄光祿蒋卿夢錫堦及送朱博士駿發終篇皆見及次韻寄懷  其二','程俱','宋','宋诗','song-poetry','','[]','金華王府九天開，夜誦何人薦逸才。',64,'全唐诗/poet.song.82000.json','["金華王府九天開，夜誦何人薦逸才。", "太學諸生終莫挽，長沙賢傅幾時來。", "别離傳恨空魚素，歲月如飛逐管灰。", "亦欲相追老湖海，稽山肯放酒船回。"]'),
('740c967c-109d-43a6-8063-a3329c57fe49','和江子我端友','程俱','宋','宋诗','song-poetry','','[]','雨脚初收曉霧開，青鞋布韈好追陪。',64,'全唐诗/poet.song.82000.json','["雨脚初收曉霧開，青鞋布韈好追陪。", "幽人無事常相見，佳句有時還自來。", "白業誰能超石壁，朱顔亦任發春醅。", "憂來忽憶燕南信，安得閿鄉老萬回。"]'),
('1122b03a-0222-4cfb-b973-b46b7e8b1b9b','齒落','程俱','宋','宋诗','song-poetry','','[]','年運過半百，齒搖先右車。',48,'全唐诗/poet.song.82000.json','["年運過半百，齒搖先右車。", "朝來忽自墮，笑罷却成嗟。", "鶴髪情知爾，牛呞老更加。", "舌柔真足恃，寂默寄生涯。"]'),
('f6690787-c70a-4577-8d5d-7d4be811600c','種蓮','程俱','宋','宋诗','song-poetry','','[]','不向東林社，聊分玉井蓮。',48,'全唐诗/poet.song.82000.json','["不向東林社，聊分玉井蓮。", "淤泥超黑業，定葉異青錢。", "八法那能染，三車固可捐。", "從容共魚樂，吾意已忘筌。"]'),
('c9123627-fbb5-484d-a59a-87b33cf46584','别後有懷子我追用巾字韻作寄','程俱','宋','宋诗','song-poetry','','[]','漉酒空峨五柳巾，一觴相属念情親。',64,'全唐诗/poet.song.82000.json','["漉酒空峨五柳巾，一觴相属念情親。", "玉川奴婢今猶昔，錦里田園老更貧。", "冰洞清泉誰共酌，風篁幽徑好尋春。", "開年晴暖須歸去，還向江湖覓故人。"]'),
('51027d8d-639e-41bf-8859-2a36aea8ab5a','殷浩廢處信安偶覽衢州圖經故居尚有遺址有感予懷書四十字','程俱','宋','宋诗','song-poetry','','[]','中軍時所廢，我廢坐衰殘。',48,'全唐诗/poet.song.82000.json','["中軍時所廢，我廢坐衰殘。", "軒冕儻來寄，炎凉非意干。", "空函嗟外重，小品亦徒看。", "異代均流落，還來客信安。"]'),
('ca78867f-a694-40c9-b782-f07302b9cc55','觀梅','程俱','宋','宋诗','song-poetry','','[]','江梅開過尚餘香，半面殘粧對夕陽。',32,'全唐诗/poet.song.82000.json','["江梅開過尚餘香，半面殘粧對夕陽。", "野草凡花正無賴，競將地紫占春光。"]'),
('546fce31-8f8b-484f-9928-270301ea6901','觀老杜久客一篇其言有感於吾心者因爲八詠 覉旅知交態','程俱','宋','宋诗','song-poetry','','[]','故里翻爲客，衰年亦倦遊。',48,'全唐诗/poet.song.82000.json','["故里翻爲客，衰年亦倦遊。", "犢褌慚北阮，膰饋略東丘。", "門巷遊麋鹿，閭閻風馬牛。", "翟公良可笑，大署欲何求。"]'),
('7d2bbe3f-9d53-4b43-9905-8130dba0ef30','觀老杜久客一篇其言有感於吾心者因爲八詠 淹留見俗情','程俱','宋','宋诗','song-poetry','','[]','扶病來城郭，棲遲又幾年。',48,'全唐诗/poet.song.82000.json','["扶病來城郭，棲遲又幾年。", "炎凉驚節變，榮悴與時遷。", "掉臂人趨市，駢頭蟻慕羶。", "回觀衰冷地，古竈不生烟。"]'),
('7dfb55e0-2d68-43b9-925f-a62fef1346d9','觀老杜久客一篇其言有感於吾心者因爲八詠 衰顔聊自哂','程俱','宋','宋诗','song-poetry','','[]','秃髪無重綠，疏髯已半凋。',48,'全唐诗/poet.song.82000.json','["秃髪無重綠，疏髯已半凋。", "識風搖老炷，大宅樹衰標。", "往事那堪記，幽懷不自聊。", "餘年儻窮健，猶及中興朝。"]'),
('4a1176fe-c4de-45a1-9c06-4b9fd9b92096','觀老杜久客一篇其言有感於吾心者因爲八詠 小吏每相輕','程俱','宋','宋诗','song-poetry','','[]','鼠輩何知禮，奴曹只世情。',48,'全唐诗/poet.song.82000.json','["鼠輩何知禮，奴曹只世情。", "鴟鴞嚇鸞鳯，螻蟻困鯤鯨。", "舍者時爭席，将軍莫夜行。", "豈堪供一笑，正自不須驚。"]'),
('b749a0f8-3cbb-46f5-a3ae-241982be6fed','觀老杜久客一篇其言有感於吾心者因爲八詠 去國哀王粲','程俱','宋','宋诗','song-poetry','','[]','獻納無明略，衰遲只故鄉。',48,'全唐诗/poet.song.82000.json','["獻納無明略，衰遲只故鄉。", "養痾憑藥裹，掃迹寄僧坊。", "不作荆州客，空悲漢署郎。", "登樓那暇賦，衰鬢白蒼蒼。"]'),
('dbb55d8d-315a-4cf3-bc04-04efe2c03a9f','觀老杜久客一篇其言有感於吾心者因爲八詠 傷時哭賈生','程俱','宋','宋诗','song-poetry','','[]','僭逆真苕燕，腥羶尚井蛙。',48,'全唐诗/poet.song.82000.json','["僭逆真苕燕，腥羶尚井蛙。", "蒼生困徴歛，黄屋久咨嗟。", "北狩終當返，東巡亦未賒。", "皇基甚宏遠，四海會爲家。"]'),
('d0f21ec4-0761-4579-8366-def758e633c5','觀老杜久客一篇其言有感於吾心者因爲八詠 狐狸何足首','程俱','宋','宋诗','song-poetry','','[]','宿敝雖毛舉，中原尚土隳。',48,'全唐诗/poet.song.82000.json','["宿敝雖毛舉，中原尚土隳。", "時聞殲狗鼠，未遂戮鯨鯢。", "冠蓋翔鴛鷺，兵戈集虎貔。", "埋輪豈無意，攬轡欲誰期。"]'),
('efefdbce-ee99-4cba-aaca-0d4dfc36cd8d','觀老杜久客一篇其言有感於吾心者因爲八詠 豺虎正縱横','程俱','宋','宋诗','song-poetry','','[]','黠虜頻窺塞，潢池或弄兵。',48,'全唐诗/poet.song.82000.json','["黠虜頻窺塞，潢池或弄兵。", "未傳朱泚首，時勞亞夫營。", "四海幾糜爛，羣凶會鼎烹。", "皇威清海岱，談笑掃攙搶。"]'),
('75049cf8-2833-42aa-9ef5-9008447e5a77','哭徐節之學士慎言','程俱','宋','宋诗','song-poetry','','[]','辯口懸河氣吐雲，賢豪往往盡知聞。',64,'全唐诗/poet.song.82000.json','["辯口懸河氣吐雲，賢豪往往盡知聞。", "論兵似欲無堅敵，攬轡常思去敗羣。", "正使流言成玉玷，何妨浹骨自蘭芬。", "他年罷社悲閭里，宿草猶應哭故墳。"]'),
('417b97f4-43e2-4045-b771-d37bd77a6159','又六言','程俱','宋','宋诗','song-poetry','','[]','臨汝音容近隔，源明生死俄分。',28,'全唐诗/poet.song.82000.json','["臨汝音容近隔，源明生死俄分。", "可但一朝千古，真成聚沫浮雲。"]'),
('5c7f03bd-ef34-4aa1-a980-aa7c05305554','叔問錄示樂天篘字韻詩','程俱','宋','宋诗','song-poetry','','[]','槽滴真珠不用篘，塵飛華棟發清謳。',64,'全唐诗/poet.song.82000.json','["槽滴真珠不用篘，塵飛華棟發清謳。", "時危尚想承平態，勝會那從戰鬬求。", "遺物方将期汗漫，苦心何必志窮愁。", "憑君賸作消憂計，痛飲狂歌爛熳遊。"]'),
('b006d97b-5f31-4f12-b2d5-562c4ce58739','興龍節日有感二首  其一','程俱','宋','宋诗','song-poetry','','[]','往歲興龍節，寰區樂未央。',48,'全唐诗/poet.song.82000.json','["往歲興龍節，寰區樂未央。", "姜任垂德化，夔契拱巖廊。", "事逐流年往，憂随愛日長。", "嘉時真易失，追想故難忘。"]'),
('77525a09-5094-4ed4-be4d-b49297d0220e','興龍節日有感二首  其二','程俱','宋','宋诗','song-poetry','','[]','往歲坤成節，羣生鼓舞中。',48,'全唐诗/poet.song.82000.json','["往歲坤成節，羣生鼓舞中。", "至公同造化，和氣浹羌戎。", "佐佑三王治，彌縫十亂功。", "戎衣何日定，無處問高穹。"]'),
('fbf729aa-0e2f-4564-b8e5-43255985b187','龍圖閣待制知亳州事傅公挽詞四首  其一','程俱','宋','宋诗','song-poetry','','[]','北地休奇績，東閩出雋儒。',48,'全唐诗/poet.song.82000.json','["北地休奇績，東閩出雋儒。", "文明知世異，才德應時須。", "臺閣咨純正，朝廷重楷模。", "九原如可作，素業上唐虞。"]'),
('fc1e82c3-e789-4c20-936f-563c50eeeb01','龍圖閣待制知亳州事傅公挽詞四首  其二','程俱','宋','宋诗','song-poetry','','[]','置醴王門重，和羮帝意深。',48,'全唐诗/poet.song.82000.json','["置醴王門重，和羮帝意深。", "方酬稽古力，未展濟時心。", "履道端由戶，繩身異直尋。", "如何天不憗，注想動宸襟。"]'),
('b36dd4b3-3973-4636-aba6-622689f8208b','龍圖閣待制知亳州事傅公挽詞四首  其三','程俱','宋','宋诗','song-poetry','','[]','龍駕初從代，羊裘首訪齊。',48,'全唐诗/poet.song.82000.json','["龍駕初從代，羊裘首訪齊。", "但聞還舊物，已足慰羣黎。", "綸綍王言大，蓍龜國論稽。", "空留吾黨恨，桃李信成蹊。"]'),
('5447878d-88d0-48fe-a32c-9b9446570372','龍圖閣待制知亳州事傅公挽詞四首  其四','程俱','宋','宋诗','song-poetry','','[]','曳杖空成嘆，騎箕去莫追。',48,'全唐诗/poet.song.82000.json','["曳杖空成嘆，騎箕去莫追。", "桑陰曾未改，棠茇有餘悲。", "笳鼓千山路，龜螭萬古碑。", "登門慚憃陋，何以報深知。"]'),
('d026a9ff-79f3-41ec-aff6-43bed3e2539c','黄脩中大夫挽詩  其一','程俱','宋','宋诗','song-poetry','','[]','少日無雙譽，中年歎數奇。',48,'全唐诗/poet.song.82000.json','["少日無雙譽，中年歎數奇。", "音徽叔度比，治迹次公爲。", "羔雁徒三至，牛雞不兩施。", "空令吴楚地，阡陌有餘思。"]'),
('083f2a92-b37e-48da-8ac5-a07a27bcc8e8','黄脩中大夫挽詩  其二','程俱','宋','宋诗','song-poetry','','[]','曠度中無類，懷才竟莫伸。',48,'全唐诗/poet.song.82000.json','["曠度中無類，懷才竟莫伸。", "入朝誰不達，出宰一何頻。", "吏隱琳宫冷，郎潛素髪新。", "話言猶可想，攬拂涕霑巾。"]'),
('8c8a1f38-4605-4b34-aa47-d1a24299aceb','致政程承議挽歌詞','程俱','宋','宋诗','song-poetry','','[]','手種庭槐擢幹長，誰知種德久彌芳。',64,'全唐诗/poet.song.82000.json','["手種庭槐擢幹長，誰知種德久彌芳。", "錦標荷橐看榮養，命服恩書被寵章。", "合浦珠還增氣象，延平劍客斂光芒。", "新阡鬰鬰車千兩，慶善哀榮動故鄉。"]'),
('dcfcbf45-a0c8-4e11-b496-441f21d58470','太守富樞密見示題趙叔問回光庵詩次韵奉和因敘比蒙屈顧郊居愧謝之意','程俱','宋','宋诗','song-poetry','','[]','千騎雙旌間綠沉，草堂無逕辱幽尋。',64,'全唐诗/poet.song.82000.json','["千騎雙旌間綠沉，草堂無逕辱幽尋。", "應憐范叔窮愁甚，更覺文翁德化深。", "泌飲衡門聊寄老，高山流水舊知心。", "朝來拭目窺新句，入木鏘金比道林。"]'),
('57072fbf-492e-4563-aada-017abbbaf957','又和呈叔問','程俱','宋','宋诗','song-poetry','','[]','潮海當年共陸沉，山林投老得追尋。',64,'全唐诗/poet.song.82000.json','["潮海當年共陸沉，山林投老得追尋。", "清溪宛轉千山静，喬木陰森一徑深。", "法界含容居士室，庵基堅固祖師心。", "山王終恐歸廊廟，回首清遊嘆竹林。"]'),
('a02133fd-d979-4bc4-8155-eed235979c44','用韻述懷','程俱','宋','宋诗','song-poetry','','[]','故交離合異升沉，枉直寧當問尺尋。',64,'全唐诗/poet.song.82000.json','["故交離合異升沉，枉直寧當問尺尋。", "伏櫪疲驂千里暮，當關虓虎九門深。", "炎凉殊態看浮俗，衰病交侵失壮心。", "一壑一丘真自足，野糜終是樂長林。"]'),
('9eb02f46-a8cd-4bb9-a3b1-34d915139ea1','送荘大夫綽赴鄂州守','程俱','宋','宋诗','song-poetry','','[]','白首同經本命年，君臨方面我歸田。',64,'全唐诗/poet.song.82000.json','["白首同經本命年，君臨方面我歸田。", "應無衛尉一錢直，空羡漆園三十篇。", "麟閣功名應未晚，羊腸岐路莫爭先。", "西歸不待三年最，肯訪柴門濲水邊。"]'),
('0fb0af6f-3555-49bb-b3eb-94469fd5f874','偶成四十字上呈彦章內翰叔問侍郎','程俱','宋','宋诗','song-poetry','','[]','頭童心亦盡，老矣不中書。',48,'全唐诗/poet.song.82000.json','["頭童心亦盡，老矣不中書。", "賴有金閨彦，時來冰氏墟。", "但令尊有酒，安問出無車。", "更得身強健，登臨縱所如。"]'),
('e59c920c-b8b6-46a5-920c-a84ba103dd6c','彦文見和謹用韵作二首  其一','程俱','宋','宋诗','song-poetry','','[]','禪翁憐病士，時枉數行書。',48,'全唐诗/poet.song.82000.json','["禪翁憐病士，時枉數行書。", "野寺尋荒逕，烟林接遠墟。", "擬回逋客駕，仍挽故人車。", "會赴山林約，無勞問久如。"]'),
('6fe21b44-8c85-4f3d-8e43-93e84dee2499','彦文見和謹用韵作二首  其二','程俱','宋','宋诗','song-poetry','','[]','知公探理窟，玉檢袐瓊書。',48,'全唐诗/poet.song.82000.json','["知公探理窟，玉檢袐瓊書。", "宴坐超三界，靈光洞九墟。", "折腰憐五斗，舐痔笑多車。", "定起時遊戲，新詩錦不如。"]'),
('42b905a0-497a-4aa6-a56c-acfe8583a16f','再作述懷','程俱','宋','宋诗','song-poetry','','[]','不作頭錢直，徒看萬卷書。',48,'全唐诗/poet.song.82000.json','["不作頭錢直，徒看萬卷書。", "秋螢羞赫日，潢潦異歸墟。", "絕意高門地，真乘下澤車。", "終年日高卧，豈問夜何如。"]'),
('80f18e85-1850-4909-9c7d-887981e46db1','再和寄彦文','程俱','宋','宋诗','song-poetry','','[]','踵息庵中老，看書不蠧書。',48,'全唐诗/poet.song.82000.json','["踵息庵中老，看書不蠧書。", "青燈對編簡，秋氣入郊墟。", "農圃從爭席，笙歌載後車。", "風流傾一座，誰復似相如。"]'),
('5cbe5e2a-fbef-4829-a988-11f9ea9a5d3a','某啓伏蒙宫使資政左丞以某末疾漸平寵貺新詩仰荷眷私欽誦不足謹依嚴韵攀和四首少敘盛德仍述鄙懷伏惟采覽某再拜  其一','程俱','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','如公真似泰山雲，敷寸崇朝四海聞。',64,'全唐诗/poet.song.82000.json','["如公真似泰山雲，敷寸崇朝四海聞。", "出處要同周四友，聲名何减漢三君。", "詞源笑唾三冬學，妙旨深明六藝文。", "要是天孫機杼手，莫将雲錦並纖紋。"]'),
('c2f33c65-8f2d-4cf1-b369-fe19cf694d86','某啓伏蒙宫使資政左丞以某末疾漸平寵貺新詩仰荷眷私欽誦不足謹依嚴韵攀和四首少敘盛德仍述鄙懷伏惟采覽某再拜  其二','程俱','宋','宋诗','song-poetry','','[]','典訓文章見白麻，經綸才術又王家。',64,'全唐诗/poet.song.82000.json','["典訓文章見白麻，經綸才術又王家。", "如何袖手千巖裏，却傍臨溪一徑斜。", "憂國丹心知益壮，濟時素業復誰加。", "何當樂壽亭前路，杖屨追遊閲歲華。"]'),
('9edddf4a-f7e7-44d6-ae47-1680415aaecd','某啓伏蒙宫使資政左丞以某末疾漸平寵貺新詩仰荷眷私欽誦不足謹依嚴韵攀和四首少敘盛德仍述鄙懷伏惟采覽某再拜  其三','程俱','宋','宋诗','song-poetry','','[]','載酒何人過子雲，閉關蘭若斷知聞。',64,'全唐诗/poet.song.82000.json','["載酒何人過子雲，閉關蘭若斷知聞。", "分無秔秫資三徑，豈有篇章詠五君。", "新故易成南浦别，漁樵時寄北山文。", "懸知倚市傾城態，應笑寒窗刺繡紋。"]'),
('4249a4f7-82f3-413b-8ca6-18cefccb52fa','某啓伏蒙宫使資政左丞以某末疾漸平寵貺新詩仰荷眷私欽誦不足謹依嚴韵攀和四首少敘盛德仍述鄙懷伏惟采覽某再拜  其四','程俱','宋','宋诗','song-poetry','','[]','充庭英俊劇蓬麻，迂憃無庸合卧家。',64,'全唐诗/poet.song.82000.json','["充庭英俊劇蓬麻，迂憃無庸合卧家。", "錦里烟塵終不到，玉川思慮本無斜。", "山東何翅三年别，霜鬢潛驚一半加。", "會見中興平四海，要看元凱佐重華。"]'),
('264ef8a9-4ab7-47b0-bc2b-8f78fc859d1c','叔問覽北山小集用葉左丞韵辱惠佳篇推與過情良深愧戢謹次韵奉酬二首  其一','程俱','宋','宋诗','song-poetry','','[]','過眼紛紛夢電雲，羡君強識與多聞。',64,'全唐诗/poet.song.82000.json','["過眼紛紛夢電雲，羡君強識與多聞。", "風流千載鑑湖老，博極羣書都水君。", "顧我衰懷無復理，空餘宿習寄微文。", "深慚推借逾涯甚，偶爾真同禦木紋。"]'),
('9706d2f2-3a11-4407-ae4e-b9257e4d6574','叔問覽北山小集用葉左丞韵辱惠佳篇推與過情良深愧戢謹次韵奉酬二首  其二','程俱','宋','宋诗','song-poetry','','[]','衡門相望接桑麻，人識城南二士家。',64,'全唐诗/poet.song.82000.json','["衡門相望接桑麻，人識城南二士家。", "老罷應難誇競病，詩狂無復賦車斜。", "韋編閲世時時絕，班劍看人歲歲加。", "徒把槧鉛消永日，強分奇正與英華。"]'),
('67a38391-e5a7-4580-a1a1-c348bf7e889b','鄭希尹大夫會吴中諸老惟方子通不至余作詩呈希尹','程俱','宋','宋诗','song-poetry','','[]','黑頭新貴擁朱輪，交會耆英久不聞。',64,'全唐诗/poet.song.82000.json','["黑頭新貴擁朱輪，交會耆英久不聞。", "博識猶多漢郎吏，敦詩仍有晉将軍。", "河流曲曲靈光異，芝蓋莖莖瑞氣芬。", "坐想城東隱君子，無心閑似嶺頭雲。"]'),
('fa8a6af3-51be-4963-8f78-6fbdd5dbd13f','避寇還舍一首','程俱','宋','宋诗','song-poetry','','[]','亂定還三徑，陰陰夏木初。',72,'全唐诗/poet.song.82000.json','["亂定還三徑，陰陰夏木初。", "驚絃無固志，巢幕且安居。", "宴坐心如地，幽尋步當車。", "經丘仍窈窕，遶屋正扶疏。", "摶黍空懷友，提壺或起予。", "老來無住着，聊復愛吾廬。"]'),
('f7ab26e4-28a7-459e-b2f4-cf8a73a91464','得趙叔問衢婺道中書作寄','程俱','宋','宋诗','song-poetry','','[]','田中有秫醉淵明，石上無禾養伯齡。',64,'全唐诗/poet.song.82000.json','["田中有秫醉淵明，石上無禾養伯齡。", "聳澗蒼根終鬰鬰，拂雲歸翼會冥冥。", "避喧人境心随遠，入夢家山眼共青。", "歲晚定知成二老，深慚招隱苦丁寧。"]'),
('2b4db40d-a4e6-41bc-b839-609a9a714dba','和答江彦文送行長句  其一','程俱','宋','宋诗','song-poetry','','[]','醉裏求名苦不情，翛然誰信萬緣輕。',64,'全唐诗/poet.song.82000.json','["醉裏求名苦不情，翛然誰信萬緣輕。", "却觀塵境端如夢，更喜幽棲得此生。", "游客乍歸寒雀噪，山人還去曉猿驚。", "會當蠟屐同幽討，無限青山照眼明。"]'),
('4882bc1c-3f55-4f8b-84d8-30c0a7834d45','和答江彦文送行長句  其二','程俱','宋','宋诗','song-poetry','','[]','贈行新句比陽春，朝奏當年竦縉紳。',64,'全唐诗/poet.song.82000.json','["贈行新句比陽春，朝奏當年竦縉紳。", "素業異時應有待，玄談高處亦無論。", "平生骯髒皆華首，閲世崎嶇信損神。", "只恐鶴書還赴隴，未容公作獨醒人。"]'),
('689bee36-d8e8-4eec-9e7b-a1f4da4d8fa7','會稽旅舍言懷','程俱','宋','宋诗','song-poetry','','[]','北山之北寄柴扉，茅屋参差倚翠微。',64,'全唐诗/poet.song.82000.json','["北山之北寄柴扉，茅屋参差倚翠微。", "老罷那知還作客，春來無奈苦思歸。", "淹留恐復荒三徑，潦倒寧堪扈六飛。", "乘鴈雙鳬成底事，不應容易裂荷衣。"]'),
('1251e4c0-aaf1-43f4-9f48-1affec168cfe','次韻江子我見寄長句','程俱','宋','宋诗','song-poetry','','[]','泥行正作龜藏穴，霧隱初徴豹一斑。',64,'全唐诗/poet.song.82000.json','["泥行正作龜藏穴，霧隱初徴豹一斑。", "豈有高標如冠玉，况無談舌解連環。", "一登文石趨宣室，三竊蟠桃向道山。", "早晚共尋雞黍約，林泉猶得半生閑。"]'),
('1ab277eb-2d5a-4e7b-9496-028e95849f71','苦雨','程俱','宋','宋诗','song-poetry','','[]','積潦徹厚地，油雲成漏天。',96,'全唐诗/poet.song.82000.json','["積潦徹厚地，油雲成漏天。", "乘舟迷晚市，懸釡鬰晨烟。", "卉服幾三沐，蘧廬亦九遷。", "何由開白日，直恐墊黄泉。", "天道終持滿，皇心劇捄然。", "多應洗兵馬，且復奠山川。", "浩浩收溟漲，穰穰浹帝廛。", "爕調知努力，延頸待豐年。"]'),
('68e45a89-a04d-45e8-a971-d80c701ee391','比閲藏經偶成短偈仍寄同志者','程俱','宋','宋诗','song-poetry','','[]','君看故教定何緣，豈爲多聞與福田。',64,'全唐诗/poet.song.82000.json','["君看故教定何緣，豈爲多聞與福田。", "念念會融歸自已，言言當處便忘筌。", "無錢空數他人寶，遮眼那令兕革穿。", "鳥度虚空風過穴，不妨開卷亦安禪。"]'),
('444eff80-a196-4d96-af6a-fdfe36f7ac93','丙辰八月六日作','程俱','宋','宋诗','song-poetry','','[]','負痾今日四周年，藥裏關心雪滿顛。',64,'全唐诗/poet.song.82000.json','["負痾今日四周年，藥裏關心雪滿顛。", "坐失分陰嗟倐忽，行扶跬步苦跰𨇤。", "支離徒費三鍾粟，潦倒仍依二頃田。", "身在山林名絳闕，無功飽食愧前賢。"]'),
('c322fe5c-66c8-4437-9d72-22ef02118ee1','戲呈叔問','程俱','宋','宋诗','song-poetry','','[]','野寺蕭條獨掩扉，了無才術赴時危。',64,'全唐诗/poet.song.82000.json','["野寺蕭條獨掩扉，了無才術赴時危。", "未成鴻鵠舉千里，且比鷦鷯足一枝。", "短髪望秋如葉落，壮懷因病與年衰。", "何時負郭通三徑，鳩杖相将醉習池。"]'),
('68025db1-d89f-4b83-95b8-3f4105a90cb8','彦章屢顧郊居敘謝','程俱','宋','宋诗','song-poetry','','[]','骯髒衰頽歲月侵，冰墟誰復顧山林。',64,'全唐诗/poet.song.82000.json','["骯髒衰頽歲月侵，冰墟誰復顧山林。", "閭閻揖讓潛夫老，車騎雍容重客臨。", "表裏絲綸曾濫吹，推揚巴俚久知音。", "時來解带揮談麈，正始微言得重尋。"]'),
('47603b4c-7b47-4a55-b001-98ef283c5d43','鬰鬰澗底松','程俱','宋','宋诗','song-poetry','','[]','鬰鬰千山麓，常嗟澗底松。',72,'全唐诗/poet.song.82000.json','["鬰鬰千山麓，常嗟澗底松。", "老應從禹貢，清不受秦封。", "偃蹇龍蛇蟄，埋藏冰雪容。", "地偏難聳壑，根固獨凌冬。", "天近知才大，辰來有棟隆。", "山苗應見笑，穴蟻莫相攻。"]'),
('a7fae6a8-5fdc-4357-a35f-53347c4ec3aa','與叔問預約繼九老之會','程俱','宋','宋诗','song-poetry','','[]','七老當年四美并，韓温千載接儀型。',64,'全唐诗/poet.song.82000.json','["七老當年四美并，韓温千載接儀型。", "世間天爵兼人爵，雲外台星聚德星。", "白髮篸花看更好，碧山環座眼偏青。", "相期勉繼耆英會，留與衢人作畫屏。"]'),
('f46f08fe-0ea0-4820-8139-26705ce3909c','日日','程俱','宋','宋诗','song-poetry','','[]','日日長川去，行行萬化新。',48,'全唐诗/poet.song.82000.json','["日日長川去，行行萬化新。", "回思幾年事，已似隔生人。", "章甫寧資越，連城漫入秦。", "應知衣內寶，肯渾隙中塵。"]'),
('5a67fcaa-bc6c-4c64-a1ee-f60485d9fa8a','山近','程俱','宋','宋诗','song-poetry','','[]','山近雲多態，身閑夢亦幽。',48,'全唐诗/poet.song.82000.json','["山近雲多態，身閑夢亦幽。", "紙窗先得曉，布被最知秋。", "海眼來陰冷，雲根逗暗流。", "結茅容我卜，投老爲君留。"]'),
('c794576e-6fc7-46b9-a590-414f42baed9c','看鏡','程俱','宋','宋诗','song-poetry','','[]','看鏡怳如夢，今余猶昔余。',48,'全唐诗/poet.song.82000.json','["看鏡怳如夢，今余猶昔余。", "身經幾堕甑，迹寄一蘧廬。", "仙客有遐怨，孔兄無近書。", "塵纓與蕙帳，兩事欲何居。"]'),
('093a8b38-2852-4a80-8395-14573c21d438','丁巳九日携酒要叔問登通道門樓而江彦文寄玉友適至因用己未歲吴下九日詩韻作','程俱','宋','宋诗','song-poetry','','[]','凉秋風物正清華，極目高樓不見花。',64,'全唐诗/poet.song.82000.json','["凉秋風物正清華，極目高樓不見花。", "老境固知無樂事，醉鄉聊欲寄生涯。", "銀鈎遠寄清桐滑，玉液親題赤印斜。", "笑引壺觴成一醉，歌筵遙想鬢堆鴉。"]'),
('0f095486-0f0a-4720-a78a-19c2a92fbb7f','戊午歲九日復與叔問登城樓再用前韻作','程俱','宋','宋诗','song-poetry','','[]','兀坐空哦服九華，衰頹深覺負黄花。',64,'全唐诗/poet.song.82000.json','["兀坐空哦服九華，衰頹深覺負黄花。", "但令無事長相見，敢嘆百年生有涯。", "雉堞曉登千嶂抱，縠波秋凈一溪斜。", "歸來更展新詩卷，醉墨淋漓似老鴉。"]'),
('cf25baad-74fc-470c-b565-396fba0c762c','靈山觀','程俱','宋','宋诗','song-poetry','','[]','入夢無黄石，收身賴赤松。',120,'全唐诗/poet.song.82000.json','["入夢無黄石，收身賴赤松。", "濯冠臨皖水，執簡叩灊峰。", "司命開琳闕，明光下玉龍。", "高靈心拱衛，江海勢朝宗。", "清夜垂星斗，空山答鼓鐘。", "雲車來絳節，風馬上丹封。", "樓觀参差見，巖崖轉仄容。", "山川瞻勝異，蘋藻薦嚴恭。", "凡骨應難換，幽人豈易逢。", "他年華山藕，安用葛陂筇。"]'),
('b101a4c2-3445-40e9-8a5c-1ae8ffa11924','題靈山息軒','程俱','宋','宋诗','song-poetry','','[]','擾擾塵勞客，誰能一念休。',48,'全唐诗/poet.song.82000.json','["擾擾塵勞客，誰能一念休。", "向炎皆渇鹿，犯稼劇奔牛。", "舟壑雖無住，江河竟不流。", "超然随萬境，轉處實能幽。"]'),
('4838e8fc-c2d6-4f57-9fee-b2260077fbbf','舟行過吴江有感  其一','程俱','宋','宋诗','song-poetry','','[]','陳迹端如幻，覉懷祇自驚。',48,'全唐诗/poet.song.82000.json','["陳迹端如幻，覉懷祇自驚。", "十年窮不死，四海寄餘生。", "蒲柳成衰質，枌揄憶舊耕。", "重吟五湖句，慷慨動幽情。"]'),
('c86a7a0d-241c-42ff-96a9-67afe5078a70','舟行過吴江有感  其二','程俱','宋','宋诗','song-poetry','','[]','棲棘空迴首，飛鳬竟折腰。',48,'全唐诗/poet.song.82000.json','["棲棘空迴首，飛鳬竟折腰。", "祇今随泛宅，敢復歎沉僚。", "行路終難拗，迷魂不可招。", "山川良是昔，恍似鶴歸遼。"]'),
('190c8e40-4d6b-4145-800a-3e4d0db521e8','葺蝸廬吴下用葉翰林見寄詩韻作','程俱','宋','宋诗','song-poetry','','[]','四海無廬置此翁，故營松竹儘囊空。',64,'全唐诗/poet.song.82000.json','["四海無廬置此翁，故營松竹儘囊空。", "明知計出柏馬下，正擬身全木鴈中。", "東郭易成生草舍，南村先怯卷茅風。", "向來豪氣今如此，敢與元龍比長雄。"]'),
('b1e72179-ff27-46ce-9c1b-ad806e365676','和白樂天二首寫懷仍效其體  其一','程俱','宋','宋诗','song-poetry','','[]','莫把蓍龜更問天，向來心事已蕭然。',64,'全唐诗/poet.song.82000.json','["莫把蓍龜更問天，向來心事已蕭然。", "塵中惝恍常如失，夢裏呻吟半不眠。", "三徑松筠終問舍，五湖烟水不須錢。", "艾耆相去能多少，早擬懸車十五年。"]'),
('ad30f39c-9e8b-401e-bfa2-7e91476d6831','和白樂天二首寫懷仍效其體  其二','程俱','宋','宋诗','song-poetry','','[]','中臺退食每逡巡，不向重華即浮因。',64,'全唐诗/poet.song.82000.json','["中臺退食每逡巡，不向重華即浮因。", "豈但語言多少味，亦知才術不如人。", "五雲華闕通閨籍，萬頃烟波擲幽尋。", "舊遊回首成春夢，太息憑誰寫寸心。"]'),
('c47b8415-c239-44d6-a63d-b127ea8da89f','和趙子雍游石園','程俱','宋','宋诗','song-poetry','','[]','長嘯西風一散襟，重陰疏影靜相臨。',64,'全唐诗/poet.song.82000.json','["長嘯西風一散襟，重陰疏影靜相臨。", "水通笠澤秋容凈，竹種玄池野思深。", "石磴掃雲留晚步，松蹊隨鶴盡幽尋。", "舊游回首成春夢，太息憑誰寫寸心。"]'),
('b76b36b4-fca9-4778-9e2e-0c7cd1414309','謁蔡開府延客周歷堂宇覽觀山林巖洞之勝頓失袢暑退作律詩一首','程俱','宋','宋诗','song-poetry','','[]','蒼虬銜雨轉晴巒，噴霧跳珠玉甃寒。',96,'全唐诗/poet.song.82000.json','["蒼虬銜雨轉晴巒，噴霧跳珠玉甃寒。", "掩冉風林聽竽籟，蕭森烟蘀種琅玕。", "期仙磴属三休逕，羃翠庭邊八節灘。", "赫赫雲峰張火繖，陰陰冰洞却霜紈。", "山藏神府新瓊簡，壁掛磻谿舊釣竿。", "怪底蕭條增秀發，六龍曾此駐和鑾。"]'),
('82139300-2f09-4070-9f08-1049149e09c6','和王給事易簡殿試舉人五首 試進士','程俱','宋','宋诗','song-poetry','','[]','切雲冠弁拱長生，匝地英髦集紫清。',64,'全唐诗/poet.song.82000.json','["切雲冠弁拱長生，匝地英髦集紫清。", "共喜草茅承帝問，欲傾塵霧贊皇明。", "飄飄六翮鳴臯意，浩浩三眠食葉聲。", "正學儻言應不乏，松筠寧爲四時更。"]'),
('8d7f888f-6d48-41a7-9167-0a10364d0774','和王給事易簡殿試舉人五首 試特奏名','程俱','宋','宋诗','song-poetry','','[]','十上寧嗟老此生，長年終得似河清。',64,'全唐诗/poet.song.82000.json','["十上寧嗟老此生，長年終得似河清。", "良金熟練精英在，古劍磨光星斗明。", "伏櫪向來猶壯志，據鞍他日想騰聲。", "當時誰出菑川右，充選何勞固請更。"]'),
('7cf86c37-b21e-4a1a-bb63-52563b2b1c52','和王給事易簡殿試舉人五首 試武士','程俱','宋','宋诗','song-poetry','','[]','射策兼收燕頷生，不須文檄似常清。',64,'全唐诗/poet.song.82000.json','["射策兼收燕頷生，不須文檄似常清。", "驚弦戎虜從容下，聚米山川指顧明。", "豈但執戈堪武衛，還因舞羽繼仁聲。", "汾陽千古知無匹，怪底麾旌不浪更。"]'),
('89e45b73-5fff-45bc-8c81-f89c51b77bd2','和王給事易簡殿試舉人五首 考校','程俱','宋','宋诗','song-poetry','','[]','金閨人靜月華生，玉宇風微曉露清。',64,'全唐诗/poet.song.82000.json','["金閨人靜月華生，玉宇風微曉露清。", "深拱北辰三素遠，靜看東壁幾星明。", "嬙嫫豈易欺軒鑑，韶濩那容奏鄭聲。", "聞說壺天春日永，怳疑鼇戴欲番更。"]'),
('b0943373-5a97-43fe-a591-14dd4b0d1bd1','和王給事易簡殿試舉人五首 唱名','程俱','宋','宋诗','song-poetry','','[]','萬里烟霄羽翼生，肉飛安用潄華清。',64,'全唐诗/poet.song.82000.json','["萬里烟霄羽翼生，肉飛安用潄華清。", "緋頭黄尾何勞記，紫籍青書故自明。", "香撲賜袍迷草色，風傳宫漏出花聲。", "騏騮一一充閑厩，千里那聞駕屢更。"]'),
('7f1b1757-f878-475d-a6ab-9827c64c1b65','和何文縝禮部種竹一首','程俱','宋','宋诗','song-poetry','','[]','筠節寧當混草萊，寸根中有拂雲材。',64,'全唐诗/poet.song.82000.json','["筠節寧當混草萊，寸根中有拂雲材。", "清游未接諸賢遠，幽徑終因二仲開。", "歲晚蒼陰元自茂，實成丹鳯幾時來。", "何郎冰雪森相對，默轉談峰萬壑雷。"]'),
('3a7d119e-f98f-4450-913b-973b0a1ee37b','某皇恐上啓伏承太師均佚之暇修真養浩日與造物者游謹成拙句上塵鈞覽','程俱','宋','宋诗','song-poetry','','[]','碧海崑崙接絳臺，故應春至自花開。',64,'全唐诗/poet.song.82000.json','["碧海崑崙接絳臺，故應春至自花開。", "絲毫不立元非靜，梨棗潛生豈用栽。", "種種初無心外法，綿綿時向定中回。", "却來重展調元手，會見華胥遍九垓。"]'),
('8cb672e2-a980-44be-bdad-c5b18ab8aebb','太湖沿檄西原道即事三首  其一','程俱','宋','宋诗','song-poetry','','["\u592a\u6e56"]','司空山頭朝出雲，西原渡口十里陰。',32,'全唐诗/poet.song.82000.json','["司空山頭朝出雲，西原渡口十里陰。", "煙中雞唱未及午，白雨作泥泥已深。"]'),
('f8e4de5c-b99b-4abd-bd77-ddbf0240a37f','太湖沿檄西原道即事三首  其二','程俱','宋','宋诗','song-poetry','','["\u592a\u6e56"]','上崖下谷鳥道中，前屩後巾魚貫從。',32,'全唐诗/poet.song.82000.json','["上崖下谷鳥道中，前屩後巾魚貫從。", "西山路暗光已夕，東山山頭餘日紅。"]'),
('ee61adbd-cedb-4f97-98aa-453b44f0f599','太湖沿檄西原道即事三首  其三','程俱','宋','宋诗','song-poetry','','["\u592a\u6e56"]','道旁甕盎如汝陽，石間電雹如吕梁。',32,'全唐诗/poet.song.82000.json','["道旁甕盎如汝陽，石間電雹如吕梁。", "不知身世在何許，舉頭四山鬰蒼蒼。"]'),
('b226a19c-42d2-487d-8c0d-db4cca58ef4e','登富陽觀山亭  其一','程俱','宋','宋诗','song-poetry','','[]','游雲凝空日無華，烟江冥迷如眼花。',32,'全唐诗/poet.song.82000.json','["游雲凝空日無華，烟江冥迷如眼花。", "觀山直南是秦望，不見高青天雨沙。"]'),
('3e5144f4-3113-4dfc-aa1d-38a0908452eb','登富陽觀山亭  其二','程俱','宋','宋诗','song-poetry','','[]','東吴山川少雄遠，此中形勢如江南。',32,'全唐诗/poet.song.82000.json','["東吴山川少雄遠，此中形勢如江南。", "當年伯符亦浪出，三雄相視徒眈眈。"]'),
('5a0400f5-e779-4ad7-bb4e-f73723b63d9e','登富陽觀山亭  其三','程俱','宋','宋诗','song-poetry','','[]','喬公宅中木参天，孫郎山前春燒煙。',32,'全唐诗/poet.song.82000.json','["喬公宅中木参天，孫郎山前春燒煙。", "大橋不向五湖去，建康宫深空歲年。"]'),
('6a131c3b-c99b-4eb5-9aae-953df50599ac','壬子春暮罷職西省以宫觀東歸道由富陽默記舊詩俯仰二十八年矣有足感者用前韻作因簡叔問并諸故人  其一','程俱','宋','宋诗','song-poetry','','[]','春風吹衣雙鬢華，山中小桃應着花。',32,'全唐诗/poet.song.82000.json','["春風吹衣雙鬢華，山中小桃應着花。", "回思二十九年事，世故困人如弄沙。"]'),
('1bc197b6-7e0d-42df-be65-39d15b0c13dc','壬子春暮罷職西省以宫觀東歸道由富陽默記舊詩俯仰二十八年矣有足感者用前韻作因簡叔問并諸故人  其二','程俱','宋','宋诗','song-poetry','','[]','故園在眼日漸近，北山之北南山南。',32,'全唐诗/poet.song.82000.json','["故園在眼日漸近，北山之北南山南。", "從來不飲聲聞酒，况學詩翁老更眈。"]'),
('25da0010-8457-447b-812a-19b039c9e94d','壬子春暮罷職西省以宫觀東歸道由富陽默記舊詩俯仰二十八年矣有足感者用前韻作因簡叔問并諸故人  其三','程俱','宋','宋诗','song-poetry','','[]','擊水三千尺五天，故人拭目上凌煙。',32,'全唐诗/poet.song.82000.json','["擊水三千尺五天，故人拭目上凌煙。", "北山還我扶犂手，准擬今年大有年。"]'),
('a632ae2a-97a9-4ae5-bddc-ddc7cd4f281b','題蔣崇德彝所藏明皇夜游圖  其一','程俱','宋','宋诗','song-poetry','','[]','燃膏飛控逐流光，露溢金盤樂未央。',32,'全唐诗/poet.song.82000.json','["燃膏飛控逐流光，露溢金盤樂未央。", "擬跨八龍窮轍迹，誰令一馬向銅梁。"]'),
('f8bb2fd5-a93b-4bcb-90b5-1a4f5f9d969a','題蔣崇德彝所藏明皇夜游圖  其二','程俱','宋','宋诗','song-poetry','','[]','崤函伊洛好家居，四十三年如覆盂。',32,'全唐诗/poet.song.82000.json','["崤函伊洛好家居，四十三年如覆盂。", "盡道蛾眉供一笑，安知傾國有胡雛。"]'),
('32ba373e-52d4-43d7-aefe-8e9e25527ed8','即事','程俱','宋','宋诗','song-poetry','','[]','照空初涌玉芙蕖，驚起霜林尾畢逋。',32,'全唐诗/poet.song.82000.json','["照空初涌玉芙蕖，驚起霜林尾畢逋。", "託宿一枝翻自失，倦飛三匝正相呼。"]'),
('e60907ff-0728-4cfc-b738-bd87731fca4b','山中次葉翰林韻  其一','程俱','宋','宋诗','song-poetry','','[]','四山松桂擁高寒，臘盡陰崖雪未乾。',32,'全唐诗/poet.song.82000.json','["四山松桂擁高寒，臘盡陰崖雪未乾。", "發石開林窮鳥道，披榛尋壑見鯢桓。"]'),
('b6513635-ea65-417b-a9b5-3e10cc8a5e1d','山中次葉翰林韻  其二','程俱','宋','宋诗','song-poetry','','[]','繞舍蕭森碧玉椽，西丘桑苧遠相連。',32,'全唐诗/poet.song.82000.json','["繞舍蕭森碧玉椽，西丘桑苧遠相連。", "東山一爲蒼生起，付與幽人枕石眠。"]'),
('7148f66b-ca5f-4382-85a6-b1cf8065153c','山中次葉翰林韻  其三','程俱','宋','宋诗','song-poetry','','[]','步尋芳草坐班荆，照眼林泉動客情。',32,'全唐诗/poet.song.82000.json','["步尋芳草坐班荆，照眼林泉動客情。", "安得長年專一壑，北窗高卧更何營。"]'),
('76663386-9c08-471c-9d7e-15c0ed5170ff','山中次葉翰林韻  其四','程俱','宋','宋诗','song-poetry','','[]','李郭一舟知謾與，羊求三徑可無人。',32,'全唐诗/poet.song.82000.json','["李郭一舟知謾與，羊求三徑可無人。", "他年午橋窮勝事，應許幅巾來卜鄰。"]'),
