('a16faa5c-8462-43e4-b399-ede6942437de','題閻立本畫','程俱','宋','宋诗','song-poetry','','[]','大塊浮空轉兩輪，越南燕北共毫塵。',32,'全唐诗/poet.song.82000.json','["大塊浮空轉兩輪，越南燕北共毫塵。", "齊州古莽應相笑，夢覺何人定識真。"]'),
('0abd920e-9476-4d3d-a202-49ad265a805a','讀書','李光','宋','宋诗','song-poetry','','[]','低頭對千載，把卷竟長日。',72,'全唐诗/poet.song.82000.json','["低頭對千載，把卷竟長日。", "興亡見俯仰，忠佞更得失。", "意合心自知，感嘅屢沾臆。", "朱黄紛几硯，緗素互編帙。", "比鄰亦好事，挾策到蓬蓽。", "縱談及羲皇，坐待寒月出。"]'),
('117fc181-4ba9-46cc-8e0f-aa56a63cbc5a','贈李頤老','李光','宋','宋诗','song-poetry','','[]','弘毅年少時，學易一念酷。',156,'全唐诗/poet.song.82000.json','["弘毅年少時，學易一念酷。", "研精覃思苦，見理不見欲。", "一朝感蒼蒼，床下産神竹。", "弘毅益自信，夜寐目不屬。", "族長閔其勞，令人付斤劚。", "惜哉凌雲姿，一斷不復續。", "弘毅少安枕，旦氣幾爲梏。", "時匠司剪伐，壽命旋見蹙。", "神明信可畏，感應亦何速。", "至今旁舍笋，不生弘毅屋。", "康成書带草，千載登史錄。", "吾書此段奇，後學宜三復。", "弘毅勉歲寒，任道照猗綠。"]'),
('17c70d0b-2616-42c1-8c75-7167b5121d0a','夜起對月','李光','宋','宋诗','song-poetry','','[]','西風掃浮雲，素月清夜滿。',72,'全唐诗/poet.song.82000.json','["西風掃浮雲，素月清夜滿。", "幽人愁不寐，一夕幾輾轉。", "天河見澄霽，江流俯清淺。", "身隨栖鳥息，興與孤雲遠。", "叩門復何人，隔竹空吠犬。", "竟須掩關眠，爐薫裊香篆。"]'),
('1a52412d-7b83-460b-a270-4d31c53383eb','縣齋清坐有懷  其一','李光','宋','宋诗','song-poetry','','[]','門外無俗軌，相對惟獨鶴。',216,'全唐诗/poet.song.82000.json','["門外無俗軌，相對惟獨鶴。", "短翮雖未全，志已翔寥廓。", "軒然避雞羣，不受鷹隼搏。", "持以比佳士，潔白誠相若。", "筆端生雲烟，胸中貯丘壑。", "憐君青雲姿，胡爲滯蓮幕。", "英豪出草萊，闒茸履臺閣。", "新詩時有寄，妙語洗煩灼。", "種學求根源，意匠無斧鑿。", "自慚非清流，訟牒困酬酢。", "好古雖膽大，去惡愧力弱。", "君來破吾顔，商榷盡流略。", "高軒掛琴劍，景物如宿約。", "遙山倚青冥，遠水带城郭。", "圓荷已浮花，晚筍亦脱籜。", "涓涓風露清，湛湛河漢落。", "濁醪有妙理，與子隨意酌。", "萬事付儻來，何必問日脚。"]'),
('b208b95f-0efb-4eec-83c1-298d58938783','縣齋清坐有懷  其二','李光','宋','宋诗','song-poetry','','[]','學道未忘名，欲跨揚州鶴。',216,'全唐诗/poet.song.82000.json','["學道未忘名，欲跨揚州鶴。", "淵明賦歸來，頗恨未恢廓。", "平生剛褊性，敢避窮獸搏。", "君詩如清琴，平淡猶賀若。", "泠然山水音，妙響振林壑。", "寧爲太史走，豈事桓温幕。", "樂哉吴望游，微凉生殿閣。", "况兹積雨後，枕簟謝焚灼。", "未能去三彭，便可休六鑿。", "跌宕文字間，詩酒自相酢。", "氣凌李杜豪，力振曹劉弱。", "偏師攻長城，稍稍出方略。", "山川助離騷，景象如宿約。", "陰風起虚籟，暮靄昏城郭。", "菡萏泛金塘，篔簹隕銀籜。", "卧看曉參横，坐待殘月落。", "不愁衣典盡，尊空莫起酌。", "明朝醉復醒，生憂押垂脚。"]'),
('90894d9b-0d87-4351-a2b3-1a47441c535e','雪中過盤石山寄劉季山','李光','宋','宋诗','song-poetry','','[]','離家六十日，晴嵐逐征鞍。',144,'全唐诗/poet.song.82000.json','["離家六十日，晴嵐逐征鞍。", "已嫌狐裘重，漸喜絺縠單。", "朅來古清湘，狂風捲濤瀾。", "小市人寂寂，夜深雪漫漫。", "誰知桂嶺北，風雪如長安。", "明朝過盤石，仰見蒼蒼山。", "上有千尺松，下有百丈灘。", "劉子方避謗，結茅寓其間。", "却掃謝友朋，兒女俱團圞。", "南行敢躊躇，履險如驚湍。", "我心本無慮，莫作拘囚看。", "肯學老鍾儀，楚奏聲嘶酸。"]'),
('6e2b8ea7-8dab-4758-a947-454e3684ffb1','伊洛節上人寓浯溪中宫寺作溪月亭諸人咸賦詩輙留鄙句','李光','宋','宋诗','song-poetry','','[]','結亭臨大江，浯溪出其側。',84,'全唐诗/poet.song.82000.json','["結亭臨大江，浯溪出其側。", "道人傍溪月，月照溪逾碧。", "當知月在天，分身千百億。", "此月有虧盈，我心本澄寂。", "合眼聽溪聲，開眼見溪色。", "聲色兩不留，我心何處覓。", "夢覺月在窗，還如舊知識。"]'),
('7a07d216-ef65-46d9-9d86-c6faea10f369','次韻子忱游東山古風','李光','宋','宋诗','song-poetry','','[]','休沐不暇懶，趁此郊原晴。',180,'全唐诗/poet.song.82000.json','["休沐不暇懶，趁此郊原晴。", "駕言出東門，蹀躞馬在坰。", "江山恣游眺，頗惬幽人情。", "同行有勝侣，豪氣如陳登。", "妙語傾錦囊，璀璨珠璣盈。", "暫釋簿領勞，頓覺心迹清。", "人生一世中，轉徙如郵亭。", "愛君絕塵姿，坦坦心地平。", "當年功名念，晚節師淵明。", "出處豈有心，敢論虧與成。", "吾衰百念冷，端如在家僧。", "東山本非山，名字空峥嶸。", "不見古松色，詎聞山鳥聲。", "演師獨面壁，燕坐朝黄庭。", "骨冷喚不回，蚌珠秘龕燈。"]'),
('13bf5755-8084-4c50-a941-19a8df8426f6','次韻元裕同游東山佳什東坡所謂愛此小天竺即其地也','李光','宋','宋诗','song-poetry','','[]','東坡謫蠻荒，夢想兩天竺。',168,'全唐诗/poet.song.82000.json','["東坡謫蠻荒，夢想兩天竺。", "哦詩寄東山，妙響振林麓。", "作祠衛公旁，一杯奠椒漿。", "相望柳柳州，追配韓潮陽。", "懷人空隕涕，亭榭今荒墟。", "溪山不改色，松聲契真如。", "嗟余麋鹿姿，慣逐漁樵伴。", "平生鐵石腸，那復置冰炭。", "尋山得佳侣，聊遂幽人意。", "登臨有遐矚，俯仰觀此世。", "君爲丞相孫，仕作淵明清。", "一枰可消憂，五字堪析酲。", "人生各有役，詩棋豈妨道。", "閉戶朝黄庭，習氣終一掃。"]'),
('78242706-e944-4709-8de4-e4f95fc9e9fa','杜子固參議累覓南窗詩勉成鄙句子固謂杜氏古無二族祁公其近屬也','李光','宋','宋诗','song-poetry','','[]','長懷杜陵老，遐想靖節翁。',144,'全唐诗/poet.song.82000.json','["長懷杜陵老，遐想靖節翁。", "二子不並世，千載餘清風。", "君爲南國秀，志氣陵蒼穹。", "盤屈不得伸，妙略參元戎。", "歸來侣漁樵，香火陪琳宫。", "卜居牛斗墟，築室瓦礫中。", "依然植五柳，彷彿餘四松。", "南窗有幽意，寄傲膝可容。", "拊床寒月侵，曝背微陽通。", "琴書樂忘憂，尊中常不空。", "吾鄉有諸杜，源流自祁公。", "歸歟有成言，葛巾永相從。"]'),
('2f2205de-bde3-4a27-a2fb-241524b312cc','季微季暉昆仲相繼見訪風姿議論皆慨然有祖風季暉仍出佳篇見貽語極不凡且云即往山中讀書作詩送行','李光','宋','宋诗','song-poetry','','[]','吾鄉顧虎頭，千里飛食肉。',216,'全唐诗/poet.song.82000.json','["吾鄉顧虎頭，千里飛食肉。", "名参慶歷賢，罪入元祐錄。", "堂堂想儀刑，凛凛見眉目。", "百年議論定，奇禍反爲福。", "森然見諸孫，刻勵如白屋。", "我觀宣和間，權倖互當軸。", "一時名家子，半爲閹宦辱。", "暫時得富貴，卑賤等厮僕。", "君家賢伯仲，抗志守先躅。", "幽情寄鉛槧，雅尚在松竹。", "僧房忍朝饑，雪牖耽夜讀。", "訪我五松山，懷袖粲珠玉。", "嗟予久放浪，歲晚守窮獨。", "閉門雀可羅，三徑草常綠。", "依山結衡茅，一飯共脱粟。", "呼兒具□□，山肴雜野蔌。", "對桉笑復顰，負我十圍腹。", "去去樂琴書，山中芋魁熟。"]'),
('095b289b-37a6-4626-a1e6-77b8d2e70fe0','迎山閣爲長慶寺登覽之勝暇日攜觴命友屢醉其上因賦此詩','李光','宋','宋诗','song-poetry','','[]','青山似幽人，那肯入城府。',192,'全唐诗/poet.song.82000.json','["青山似幽人，那肯入城府。", "遠碧横春空，穠綠浮天宇。", "常苦俗物遮，不得快觀覩。", "何年敞層閣，軒豁開牖戶。", "千巖勞顧揖，萬壑隨仰俯。", "飛騰若鵬鸞，盤踞狀龍虎。", "翩翩垂翅翼，蜿蜿回肘股。", "朝來拄笏看，爽氣逼簷廡。", "孤雲時去來，寒月静吞吐。", "溪山自奇絕，信美真吾土。", "我老賸得閑，遇勝輙爲主。", "朋簪俱莫逆，棋酒屢清聚。", "亦有支遁流，時來共揮麈。", "迎客如迎山，好事免嘲侮。", "常烹雨前茶，不打齋後鼓。", "從今贊公房，名字照千古。"]'),
('286ffbfc-4102-4d8a-80bd-d7403a8cdc15','五月七日分韻得食苦筍詩','李光','宋','宋诗','song-poetry','','[]','此君凌雲材，節葉貫霜雪。',144,'全唐诗/poet.song.82000.json','["此君凌雲材，節葉貫霜雪。", "千林富東南，百種自區别。", "前後互萌芽，一一調苦舌。", "貓頭效𡾋嵬，竹箭資瑣屑。", "世方嗜柔腴，我獨甘苦節。", "幽姿照匕筯，挺特似英傑。", "定非淇園栽，要是首陽蘖。", "侯門厭珍烹，鼎俎雜葵蕨。", "安能知正味，但欲取客悦。", "何當薦君槃，茹香資激烈。", "欲雪會稽恥，志氣在餔歠。", "甲卒五千人，猶能霸吴越。"]'),
('84e3a0b1-37b4-4bab-82c2-d44b394cb843','和胡江州丹陽道中二首  其一','李光','宋','宋诗','song-poetry','','[]','君才固英奇，志在行天討。',72,'全唐诗/poet.song.82000.json','["君才固英奇，志在行天討。", "胡爲尚兀兀，疲馬踏長道。", "論兵當節制，摧敵如振槁。", "不數圯上翁，顧笑渭濱老。", "凛然擊搏手，試用豈不早。", "他年梁棟姿，涵養已合抱。"]'),
('2bd695d1-cce2-4248-94ab-1bd60dd3b60e','和胡江州丹陽道中二首  其二','李光','宋','宋诗','song-poetry','','[]','士卒常有餘，食廪苦不足。',72,'全唐诗/poet.song.82000.json','["士卒常有餘，食廪苦不足。", "妻孥驚笑我，陡換髯鬢綠。", "江西魚稻鄉，升平氣全復。", "以公封侯相，自可飛食肉。", "韜略固輻凑，精神常滿腹。", "去去復何憂，驅除仍覆育。"]'),
('f7ce9a9c-91cf-4f3e-aac2-bbdd90151d15','伯宇知府給事寵和子賤與僕域字韻詩格力超絕輙復次韻','李光','宋','宋诗','song-poetry','','[]','中原困干戈，衣冠淪異域。',96,'全唐诗/poet.song.82000.json','["中原困干戈，衣冠淪異域。", "忠臣憤切骨，義士血空滴。", "平生憂國心，豈以死生易。", "年來返田廬，門巷無轍迹。", "老驥萬里心，垂耳卧空櫪。", "素交今幾人，十載勞夢役。", "宣城擁朱轓，潘子縛禪寂。", "屹然障頹波，我亦心匪石。"]'),
('4bb2cf4b-b21a-4896-8d0c-18d773d67b47','和杜得之探梅之什','李光','宋','宋诗','song-poetry','','[]','家山富梅林，開落紛無數。',96,'全唐诗/poet.song.82000.json','["家山富梅林，開落紛無數。", "二年屏荒村，踏遍溪頭路。", "孤標凛冰雪，幽香襲巾屨。", "陽坡照晨曦，永夜泣月露。", "端如玉妃謫，清絕欲誰顧。", "歲寒偶相逢，政復慰遲暮。", "君看桃杏面，爭妍競深注。", "何如叢棘中，獲此秀傑句。"]'),
('e5c50c8f-9a81-4fa1-9e89-614c792013da','寄題餘姚徐宰新作嚴公堂','李光','宋','宋诗','song-poetry','','[]','子陵古真隱，逸氣横九州。',204,'全唐诗/poet.song.82000.json','["子陵古真隱，逸氣横九州。", "平生江海志，自比巢與由。", "鴻飛本冥冥，肯爲稻粱謀。", "虚屈萬乘顧，枉煩物色求。", "貽書誚君房，預作腰領憂。", "舜江公邑里，公去踰千秋。", "青山無古今，大江日東流。", "人物浪淘盡，英名至今留。", "當年漁釣地，陳迹餘荒丘。", "徐侯有佳政，百里安田疇。", "作堂名嚴公，懷賢慕前修。", "時來對江山，一尊更獻酬。", "我豈隱淪歟，三黜今白頭。", "年來賸得閑，忘機狎羣鷗。", "結茅牟湖傍，一竿幸可投。", "蒻笠青蓑衣，生涯寄扁舟。", "嚴子定不死，吾将從之游。"]'),
('e58ef3bf-57fe-4720-abe4-0e2cb8e8c2a8','稚山運使作齋名藏暉且覓詩久不能成今兹以大農召行有日因成鄙句并以送行','李光','宋','宋诗','song-poetry','','[]','美玉當韞櫝，明珠産深淵。',168,'全唐诗/poet.song.82000.json','["美玉當韞櫝，明珠産深淵。", "達士貴混俗，大隱常居廛。", "皓皓終易汙，嶢嶢難自全。", "和光同其塵，老聃有成言。", "徐侯如水鑑，胸中定媸妍。", "疾惡若仇讎，論事敢直前。", "朅來大江西，獨攬刺舉權。", "姦贓盡屏迹，豺狼敢垂涎。", "顧欲藏其暉，名室以自鐫。", "老火正淫恣，旱氣方接連。", "悵别南浦亭，去去朝日邊。", "中原正塗炭，生民思息肩。", "公歸明光奏，輸忠傾肺肝。", "功成不自居，名與日月懸。"]'),
('55f68018-632c-4d5e-bb50-f844f93632db','江西久旱徧禱莫應稚山少卿将赴行朝一夕大雨遐邇霑足因成喜雨詩送行','李光','宋','宋诗','song-poetry','','[]','老火擅炎夏，枯旱氣欲然。',168,'全唐诗/poet.song.82000.json','["老火擅炎夏，枯旱氣欲然。", "傷心早晚禾，注目高下田。", "民窮捨耒耜，羣起操戈鋋。", "小偷何足道，所憂在四邊。", "夜來滄江雨，朝望水接天。", "歡聲達四境，渥澤遍大千。", "清風亦徐來，扇簟皆可捐。", "有懷林壑幽，僧窗思晝眠。", "流浪生死海，一往六十年。", "何以報主恩，粗了江西緣。", "羡子朝上國，揚帆若登仙。", "江山亦世情，雨後清且妍。", "悵别南浦亭，杯行莫流連。", "去去聞好音，一歲定九遷。"]'),
('04afe6c5-4f8e-41ca-a365-d98662abf0c4','某天資坦率人也性又剛褊偶以使事暫去行闕馬上放目頗適野性作出郊一首簡知我者','李光','宋','宋诗','song-poetry','','[]','出郊何所欣，所欣在觀眺。',144,'全唐诗/poet.song.82000.json','["出郊何所欣，所欣在觀眺。", "殷紅著新枝，濃綠浮遠嶠。", "悠然出塵想，快若追風驃。", "幾年偪仄懷，兒女困嘲誚。", "人生貴適意，官職豈不要。", "從來坦率性，痼疾難救療。", "沈湎與獨醒，亦各以所好。", "鶴脛自然長，斷之定號叫。", "譬如食茶味，煎煎人外料。", "言行自有常，安能改吾調。", "浩歌歸去來，家有老德耀。", "永託煙雲岑，終焉擅漁釣。"]'),
('3348e24d-9149-4877-89b3-b103d295d835','爲向伯恭題','李光','宋','宋诗','song-poetry','','[]','向公天下士，慷慨有祖風。',144,'全唐诗/poet.song.82000.json','["向公天下士，慷慨有祖風。", "亦復對行殿，密議禆天聰。", "君臣意氣合，每進嘗從容。", "飄飄青雲志，顧肯貪天功。", "榮塗拂衣歸，安坐薌林中。", "作堂榜企疏，進退聊比蹤。", "父老非故鄉，何必囊金空。", "俗軌競奔馳，世路方尚同。", "善爲子孫謀，但務田園豐。", "偉哉此二子，遐舉希冥鴻。", "富貴如浮雲，聲名壓岱嵩。", "千載繼者誰，我友向伯恭。"]'),
('4757db44-9017-4cf3-8015-c79a8d0398ff','和劉提舉游龍井謁清獻辨才二像','李光','宋','宋诗','song-poetry','','[]','我觀二大士，超悟非適今。',192,'全唐诗/poet.song.82000.json','["我觀二大士，超悟非適今。", "過去與未來，一一現此心。", "緬懷清獻公，兹地舊所臨。", "餘愛存甘棠，過者猶斂襟。", "平生辨才老，般若緣契深。", "圖像儼如昔，遺迹了可尋。", "坐使茨棘場，化爲薝蔔林。", "法嗣傳衣燈，膏肓存砭箴。", "圓顱擁敗褐，華髪欹半簪。", "相對了無言，清標映孤岑。", "丹青久剝落，感嘆成微吟。", "了知身外身，不坐喬木陰。", "真形換緗素，妙句劖青琳。", "與子成三賢，清風迥蕭森。", "凛然龍象姿，不受鼯鼠侵。", "從兹香火社，永爲人天欽。"]'),
('292b72a4-704d-44ce-b670-0fd6f5f70de3','謫居古藤病起禁鷄猪不食與兒子攻苦食淡久之頗覺安健吕居仁書來傳道家胎息之術因作食粥詩示孟愽并寄德應侍郎','李光','宋','宋诗','song-poetry','','[]','晨起一甌粥，香粳粲如玉。',168,'全唐诗/poet.song.82000.json','["晨起一甌粥，香粳粲如玉。", "稀稠要得所，進火寧過熟。", "空腸得軟暖，和氣自渗漉。", "過午一甌粥，缾罍有餘粟。", "淡薄資薑鹽，腥穢謝魚肉。", "嶺南氣候惡，永日值三伏。", "外強幾中乾，那受外物觸。", "兩餐莫過飽，二粥可接續。", "故人尺書至，教我禦瘴毒。", "燕坐朝黄庭，妙理端可矚。", "神車御氣馬，晝夜更往復。", "久久當自佳，根深柯葉綠。", "寄語陳太丘，人生真易足。", "醉飽厭腥羶，忽認海南叔。"]'),
('0c139434-397e-4918-8883-174245fabeab','送孟博二首  其一','李光','宋','宋诗','song-poetry','','[]','我昔在閭里，燕居處中堂。',240,'全唐诗/poet.song.82000.json','["我昔在閭里，燕居處中堂。", "兒女滿眼前，嬉戲羅酒漿。", "威命忽臨門，一物不得將。", "回顧堂中人，獨汝在我傍。", "舟行有蛟螭，夜宿畏虎狼。", "豈無平生交，鄙遠多遁藏。", "古藤底處所，敗驛無垣墻。", "急雨挟風雷，漏水夜沒床。", "竹屋聞號呼，老兵凍欲僵。", "郡僚誰復顧，獨見李與黄。", "時時餽一臠，稍稍葺兩廊。", "生意春欲回，倒景照屋梁。", "散步得幽徑，讀書有明窗。", "僕夫浣我衣，鄰娃縫汝裳。", "晨庖鱸膾美，密室沉水香。", "文字可消憂，探索易老荘。", "我唱汝輙和，不知歲月長。", "葛洪隱岣嶁，蒼梧真帝鄉。", "汝歸固不惡，淹泊庸何傷。", "作詩送汝行，示汝鴻雁行。"]'),
('1df492c8-f82c-47f8-8d5f-ed5820aa546e','送孟博二首  其二','李光','宋','宋诗','song-poetry','','[]','我少事遠遊，出門如野鶴。',144,'全唐诗/poet.song.82000.json','["我少事遠遊，出門如野鶴。", "藩籬脱雞羣，乘風縱寥廓。", "一往四十年，平地起山嶽。", "世緣真夢幻，電過不可捉。", "南來幾萬里，顧笑恍如昨。", "昔如雲釋嶠，今若龜脱殻。", "朅來容江上，風物喜淳朴。", "豈無鄉土戀，浮念起即覺。", "汝歸暫歡顔，所念路悠邈。", "朝行避煙瘴，夜宿傍城郭。", "賸誇魚米賤，勿說風土惡。", "嚬送與笑迎，但可付一噱。"]'),
('48b312f2-dabd-42fc-83a6-38e5b5bf365b','有嘉堂酒寄吴令','李光','宋','宋诗','song-poetry','','[]','今晨有好懷，薄日照窗牖。',84,'全唐诗/poet.song.82000.json','["今晨有好懷，薄日照窗牖。", "幽人不可致，誰共一杯酒。", "鄰翁有遠餉，分寄中山友。", "歡伯信可人，麴生亦耐久。", "豈比從事君，開緘化烏有。", "獨酌還徑醉，千篇莫停手。", "應思水邊人，竹屋雜蜑叟。"]'),
('549ac9c2-5ded-44fd-ab6a-69ebb5b48458','簽判黄元功公廨枕江有小亭落成之初予偶假居之明潔深穩因得游息其上榜曰寓亭并留鄙句以見意','李光','宋','宋诗','song-poetry','','[]','物生天壤間，有形孰非寓。',144,'全唐诗/poet.song.82000.json','["物生天壤間，有形孰非寓。", "心隨萬境轉，飛走各依附。", "嶠南山河異，歲月亦屢度。", "新亭枕江臯，杳渺可飛步。", "風濤振几席，雲月隨杖屨。", "吾生真寄耳，那復歎淹駐。", "當年有離憂，政以南北故。", "舉足皆道場，意適隨所遇。", "往參少林禪，歸指曹溪路。", "去住吾何心，要以生死喻。", "遠迹混漁樵，忘機狎鷗鷺。", "千載如知心，相對猶旦暮。"]'),
('d91af1b4-c676-4b4c-9f40-55a2fbcb8650','題李子從清風閣','李光','宋','宋诗','song-poetry','','[]','吾宗河山傑，氣直甘賤貧。',120,'全唐诗/poet.song.82000.json','["吾宗河山傑，氣直甘賤貧。", "一坐古藤州，十見嶺嶠春。", "深林寄倦翼，涸轍横修鱗。", "華閣俯大江，東望山嶙峋。", "一榻自俯仰，鼻息撼四鄰。", "稚兒日戲側，丱妙參席珍。", "人間正熱惱，道上多瘴塵。", "清風颯然至，自謂羲皇人。", "願師陶靖節，不羡石季倫。", "有酒但頻酌，從渠喜還嗔。"]'),
('63550646-186a-4d6e-aae1-56abd02e0d8c','新亭','李光','宋','宋诗','song-poetry','','[]','新亭結雲根，暗谷通子午。',216,'全唐诗/poet.song.82000.json','["新亭結雲根，暗谷通子午。", "環山繚遠碧，雲木巧相補。", "峭壁倚層霄，痕迹無鑿斧。", "朝登晻靄中，嵐氣隨步武。", "須臾大明升，萬象快觀覩。", "一日一坐間，變態難悉數。", "松陰轉虛簷，清梵出重廡。", "閭閻萬瓦合，下視纔一縷。", "悠悠落日吞，耿耿寒月吐。", "邀朋文字飲，四座揮玉麈。", "雅詩發天慳，妙語叩玄圃。", "援琴奏哀彈，得趣忘抑撫。", "人生貴適意，涉世隨仰俯。", "陋矣韓淮陰，耻與噲等伍。", "三年瞬息中，聊作溪山主。", "杯深且樂聖，綆短強汲古。", "至理在目擊，何用苦撐拄。", "超然心境空，逸韻渺天宇。"]'),
('6eff9f5d-a136-43f7-ba28-9462227ba117','九月二日自公館遷居雙泉風物幽勝作雙泉詩二十韻','李光','宋','宋诗','song-poetry','','[]','山腰秘靈源，初出纔一線。',240,'全唐诗/poet.song.82000.json','["山腰秘靈源，初出纔一線。", "方池湛空碧，奔馳忽縈轉。", "皎皎涵青蘋，纍纍湧珠串。", "夜深耿落月，澄澈静如練。", "呀然舊穴深，神物或時現。", "邦人儻知敬，早歲起雷電。", "瓊山瀕巨海，鹵水充煎煉。", "凛然居其間，正味獨不變。", "我來卜幽居，蕭灑得奇觀。", "挹彼注兩泉，澠淄忘分辨。", "陶公豈虚言，掬飲逃禍難。", "激齒冰雪寒，晨起頻嗽嚥。", "入腹清而冽，丹田賴澆灌。", "甘寒勝鍾乳，精潔可羞薦。", "静無蛙蜩喧，不受泥滓澱。", "惠泉入權門，疲人走郵傳。", "貪泉亦強名，聞者自鄙賤。", "瓶罌日夜汲，閭里悉周徧。", "數椽如可老，一壑吾欲擅。", "時時俯清泠，照見本來面。"]'),
('ad50a05d-7bcb-4ecd-9f5e-1ee372327592','九月二日徙居雙泉翌日徐自然使君李申之監郡携酒見過退成古調百三十言戲簡二公一笑','李光','宋','宋诗','song-poetry','','[]','南行踰萬里，公館煩造請。',156,'全唐诗/poet.song.82000.json','["南行踰萬里，公館煩造請。", "主人憐老病，爲卜林廬静。", "郊居偶然遂，俗慮盡可屏。", "雙泉信奇絕，歲久渾泥濘。", "稍覺藻荇繁，漸已産蛙黽。", "滌除賴衆力，傾頹費修整。", "幽竇響珮環，平地散林影。", "潺潺來枕上，客夢安得永。", "邦人日夜汲，攜挈雜罌皿。", "秋蔬灌百畦，夏稻溉千頃。", "端能滴冷泉，那復遜冰井。", "使君屏歌吹，政恐煞風景。", "我亦慣窮獨，客至但煎茗。"]'),
('a11567c2-3170-49b8-b3d4-5f8213bb4053','雙泉詩','李光','宋','宋诗','song-poetry','','[]','作詩愧才慳，徒勤再三請。',156,'全唐诗/poet.song.82000.json','["作詩愧才慳，徒勤再三請。", "一聆咸池奏，頓覺哇淫静。", "惡句如惡人，浪出必遭屏。", "君詩似澄江，萬里無滓濘。", "我詩昩格律，聒耳類鼃黽。", "蘇公經行地，亭宇稍葺整。", "方池湛寒碧，曾照東坡影。", "新詩與妙畫，千載未爲永。", "不聞宗廟器，傍欲間瓦皿。", "吾徒且加餐，今古屈伸頃。", "何如棄寸繩，要出千尺井。", "蓬莱隔弱水，未易凌倒景。", "時能訪幽獨，論文具醪茗。"]'),
('d217417b-c9ce-4dc5-938a-ea8bf7caf182','九日登瓊臺再次前韻','李光','宋','宋诗','song-poetry','','[]','異鄉感節物，聊赴使君請。',156,'全唐诗/poet.song.82000.json','["異鄉感節物，聊赴使君請。", "層臺縹緲間，野曠天宇静。", "木落水涵空，氛霧俱遠屏。", "籬邊菊斕斑，遠摘带沙濘。", "誰云鼓吹雄，謾欲等鼃黽。", "短髪不勝簪，烏帽倩誰整。", "衰頹強追歡，起舞羞顧影。", "君憂白晝短，我愛清夜永。", "三釂意彌勤，殽酒罄杯皿。", "棄置身外事，聊復樂俄頃。", "世方洶波瀾，我心猶古井。", "歸來豪興盡，宴坐朝內景。", "明朝汲新泉，舊篋餘賜茗。"]'),
('81185b58-0d03-4492-bd69-ccc77f1dfc57','中秋謝彦恭惠酒','李光','宋','宋诗','song-poetry','','[]','中秋有佳月，名醖來海康。',144,'全唐诗/poet.song.82000.json','["中秋有佳月，名醖來海康。", "海康太守賢，憐我持空觴。", "遠分十具至，呼兒喚鄰墻。", "坐客盡飲流，一舉空罍缸。", "酒酣對明月，不藉燈燭光。", "移席俯清流，照我兩鬢霜。", "海北與海南，各在天一方。", "我老歸無期，兩地遙相望。", "宴坐桄榔庵，守此歲月長。", "願子一咄嗟，跨空結飛梁。", "度此往來人，魚鹽變耕桑。", "籬邊白衣來，莫待菊蘂黄。"]'),
('f99b9943-d312-4a99-b7a3-4d9ccc3e5d87','和徐漕苦雨之什','李光','宋','宋诗','song-poetry','','[]','澤國三月雨，浩渺灌室廬。',120,'全唐诗/poet.song.82000.json','["澤國三月雨，浩渺灌室廬。", "爕調歸化工，佞佛計已疏。", "乘時舞鰌鱔，快意鳬鶩趋。", "君來持龍節，問俗浮江湖。", "風濤正豗蹙，斯民豈寧居。", "一飽不可期，况乃供軍須。", "素懷澄清志，慷慨時登車。", "田疇得安業，十郡通有無。", "陰霾會消釋，清風爲驅除。", "漸聞閭里間，歡聲變嗟吁。"]'),
('b3d058f2-1e84-49ca-ae8e-3839e6d7e05d','元夕陰雨孤城愁坐適魏十二介然書來言瓊臺将然萬炬因以寄之','李光','宋','宋诗','song-poetry','','[]','海濱遇元夕，况值愁陰天。',180,'全唐诗/poet.song.82000.json','["海濱遇元夕，况值愁陰天。", "重雲障佳月，微雨雜瘴煙。", "孤城欲黄昏，里巷已蕭然。", "荒祠鼓坎坎，老巫舞蹁躚。", "揮杖眩村氓，捩齒傳神言。", "異域俗尚鬼，殊形耳垂肩。", "邦人素敬畏，香燈競駢闐。", "使君招我飲，老病不得前。", "有如伏櫪馬，硉兀難加鞭。", "遙知瓊臺上，萬炬照綺筵。", "幽人正愁絕，跏趺坐深禪。", "霧靄埋羣山，不礙孤月圓。", "茅菴一燈留，照我獨不眠。", "夜闌香篆銷，息息火自傳。", "何當訪羽客，同上羅浮巔。"]'),
('9613e99e-dc6e-4be9-923e-92c88b03800f','丙寅重九權郡李申之置酒嚴氏野趣亭愛其幽深因作此詩','李光','宋','宋诗','song-poetry','','[]','遷流南海濱，兩見菊蘂黄。',120,'全唐诗/poet.song.82000.json','["遷流南海濱，兩見菊蘂黄。", "今晨有嘉招，駕言陟崇岡。", "負郭得勝游，幽居渺雲荘。", "小亭椰葉間，下有青蓮塘。", "寒花卧短籬，疏松間修篁。", "隔屋雞犬聲，遠村散牛羊。", "使君慕幽貞，愛此野趣長。", "緬懷千載人，聊復舉一觴。", "西風起蕭瑟，吹我兩鬢霜。", "旋駕豈無期，良燕詎易忘。"]'),
('71d376e2-cc32-4ef3-8072-190d1306a019','瓊惟水東林木幽茂予愛此三士所居雖無亭館之勝而氣象清遠連日水漲隔絕悠然遐想各成一詩目爲城東三詠  其一','李光','宋','宋诗','song-poetry','','[]','南極多老人，及見九代孫。',144,'全唐诗/poet.song.82000.json','["南極多老人，及見九代孫。", "君生古崖州，氣質清且溫。", "今年八十二，頗覺行步奔。", "白髪暎紅頰，疑是羲皇人。", "城東有幽居，瀟灑真隱淪。", "淵明寓栗里，子美還羌村。", "遷流到雙泉，得與君子鄰。", "仁里聖所擇，德齒古所尊。", "佳節近重陽，黄花已紛紛。", "家家社酒香，處處烹雞豚。", "今朝風日好，水落依舊痕。", "一散腰脚頑，杖策時叩門。"]'),
('c7b405ff-b2fa-4263-a910-a43cfc92bc65','瓊惟水東林木幽茂予愛此三士所居雖無亭館之勝而氣象清遠連日水漲隔絕悠然遐想各成一詩目爲城東三詠  其二','李光','宋','宋诗','song-poetry','','[]','我愛曾城居，負郭頗幽雅。',96,'全唐诗/poet.song.82000.json','["我愛曾城居，負郭頗幽雅。", "田疇遶屋廬，門逕絕車馬。", "但虞水侵門，敢怨風飄瓦。", "淵明非避俗，自覺往來寡。", "嗟予屏斥久，兹地猶里社。", "相望十里間，舟楫幸可假。", "風休水亦落，晴日照郊野。", "願言駕柴車，始覺我憂寫。"]'),
('d5da9d89-f126-4acf-881e-4d448e4d4ae1','自然解印北還作古風送行','李光','宋','宋诗','song-poetry','','[]','徐侯古循吏，作牧海南邊。',168,'全唐诗/poet.song.82000.json','["徐侯古循吏，作牧海南邊。", "三載撫民夷，擒縱出拘攣。", "里巷絕嗟呼，囹圄無淹延。", "父老有好詞，不見吏索錢。", "忽聞解印綬，蠻歌惨離筵。", "遠控横海鯨，追躡凌波仙。", "寄語廣利神，無令颶風顛。", "臨行一麾手，萬事盡棄捐。", "勿作兒女戀，吚嚘涕潺湲。", "火雲赤崢嶸，修途願加鞭。", "愛君氣猛厲，心似鐵石堅。", "迥悟出世法，痛掃習氣纒。", "明窗净棐几，華藏了大千。", "别語徒諄諄，維摩本無言。"]'),
('bd849fbc-6430-41d2-b198-4f2e30212a58','憶筍','李光','宋','宋诗','song-poetry','','[]','會稽富竹萌，窮臘鞭已抽。',180,'全唐诗/poet.song.82000.json','["會稽富竹萌，窮臘鞭已抽。", "我家南山南，不羡萬戶侯。", "暮春杜鵑啼，茁茁蓬麻稠。", "冒土出羊角，穿籬露猫頭。", "紫蕨性陰冷，荻芽體輕浮。", "愛此凌雲姿，不與凡卉儔。", "勝韻貴苦腴，兒童悦甘柔。", "爽口聊一快，弱胃敢怨尤。", "朅來海南邦，腥鹹厭蠻羞。", "桃枝但叢生，澀勒蔽道周。", "遙看貌或似，美惡如薫蕕。", "安能助盤餐，嘔嘔但棘喉。", "唯有檳榔心，羮臛或暗投。", "鄉味不可忘，坐想空涎流。", "人生各有適，勿語王子猷。"]'),
('c073786f-0b16-47c4-89f2-f6957ed2f7b1','去地草','李光','宋','宋诗','song-poetry','','[]','城東古雙泉，清駛給萬家。',144,'全唐诗/poet.song.82000.json','["城東古雙泉，清駛給萬家。", "缾罌晝夜給，舶賈雜鄰娃。", "蠻童與蜑女，赤脚兩髻丫。", "常苦藻荇繁，滋蔓掩白沙。", "蕭疏失林影，聒聒鳴亂蛙。", "十夫勇善沒，入水初紛拏。", "詎勞斧鉞誅，芟荑費鋤杷。", "除惡去根本，無令再萌芽。", "依憑絕纖鱗，驚懼失老蛇。", "風吹有縠紋，月照無纖瑕。", "銅盆湛冰雪，石鼎發乳花。", "餘波及農圃，父老免嘆嗟。"]'),
('088b0534-0ba3-44fb-97cb-216595b507ff','敘遊二十韻呈亨叔列之','李光','宋','宋诗','song-poetry','','[]','戊辰三月晦，端居倦煩促。',240,'全唐诗/poet.song.82000.json','["戊辰三月晦，端居倦煩促。", "是時天久旱，炎烝劇三伏。", "出門得幽尋，佳處在東北。", "二子俱可人，皎皎瑩冰玉。", "得趣琴有絃，對案食無肉。", "初弹醉翁操，再鼓南風曲。", "琅然山水音，一洗瘴霧毒。", "陳園俯江郊，茅茨擁修竹。", "造門慕子猷，緩步效顔斶。", "汲泉瀹佳茗，蕭散謝羈束。", "清華臨水岸，下有萬荷綠。", "披榛訪蕭子，清净獨無欲。", "黎沈爇瓦鼎，溪蓀養石斛。", "杖藜轉修徑，夹道森喬木。", "歸途遇馮姥，斂袂不羞縮。", "蕉花雜山丹，檳榔繞新屋。", "欲我留姓名，呼兒爲磨墨。", "似憐窮獨叟，曾忝十州牧。", "良辰不易遇，此會豈難續。", "他時儻重來，更爲呼醉秃。"]'),
('514e7c4b-e5ec-440e-af94-54208693347c','世以啄木爲珍禽其聲至入樂府而海南一種形小而聲淫每四五月間飛鳴如蛙蟈至八九月乃已亦名啄木繁聲可惡然瓊人訛其聲爲罵秃禽殆得其實因爲賦詩','李光','宋','宋诗','song-poetry','','[]','南海四五月，有鳥名啄木。',132,'全唐诗/poet.song.82000.json','["南海四五月，有鳥名啄木。", "飛鳴亂葉間，形眇聲繁促。", "枝間時瞥見，黑啄羽毛綠。", "雌雄相應和，生哺依老穀。", "或疑在家僧，受施不看讀。", "爲禽不知名，但自罵秃秃。", "小兵特輕趫，修竿每馳逐。", "今晨耳目清，桑下聞布穀。", "黄鸝兩三聲，睍睆出幽谷。", "從今屏菑翳，遶舍植梧竹。", "鳴鳳儻可期，樛枝要棲宿。"]'),
('eafc394a-8851-41d2-8870-722c95aeb3e6','居嶺外遇寒食','李光','宋','宋诗','song-poetry','','[]','春日自明霽，我心何鬰傷。',156,'全唐诗/poet.song.82000.json','["春日自明霽，我心何鬰傷。", "草木競芳菲，飛鳴自頡頏。", "悄悄坐書幌，幽幽宴空床。", "既無功名念，反思白晝長。", "愁來不自持，零落鴻雁行。", "三過解澤流，六見槐柳黄。", "最憐小兒女，路遠不得将。", "生還一笑喜，死去埋他鄉。", "生死如循環，我師佛老荘。", "感此寒食節，新烟過鄰墻。", "松楸渺雲海，目極摧肝腸。", "書成附鱗翼，不如永相忘。", "何以慰目前，作詩示阿張。"]'),
('8995329f-29f0-45d4-aa90-d045bed33617','仲兄去歲落一齒書來悵然作詩以寛其意','李光','宋','宋诗','song-poetry','','[]','四大非我有，元氣力護持。',180,'全唐诗/poet.song.82000.json','["四大非我有，元氣力護持。", "齒從齠齓換，既老還復隳。", "太公含兩齒，卒爲帝王師。", "睢陽嚼空齦，名與日月垂。", "張儀但舌在，折齒激范雎。", "漢相老無齒，飲乳如嬰兒。", "安得鐵如意，擊堕還離離。", "齒存固可喜，齒落無深悲。", "退之有成言，軟飯穩送之。", "何須噬乾胏，但可食肉靡。", "養生已有堂，晏坐吞朝曦。", "谷神定不死，老聃豈吾欺。", "時爲五禽戲，納息如靈龜。", "命友日飲醇，弄孫且含飴。", "齒落會復生，千載儻可期。"]'),
('988a6a35-e844-41de-b28d-fe9a6bb11be5','八月七日夜對月','李光','宋','宋诗','song-poetry','','[]','仲秋氣已爽，林壑雨新過。',120,'全唐诗/poet.song.82000.json','["仲秋氣已爽，林壑雨新過。", "忽驚浮靄空，乍覺天宇大。", "夜凉風露清，佳月纔半破。", "清輝漸可愛，入戶驚照坐。", "團圞遶中庭，有似蟻循磨。", "西山聳岡巒，輪側愁易堕。", "魏子不解飲，詩語頗頓挫。", "呼兒聊與醆，我唱渠輙和。", "停杯看月落，客去未能卧。", "海月夜夜好，新詩幸頻課。"]'),
('16ce4156-fc84-43b5-9353-beeb09919cc8','庚午春予得罪再貶昌化瓊士餞送者皆悵然有不忍别之意嚴君錫魏介然追路至儋耳兹事當求之古人感歎成古風二百言送行','李光','宋','宋诗','song-poetry','','[]','紹興庚午春，李子復南徙。',240,'全唐诗/poet.song.82000.json','["紹興庚午春，李子復南徙。", "倉皇就長途，夜擔不敢弛。", "餞我無雜賓，亦有方外士。", "裴杜二耆哲，矍鑠渾童稚。", "老禪不忍别，握手揮涕淚。", "行行至澄邁，名姓難盡紀。", "酒酣通湖閣，頗獲一笑喜。", "緬懷雙泉居，風土信清美。", "牀頭掛海月，枕上聽流水。", "夜棋招隱淪，濁酒會鄰里。", "桑下不三宿，悵戀吾過矣。", "人生隨遇樂，已過猶脱屣。", "最憐嚴與魏，觸熱到儋耳。", "世情逐炎凉，萬古同一軌。", "對境心數役，何以敵生死。", "南窗可寄傲，散帙忽盈几。", "松林十里間，移植頗易致。", "赫日資繁陰，且復宥老楮。", "夜凉得深禪，日永常晚起。", "恨君不少留，伴我讀書史。"]'),
('9cb71a1a-f992-4c5b-8e79-dee3da6cb7f1','海外謡','李光','宋','宋诗','song-poetry','','[]','嗟爾海南民，遭此贓吏阨。',288,'全唐诗/poet.song.82000.json','["嗟爾海南民，遭此贓吏阨。", "銜冤無所訴，相熾起爲賊。", "爲賊計誠拙，尚可活朝夕。", "攝官陳建中，貪猥最狼藉。", "有女攀勢要，不料非偶匹。", "但務房奩多，苞苴又絡繹。", "挟此恣貪惏，如虎傅以翼。", "貳車號按察，往訴遭箠擊。", "最後差丁夫，欲免人十直。", "貧民賣妻孥，強者起持戟。", "至今文昌縣，白晝無人迹。", "其次經界官，太守乃姻戚。", "隨行縱獄吏，聲勢如霹靂。", "郡縣遭唾罵，圖冊成覆易。", "三豪因衆怒，從者如葦棘。", "去年從說諭，閭里已帖息。", "狂謀起賕吏，從此復反側。", "愚民本無知，脅誘冒鋒鏑。", "焚蕩玉石俱，老弱轉溝洫。", "遺骸横道路，流血千里赤。", "殺戮誠快意，贓吏有德色。", "從今無忌憚，徴斂幾時息。", "沉香與翠羽，窮搜遠彈射。", "烏衣徧村墟，氣焰已可炙。"]'),
('b18c3075-e6c2-47a9-b002-aaff095705a0','紹聖中蘇公內翰謫居儋耳嘗與軍使張中遊黎氏園愛其水木之勝勸坐客醵錢作堂黎氏名子雲因用揚雄故事名其堂曰載酒予始至儋與瓊士魏安石杖策訪之退作二詩','李光','宋','宋诗','song-poetry','','[]','何年老揚雄，寄此十畝園。',72,'全唐诗/poet.song.82000.json','["何年老揚雄，寄此十畝園。", "年深草木荒，杖策誰叩門。", "緬懷東坡老，陳迹記舊痕。", "空餘載酒堂，往事孰與論。", "黄柑與丹荔，不受瘴霧昏。", "邦人時餽奠，一笑空罍尊。"]'),
('49b99914-70e1-4da2-9cbc-abf49a364e2d','東坡載酒堂二詩蓋用淵明始春懷古田舍韻遂不見於後集予至儋始得真本因追和其韻  其一','李光','宋','宋诗','song-poetry','','[]','荒園草木深，樵牧不敢踐。',84,'全唐诗/poet.song.82000.json','["荒園草木深，樵牧不敢踐。", "雖無南國愛，正以東坡免。", "平泉與金谷，視此顔有靦。", "至今儋耳民，里巷多樂善。", "勝遊儻可繼，杖策敢辭遠。", "燕談有佳侣，永日可忘返。", "酒酣任歌呼，此興吾不淺。"]'),
('50936523-bb77-45d2-94e7-acb680ab4be1','東坡載酒堂二詩蓋用淵明始春懷古田舍韻遂不見於後集予至儋始得真本因追和其韻  其二','李光','宋','宋诗','song-poetry','','[]','嗟彼海南郡，土瘠士常貧。',96,'全唐诗/poet.song.82000.json','["嗟彼海南郡，土瘠士常貧。", "藷芋餉晝耕，松明照夜勤。", "當年兩黎老，能邀玉堂人。", "一往五十年，遺迹宛若新。", "邦君時舉酒，父老舉欣欣。", "賢多隱農圃，耦耕可問津。", "魯叟欲乘桴，東坡願卜鄰。", "他年青衿子，凛凛多秀民。"]'),
('63ab7a32-982a-4f3a-b61e-a287f767ac6e','客有見饋溫劑云可壮元陽感而有作','李光','宋','宋诗','song-poetry','','[]','世人服暖藥，皆云壮元陽。',276,'全唐诗/poet.song.82000.json','["世人服暖藥，皆云壮元陽。", "元陽本無虧，藥石徒損傷。", "人生百歲期，南北隨炎凉。", "君看田野間，父老多康強。", "茅簷弄兒孫，春隴驅牛羊。", "何曾識丹劑，但喜秫黍香。", "伊予十年謫，日聞貴人亡。", "金丹不離口，丱妙常在傍。", "真元日滲漏，滓穢留空腸。", "四大忽分離，一物不得将。", "歌喉變哀音，舞衣換縗裳。", "爐殘箭鏃砂，箧餘鹿角霜。", "咄哉此愚夫，取樂殊未央。", "我有出世法，亦知不死方。", "禦寒須布帛，欲飽資稻粱。", "床頭酒一壺，膝上琴一張。", "興來或揮手，客至亦舉觴。", "滌硯臨清池，抄書傍明窗。", "日用但如斯，便覺日月長。", "参苓性和平，扶衰固難忘。", "恃藥恣聲色，如人畜豺狼。", "此理甚明白，吾言豈荒唐。", "書爲座右銘，聊以砭世盲。"]'),
('e44f04b8-300f-4b5b-9d34-62a4bb1d8043','食無肉','李光','宋','宋诗','song-poetry','','[]','養生有真詮，虚心實其腹。',108,'全唐诗/poet.song.82000.json','["養生有真詮，虚心實其腹。", "十年嶺海游，一鉢隨僧粥。", "納息歸丹田，息在火亦伏。", "黄河朝崑崙，晝夜自回復。", "空膓無滓穢，氣轉聲漉漉。", "腥膻减吾壽，厚味有腊毒。", "顔回稱好學，陋巷一瓢足。", "何侯日萬錢，但取身後辱。", "虀鹽有餘味，何必常食肉。"]'),
('900eba5b-9ff9-40c8-ba2d-ea18ad7699c0','居無屋','李光','宋','宋诗','song-poetry','','[]','處世若傳舍，吾生聊託宿。',96,'全唐诗/poet.song.82000.json','["處世若傳舍，吾生聊託宿。", "志士守蝸廬，幽人卧空谷。", "君看漢梁董，日享萬鍾祿。", "華榱庇千間，子孫無託足。", "海南吾欲老，是處堪卜築。", "結庵傍松林，開牖面修竹。", "野老日往來，席地有棋局。", "俯仰天地寛，莫嘆居無屋。"]'),
('d3273196-3fc8-49b1-ab1a-fefe0ed275ae','海南有五色雀土人呼爲小鳳罕有見者蘇子瞻謫居此郡紹聖庚辰冬再見之常作詩記其事公實以是年北歸癸酉冬予亦兩見之今二年矣乙亥八月二十二日會客陳氏園飛鳴庭下回翔久之衆客驚嘆創見因賦是詩','李光','宋','宋诗','song-poetry','','[]','海南有珍禽，厥服具五色。',168,'全唐诗/poet.song.82000.json','["海南有珍禽，厥服具五色。", "絳者爲之長，飛鳴隨止息。", "佳哉陳氏園，形制存古迹。", "我遊秀野堂，森木蔭華席。", "羣飛爲我來，馴擾如夙昔。", "鴟梟既遠遁，烏鳶俱辟易。", "邦人號小鳳，隱見異凡翼。", "姬公嘆不聞，尼父未之識。", "嗟予戅且愚，疾惡不量力。", "叱杞誚希烈，流竄至南極。", "神物知吾忠，天公憐我直。", "吉凶有先兆，告我將返北。", "蘇公不吾欺，流詠冠今昔。", "斯言儻有徴，便可具接淅。"]'),
('24ca5dca-ad6c-44c5-8a94-bfb9d51b206f','不出','李光','宋','宋诗','song-poetry','','[]','老氏不出牖，莊生務內游。',72,'全唐诗/poet.song.82000.json','["老氏不出牖，莊生務內游。", "猿猱猶習定，難犬放須收。", "俛仰超三際，翺翔隘九州。", "坐忘師正一，辟穀慕留侯。", "客至酒三酌，睡餘茶一甌。", "蕭然方丈內，卒歲更何求。"]'),
('0a625072-2e22-4f42-9c87-e4c40ae35113','五月十三日北歸雷化道中','李光','宋','宋诗','song-poetry','','[]','謫居了無營，贏得一味間。',168,'全唐诗/poet.song.82000.json','["謫居了無營，贏得一味間。", "杜門十六年，草深沒柴關。", "猛獸當路號，虺蛇伏榛菅。", "今兹果何年，天誅此凶姦。", "羣妖既蕩除，善類稍北遷。", "仲子萬里來，喜極涕淚潸。", "坐定復載笑，喜我顔渥丹。", "人生七十稀，况復加九年。", "平生學飬生，吐納留真詮。", "忘家何足道，絕欲亦偶然。", "歸歟謝世榮，收功在丹田。", "宴坐息息匀，頻嚥舌底泉。", "日用形欲勞，何必驅小蠻。", "看我鰥氣成，空行躡飛仙。"]'),
('9c5177c5-54b3-453a-93f7-1c34137f8933','和胡德暉松軒詩','李光','宋','宋诗','song-poetry','','[]','炎天羣木無葱蒼，朝曦夕照繞屋梁。',138,'全唐诗/poet.song.82000.json','["炎天羣木無葱蒼，朝曦夕照繞屋梁。", "一榻南窗復東廂，老松效技扶披猖。", "微風颼飀弄笙簧，坐變熱惱爲清凉。", "簿書相仍愁肺腸，細聲入夢我豈遑。", "但覺風日明晴窗，皎如夜月和秋霜。", "樛枝鱗皴龍蜃走，翠葉鬰律鸞鳳翔。", "燧明徒誇能照夜，坐想煙霧風中香。", "何如軒成獨賦雲錦章，從兹遂愛夏日長，會看壑聳仍霄昂。"]'),
('693885f9-1de0-4be4-b9f5-82ffd700db13','辛未人日同郡僚遊陳氏園','李光','宋','宋诗','song-poetry','','[]','海南人日春已濃，柳條遠映桃花紅。',112,'全唐诗/poet.song.82000.json','["海南人日春已濃，柳條遠映桃花紅。", "攜觴尋伴逐春色，杖藜縱步遊城東。", "陳園新築芳亭小，綠竹猗猗自圍繞。", "杯行不用管絃催，枝上綿蠻囀春鳥。", "舊傳人日天多陰，今年人日春光好。", "田家但喜藷芋收，我輩惟憂酒樽少。", "明朝有興還復來，賸買鹿蹄拚醉倒。"]'),
('6f2a2921-5404-4b4a-b240-a8c0e2328f64','樂會雷令數惠筍作詩爲謝','李光','宋','宋诗','song-poetry','','[]','朝餐敢歎庖無肉，食罷時時自捫腹。',96,'全唐诗/poet.song.82000.json','["朝餐敢歎庖無肉，食罷時時自捫腹。", "肯羡何侯日萬錢，不學天隨嘗杞菊。", "傳聞樂會似淇園，坐想猗猗千畝綠。", "邦人富比萬戶侯，縣尹清亷仍不俗。", "尺書遠致擬兼金，錦綳解縛排寒玉。", "爲君急食不敢餘，恐被南風吹作竹。"]'),
('0c2668c1-6084-47bf-b524-9aaaf595042d','清湘道士潘静素抱琴南來予方謫居遠屏郊外如逃虚中每佳辰良夜風清月明對脩竹俯清池必快作數弄如是幾年今将北還舊隱索詩爲别屢請而不懈因歌而送之','李光','宋','宋诗','song-poetry','','[]','道人南來冒炎酷，雲水生涯寄枯木。',208,'全唐诗/poet.song.82000.json','["道人南來冒炎酷，雲水生涯寄枯木。", "嗟予久墮魑魅羣，黎唱蠻歌耳根熟。", "深林迥静嘯鵂鶹，雨濕天陰聞鬼哭。", "君來爲我一揮手，洗盡胸中塵萬斛。", "伯牙師涓死已久，此聲欲絕君能續。", "快彈初作鸞鳳鳴，忽如啼烏集華屋。", "吟猱抑按神氣閑，流水涓涓赴幽谷。", "夜深餘響應霜鐘，朝來吟對蕭蕭竹。", "静中最喜讀書聲，妙響琅然振寒玉。", "要知心與古人會，不務新奇誇俚俗。", "浩歌别我出門去，潮回風便難追逐。", "道人來時湘水渾，道人歸去湘江綠。", "湘靈抱琴待君來，月明莫向江頭宿。"]'),
('053fc7b7-83e0-4477-9bf9-8558d6320910','贈裴道人','李光','宋','宋诗','song-poetry','','[]','道人今年七十六，問我修行惟絕欲。',250,'全唐诗/poet.song.82000.json','["道人今年七十六，問我修行惟絕欲。", "密栽澀勒當疏籬，旋闢荒榛結茅屋。", "不抄書，不看讀，宴坐凝然常瞑目。", "夜深頻嚥玉池泉，晨起隨緣飽藷粥。", "甘脆肥濃腐我腸，巧笑蛾眉真鴆毒。", "蠻煙瘴霧隘空虚，謹守藥爐誰敢觸。", "我愛裴君道機熟，過我玄談已超俗。", "三峰頂上少人行，百尺竿頭防失足。", "世人那識天地根，往來綿綿無斷續。", "嗟予流轉海南村，智者方明禍中福。", "君不見龐道藴，盡将活計沈湘江，自織笟籬供口腹。", "又不見成都市上嚴君平，終日垂簾唯賣卜。", "王侯螻螘同丘墟，學道從來貴幽獨。", "蚌生珠，石含玉，看我丹成跨鴻鵠。", "馬蹄去去穩着鞭，關山路永多坑谷。"]'),
('47ae6df3-6987-4489-bf35-ee7ed8f3333c','成氏園','李光','宋','宋诗','song-poetry','','[]','泰和坊外成家園，花木幽茂泉涓涓。',128,'全唐诗/poet.song.82000.json','["泰和坊外成家園，花木幽茂泉涓涓。", "竹籬茅舍稱野逸，平坡細徑遙相連。", "青松翠竹晚色净，紅蕉素槿秋爭鮮。", "幽禽頡頏樹蒙密，古木夭矯藤交纒。", "嗟予與子成二老，登山臨水追少年。", "幕中羣彦盡豪俊，小兒亦許依紅蓮。", "焚香隱几如逃禪，一枰勝負聊欣然。", "誰云嶺南瘴癘地，城西一壑吾欲専。"]'),
('4e79b967-f0ee-4ec3-93ab-42352438ad9c','四月十七夜觀月成詠','李光','宋','宋诗','song-poetry','','[]','曉來新過雨，天宇肅以凉。',150,'全唐诗/poet.song.82000.json','["曉來新過雨，天宇肅以凉。", "横空跨綵虹，物被五色光。", "夜久羣動息，月出東南方。", "團團葉間露，皎皎瓦上霜。", "四月未全熱，清飈吹我裳。", "新橋跨長堤，下有百里江。", "月色萬古在，江流自奔忙。", "誰呼謫仙人，被髪下大荒。", "對月哦汝詩，臨流飲我觴。", "夜景信奇絕，茲游固難忘。", "天地多變態，况乃魑魅鄉。", "不如坐待赫日射屋梁，妖禽孽狐都走藏。"]'),
('0d34f1b6-e15a-411b-a89b-d6089a02afc0','玄珠吟','李光','宋','宋诗','song-poetry','','[]','黄帝曾遊赤水北，遺了玄珠無處覓。',96,'全唐诗/poet.song.82000.json','["黄帝曾遊赤水北，遺了玄珠無處覓。", "我今偶到海南村，煩惱泥中親拾得。", "珠體圓明光滴瀝，流轉根塵人不識。", "只在尋常動用中，未見爭知吾不失。", "吁嗟世人空費力，欲見此珠須目擊。", "要令心息每相依，密密護持防六賊。"]'),
('a1558203-4342-4ac4-9265-e136a06d99b3','可歎','李光','宋','宋诗','song-poetry','','[]','金陵失守何匆匆，敵兵燒我天子宫。',160,'全唐诗/poet.song.82000.json','["金陵失守何匆匆，敵兵燒我天子宫。", "守臣頂香率父老，開門羅拜惟鞠躬。", "翠華遙遙遵海道，漢家詔令不得通。", "外交內應儔與鄴，所在州縣皆望風。", "坐觀豈但宣撫望，降夷亦有丞相充。", "山巔水涯多白骨，邇來十室九已空。", "權臣悍将恣吞噬，剝膚椎髓方稱雄。", "敵來擁兵保妻子，敵去奏捷希侯封。", "城狐社鼠爭附會，浙部復産勔與冲。", "紛紛餘子何足數，我眎文舉真如龍。"]'),
('e37a3c09-f86a-491b-b02a-b6756b108fb2','子猷知府給事寵寄道中阻雨之什憂時憫農有古良二千石之風感歎次韻  其一','李光','宋','宋诗','song-poetry','','[]','老農麥熟還忍饑，蠶婦見絲翻淚垂。',64,'全唐诗/poet.song.82000.json','["老農麥熟還忍饑，蠶婦見絲翻淚垂。", "耕田辛苦竟何補，長安游手多輕肥。", "良牧憂晴復憂雨，咄咄書空應自語。", "皇天于物無偏頗，不須怨嗟梅雨多。"]'),
('9c5a3aac-a1e5-4d1c-a5ff-8a5326b90473','子猷知府給事寵寄道中阻雨之什憂時憫農有古良二千石之風感歎次韻  其二','李光','宋','宋诗','song-poetry','','[]','赤子既迫寒且饑，異時嚴警如邊垂。',64,'全唐诗/poet.song.82000.json','["赤子既迫寒且饑，異時嚴警如邊垂。", "棄捐溝壑死鋒鏑，有如秦越視瘠肥。", "公來隨車霈靈雨，織婦耕農聞好語。", "愛民戢吏政不苛，兵興敢避科徭多。"]'),
('a49e8669-ef61-4f5f-bb18-b60ed7cf8d95','坐忘吟','李光','宋','宋诗','song-poetry','','[]','我聞天台坐忘仙，清虚石壁留真詮。',128,'全唐诗/poet.song.82000.json','["我聞天台坐忘仙，清虚石壁留真詮。", "長生要妙止一篇，林間宴坐心超然。", "壁觀無異達磨禪，繫念一處離葛纒。", "真人秘語豈浪傳，谷神玄牝常綿綿。", "嚥津納息歸丹田，泝流直上朝泥丸。", "下灌舌底生玉泉，身輕超脱如蜕蟬。", "御風騎氣追偓佺，神遊八極俯仰間。", "度人濟物功行圓，要看白日見青天。"]'),
('e0df049a-bc04-4c90-bb07-7a48688554e0','短歌贈柯山祝道人','李光','宋','宋诗','song-poetry','','[]','年來憂患老病纒，獨寝一室方蕭然。',192,'全唐诗/poet.song.82000.json','["年來憂患老病纒，獨寝一室方蕭然。", "道人顧我笑且憐，贈以一粒金華丹。", "彤霞入腹氣熻赫，紫焰照日光斒斕。", "寸田溫溫起真火，尾閭歷歷朝泥丸。", "道人年少遊賢關，曳裾躧履公卿間。", "宣和天子崇神仙，近臣薦引登金鑾。", "造膝一語開天顔，羽衣縹緲黄其冠。", "吴筠雖嘗入禁掖，稚川終隱羅浮山。", "荆棘掃盡棃棗熟，汞鉛九轉龍虎蟠。", "一裘百衲聊卒歲，斗酒滿引冰雪寒。", "朅來鐔津施丹劑，應病與藥俱輕安。", "度人濟世功行圓，超脱滓穢猶蜕蟬。"]'),
('3d9a5061-2552-46af-a39d-e161da830b46','良弼使君寄梅花翌日曹憲仲約偶成長句','李光','宋','宋诗','song-poetry','','["\u897f\u6e56"]','北歸已度梅花嶺，洗盡瘴塵愁欲醒。',128,'全唐诗/poet.song.82000.json','["北歸已度梅花嶺，洗盡瘴塵愁欲醒。", "一枝何處最奇絕，鏡裏形容水中影。", "西湖處士語已妙，東坡先生句尤警。", "三篇自可追少陵，一賦誰復傳宋璟。", "老人新從海外歸，枕冷燈清愁夜永。", "使君憐我老無伴，折贈欲令娱晚境。", "夜寒相對默無言，耿耿此心如古井。", "主人皓首自能歌，倒載花前拚酩酊。"]'),
('c6bee07c-011c-4e8d-a64a-d8cda07abdf2','飲茶歌','李光','宋','宋诗','song-poetry','','[]','朝來一飽萬事足，鼻息齁齁眠正熟。',227,'全唐诗/poet.song.82000.json','["朝來一飽萬事足，鼻息齁齁眠正熟。", "忽聞剝啄誰叩門，窗外蕭蕭風動竹。", "起尋幽夢不可追，旋破小團敲碎玉。", "山東石銚海上來，活火新泉候魚目。", "湯多莫使雲脚散，激沸須令面如粥。", "嗜好初傳陸羽經，品流詳載君謨錄。", "輕身換骨有奇功，一洗塵勞散昏俗。", "盧仝七盌喫不得，我今日飲亦五六。", "修仁土茗亦時須，格韻卑凡比奴僕。", "客來清坐但飲茶，壑源日鑄新且馥。", "炎方酷熱夏日長，麴蘖薫人仍有毒。", "古來飲流多喪身，竹林七子俱沉淪。", "飲人以狂藥，不如茶味真。", "君不見古語云，欲知花乳清泠味，須是眠雲卧石人。"]'),
('2819aa94-6cbf-454d-9c59-ccf3480e9a83','義郴廖翁贈予靈壽杖歌以謝之','李光','宋','宋诗','song-poetry','','[]','郴山峨峨水濺濺，清淑之氣鍾神仙。',128,'全唐诗/poet.song.82000.json','["郴山峨峨水濺濺，清淑之氣鍾神仙。", "山頭老木幾千年，不入樵斧隨飛烟。", "廖翁好奇自掄選，真材不用加雕鐫。", "鏗然入手龍脊瘦，宛轉隨步鶴膝堅。", "今晨過我有喜色，磨捋持贈誇奇特。", "老人年來腰脚頑，出入政藉扶持力。", "拄上岡頭望故鄉，萬壑千巖纔咫尺。", "天寒醉卧不出門，杖兮雖良長倚壁。"]'),
('0edde857-e9c8-44a6-9cbd-3de9243db610','載酒堂','李光','宋','宋诗','song-poetry','','[]','東坡文章喧宇宙，粲如日星垂不朽。',192,'全唐诗/poet.song.82000.json','["東坡文章喧宇宙，粲如日星垂不朽。", "六一老人猶避路，作者紛紛皆束手。", "俊逸精神追李杜，華妙雄豪配韓柳。", "晚年流落海南村，黎唱蠻謳隨蜑叟。", "先生已去五十年，遺墨殘篇尚多有。", "豐城寶劍埋獄中，光焰猶能射牛斗。", "敗垣壞壁秘蝸涎，夭矯龍蛇已驚走。", "獨餘黎氏舊園亭，喬木森森免薪槱。", "半是東坡親手植，老幹樛枝互纒糾。", "杖藜乘興訪遺像，遐想英風竚立久。", "曾吹葱葉送迎翁，當日兒童今白首。", "莫嗟寂寂路荒蕪，亦有幽人時載酒。"]'),
('ac392580-8b0b-461e-a928-5d177f0d58c8','郊居雜興','李光','宋','宋诗','song-poetry','','[]','竹舍臨寒浦，柴門閉落暉。',48,'全唐诗/poet.song.82000.json','["竹舍臨寒浦，柴門閉落暉。", "潮回沙路净，月出野航歸。", "風勁砧聲急，夜長更點稀。", "子雲雖寂寞，未覺草玄非。"]'),
('7329f7a0-0e2d-4dd8-8dd0-81e2e4f041bc','荷珠','李光','宋','宋诗','song-poetry','','[]','荷珠圓復碎，欹側動相關。',48,'全唐诗/poet.song.82000.json','["荷珠圓復碎，欹側動相關。", "去似臨江失，來如合浦還。", "賈人應誤喜，蓮女想輕攀。", "百斛傾梅雨，天公豈是慳。"]'),
('da51a5ef-ee39-4868-a0f5-642c300ccc47','觀穫','李光','宋','宋诗','song-poetry','','[]','老農勤畚鍤，歲暮閲星霜。',48,'全唐诗/poet.song.82000.json','["老農勤畚鍤，歲暮閲星霜。", "相見如遺秉，安能助太倉。", "晚晴雞鶩喜，蓐食婦姑忙。", "應有深村酒，招邀隔短墻。"]'),
('ad5623d0-e949-4efc-8e81-f081f1234f3f','贈林湘','李光','宋','宋诗','song-poetry','','[]','先君師建學，梅塢最交深。',48,'全唐诗/poet.song.82000.json','["先君師建學，梅塢最交深。", "共探先天易，同哦正始音。", "親亡友亦盡，人古道猶今。", "子續通家好，遺書幸細尋。"]'),
('0d6f5d50-1d51-4216-ac24-bb8f39ebd5a6','九日登樓二首  其一','李光','宋','宋诗','song-poetry','','[]','久客驚秋意，天涯思不窮。',48,'全唐诗/poet.song.82000.json','["久客驚秋意，天涯思不窮。", "三年猶北國，萬里對西風。", "時序悲歌裏，乾坤醉眼中。", "黄花一樽酒，千古此心同。"]'),
('e792a8f7-293e-4615-9f62-26adf14e57f4','九日登樓二首  其二','李光','宋','宋诗','song-poetry','','[]','木落秋容静，時平國勢雄。',48,'全唐诗/poet.song.82000.json','["木落秋容静，時平國勢雄。", "望雲心自遠，采菊興誰同。", "詩酒浮生過，功名一笑空。", "留連憑痛飲，冠幘任高風。"]'),
('29ef9f85-0c57-469b-bab4-87479d830468','寄吴元預','李光','宋','宋诗','song-poetry','','[]','出門懷抱惡，别我去遊秦。',48,'全唐诗/poet.song.82000.json','["出門懷抱惡，别我去遊秦。", "季子黄金盡，潘郎白髪新。", "一枰誰敵手，五字愈驚人。", "勉赴功名會，如公定不貧。"]'),
('3ffac380-b2c8-46bc-b441-045569c3fe61','人日','李光','宋','宋诗','song-poetry','','[]','人日靈川縣，山深雪未融。',48,'全唐诗/poet.song.82000.json','["人日靈川縣，山深雪未融。", "誰知桂嶺北，宛似浙江東。", "墟市人煙合，僧窗竹逕通。", "杖藜閑信步，日暮怯溪風。"]');
